window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["ibnu-majah_0"] = {"1":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَمَرْتُكُمْ بِهِ فَخُذُوهُ وَمَا نَهَيْتُكُمْ عَنْهُ فَانْتَهُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata; telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang aku perintahkan maka ambillah, dan apa yang aku larang maka tinggalkanlah.\""},"2":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَرُونِي مَا تَرَكْتُكُمْ فَإِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ بِسُؤَالِهِمْ وَاخْتِلَافِهِمْ عَلَى أَنْبِيَائِهِمْ فَإِذَا أَمَرْتُكُمْ بِشَيْءٍ فَخُذُوا مِنْهُ مَا اسْتَطَعْتُمْ وَإِذَا نَهَيْتُكُمْ عَنْ شَيْءٍ فَانْتَهُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] ia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah apa yang telah aku tinggalkan untuk kalian. Sesungguhnya orang-orang sebelum kalian binasa karena pertanyaan dan perselisihan mereka kepada para Nabinya. Jika aku perintahkan kepada kalian terhadap suatu perkara maka laksanakanlah semampu kalian, dan jika aku larang kalian dari suatu perkara maka jauhilah.\" "},"3":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah], dan [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa menta'atiku maka ia telah ta'at kepada Allah dan barangsiapa durhaka kepadaku maka ia telah durhaka kepada Allah.\""},"4":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ ابْنِ الْمُبَارَكِ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ أَبِي جَعْفَرٍ قَالَكَانَ ابْنُ عُمَرَ إِذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا لَمْ يَعْدُهُ وَلَمْ يُقَصِّرْ دُونَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Zakaria bin 'Adi] dari [Ibnu Mubarak] dari [Muhammad bin Suqah] dari [Abu Ja'far] ia berkata; \" [Ibnu Umar] Jika mendengar sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam, ia tidak melewatkannya dan tidak pula sibuk dengan yang lainnya.\" "},"5":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى بْنِ سُمَيْعٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُلَيْمَانَ الْأَفْطَسُ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَذْكُرُ الْفَقْرَ وَنَتَخَوَّفُهُ فَقَالَ أَالْفَقْرَ تَخَافُونَ وَالَّذِي نَفْسِي بِيَدِهِ لَتُصَبَّنَّ عَلَيْكُمْ الدُّنْيَا صَبًّا حَتَّى لَا يُزِيغَ قَلْبَ أَحَدِكُمْ إِزَاغَةً إِلَّا هِيهْ وَايْمُ اللَّهِ لَقَدْ تَرَكْتُكُمْ عَلَى مِثْلِ الْبَيْضَاءِ لَيْلُهَا وَنَهَارُهَا سَوَاءٌقَالَ أَبُو الدَّرْدَاءِ صَدَقَ وَاللَّهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَكَنَا وَاللَّهِ عَلَى مِثْلِ الْبَيْضَاءِ لَيْلُهَا وَنَهَارُهَا سَوَاءٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar Ad Dimasyqi] berkata, telah menceritakan kepada kami [Muhammad bin Isa bin Sumai'] berkata, telah menceritakan kepada kami [Ibrahim bin Sulaiman Al Afthas] dari [Al Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] dari [Abu Darda`] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, sementara kami sedang memperbincangkan masalah kefaqiran dan kami merasa takut darinya. Lalu beliau bersabda: \" Apakah kalian takut kepada kemiskinan? Demi Dzat yang jiwaku berada di tangan-Nya, sungguh akan diberikan kepada kalian dunia, hingga hati salah seorang dari kalian tidak bisa berpaling kecuali akan menemuinya. Sungguh, telah aku tinggalkan untuk kalian perkara terang benderang, malam dan siangnya sama.\" Abu Darda` berkata; \"Demi Allah benar, Rasulullah shallallahu 'alaihi wasallam telah meniggalkan bagi kita perkara yang terang benderang, malam dan siangnya sama.\""},"6":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Akan senantiasa ada sekelompok dari umatku mendapat pertolongan. Orang-orang yang menghinakannya tidak akan membahayakan mereka hingga terjadi hari kiamat.\""},"7":{"ar":"حَدَّثَنَا أَبُو عَبْد اللَّهِ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ قَالَ حَدَّثَنَا أَبُو عَلْقَمَةَ نَصْرُ بْنُ عَلْقَمَةَ عَنْ عُمَيْرِ بْنِ الْأَسْوَدِ وَكَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي قَوَّامَةً عَلَى أَمْرِ اللَّهِ لَا يَضُرُّهَا مَنْ خَالَفَهَا","id":"Telah menceritakan kepada kami Abu Abdullah ia berkata; telah menceritakan kepada kami [Hisyam bin 'Ammar] ia berkata; telah menceritakan kepada kami [Yahya bin Hamzah] berkata; telah menceritakan kepada kami [Abu Alqamah Nashr bin Alqamah] dari [Umair Al Aswad] dan [Katsir bin Murrah Al Hadlrami] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Akan senantiasa ada sekelompok dari umatku yang tegar berdiri di atas perintah Allah, tidak akan membahayakan mereka orang yang menyelisihinya.\""},"8":{"ar":"حَدَّثَنَا أَبُو عَبْد اللَّهِ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْجَرَّاحُ بْنُ مَلِيحٍ حَدَّثَنَا بَكْرُ بْنُ زُرْعَةَ قَالَ سَمِعْتُ أَبَا عِنَبَةَ الْخَوْلَانِيَّ وَكَانَ قَدْ صَلَّى الْقِبْلَتَيْنِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ اللَّهُ يَغْرِسُ فِي هَذَا الدِّينِ غَرْسًا يَسْتَعْمِلُهُمْ فِي طَاعَتِهِ","id":"Telah menceritakan kepada kami Abu Abdullah ia berkata; telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Al Jarrah bin Malih] berkata, telah menceritakan kepada kami [Bakr bin Zur'ah] ia berkata; aku mendengar [Abu 'Inabah Al Khaulani] dan ia adalah sahabat yang mengalami shalat menghadap dua kiblat bersama Rasulullah shallallahu 'alaihi wasallam, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah akan senantiasa menanam tanaman (pembaharu) dalam agama ini, yang akan Ia arahkan untuk ketaatan kepada-Nya.\""},"9":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي عَلَى الْحَقِّ مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib] berkata, telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Abu Qilabah] dari [Abu Asma` Ar Rahabi] dari [Tsauban] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Akan senantiasa ada sekelompk dari umatku yang ditolong di atas kebenaran, tidak membahayakan mereka orang yang menyelisihinya hingga datang keputusan Allah.\" "},"10":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ قَالَ سَمِعْتُ مُجَالِدًا يَذْكُرُ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَّ خَطًّا وَخَطَّ خَطَّيْنِ عَنْ يَمِينِهِ وَخَطَّ خَطَّيْنِ عَنْ يَسَارِهِ ثُمَّ وَضَعَ يَدَهُ فِي الْخَطِّ الْأَوْسَطِ فَقَالَ هَذَا سَبِيلُ اللَّهِ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَأَنَّ هَذَا صِرَاطِي مُسْتَقِيمًا فَاتَّبِعُوهُ وَلَا تَتَّبِعُوا السُّبُلَ فَتَفَرَّقَ بِكُمْ عَنْ سَبِيلِهِ }","id":"Telah menceritakan kepada kami [Abu Sa'id Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] ia berkata; aku mendengar [Mujalid] menyebutkan dari [Asy Sya'bi] dari [Jabir bin Abdullah] ia berkata; \"Kami berada di sisi Nabi shallallahu 'alaihi wasallam, beliau lalu membuat satu garis, kemudian membuat dua garis di sisi kanannya dan dua garis lagi di sisi kirinya. Kemudian beliau meletakkan tangannya di garis yang tengah seraya bersabda: \" Inilah jalan Allah.\" Kemudian beliau membaca ayat ini: \"Dan bahwa (yang Kami perintahkan) ini adalah jalan-Ku yang lurus, maka ikutilah dia; dan janganlah kamu mengikuti jalan-jalan (yang lain), karena jalan-jalan itu mencerai-beraikan kamu dari jalan-Nya.\""},"11":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ حَدَّثَنِي الْحَسَنُ بْنُ جَابِرٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَ الْكِنْدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُوشِكُ الرَّجُلُ مُتَّكِئًا عَلَى أَرِيكَتِهِ يُحَدَّثُ بِحَدِيثٍ مِنْ حَدِيثِي فَيَقُولُ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ عَزَّ وَجَلَّ مَا وَجَدْنَا فِيهِ مِنْ حَلَالٍ اسْتَحْلَلْنَاهُ وَمَا وَجَدْنَا فِيهِ مِنْ حَرَامٍ حَرَّمْنَاهُ أَلَّا وَإِنَّ مَا حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلُ مَا حَرَّمَ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, ia berkata; telah menceritakan kepada kami [Zaid Ibnu Al Hubab] dari [Mu'awiyah bin Shalih] berkata, telah menceritakan kepadaku [Al Hasan bin Jabir] dari [Al Miqdam bin Ma'dikarib Al Kindi] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Dikhawatirkan seseorang bersandaran di tempat duduknya, diceritakan kepadanya sebuah hadits dariku, namun ia berkata; 'Antara kami dan kalian adalah kitabullah 'azza wajalla. Apa yang kami temukan yang halal darinya maka kami menghalalkannya dan apa yang kami temukan yang haram darinya, maka kami mengharamkannya.' Ketahuilah, sesungguhnya apa yang diharamkan Rasulullah shallallahu 'alaihi wasallam adalah seperti yang diharamkan Allah.\""},"12":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ فِي بَيْتِهِ أَنَا سَأَلْتُهُ عَنْ سَالِمٍ أَبِي النَّضْرِ ثُمَّ مَرَّ فِي الْحَدِيثِ قَالَ أَوْ زَيْدِ بْنِ أَسْلَمَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ مُتَّكِئًا عَلَى أَرِيكَتِهِ يَأْتِيهِ الْأَمْرُ مِمَّا أَمَرْتُ بِهِ أَوْ نَهَيْتُ عَنْهُ فَيَقُولُ لَا أَدْرِي مَا و��جَدْنَا فِي كِتَابِ اللَّهِ اتَّبَعْنَاهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] -aku bertanya kepadanya di rumahnya- dari [Salim Abu Al Nadlr] -kemudian ia membaca sebuah hadits-, ia berkata; atau [Zaid bin Aslam] dari [Ubaidullah bin Abu Rafi'] dari [Bapaknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, salah seorang dari kalian akan ditemui dalam keadaan duduk bersandaran di tempat duduknya, lalu datang kepadanya perintah dan laranganku, namun ia berkata; 'Aku tidak mengetahui, apa yang kami jumpai dalam kitabullah, maka kami mengikutinya.'\""},"13":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ مِنْهُ فَهُوَ رَدٌّ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd bin Ibrahim bin Abdurrahman bin Auf] dari [Bapaknya] dari [Al Qasim bin Muhammad] dari [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa membuat perkara baru dalam urusan kami yang tidak termasuk darinya maka dia tertolak.\""},"14":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ قَالَ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنْفُسِهِمْ حَرَجًا مِمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا }","id":"Telah menceritakan kepada kami [Muhammad bin Rumh bin Al Muhajir Al Mishri] berkata, telah menceritakan kepada kami [Al Laist bin Sa'd] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] bahwasanya [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa seorang laki-laki Anshar mendebat Az Zubair di samping Rasulullah shallallahu 'alaihi wasallam tentang masalah pengairan yang biasa mereka gunakan untuk menyiram pohon kurma. Orang Anshar itu berkata; \"Biarkan air itu lewat, \" tetapi Az Zubair tidak mengindahkannya. Maka terjadilah perdebatan di antara keduanya di hadapan Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \" Airilah (kebunmu) wahai Zubair, setelah itu Alirkan air tersebut untuk tetanggamu.\" Tetapi orang Anshar tersebut marah seraya berkata; \"Ya Rasulullah, apakah karena dia anak pamanmu?\" Maka berubahlah wajah Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Hai Zubair, airilah (kebunmu), setelah itu tahan airnya agar ia kembali ke asalnya.\" Abdullah bin Zubair berkata; Maka Zubair berkata: \"Demi Allah saya mengira bahwa ayat ini turun dalam kejadian tersebut: \"Maka demi Rabbmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim dalam perkara yang mereka perselisihkan, kemudian mereka tidak merasa keberatan dalam hati mereka terhadap putusan yang kamu berikan, dan mereka menerima dengan sepenuhnya.\""},"15":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَمْنَعُوا إِمَاءَ اللَّهِ أَنْ يُصَلِّينَ فِي الْمَسْجِدِفَقَالَ ابْنٌ لَهُ إِنَّا لَنَمْنَعُهُنَّ فَغَضِبَ غَضَبًا شَدِيدًا وَقَالَ أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ إِنَّا لَنَمْنَعُهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Janganlah kalian melarang hamba perempuan Allah untuk shalat di masjid.\" Lalu seorang anaknya berkata; \"Sungguh, kami akan melarang mereka.\" Maka Ibnu Umar pun marah besar seraya menghardik; \"Aku bacakan kepada kalian hadits Rasulullah shallallahu 'alaihi wasallam, namun engkau katakan; 'Sungguh, kami akan melarang mereka.'\" "},"16":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ وَأَبُو عَمْرٍو حَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا أَيُّوبُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّهُ كَانَ جَالِسًا إِلَى جَنْبِهِ ابْنُ أَخٍ لَهُ فَخَذَفَ فَنَهَاهُ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا فَقَالَ إِنَّهَا لَا تَصِيدُ صَيْدًا وَلَا تَنْكِي عَدُوًّا وَإِنَّهَا تَكْسِرُ السِّنَّ وَتَفْقَأُ الْعَيْنَقَالَ فَعَادَ ابْنُ أَخِيهِ فَخَذَفَ فَقَالَ أُحَدِّثُكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا ثُمَّ عُدْتَ تَخْذِفُ لَا أُكَلِّمُكَ أَبَدًا","id":"Telah menceritakan kepada kami [Ahmad binTsabit Al Jadari] dan [Abu 'Amru Hafsh bin Umar] keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] berkata, telah menceritakan kepada kami [Ayyub] dari [Sa'id bin Jubair] dari [Abdullah bin Mughaffal], bahwa salah seorang dari keponakannya duduk di sampingnya, kemudian ia mengetapel. Maka ia pun mencegahnya seraya berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarangnya. Beliau bersabda: \"Tindakan itu tidak dapat memburu buruan, dan tidak pula menghancurkan musuh. Ia hanya memecahkan gigi dan mencungkil mata.\" "},"17":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي بُرْدُ بْنُ سِنَانٍ عَنْ إِسْحَقَ بْنِ قَبِيصَةَ عَنْ أَبِيهِأَنَّ عُبَادَةَ بْنَ الصَّامِتِ الْأَنْصَارِيَّ النَّقِيبَ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا مَعَ مُعَاوِيَةَ أَرْضَ الرُّومِ فَنَظَرَ إِلَى النَّاسِ وَهُمْ يَتَبَايَعُونَ كِسَرَ الذَّهَبِ بِالدَّنَانِيرِ وَكِسَرَ الْفِضَّةِ بِالدَّرَاهِمِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَأْكُلُونَ الرِّبَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَبْتَاعُوا الذَّهَبَ بِالذَّهَبِ إِلَّا مِثْلًا بِمِثْلٍ لَا زِيَادَةَ بَيْنَهُمَا وَلَا نَظِرَةًفَقَالَ لَهُ مُعَاوِيَةُ يَا أَبَا الْوَلِيدِ لَا أَرَى الرِّبَا فِي هَذَا إِلَّا مَا كَانَ مِنْ نَظِرَةٍ فَقَالَ عُبَادَةُ أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتُحَدِّثُنِي عَنْ رَأْيِكَ لَئِنْ أَخْرَجَنِي اللَّهُ لَا أُسَاكِنُكَ بِأَرْضٍ لَكَ عَلَيَّ فِيهَا إِمْرَةٌ فَلَمَّا قَفَلَ لَحِقَ بِالْمَدِينَةِ فَقَالَ لَهُ عُمَرُ بْنُ الْخَطَّابِ مَا أَقْدَمَكَ يَا أَبَا الْوَلِيدِ فَقَصَّ عَلَيْهِ الْقِصَّةَ وَمَا قَالَ مِنْ مُسَاكَنَتِهِ فَقَالَ ارْجِعْ يَا أَبَا الْوَلِيدِ إِلَى أَرْضِكَ فَقَبَحَ اللَّهُ أَرْضًا لَسْتَ فِيهَا وَأَمْثَالُكَ وَكَتَبَ إِلَى مُعَاوِيَةَ لَا إِمْرَةَ لَكَ عَلَيْهِ وَاحْمِلْ النَّاسَ عَلَى مَا قَالَ فَإِنَّهُ هُوَ الْأَمْرُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepadaku [Burd bin Sinan] dari [Ishaq bin Qabishah] dari [Bapaknya] berkata; [Ubadah bin Shamit Al Anshari] adalah seorang komandan dan sahabat Rasulullah shallallahu 'alaihi wasallam yang ikut berperang bersama Mu'awiyah di bumi Romawi. Dia memperhatikan orang-orang yang sedang melakukan jual beli pecahan emas dengan dinar dan pecahan perak dengan dirham. Kemudian ia berseru; \"Hai manusia, sesungguhnya kalian telah memakan riba, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Janganlah kalian menjual emas dengan emas kecuali sebanding, tidak ada kelebihan dan tidak ada penangguhan antara keduanya.\" Mu'awiyah berkata kepadanya; \"Wahai Abul Walid saya tidak memandang riba dalam transaksi ini, kecuali dalam penangguhannya! \" Ubadah menjawab; \"Aku sampaikan kepadamu hadits dari Rasulullah shallallahu 'alaihi wasallam, namun engkau berpendapat dengan pandanganmu sendiri. Sungguh, sekiranya Allah mengeluarkanku, maka aku tidak akan tinggal di wilayah kekuasaanmu meski aku di bawah perintahmu.\" Ketika kembali ke Madinah ia bertemu Umar bin Khaththab, lalu Umar berkata kepadanya, \"Hai Abul Walid, apa yang membuatmu datang ke sini? Lalu ia ceritakan kisah tersebut kepada Umar, dan ia tidak bercerita tentang tempat tinggalnya. Umar pun berkata: \"Hai Abul Walid, kembalilah ke negerimu. Sungguh, Allah akan membuat satu negeri menjadi hina tanpa keberadaanmu dan orang-orang sepertimu.\" Kemudian Umar menulis surat untuk Mu'awiyah; \"Engkau tidak berhak memerintahnya, dan ajaklah manusia mengikuti apa yang dikatakannya, karena dia di atas kebenaran.\""},"18":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ الْخَلَّادِ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ عَجْلَانَ أَنْبَأَنَا عَوْنُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَإِذَا حَدَّثْتُكُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَظُنُّوا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي هُوَ أَهْنَاهُ وَأَهْدَاهُ وَأَتْقَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Al Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu 'Ajlan] berkata, telah memberitahukan kepada kami ['Aun bin Abdullah] dari [Abdullah bin Mas'ud] ia berkata; \" Jika aku bacakan kepada kalian sebuah hadits dari Rasulullah, maka anggaplah bahwa Rasulullah yang menyampaikannya, dia yang memberi petunjuk dan dia yang berwasiat takwa.\""},"19":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ حَدَّثَنَا الْمَقْبُرِيُّ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا أَعْرِفَنَّ مَا يُحَدَّثُ أَحَدُكُمْ عَنِّي الْحَدِيثَ وَهُوَ مُتَّكِئٌ عَلَى أَرِيكَتِهِ فَيَقُولُ اقْرَأْ قُرْآنًا مَا قِيلَ مِنْ قَوْلٍ حَسَنٍ فَأَنَا قُلْتُهُ","id":"Telah menceritakan kepada kami [Ali Ibnul Mundzir] berkata, telah menceritakan kepada kami [Muhammmad bin Fudlail] berkata, telah menceritakan kepada kami [Al Maqburi] dari [Kakeknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh akan aku beritahukan, ada seseorang dari kalian yang tidak mau menyampaikan haditsku. Sambil bersandar di tempat duduknya ia berkata; 'Bacalah Al Qur'an, semua yang dikatakan (dalam Al-Qur'an) berupa perkataan yang baik maka akupun mengatakannya.\""},"20":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادِ بْنِ آدَمَ حَدَّثَنَا أَبِي عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ ح و حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَقَالَ لِرَجُلٍ يَا ابْنَ أَخِي إِذَا حَدَّثْتُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا فَلَا تَضْرِبْ لَهُ الْأَمْثَالَقَالَ أَبُو الْحَسَنِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ الْكَرَابِيسِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ مِثْلَ حَدِيثِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abbad bin Adam] berkata, telah menceritakan kepada kami [Bapakku] dari [Syu'bah] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah]. Menurut jalur lain; Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] berkata, telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] bahwa [Abu Hurairah] pernah berkata kepada seseorang; \"Hai keponakanku, jika aku bacakan kepadamu sebuah hadits dari Rasulullah, maka janganlah kamu membuat perumpamaan selainnya.\" Abul Hasan berkata; telah menceritakan kepada kami Yahya bin Abdullah Al Karabisi berkata, telah menceritakan kepada kami Ali bin Al Ja'd dari Syu'bah dari 'Amru bin Murrah sebagaimana hadits Ali Radliallahu Ta'ala 'anhu.\""},"21":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ ابْنِ عَوْنٍ حَدَّثَنَا مُسْلِمٌ الْبَطِينُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَمَا أَخْطَأَنِي ابْنُ مَسْعُودٍ عَشِيَّةَ خَمِيسٍ إِلَّا أَتَيْتُهُ فِيهِ قَالَ فَمَا سَمِعْتُهُ يَقُولُ بِشَيْءٍ قَطُّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كَانَ ذَاتَ عَشِيَّةٍ قَالَ قَالَ رَسُولُ اللَّهِ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَكَسَ قَالَ فَنَظَرْتُ إِلَيْهِ فَهُوَ قَائِمٌ مُحَلَّلَةً أَزْرَارُ قَمِيصِهِ قَدْ اغْرَوْرَقَتْ عَيْنَاهُ وَانْتَفَخَتْ أَوْدَاجُهُ قَالَ أَوْ دُونَ ذَلِكَ أَوْ فَوْقَ ذَلِكَ أَوْ قَرِيبًا مِنْ ذَلِكَ أَوْ شَبِيهًا بِذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Ibnu 'Aun] berkata, telah menceritakan kepada kami [Muslim Al Bathin] dari [Ibrahim At Taimi] dari [Bapaknya] dari ['Amru bin Maimun] ia berkata; Tidaklah [Ibnu Mas'ud] menyalahkanku di malam kamis, melainkan aku mendatanginya. -'Amru bin Maimun berkata; - Aku tidak mendengarnya mengatakan sesuatu pun dari hadits Rasulullah shallallahu 'alaihi wasallam. Kemudian pada suatu malam dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda;, maka dia menunduk. -'Amru bin Maimun berkata; - Aku lalu memandang kepadanya, ia waktu itu sedang berdiri sambil mengancingkan kancing-kancing jubahnya, airmatanya bercucuran dan urat lehernya naik turun. Dia berkata: \"Atau selain itu, atau di atas itu, atau dekat dari itu, atau serupa dengan itu.\""},"22":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَكَانَ أَنَسُ بْنُ مَالِكٍ إِذَا حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا فَفَرَغَ مِنْهُ قَالَ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Ibnu 'Aun] dari [Muhammad bin Sirin] ia berkata; Jika [Anas bin Malik] telah selesai dari membacakan sebuah hadits Rasulullah, ia berkata; \"atau sebagaimana Rasulullah shallallahu 'alaihi wasallam bersabda.\" "},"23":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَقُلْنَا لِزَيْدِ بْنِ أَرْقَمَ حَدِّثْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَبِرْنَا وَنَسِينَا وَالْحَدِيثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَدِيدٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ghundar] dari [Syu'bah]. Dan dari jalur lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdiy] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila] ia berkata; Kami berkata kepada [Zaid bin Arqam]; \"ceritakanlah kepada kami hadits dari Rasulullah shallallahu 'alaihi wasallam, \" ia berkata; \" Kami telah menjadi tua dan pelupa, sedangkan hadits Rasulullah shallallahu 'alaihi wasallam itu sangat keras (berat).\" "},"24":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو النَّضْرِ عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ يَقُولُجَالَسْتُ ابْنَ عُمَرَ سَنَةً فَمَا سَمِعْتُهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu An Nadhr] dari [Syu'bah] dari [Abdullah bin Abu As Safar] ia berkata; \"Aku mendengar [Asy Sya'bi] berkata; \" Aku berguru kepada [Ibnu Umar] selama satu tahun, namun aku tidak pernah mendengar ia membacakan satu hadits pun dari Rasulullah shallallahu 'alaihi wasallam.\""},"25":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُإِنَّمَا كُنَّا نَحْفَظُ الْحَدِيثَ وَالْحَدِيثُ يُحْفَظُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا إِذَا رَكِبْتُمْ الصَّعْبَ وَالذَّلُولَ فَهَيْهَاتَ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Abdurazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya] ia berkata; Aku mendengar [Ibnu Abbas] berkata; \"Dahulu kami menghafal hadits, sedangkan hadits dihafal langsung dari Rasulullah shallallahu 'alaihi wasallam. Maka jika kalian melakukan kesulitan dan bermanja-manja maka sekali-kali tidak mungkin bisa.\""},"26":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ قَرَظَةَ بْنِ كَعْبٍ قَالَبَعَثَنَا عُمَرُ بْنُ الْخَطَّابِ إِلَى الْكُوفَةِ وَشَيَّعَنَا فَمَشَى مَعَنَا إِلَى مَوْضِعٍ يُقَالُ لَهُ صِرَارٌ فَقَالَ أَتَدْرُونَ لِمَ مَشَيْتُ مَعَكُمْ قَالَ قُلْنَا لِحَقِّ صُحْبَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِحَقِّ الْأَنْصَارِ قَالَ لَكِنِّي مَشَيْتُ مَعَكُمْ لِحَدِيثٍ أَرَدْتُ أَنْ أُحَدِّثَكُمْ بِهِ وَأَرَدْتُ أَنْ تَحْفَظُوهُ لِمَمْشَايَ مَعَكُمْ إِنَّكُمْ تَقْدَمُونَ عَلَى قَوْمٍ لِلْقُرْآنِ فِي صُدُورِهِمْ هَزِيزٌ كَهَزِيزِ الْمِرْجَلِ فَإِذَا رَأَوْكُمْ مَدُّوا إِلَيْكُمْ أَعْنَاقَهُمْ وَقَالُوا أَصْحَابُ مُحَمَّدٍ فَأَقِلُّوا الرِّوَايَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا شَرِيكُكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Mujalid] dari [Asy Sya'bi] dari [Qarazhah bin Ka'ab] ia berkata; Umar bin Khaththab mengutus dan mengantar kami ke Kufah. Ia berjalan bersama kami hingga sampai di suatu tempat yang disebut Shirar. Ia lalu berkata; \"Apakah kalian tahu kenapa aku berjalan bersama kalian?\" Qarazhah bin Ka'ab berkata; Kami menjawab, \"Karena hak menemani Rasulullah shallallahu 'alaihi wasallam dan hak sahabat Anshar.\" [Umar berkata]; \"Aku berjalan bersama kalian karena ada satu hadits yang ingin aku sampaikan kepada kalian, dan aku ingin kalian menghafalnya karena perjalananku bersama kalian, beliau bersabda; \"Sesungguhnya kalian datang kepada satu kaum karena Al Qur'an di dalam dada mereka mendidih seperti periuk yang mendidih. Jika mereka melihat kalian mereka akan menjulurkan leher-lehernya kepada kalian seraya berkata; 'Hai para sahabat Muhammad, riwayatkan sedikit saja hadits dari Rasulullah shallallahu 'alaihi wasallam dan aku adalah rekan kalian.\""},"27":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَصَحِبْتُ سَعْدَ بْنَ مَالِكٍ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَمَا سَمِعْتُهُ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَدِيثٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdurrahman] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [As Sa`ib bin Yazid] ia berkata; \" Aku menemani [Sa'd bin Malik] dari Madinah ke Makkah, dan aku tidak mendengar ia membacakan satu hadits pun dari Rasulullah shallallahu 'alaihi wasallam.\""},"28":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسُوَيْدُ بْنُ سَعِيدٍ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَإِسْمَعِيلُ بْنُ مُوسَى قَالُوا حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Suwaid bin Sa'id] dan [Abdullah bin 'Amir bin Zurarah] dan [Isma'il bin Musa] mereka berkata; telah menceritakan kepada kami [Syarik] dari [Simak] dari [Abdurrahman bin Abdullah bin Mas'ud] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berdusta atas namaku dengan sengaja, maka hendaklah ia menyiapkan tempat duduknya di neraka.\""},"29":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَإِسْمَعِيلُ بْنُ مُوسَى قَالَا حَدَّثَنَا شَرِيكٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْذِبُوا عَلَيَّ فَإِنَّ الْكَذِبَ عَلَيَّ يُولِجُ النَّارَ","id":"Telah menceritakan kepada kami [Abdullah bin 'Amir bin Zurarah] dan [Isma'il bin Musa] keduanya berkata; telah menceritakan kepada kami [Syarik] dari [Manshur] dari [Rib'i bin Hirasy] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Janganlah kalian berdusta atas namaku, karena sesungguhnya dusta atas namaku akan memasukkan ke dalam neraka.\""},"30":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ حَسِبْتُهُ قَالَ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berdusta atas namaku, -aku mengira beliau bersabda: - dengan sengaja, maka hendaklah ia menyiapkan tempat duduknya di neraka.\" "},"31":{"ar":"حَدَّثَنَا أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Khaitsamah Zuhair bin Harb] berkata, telah menceritakan kepada kami [Husyaim] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata: \" Barangsiapa berdusta atas namaku dengan sengaja, maka hendaklah ia menyiapkan tempat duduknya di neraka.\" "},"32":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَقَوَّلَ عَلَيَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berbicara atas namaku dengan sesuatu yang aku tidak mengatakannya, maka hendaklah ia menyiapkan tempat duduknya di neraka.\""},"33":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَعْبَدِ بْنِ كَعْبٍ عَنْ أَبِي قَتَادَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى هَذَا الْمِنْبَرِ إِيَّاكُمْ وَكَثْرَةَ الْحَدِيثِ عَنِّي فَمَنْ قَالَ عَلَيَّ فَلْيَقُلْ حَقًّا أَوْ صِدْقًا وَمَنْ تَقَوَّلَ عَلَيَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], telah menceritakan kepada kami [Yahya bin Ya'la At Taimi] dari [Muhammad bin Ishaq] dari [Ma'bad bin Ka'b] dari [Abu Qatadah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar ini: \" Janganlah kalian banyak-banyak membacakan hadits dariku, maka barangsiapa berkata atas namaku, hendaklah ia berkata dengan benar atau jujur. Barangsiapa berkata atas namaku dengan sesuatu yang aku tidak mengatakannya, maka hendaklah ia menyiapkan tempat duduknya di neraka.\" "},"34":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا غُنْدَرٌ مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ أَبِي صَخْرَةَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ قُلْتُ لِلزُّبَيْرِ بْنِ الْعَوَّامِمَا لِيَ لَا أَسْمَعُكَ تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَسْمَعُ ابْنَ مَسْعُودٍ وَفُلَانًا وَفُلَانًا قَالَ أَمَا إِنِّي لَمْ أُفَارِقْهُ مُنْذُ أَسْلَمْتُ وَلَكِنِّي سَمِعْتُ مِنْهُ كَلِمَةً يَقُولُ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Ghundar Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad Abu Shakhrah] dari ['Amir bin Abdullah bin Zubair] dari [Bapaknya] ia berkata; Aku berkata kepada [Zubair bin Awwam]; \"Kenapa aku tidak mendengarmu menceritakan hadits dari Rasulullah shallallahu 'alaihi wasallam, sebagaimana aku pernah mendengarnya dari Ibnu Mas'ud, Fulan dan Fulan?\" ia menjawab; \"Sesungguhnya aku tidak pernah berpisah dengan Rasulullah semenjak aku memeluk Islam, akan tetapi aku telah mendengar satu kalimat yang beliau ucapkan: \" Barangsiapa berdusta atas namaku dengan sengaja, maka hendaklah ia menyiapkan tempat duduknya di neraka.\" "},"35":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُطَرِّفٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Mutharrif] dari ['Athiyyah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berdusta atas namaku dengan sengaja, maka hendaklah ia menyiapkan tempat duduknya di neraka.\""},"36":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَدَّثَ عَنِّي حَدِيثًا وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Hisyam] dari [Ibnu Abu Laila] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Ali radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Barangsiapa menyampaikan satu hadits dariku, sementara dia melihat bahwa hadits itu dusta, maka dia adalah salah satu pendusta.\""},"37":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَدَّثَ عَنِّي حَدِيثًا وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki']. Menurut jalur lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Barangsiapa menceritakan satu hadits dariku, sementara dia melihat bahwa hadits itu dusta, maka dia adalah salah satu pendusta.\""},"38":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَوَى عَنِّي حَدِيثًا وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ أَنْبَأَنَا الْحَسَنُ بْنُ مُوسَى الْأَشْيَبُ عَنْ شُعْبَةَ مِثْلَ حَدِيثِ سَمُرَةَ بْنِ جُنْدَبٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Al A'masy] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Ali] dari Nabi shallallahu 'alaihi wasallam, Beliau bersabda: \" Barangsiapa meriwayatkan dariku satu hadits, sementara dia melihat bahwa hadits itu dusta, maka dia adalah salah satu pendusta.\" Telah menceritakan kepada kami [Muhammad bin Abdullah] berkata, telah memberitakan kepada kami [Al Hasan bin Musa Al Asyyab] dari [Syu'bah] sebagaimana hadits [Samurah bin Jundab]."},"39":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَدَّثَ عَنِّي بِحَدِيثٍ وَهُوَ يَرَى أَنَّهُ كَذِبٌ فَهُوَ أَحَدُ الْكَاذِبَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Mughirah bin Syu'bah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa menyampaikan satu hadits dariku, sementara dia melihat bahwa hadits itu dusta, maka dia adalah salah satu pendusta.\""},"40":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ حَدَّثَنِي يَحْيَى بْنُ أَبِي الْمُطَاعِ قَالَ سَمِعْتُ الْعِرْبَاضَ بْنَ سَارِيَةَ يَقُولُقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً وَجِلَتْ مِنْهَا الْقُلُوبُ وَذَرَفَتْ مِنْهَا الْعُيُونُ فَقِيلَ يَا رَسُولَ اللَّهِ وَعَظْتَنَا مَوْعِظَةَ مُوَدِّعٍ فَاعْهَدْ إِلَيْنَا بِعَهْدٍ فَقَالَ عَلَيْكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا وَسَتَرَوْنَ مِنْ بَعْدِي اخْتِلَافًا شَدِيدًا فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ عَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَالْأُمُورَ الْمُحْدَثَاتِ فَإِنَّ كُلَّ بِدْعَةٍ ضَلَالَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Abdullah bin Al 'Ala`] berkata, telah menceritakan kepadaku [Yahya bin Abi Al Mutha'] ia berkata; aku mendengar ['Irbadl bin Sariyah] berkata; \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam berdiri di tengah-tengah kami. Beliau memberi nasihat yang sangat menyentuh, membuat hati menjadi gemetar, dan airmata berlinangan. Lalu dikatakan; \"Wahai Rasulullah, engkau telah memberikan nasihat kepada kami satu nasihat perpisahan, maka berilah kami satu wasiyat.\" Beliau bersabda: \" Hendaklah kalian bertakwa kepada Allah, mendengar dan taat meski kepada seorang budak Habasyi. Dan sepeninggalku nanti, kalian akan melihat perselisihan yang sangat dahsyat, maka hendaklah kalian berpegang dengan sunnahku dan sunnah para khulafaur Rasyidin yang mendapat petunjuk. Gigitlah sunnah itu dengan gigi geraham, dan jangan sampai kalian mengikuti perkara-perkara yang dibuat-buat, karena sesungguhnya semua bid'ah itu adalah sesat.\""},"41":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ بِشْرِ بْنِ مَنْصُورٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ السَّوَّاقُ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو السُّلَمِيِّ أَنَّهُ سَمِعَ الْعِرْبَاضَ بْنَ سَارِيَةَ يَقُولُوَعَظَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْعِظَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذِهِ لَمَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا قَالَ قَدْ تَرَكْتُكُمْ عَلَى الْبَيْضَاءِ لَيْلُهَا كَنَهَارِهَا لَا يَزِيغُ عَنْهَا بَعْدِي إِلَّا هَالِكٌ مَنْ يَعِشْ مِنْكُمْ فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِمَا عَرَفْتُمْ مِنْ سُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ عَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَعَلَيْكُمْ بِالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا فَإِنَّمَا الْمُؤْمِنُ كَالْجَمَلِ الْأَنِفِ حَيْثُمَا قِيدَ انْقَادَحَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ الْمِسْمَعِيُّ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Bisyr bin Manshur] dan [Ishaq bin Ibrahim As Sawwaq] keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Dlamrah bin Habib] dari [Abdurrahman bin 'Amru As Sulami] bahwasanya ia mendengar ['Irbadl bin Sariyah] berkata; Rasulullah shallallahu 'alaihi wasallam memberi kami satu nasehat yang membuat air mata mengalir dan hati menjadi gemetar. Maka kami berkata kepada beliau; \"Ya Rasulullah, sesungguhnya ini merupakan nasihat perpisahan, lalu apa yang engkau wasiatkan kepada kami?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \" Aku telah tinggalkan untuk kalian petunjuk yang terang, malamnya seperti siang. Tidak ada yang berpaling darinya setelahku melainkan ia akan binasa. Barangsiapa di antara kalian hidup, maka ia akan melihat banyaknya perselisihan. Maka kalian wajib berpegang teguh dengan apa yang kalian ketahui dari sunnahku, dan sunnah para Khulafaur Rasyidin yang mendapat petunjukk, gigitlah sunnah-sunnah itu dengan gigi geraham. Hendaklah kalian taat meski kepada seorang budak Habasyi. Orang mukmin itu seperti seekor unta jinak, di mana saja dia diikat dia akan menurutinya.\" Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abdul Malik bin Ash Shabbah Al Misma'i] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abdurrahman bin 'Amru] dari ['Irbadl bin Sariyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengimami kami pada shalat subuh, kemudian Beliau berpaling kepada kami dan memberi nasehat yang sangat menyentuh.\" Lalu ia menyebutkan sebagaimana dalam hadits di atas. "},"42":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ وَأَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ احْمَرَّتْ عَيْنَاهُ وَعَلَا صَوْتُهُ وَاشْتَدَّ غَضَبُهُ كَأَنَّهُ مُنْذِرُ جَيْشٍ يَقُولُ صَبَّحَكُمْ مَسَّاكُمْ وَيَقُولُ بُعِثْتُ أَنَا وَالسَّاعَةَ كَهَاتَيْنِ وَيَقْرِنُ بَيْنَ إِصْبَعَيْهِ السَّبَّابَةِ وَالْوُسْطَى وَيَقُولُ أَمَّا بَعْدُ فَإِنَّ خَيْرَ الْأُمُورِ كِتَابُ اللَّهِ وَخَيْرُ الْهَدْيِ هَدْيُ مُحَمَّدٍ وَشَرُّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلُّ بِدْعَةٍ ضَلَالَةٌ وَكَانَ يَقُولُ مَنْ تَرَكَ مَالًا فَلِأَهْلِهِ وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَعَلَيَّ وَإِلَيَّ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] dan [Ahmad bin Tsabit Al Jahdari] keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafiy] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir bin Abdullah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam apabila berkhutbah matanya menjadi merah, suaranya tinggi dan emosinya menggebu-gebu, seakan-akan ia adalah seorang pemberi peringatan pada pasukan, beliau berseru: \"Waspadalah, musuh akan datang di pagi hari, musuh akan datang di sore hari! \" Dan beliau berseru: \"Aku diutus dengan datangnya hari kiamat seperti (kedua jari) ini, \" beliau menggandengkan antara dua jarinya; jari telunjuk dan jari tengah. Beliau lalu bersabda: \"'Amma ba'du; sesungguhnya sebaik-baik perkara adalah Kitabullah dan sebaik-baik petunjuk adalah petunjuk Muhammad, seburuk-buruk perkara adalah yang diada-adakan, dan setiap bid'ah adalah sesat.\" Dan beliau selalu bersabda: \"Barangsiapa meninggalkan harta, maka bagi ahli warisnya. Dan barang siapa meninggalkan hutang atau amanah maka akulah yang menanggungnya.\""},"43":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ الْمَدَنِيُّ أَبُو عُبَيْدٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ أَبِي كَثِيرٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا هُمَا اثْنَتَانِ الْكَلَامُ وَالْهَدْيُ فَأَحْسَنُ الْكَلَامِ كَلَامُ اللَّهِ وَأَحْسَنُ الْهَدْيِ هَدْيُ مُحَمَّدٍ أَلَا وَإِيَّاكُمْ وَمُحْدِثَاتِ الْأُمُورِ فَإِنَّ شَرَّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلُّ مُحْدَثَةٍ بِدْعَةٌ وَكُلُّ بِدْعَةٍ ضَلَالَةٌ أَلَا لَا يَطُولَنَّ عَلَيْكُمْ الْأَمَدُ فَتَقْسُوَ قُلُوبُكُمْ أَلَا إِنَّ مَا هُوَ آتٍ قَرِيبٌ وَإِنَّمَا الْبَعِيدُ مَا لَيْسَ بِآتٍ أَلَا أَنَّمَا الشَّقِيُّ مَنْ شَقِيَ فِي بَطْنِ أُمِّهِ وَالسَّعِيدُ مَنْ وُعِظَ بِغَيْرِهِ أَلَا إِنَّ قِتَالَ الْمُؤْمِنِ كُفْرٌ وَسِبَابُهُ فُسُوقٌ وَلَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍ أَلَا وَإِيَّاكُمْ وَالْكَذِبَ فَإِنَّ الْكَذِبَ لَا يَصْلُحُ بِالْجِدِّ وَلَا بِالْهَزْلِ وَلَا يَعِدُ الرَّجُلُ صَبِيَّهُ ثُمَّ لَا يَفِي لَهُ فَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارَ وَإِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ وَإِنَّهُ يُقَالُ لِلصَّادِقِ صَدَقَ وَبَرَّ وَيُقَالُ لِلْكَاذِبِ كَذَبَ وَفَجَرَ أَلَا وَإِنَّ الْعَبْدَ يَكْذِبُ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ كَذَّابًا","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun Al Madani Abu Ubaid] berkata, telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ja'far bin Abu Katsir] dari [Musa bin 'Uqbah] dari [Abu Ishaq] dari [Abul Ahwash] dari [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Keduanya merupakan perkataan dan petunjuk. Maka sebaik-baik perkataan adalah kalamullah, dan sebaik-baik petunjuk adalah petunjuk Muhammad. Ketahuilah, jangan kalian membuat perkara-perkara baru. Sesungguhnya seburuk-buruk perkara adalah hal-hal baru (diada-adakan), dan setiap hal baru adalah bid'ah, dan setiap bid'ah adalah sesat. Ketahuilah, janganlah kalian terlalu panjang dalam berangan-angan, hingga menjadikan hati kalian keras. Ketahuilah, segala sesuatu yang akan datang itu adalah dekat, dan bahwasanya yang jauh itu sesuatu yang tidak datang. Ketahuilah, bahwasanya orang yang sengsara itu adalah orang yang sengsara di perut ibunya, dan orang yang berbahagia adalah orang yang diberi nasehat dengan selainnya. Ketahuilah, sesungguhnya membunuh seorang muslim adalah kekafiran, dan mencercanya adalah kefasikan. Tidak halal bagi seorang muslim untuk tidak mengajak bicara saudaranya di atas tiga hari. Ketahuilah, jauhilah oleh kalian berkata dusta, sesungguhnya dusta itu tidak dibenarkan baik dilakukan dengan serius maupun main-main. Janganlah seseorang berjanji kepada anak kecilnya kemudian dia tidak menepatinya. Sesungguhnya dusta akan menggiring kepada perbuatan dosa dan sesungguhnya perbuatan dosa akan menggiring ke dalam neraka. Sesungguhnya kejujuran akan menunjukkan kepada kebaikan dan kebaikan akan menunjukkan kepada surga. Dan akan dikatakan kepada orang yang jujur; ia telah berlaku jujur dan berbuat baik. Sementara kepada pendusta dikatakan; ia telah berlaku dusta dan dosa. Seorang hamba yang selalu berdusta, akan dicatat di sisi Allah sebagai pendusta.\""},"44":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا أَيُّوبُ ح و حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ وَيَحْيَى بْنُ حَكِيمٍ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ هُنَّ أُمُّ الْكِتَابِ وَأُخَرُ مُتَشَابِهَاتٌ إِلَى قَوْلِهِ وَمَا يَذَّكَّرُ إِلَّا أُولُوا الْأَلْبَابِ }فَقَالَ يَا عَائِشَةُ إِذَا رَأَيْتُمْ الَّذِينَ يُجَادِلُونَ فِيهِ فَهُمْ الَّذِينَ عَنَاهُمْ اللَّهُ فَاحْذَرُوهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidas] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulaiyah] berkata, telah menceritakan kepada kami [Ayyub]. Dan menurut jalur lain; Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] dan [Yahya bin Hakim], keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada [Ayyub] dari [Abdullah bin Abu Mulaikah] dari [Aisyah] ia berkata,; Rasulullah shallallahu 'alaihi wasallam membaca ayat ini: \"Dia-lah yang menurunkan Al-Kitab (Al-Qur'an) kepada kamu. Di antara (isi) nya ada ayat-ayat yang muhkamat itulah pokok-pokok isi Al qu`ran dan yang lain (ayat-ayat) mutasyaabihaat\" sampai pada firman-Nya: \"Dan tidak dapat mengambil pelajaran (daripadanya) melainkan orang-orang yang berakal.\" Lalu beliau bersabda: \"Wahai Aisyah, apabila kalian melihat orang-orang yang memperdebatkannya, maka mereka itulah yang dimaksudkan Allah, maka berhati-hatilah terhadap mereka.\""},"45":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ ح و حَدَّثَنَا حَوْثَرَةُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ دِينَارٍ عَنْ أَبِي غَالِبٍ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا ضَلَّ قَوْمٌ بَعْدَ هُدًى كَانُوا عَلَيْهِ إِلَّا أُوتُوا الْجَدَلَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ بَلْ هُمْ قَوْمٌ خَصِمُونَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail], Dan menurut jalur lain; Telah menceritakan kepada kami [Hautsarah bin Muhammad] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Dinar] dari [Abu Ghalib] dari [Abu Umamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak akan tersesat suatu kaum setelah petunjuk selama mereka masih tetap di atasnya, kecuali orang-orang yang senang berdebat.\" Kemudian beliau membaca ayat ini: \"tetapi mereka itu adalah kaum yang senang berdebat.\""},"46":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ سُلَيْمَانَ الْعَسْكَرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَلِيٍّ أَبُو هَاشِمِ بْنِ أَبِي خِدَاشٍ الْمَوْصِلِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مِحْصَنٍ عَنْ إِبْرَاهِيمَ بْنِ أَبِي عَبْلَةَ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ لِصَاحِبِ بِدْعَةٍ صَوْمًا وَلَا صَلَاةً وَلَا صَدَقَةً وَلَا حَجًّا وَلَا عُمْرَةً وَلَا جِهَادًا وَلَا صَرْفًا وَلَا عَدْلًا يَخْرُجُ مِنْ الْإِسْلَامِ كَمَا تَخْرُجُ الشَّعَرَةُ مِنْ الْعَجِينِ","id":"Telah menceritakan kepada kami [Daud bin Sulaiman Al 'Askari] berkata, telah menceritakan kepada kami [Muhammad bin Ali Abu Hasyim bin Abu Khidasy Al Maushili] ia berkata; telah menceritakan kepada kami [Muhammad bin Mihshan] dari [Ibrahim bin Abu 'Ablah] dari [Abdullah bin Ad Dailami] dari [Huzdaifah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah tidak akan menerima dari pelaku bid'ah; puasa, shalat, sedekah, haji, umrah, jihad, prilaku dan keadilannya. Dia keluar dari Islam sebagaimana rambut keluar dari tepung.\""},"47":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا بِشْرُ بْنُ مَنْصُورٍ الْحَنَّاطُ عَنْ أَبِي زَيْدٍ عَنْ أَبِي الْمُغِيرَةِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَى اللَّهُ أَنْ يَقْبَلَ عَمَلَ صَاحِبِ بِدْعَةٍ حَتَّى يَدَعَ بِدْعَتَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Bisyr bin Manshur Al Hannath] dari [Abu Zaid] dari [Abu Al Mughirah] dari [Abdullah bin Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah enggan menerima amalan pelaku bid'ah hingga ia meninggalkan kebid'ahannya.\""},"48":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ وَهَارُونُ بْنُ إِسْحَقَ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ سَلَمَةَ بْنِ وَرْدَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْكَذِبَ وَهُوَ بَاطِلٌ بُنِيَ لَهُ قَصْرٌ فِي رَبَضِ الْجَنَّةِ وَمَنْ تَرَكَ الْمِرَاءَ وَهُوَ مُحِقٌّ بُنِيَ لَهُ فِي وَسَطِهَا وَمَنْ حَسَّنَ خُلُقَةُ بُنِيَ لَهُ فِي أَعْلَاهَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] dan [Harun bin Ishaq], keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Salamah bin Wardan] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa meninggalkan dusta, sementara dia bathil, maka akan dibangunkan baginya istana di tepian surga. Barangsiapa meninggalkan debat meskipun ia benar, maka akan dibangunkan baginya istana di tengah surga. Barangsiapa memperbaiki akhlaknya maka baginya akan dibangunkan istana di surga yang paling tinggi.\""},"49":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَعَبْدَةُ وَأَبُو مُعَاوِيَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَمُحَمَّدُ بْنُ بِشْرٍ ح و حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَمَالِكُ بْنُ أَنَسٍ وَحَفْصُ بْنُ مَيْسَرَةَ وَشُعَيْبُ بْنُ إِسْحَقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَا يَقْبِضُ الْعِلْمَ انْتِزَاعًا يَنْتَزِعُهُ مِنْ النَّاسِ وَلَكِنْ يَقْبِضُ الْعِلْمُ بِقَبْضِ الْعُلَمَاءِ فَإِذَا لَمْ يُبْقِ عَالِمًا اتَّخَذَ النَّاسُ رُءُوسًا جُهَّالًا فَسُئِلُوا فَأَفْتَوْا بِغَيْرِ عِلْمٍ فَضَلُّوا وَأَضَلُّوا","id":"Telah menceritakan kepada kami [Abu Kuraib] ia berkata; telah menceritakan kepada kami [Abdullah bin Idris] dan ['Abdah] dan [Abu Mu'awiyah] dan [Abdullah bin Numair] dan [Muhammad bin Bisyr]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Suwaid bin Sa'id] ia berkata; telah menceritakan kepada kami [Ali bin Mushir] dan [Malik bin Anas] dan [Hafsh bin Maisarah] dan [Syu'aib bin Ishaq] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Abdullah bin 'Amru bin Al 'Ash] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya Allah tidak mencabut ilmu begitu saja dari diri manusia. Akan tetapi mencabut ilmu dengan cara mewafatkan para ulama. Apabila tidak tersisa sama sekali seorang Alim, manusia akan mengambil pemimpin-pemimpin yang bodoh, tatkala mereka ditanya maka mereka akan berfatwa tanpa ilmu, maka mereka sesat dan menyesatkan.\""},"50":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ حَدَّثَنِي أَبُو هَانِئٍ حُمَيْدُ بْنُ هَانِئٍ الْخَوْلَانِيُّ عَنْ أَبِي عُثْمَانَ مُسْلِمِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُفْتِيَ بِفُتْيَا غَيْرَ ثَبَتٍ فَإِنَّمَا إِثْمُهُ عَلَى مَنْ أَفْتَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Yazid] dari [Sa'id bin Abu Ayyub] berkata, telah menceritakan kepadaku [Abu Hani` Humaid bin Hani` Al Khaulani] dari [Abu Utsman Muslim bin Yasar] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa diberi fatwa dengan fatwa yang tidak benar, maka dosanya atas orang yang memberi fatwa.\""},"51":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ قَالَ حَدَّثَنِي رِشْدِينُ بْنُ سَعْدٍ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ ابْنِ أَنْعُمٍ هُوَ الْإِفْرِيقِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِلْمُ ثَلَاثَةٌ فَمَا وَرَاءَ ذَلِكَ فَهُوَ فَضْلٌ آيَةٌ مُحْكَمَةٌ أَوْ سُنَّةٌ قَائِمَةٌ أَوْ فَرِيضَةٌ عَادِلَةٌ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala` Al Hamdani] berkata; telah menceritakan kepadaku [Risydin bin Sa'd] dan [Ja'far bin Aun] dari [Ibnu An'um] -yaitu Al Afriqi- dari [Abdurrahman bin Rafi'] dari [Abdullah bin 'Amru] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ilmu itu ada tiga, sedangkan selebihnya hanyalah keutamaan; ayat muhkamat, sunnah yang tegak dan fara'idl yang adil.\""},"52":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ حَمَّادٍ سَجَّادَةُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ عَنْ مُحَمَّدِ بْنِ سَعِيدِ بْنِ حَسَّانَ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ حَدَّثَنَا مُعَاذُ بْنُ جَبَلٍ قَالَلَمَّا بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ قَالَ لَا تَقْضِيَنَّ وَلَا تَفْصِلَنَّ إِلَّا بِمَا تَعْلَمُ فَإِنْ أَشْكَلَ عَلَيْكَ أَمْرٌ فَقِفْ حَتَّى تَبَيَّنَهُ أَوْ تَكْتُبَ إِلَيَّ فِيهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Hammad Sajjadah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] dari [Muhammad bin Sa'id bin Hassan] dari [Ubadah bin Nusai] dari [Abdurrahman bin Ghanim] berkata, telah menceritakan kepada kami [Mu'adz bin Jabal] ia berkata; Tatkala Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, beliau bersabda: \" Janganlah sekali-kali kamu menetapkan dan memutuskan kecuali dengan apa yang kamu ketahui. Jika kamu mengalami satu permasalahan, maka tahanlah hingga menjadi jelas atau engkau tulis surat kepadaku.\""},"53":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي الرِّجَالِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو الْأَوْزَاعِيِّ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَمْ يَزَلْ أَمْرُ بَنِي إِسْرَائِيلَ مُعْتَدِلًا حَتَّى نَشَأَ فِيهِمْ الْمُوَلَّدُونَ أَبْنَاءُ سَبَايَا الْأُمَمِ فَقَالُوا بِالرَّأْيِ فَضَلُّوا وَأَضَلُّوا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ibnu Abu Ar Rijal] dari [Abdurrahman bin 'Amru Al Auza'i] dari ['Abdah bin Abu Lubabah] dari [Abdullah bin 'Amru bin Al 'Ash] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Urusan bani Isra`il masih tetap stabil hingga muncul keturunan-keturunan yang lahir dari para tawanan. Mereka berpendapat dengan menggunakan logika sehingga mereka sesat dan menyesatkan.\""},"54":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِيمَانُ بِضْعٌ وَسِتُّونَ أَوْ سَبْعُونَ بَابًا أَدْنَاهَا إِمَاطَةُ الْأَذَى عَنْ الطَّرِيقِ وَأَرْفَعُهَا قَوْلُ لَا إِلَهَ إِلَّا اللَّهُ وَالْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ ح و حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad Ath Thanafusi] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Iman itu ada enam puluh sembilan, atau tujuh puluh pintu. Yang paling rendah adalah menyingkirkan duri dari jalanan, dan yang paling tinggi adalah ucapan Laa Ilaaha Illallah (tidak ada tuhan selain Allah). Sifat malu merupakan bagian dari iman.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] ia berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan]. Dan menurut jalur yang lain; Telah menceritakan kepada kami ['Amru bin Rafi'] berkata, telah menceritakan kepada kami [Jarir] dari [Suhail] semuanya dari [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"55":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَعِظُ أَخَاهُ فِي الْحَيَاءِ فَقَالَ إِنَّ الْحَيَاءَ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dan [Muhammad bin Abdullah bin Yazid] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] ia berkata; \"Nabi shallallahu 'alaihi wasallam mendengar seorang lelaki memberi nasihat kepada saudaranya tentang malu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya malu adalah bagian iman.\""},"56":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَلَّصَ اللَّهُ الْمُؤْمِنِينَ مِنْ النَّارِ وَأَمِنُوا فَمَا مُجَادَلَةُ أَحَدِكُمْ لِصَاحِبِهِ فِي الْحَقِّ يَكُونُ لَهُ فِي الدُّنْيَا أَشَدَّ مُجَادَلَةً مِنْ الْمُؤْمِنِينَ لِرَبِّهِمْ فِي إِخْوَانِهِمْ الَّذِينَ أُدْخِلُوا النَّارَ قَالَ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَحُجُّونَ مَعَنَا فَأَدْخَلْتَهُمْ النَّارَ فَيَقُولُ اذْهَبُوا فَأَخْرِجُوا مَنْ عَرَفْتُمْ مِنْهُمْ فَيَأْتُونَهُمْ فَيَعْرِفُونَهُمْ بِصُوَرِهِمْ لَا تَأْكُلُ النَّارُ صُوَرَهُمْ فَمِنْهُمْ مَنْ أَخَذَتْهُ النَّارُ إِلَى أَنْصَافِ سَاقَيْهِ وَمِنْهُمْ مَنْ أَخَذَتْهُ إِلَى كَعْبَيْهِ فَيُخْرِجُونَهُمْ فَيَقُولُونَ رَبَّنَا أَخْرَجْنَا مَنْ قَدْ أَمَرْتَنَا ثُمَّ يَقُولُ أَخْرِجُوا مَنْ كَانَ فِي قَلْبِهِ وَزْنُ دِينَارٍ مِنْ الْإِيمَانِ ثُمَّ مَنْ كَانَ فِي قَلْبِهِ وَزْنُ نِصْفِ دِينَارٍ ثُمَّ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍقَالَ أَبُو سَعِيدٍ فَمَنْ لَمْ يُصَدِّقْ هَذَا فَلْيَقْرَأْ{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا وَيُؤْتِ مِنْ لَدُنْهُ أَجْرًا عَظِيمًا }","id":"Telah menceritakan kepada kami Telah [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah telah mengangkat orang-orang mukmin dari neraka dan mereka telah merasa aman, maka tidaklah perdebatan salah seorang di antara kalian terhadap temannya di dalam perkara yang hak yang terjadi di dunia itu lebih keras dari perdebatan orang-orang mukmin kepada Tuhan mereka tentang saudara-saudara mereka yang dimasukkan ke dalam neraka.\" Beliau bersabda: \"Orang-orang yang beriman berkata; 'Wahai Tuhan kami, saudara-saudara kami dulunya shalat bersama kami, puasa bersama kami, dan melaksanakan haji bersama kami, tapi kenapa Engkau masukkan mereka ke dalam neraka! ' Allah berfirman: ' Pergi dan keluarkanlah orang-orang yang kalian kenal dari mereka.' Maka mereka mendatanginya dan mengenali mereka dengan bentuk-bentuk mereka, bentuk-bentuk mereka tidak dimakan oleh api. Di antara mereka ada yang dimakan api hingga ke sebagian kedua betisnya. Dan ada yang telah dimakan api hingga ke kedua mata kakinya. Maka mereka pun mengeluarkannya. Kemudian mereka berseru; 'Wahai Tuhan kami, kami telah mengeluarkan orang-orang yang telah Engkau perintahkan kepada kami.' Kemudian Dia berfirman: 'Keluarkanlah orang yang dalam hatinya terdapat keimanan seberat satu dinar. Kemudian orang yang dalam hatinya terdapat keimanan seberat setengah dinar. Kemudian orang yang dalam hatinya terdapat keimanan seberat biji sawi.' Abu Sa'id berkata: \"Barangsiapa tidak mempercayai ini, maka hendaklah ia membaca: \"Sesungguhnya Allah tidak menganiaya seseorang walaupun sebesar zarah, dan jika ada kebajikan sebesar zarah, niscaya Allah akan melipat gandakan dan memberikan dari sisi-Nya pahala yang besar.\""},"57":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ نَجِيحٍ وَكَانَ ثِقَةً عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ جُنْدُبِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِتْيَانٌ حَزَاوِرَةٌ فَتَعَلَّمْنَا الْإِيمَانَ قَبْلَ أَنْ نَتَعَلَّمَ الْقُرْآنَ ثُمَّ تَعَلَّمْنَا الْقُرْآنَ فَازْدَدْنَا بِهِ إِيمَانًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hammad bin Najih] -ia tsiqah (terpercaya) - dari [Abu Imran Al Jauni] dari [Jundub bin Abdullah] ia berkata; \"Ketika kami bersama Nabi shallallahu 'alaihi wasallam, pada saat itu kami merupakan sosok pemuda-pemuda yang kuat. Kami belajar iman sebelum mempelajari Al Qur`an, kemudian kami mempelajari Al Qur`an, maka dengan begitu bertambahlah keimanan kami.\""},"58":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَلِيُّ بْنُ نِزَارٍ عَنْ أَبِيهِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِنْفَانِ مِنْ هَذِهِ الْأُمَّةِ لَيْسَ لَهُمَا فِي الْإِسْلَامِ نَصِيبٌ الْمُرْجِئَةُ وَالْقَدَرِيَّةُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Ali bin Nizar] dari [Bapaknya] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ada dua golongan dari umat ini yang bukan bagian dari Islam; yaitu Murji`ah dan Qadariyah.\""},"59":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ ��َأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَلِقَائِهِ وَتُؤْمِنَ بِالْبَعْثِ الْآخِرِ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَا تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّتَهَا فَذَلِكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْغَنَمِ فِي الْبُنْيَانِ فَذَلِكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ فَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulaiyah] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata; \"Pada suatu hari tatkala Rasulullah shallallahu 'alaihi wasallam berada di tengah kaum muslimin, datang seorang lelaki dan bertanya; \"Ya Rasulullah, apakah iman itu?\" beliau menjawab: \"Engkau beriman kepada Allah, malaikat-Nya, kita-kitab-Nya, para Rasul-Nya, pertemuan-Nya, dan kamu beriman kepada hari dibangkitkan di hari akhir.\" Ia bertanya, \"Ya Rasulullah, apakah Islam itu?\" beliau menjawab: \"Engkau beribadah kepada Allah dan tidak menyekutukan-Nya dengan sesuatu apapun, menegakkan shalat yang telah diwajibkan, menunaikan zakat yang difardlukan dan menjalankan puasa di bulan Ramadlan.\" Ia bertanya lagi: \"Ya Rasulullah, apakah ihsan itu?\" beliau menjawab: \"Engkau menyembah Allah seakan-akan engkau melihat-Nya. Jika engkau tidak melihat-Nya sesungguhnya Dia melihatmu.\" Ia bertanya lagi, \"Ya Rasulullah, kapan waktunya kiamat?\" beliau menjawab: \"Yang ditanya itu tidak lebih tahu dari yang bertanya. Akan tetapi aku akan memberitahukan kepadamu tentang tanda-tandanya; apabila seorang budak perempuan melahirkan anak majikannya itu adalah salah satu dari tanda-tandanya. Para penggembala kambing berlomba-lomba dalam membuat bangunan, itu adalah salah satu dari tanda-tandanya. Di dalam lima (kunci masalah gaib) tidak ada yang mengetahuinya kecuali Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat: \"Sesungguhnya Allah, hanya pada sisi-Nya sajalah pengetahuan tentang Hari Kiamat; dan Dia-lah Yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim. Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakannya besok. Dan tiada seorangpun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal.\""},"60":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ صَالِحٍ أَبُو الصَّلْتِ الْهَرَوِيُّ حَدَّثَنَا عَلِيُّ بْنُ مُوسَى الرِّضَا عَنْ أَبِيهِ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِيمَانُ مَعْرِفَةٌ بِالْقَلْبِ وَقَوْلٌ بِاللِّسَانِ وَعَمَلٌ بِالْأَرْكَانِقَالَ أَبُو الصَّلْتِ لَوْ قُرِئَ هَذَا الْإِسْنَادُ عَلَى مَجْنُونٍ لَبَرَأَ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Abdus Salam bin Shalih Abu Ash Shalt Al Harawi] berkata, telah menceritakan kepada kami [Ali bin Musa Ar Ridla] dari [Bapaknya] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ali bin Al Hasan] dari [Bapaknya] dari [Ali bin Abu Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Iman itu adalah pengetahuan di dalam hati, perkataan dengan lisan, dan perbuatan dengan anggota badan.\" Abu Ash Shalt berkata; \"Sekiranya sanad ini dibacakan kepada orang gila, maka dia akan menjadi sembuh.\""},"61":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَلَدِهِ وَوَالِدِهِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Qotadah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang dari kalian tidak akan beriman hingga aku menjadi orang yang paling dicintainya dari pada anaknya, orang tuanya dan manusia semuanya.\""},"62":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَدْخُلُوا الْجَنَّةَ حَتَّى تُؤْمِنُوا وَلَا تُؤْمِنُوا حَتَّى تَحَابُّوا أَوَ لَا أَدُلُّكُمْ عَلَى شَيْءٍ إِذَا فَعَلْتُمُوهُ تَحَابَبْتُمْ أَفْشُوا السَّلَامَ بَيْنَكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, kalian tidak akan masuk surga hingga kalian beriman, dan kalian tidak akan beriman hingga kalian saling mencintai. Maukah aku tunjukkan kepada kalian suatu amalan jika kalian amalkan maka kalian akan saling mencintai? sebarkanlah salam di antara kalian.\""},"63":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al A'masy]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Wa`il] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran.\""},"64":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَمُحَمَّدُ بْنُ فُضَيْلٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ الصَّادِقُ الْمَصْدُوقُ أَنَّهُ يُجْمَعُ خَلْقُ أَحَدِكُمْ فِي بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمًا ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذَلِكَ ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذَلِكَ ثُمَّ يَبْعَثُ اللَّهُ إِلَيْهِ الْمَلَكَ فَيُؤْمَرُ بِأَرْبَعِ كَلِمَاتٍ فَيَقُولُ اكْتُبْ عَمَلَهُ وَأَجَلَهُ وَرِزْقَهُ وَشَقِيٌّ أَمْ سَعِيدٌ فَوَالَّذِي نَفْسِي بِيَدِهِ إِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إِلَّا ذِرَاعٌ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ فَيَدْخُلُهَا وَإِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إِلَّا ذِرَاعٌ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ فَيَدْخُلُهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dan [Muhammad bin Fudlail] dan [Abu Mu'awiyah]. Menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Muhammad bin Ubaid] dari [Al A'masy] dari [Zaid bin Wahhab] ia berkata; [Abdullah bin Mas'ud] berkata; telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam seorang yang jujur lagi dipercaya: \" Penciptaan masing-masing kalian di himpun dalam perut ibu selama empat puluh hari hingga menjadi segumpal darah. Kemudian menjadi segumpal daging seperti itu pula, kemudian Allah mengutus seorang malaikat kepadanya, dia diperintah dengan empat kalimat, kemudian Dia berfirman: 'Tulislah amal, ajal, dan rizkinya serta sengsara atau bahagia.' Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya ada salah seorang kalian berbuat dengan amalan penghuni surga hingga tidak ada jarak antara dirinya dengan surga kecuali sehasta, namun catatan telah mendahuluinya hingga ia mengerjakan perbuatan penghuni neraka dan akhirnya masuk neraka. Dan sesungguhnya ada salah seorang kalian melakukan amalan penghuni neraka hingga tidak ada jarak antara dirinya dengan neraka kecuali satu hasta, namun catatan mendahuluinya hingga ia mengerjakan amalan penghuni surga dan akhirnya ia masuk ke surga.\""},"65":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا سِنَانٍ عَنْ وَهْبِ بْنِ خَالِدٍ الْحِمْصِيِّ عَنْ ابْنِ الدَّيْلَمِيِّ قَالَوَقَعَ فِي نَفْسِي شَيْءٌ مِنْ هَذَا الْقَدَرِ خَشِيتُ أَنْ يُفْسِدَ عَلَيَّ دِينِي وَأَمْرِي فَأَتَيْتُ أُبَيَّ بْنَ كَعْبٍ فَقُلْتُ أَبَا الْمُنْذِرِ إِنَّهُ قَدْ وَقَعَ فِي نَفْسِي شَيْءٌ مِنْ هَذَا الْقَدَرِ فَخَشِيتُ عَلَى دِينِي وَأَمْرِي فَحَدِّثْنِي مِنْ ذَلِكَ بِشَيْءٍ لَعَلَّ اللَّهَ أَنْ يَنْفَعَنِي بِهِ فَقَالَ لَوْ أَنَّ اللَّهَ عَذَّبَ أَهْلَ سَمَاوَاتِهِ وَأَهْلَ أَرْضِهِ لَعَذَّبَهُمْ وَهُوَ غَيْرُ ظَالِمٍ لَهُمْ وَلَوْ رَحِمَهُمْ لَكَانَتْ رَحْمَتُهُ خَيْرًا لَهُمْ مِنْ أَعْمَالِهِمْ وَلَوْ كَانَ لَكَ مِثْلُ جَبَلِ أُحُدٍ ذَهَبًا أَوْ مِثْلُ جَبَلِ أُحُدٍ تُنْفِقُهُ فِي سَبِيلِ اللَّهِ مَا قُبِلَ مِنْكَ حَتَّى تُؤْمِنَ بِالْقَدَرِ فَتَعْلَمَ أَنَّ مَا أَصَابَكَ لَمْ يَكُنْ لِيُخْطِئَكَ وَأَنَّ مَا أَخْطَأَكَ لَمْ يَكُنْ لِيُصِيبَكَ وَأَنَّكَ إِنْ مُتَّ عَلَى غَيْرِ هَذَا دَخَلْتَ النَّارَ وَلَا عَلَيْكَ أَنْ تَأْتِيَ أَخِي عَبْدَ اللَّهِ بْنَ مَسْعُودٍ فَتَسْأَلَهُ فَأَتَيْتُ عَبْدَ اللَّهِ فَسَأَلْتُهُ فَذَكَرَ مِثْلَ مَا قَالَ أُبَيٌّ وَقَالَ لِي وَلَا عَلَيْكَ أَنْ تَأْتِيَ حُذَيْفَةَ فَأَتَيْتُ حُذَيْفَةَ فَسَأَلْتُهُ فَقَالَ مِثْلَ مَا قَالَا وَقَالَ ائْتِ زَيْدَ بْنَ ثَابِتٍ فَاسْأَلْهُ فَأَتَيْتُ زَيْدَ بْنَ ثَابِتٍ فَسَأَلْتُهُ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ أَنَّ اللَّهَ عَذَّبَ أَهْلَ سَمَاوَاتِهِ وَأَهْلَ أَرْضِهِ لَعَذَّبَهُمْ وَهُوَ غَيْرُ ظَالِمٍ لَهُمْ وَلَوْ رَحِمَهُمْ لَكَانَتْ رَحْمَتُهُ خَيْرًا لَهُمْ مِنْ أَعْمَالِهِمْ وَلَوْ كَانَ لَكَ مِثْلُ أُحُدٍ ذَهَبًا أَوْ مِثْلُ جَبَلِ أُحُدٍ ذَهَبًا تُنْفِقُهُ فِي سَبِيلِ اللَّهِ مَا قَبِلَهُ مِنْكَ حَتَّى تُؤْمِنَ بِالْقَدَرِ كُلِّهِ فَتَعْلَمَ أَنَّ مَا أَصَابَكَ لَمْ يَكُنْ لِيُخْطِئَكَ وَمَا أَخْطَأَكَ لَمْ يَكُنْ لِيُصِيبَكَ وَأَنَّك�� إِنْ مُتَّ عَلَى غَيْرِ هَذَا دَخَلْتَ النَّارَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ishaq bin Sulaiman] ia berkata; aku mendengar [Abu Sinan] dari [Wahb bin Khalid Al Himshi] dari [Ibnu Ad Dailami] ia berkata; \"Ada sesuatu yang mengganjal dalam jiwaku seputar takdir. Aku khawatir akan merusak agama dan urusanku, maka aku mendatangi [Ubai bin Ka'ab]. Aku bertanya kepadanya; \"Wahai Abul Mundzir, ada sesuatu yang mengganjal dalam jiwaku seputar perkara takdir, aku khawatir akan merusak agama dan urusanku. Maka beritakan kepadaku sesuatu yang berkaitan dengannya, semoga Allah memberikan manfaat dengannya.\" Dia berkata; \"Sekiranya Allah mengadzab penghuni langit dan bumi, niscaya Dia akan mengadzabnya, dan Dia tidak zhalim kepada mereka. Sekiranya Dia memberi rahmat, niscaya rahmat-Nya lebih baik dari amalan mereka. Jikalau kamu memiliki emas seperti gunung Uhud lalu engkau infaqkan di jalan Allah, maka itu tidak akan diterima hingga engkau beriman kepada takdir. Ketahuilah, sesungguhnya yang menjadi bagianmu tidak akan lepas darimu, dan sesuatu yang bukan milikmu maka tidak akan menjadi bagianmu. Sekiranya engkau meninggal dalam kondisi selain ini maka kamu akan masuk neraka. Tidak ada salahnya jika engkau datang kepada saudaraku, Abdullah bin Mas'ud, lalu engkau tanyakan kepadanya.\" Maka aku mendatangi [Abdullah] seraya menanyakan hal itu kepadanya, dan ia pun menyebutkan sebagaimana yang dikatakan oleh Ubai. Lalu ia berkata kepadaku, \"Tidak ada salahnya jika engkau datang kepada Hudzaifah.\" Maka aku mendatangi [Hudzaifah] seraya menanyakan hal itu kepadanya. Lalu ia menjawab sebagaimana yang dikatakan oleh mereka berdua.\" Hudzaifah berkata; \"Datanglah kepada Zaid bin Tsabit dan tanyakan kepadanya.\" Maka akupun mendatangi [Zaid bin Tsabit] dan bertanya kepadanya, lalu ia menjawab, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sekiranya Allah mengadzab penghuni langit dan bumi, niscaya Dia akan mengadzabnya, dan Dia tidak zhalim kepada mereka. Sekiranya Dia memberi rahmat, niscaya rahmat-Nya lebih baik dari amalan mereka. Jikalau kamu memiliki emas seperti gunung Uhud lalu engkau infaqkan di jalan Allah, maka itu tidak akan diterima hingga engkau beriman kepada takdir. Ketahuilah, sesungguhnya yang menjadi bagianmu tidak akan lepas darimu, dan sesuatu yang bukan milikmu maka tidak akan menjadi bagianmu. Sekiranya engkau meninggal dalam kondisi selain ini maka kamu akan masuk neraka.\""},"66":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِيَدِهِ عُودٌ فَنَكَتَ فِي الْأَرْضِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ كُتِبَ مَقْعَدُهُ مِنْ الْجَنَّةِ وَمَقْعَدُهُ مِنْ النَّارِ قِيلَ يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ قَالَ لَا اعْمَلُوا وَلَا تَتَّكِلُوا فَكُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى فَسَنُيَسِّرُهُ لِلْيُسْرَى وَأَمَّا مَنْ بَخِلَ وَاسْتَغْنَى وَكَذَّبَ بِالْحُسْنَى فَسَنُيَسِّرُهُ لِلْعُسْرَى }","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] ia berkata: \"Kami pernah duduk-duduk di samping Nabi shallallahu 'alaihi wasallam sementara di tangannya ada kayu gaharu. Beliau melemparkannya ke tanah kemudian mengangkat kepalanya seraya bersabda: \" Setiap kalian telah ditetapkan tempat duduknya di surga dan tempat duduknya di neraka.\" Beliau ditanya: \"Wahai Rasulullah, bagaimana jika kita pasrah saja?\" beliau menjawab: \"Jangan, tetaplah berbuat dan jangan menyerah. Setiap orang akan dipermudah sesuai dengan apa yang diciptakan untuknya.\" Kemudian beliau membaca: \"Adapun orang yang memberikan (hartanya di jalan Allah) dan bertaqwa, dan membenarkan adanya pahala yang terbaik (surga), maka Kami kelak akan menyiapkan baginya (jalan) yang mudah. Dan adapun orang-orang yang bakhil dan merasa dirinya cukup, serta mendustakan pahala yang terbaik, maka kelak Kami akan menyiapkan baginya (jalan) yang sukar.\""},"67":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ طَاوُسًا يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يُخْبِرُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّ آدَمُ وَمُوسَى عَلَيْهِمَا السَّلَام فَقَالَ لَهُ مُوسَى يَا آدَمُ أَنْتَ أَبُونَا خَيَّبْتَنَا وَأَخْرَجْتَنَا مِنْ الْجَنَّةِ بِذَنْبِكَ فَقَالَ لَهُ آدَمُ يَا مُوسَى اصْطَفَاكَ اللَّهُ بِكَلَامِهِ وَخَطَّ لَكَ التَّوْرَاةَ بِيَدِهِ أَتَلُومُنِي عَلَى أَمْرٍ قَدَّرَهُ اللَّهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي بِأَرْبَعِينَ سَنَةً فَحَجَّ آدَمُ مُوسَى فَحَجَّ آدَمُ مُوسَى فَحَجَّ آدَمُ مُوسَى ثَلَاثًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Amru bin Dinar] ia mendengar [Thawus] berkata; Aku mendengar [Abu Hurairah] mengabarkan kepada kami dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Adam dan Musa 'Alaihimas Salam saling berdebat. Musa berkata: 'Wahai Adam, engkau adalah bapak kami. Engkau telah mengecewakan kami dan mengeluarkan kami dari surga karena dosamu.' Adam menjawab: 'Wahai Musa, Allah telah memilihmu dengan kalam-Nya dan menulis Taurat untukmu dengan tangan-Nya. Apakah kamu mencelaku atas perkara yang telah Allah tentukan terhadapku sebelum menciptakanku empat puluh tahun.' Maka argumentasi Adam mengalahkan Musa, maka argumentasi Adam mengalahkan Musa.\" Beliau ulangi hingga tiga kali."},"68":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا شَرِيكٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ عَبْدٌ حَتَّى يُؤْمِنَ بِأَرْبَعٍ بِاللَّهِ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنِّي رَسُولُ اللَّهِ وَبِالْبَعْثِ بَعْدَ الْمَوْتِ وَالْقَدَرِ","id":"Telah menceritakan kepada kami [Abdullah bin 'Amir bin Zurarah] berkata, telah menceritakan kepada kami [Syarik] dari [Manshur] dari [Rib'i] dari [Ali radliallahu 'anhu] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Seorang hamba tidak akan beriman hingga ia mengimani empat hal; Iman kepada Allah yang tidak ada sekutu bagi-Nya, mengimani bahwa aku adalah utusan Allah, iman kepada hari kebangkitan setelah kematian dan iman kepada takdir.\" "},"69":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ زِيَادِ بْنِ إِسْمَعِيلَ الْمَخْزُومِيِّ عَنْ مُحَمَّدِ بْنِ عَبَّادِ بْنِ جَعْفَرٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ مُشْرِكُو قُرَيْشٍ يُخَاصِمُونَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْقَدَرِ فَنَزَلَتْ هَذِهِ الْآيَةُ{ يَوْمَ يُسْحَبُونَ فِي النَّارِ عَلَى وُجُوهِهِمْ ذُوقُوا مَسَّ سَقَرَ إِنَّا كُلَّ شَيْءٍ خَلَقْنَاهُ بِقَدَرٍ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Ziyad bin Isma'il Al Makhzumi] dari [Muhammad bin 'Abbad bin Ja'far] dari [Abu Hurairah] ia berkata; \"Orang-orang musyrik Quraisy datang mendebat Nabi shallallahu 'alaihi wasallam seputar takdir. Maka turunlah ayat ini: \" Di hari mereka disungkurkan muka-muka mereka di api neraka. Rasakanlah jilatan api neraka Saqor. Sesungguhnya kami menciptakan setiap sesuatu dengan qodar.\""},"70":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ مَوْلَى أَبِي بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ أَبِيهِأَنَّهُ دَخَلَ عَلَى عَائِشَةَ فَذَكَرَ لَهَا شَيْئًا مِنْ الْقَدَرِ فَقَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَكَلَّمَ فِي شَيْءٍ مِنْ الْقَدَرِ سُئِلَ عَنْهُ يَوْمَ الْقِيَامَةِ وَمَنْ لَمْ يَتَكَلَّمْ فِيهِ لَمْ يُسْأَلْ عَنْهُقَالَ أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَاهُ حَازِمُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شَيْبَانَ حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Malik bin Isma'il] berkata, telah menceritakan kepada kami [Yahya bin Utsman] mantan budak Abu Bakr, berkata; telah menceritakan kepada kami [Yahya bin Abdullah bin Abu Mulaikah] dari [Bapaknya] bahwa ia pernah menemui [Aisyah] dan menyebutkan sesuatu yang berkaitan dengan takdir. Maka ia pun berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa memperbincangkan sesuatu tentang takdir, maka pada hari kiamat ia akan dimintai pertanggung jawaban. Dan barangsiapa tidak memperbincangkannya maka tidak akan dimintai pertanggung jawaban.\" Abul Hasan Al Qaththan berkata; telah menceritakan kepada kami Hazim bin Yahya berkata, telah menceritakan kepada kami Abdul Malik bin Syaiban berkata, telah menceritakan kepada kami Yahya bin Utsman. Lalu ia menyebutkan sebagaimana hadits di atas."},"71":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَصْحَابِهِ وَهُمْ يَخْتَصِمُونَ فِي الْقَدَرِ فَكَأَنَّمَا يُفْقَأُ فِي وَجْهِهِ حَبُّ الرُّمَّانِ مِنْ الْغَضَبِ فَقَالَ بِهَذَا أُمِرْتُمْ أَوْ لِهَذَا خُلِقْتُمْ تَضْرِبُونَ الْقُرْآنَ بَعْضَهُ بِبَعْضٍ بِهَذَا هَلَكَتْ الْأُمَمُ قَبْلَكُمْقَالَ فَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو مَا غَبَطْتُ نَفْسِي بِمَجْلِسٍ تَخَلَّفْتُ فِيهِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا غَبَطْتُ نَفْسِي بِذَلِكَ الْمَجْلِسِ وَتَخَلُّفِي عَنْهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Daud bin Abu Hindun] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menjumpai para sahabatnya yang sedang berdebat tentang takdir. Maka seakan-akan wajah beliau seperti buah delima karena marah. Beliau lalu bersabda: \" Apakah untuk ini kalian diperintahkan, atau beliau mengatakan, \"untuk inikah kalian diciptakan! Kalian benturkan sebagian Al Qur'an dengan sebagian yang lain. Karena hal inilah kaum sebelum kalian binasa.\" Ia (perawi) berkata; \"Abdullah bin 'Amru lalu berkata: \"Alangkah marahnya diriku pada jiwaku jika tidak menghadiri majlis yang dihadiri Rasulullah shallallahu 'alaihi wasallam. Dan alangkah marahnya diriku pada jiwaku karena ketidak hadiranku di majlis tersebut.\""},"72":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ عِيسَى الْجَرَّارُ عَنْ عَبْدِ الْأَعْلَى بْنِ أَبِي الْمُسَاوِرِ عَنْ الشَّعْبِيِّ قَالَلَمَّا قَدِمَ عَدِيُّ ابْنُ حَاتِمٍ الْكُوفَةَ أَتَيْنَاهُ فِي نَفَرٍ مِنْ فُقَهَاءِ أَهْلِ الْكُوفَةِ فَقُلْنَا لَهُ حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عَدِيَّ ابْنَ حَاتِمٍ أَسْلِمْ تَسْلَمْ قُلْتُ وَمَا الْإِسْلَامُ فَقَالَ تَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَتُؤْمِنُ بِالْأَقْدَارِ كُلِّهَا لِخَيْرِهَا وَشَرِّهَا حُلْوِهَا وَمُرِّهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Isa Al Jarrar] dari [Abdul A'la bin Abu Al Musawir] dari [Sya'bi] ia berkata; \"Tatkala [Adi bin Hatim] datang ke Kufah, kami dengan beberapa orang dari kalangan fuqaha` mendatanginya seraya berkata kepadanya; \"Bacakanlah kepada kami hadits yang pernah engkau dengar dari Rasulullah shallallahu 'alaihi wasallam, \" Ia lalu berkata; \"Aku pernah datang kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Wahai Adi bin Hatim, masuklah Islam maka engkau akan selamat.\" Aku lalu bertanya kepada beliau, \"Apakah Islam itu?\" beliau menjawab: \" Engkau bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah dan aku adalah utusan-Nya, dan engkau beriman dengan semua ketentuan-Nya, yang baik maupun yang buruk, yang manis maupun yang pahit.\""},"73":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ يَزِيدَ الرِّقَاشِيِّ عَنْ غُنَيْمِ بْنِ قَيْسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْقَلْبِ مَثَلُ الرِّيشَةِ تُقَلِّبُهَا الرِّيَاحُ بِفَلَاةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Asbath bin Muhammad] berkata, telah menceritakan kepada kami [Al A'masy] dari [Yazid Ar Raqasyi] dari [Ghunaim bin Qais] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Perumpamaan hati adalah seperti selembar bulu yang diombang-ambingkan angin di tanah yang lapang.\""},"74":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنِّي أَبْرَأُ إِلَى كُلِّ خَلِيلٍ مِنْ خُلَّتِهِ وَلَوْ كُنْتُ مُتَّخِذًا خَلِيلًا لَاتَّخَذْتُ أَبَا بَكْرٍ خَلِيلًا إِنَّ صَاحِبَكُمْ خَلِيلُ اللَّهِ قَالَ وَكِيعٌ يَعْنِي نَفْسَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Abul Ahwash] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ketahuilah, sungguh aku adalah orang yang paling berlaku baik kepada setiap kekasihnya. Sekiranya aku dibolehkan mengambil seorang kekasih, niscaya aku akan menjadikan Abu Bakar sebagai kekasih. Sesungguhnya sahabat kalian ini adalah kekasih Allah\". Waki' berkata; \"Maksudnya adalah dirinya sendiri.\""},"75":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَفَعَنِي مَالٌ قَطُّ مَا نَفَعَنِي مَالُ أَبِي بَكْرٍ فَبَكَى أَبُو بَكْرٍ وَقَالَ هَلْ أَنَا وَمَالِي إِلَّا لَكَ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak ada harta yang dapat memberiku manfa'at sebagaimana harta Abu Bakar, \" maka menangislah Abu Bakar, dan berkata; \"Wahai Rasulullah, bukankah aku dan juga hartaku adalah milikmu.\""},"76":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الْحَسَنِ بْنِ عُمَارَةَ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ وَعُمَرُ سَيِّدَا كُهُولِ أَهْلِ الْجَنَّةِ مِنْ الْأَوَّلِينَ وَالْآخِرِينَ إِلَّا النَّبِيِّينَ وَالْمُرْسَلِينَ لَا تُخْبِرْهُمَا يَا عَلِيُّ مَا دَامَا حَيَّيْنِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Hasan bin Umarah] dari [Firas] dari [Asy Sya'bi] dari [Al Harits] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Abu Bakar dan Umar adalah pemimpin orang-orang dewasa penduduk surga dari golongan terdahulu maupun yang terakhir, kecuali para nabi dan rasul. Wahai Ali, janganlah engkau beritahu selama keduanya masih hidup.\""},"77":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عَطِيَّةَ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَهْلَ الدَّرَجَاتِ الْعُلَى يَرَاهُمْ مَنْ أَسْفَلَ مِنْهُمْ كَمَا يُرَى الْكَوْكَبُ الطَّالِعُ فِي الْأُفُقِ مِنْ آفَاقِ السَّمَاءِ وَإِنَّ أَبَا بَكْرٍ وَعُمَرَ مِنْهُمْ وَأَنْعَمَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari ['Athiyyah bin Sa'd] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya penghuni surga yang paling tinggi derajatnya bisa dilihat oleh orang-orang yang ada di bawah mereka, sebagaimana terlihatnya bintang yang terbit di ujung langit. Dan sungguh, Abu Bakr dan Umar termasuk dari mereka yang mendapat nikmat tersebut.\""},"78":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح وَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُؤَمَّلٌ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مَوْلًى لِرِبْعِيِّ بْنِ حِرَاشٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أَدْرِي مَا قَدْرُ بَقَائِي فِيكُمْ فَاقْتَدُوا بِاللَّذَيْنِ مِنْ بَعْدِي وَأَشَارَ إِلَى أَبِي بَكْرٍ وَعُمَرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu`ammal] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin Umair] dari [mantan budak Rib'i bin Hirasy] dari [Rib'i bin Hirasy] dari [Hudzaifah bin Al Yaman] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak tahu berapa lama aku akan (hidup) bersama kalian, maka ikutilah dua orang setelahku\". Beliau lalu menunjuk kepada Abu Bakr dan Umar."},"79":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُلَمَّا وُضِعَ عُمَرُ عَلَى سَرِيرِهِ اكْتَنَفَهُ النَّاسُ يَدْعُونَ وَيُصَلُّونَ أَوْ قَال�� يُثْنُونَ وَيُصَلُّونَ عَلَيْهِ قَبْلَ أَنْ يُرْفَعَ وَأَنَا فِيهِمْ فَلَمْ يَرُعْنِي إِلَّا رَجُلٌ قَدْ زَحَمَنِي وَأَخَذَ بِمَنْكِبِي فَالْتَفَتُّ فَإِذَا عَلِيُّ بْنُ أَبِي طَالِبٍ فَتَرَحَّمَ عَلَى عُمَرَ ثُمَّ قَالَ مَا خَلَّفْتُ أَحَدًا أَحَبَّ إِلَيَّ أَنْ أَلْقَى اللَّهَ بِمِثْلِ عَمَلِهِ مِنْكَ وَايْمُ اللَّهِ إِنْ كُنْتُ لَأَظُنُّ لَيَجْعَلَنَّكَ اللَّهُ عَزَّ وَجَلَّ مَعَ صَاحِبَيْكَ وَذَلِكَ أَنِّي كُنْتُ أَكْثَرُ أَنْ أَسْمَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَهَبْتُ أَنَا وَأَبُو بَكْرٍ وَعُمَرُ وَدَخَلْتُ أَنَا وَأَبُو بَكْرٍ وَعُمَرُ وَخَرَجْتُ أَنَا وَأَبُو بَكْرٍ وَعُمَرُ فَكُنْتُ أَظُنُّ لَيَجْعَلَنَّكَ اللَّهُ مَعَ صَاحِبَيْكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Ibnu Mubarak] dari [Umar bin Sa'id bin Abu Husain] dari [Ibnu Abu Mulaikah] ia berkata; aku mendengar [Ibnu Abbas] berkata; \"Tatkala Umar diletakkan di atas pembaringannya, orang-orang mengafani, mendoakan dan menshalatkannya, atau Ibnu Abbas mengatakan; \"memuji dan menshalatkannya sebelum diangkat, sedang pada waktu itu aku berada di antara mereka. Tidak ada yang memperhatikanku kecuali seseorang yang memepet dan memegang pundakku. Ketika aku menoleh ternyata ia adalah [Ali bin Abu Thalib]. Dia mengucapkan; \"Rahimahullah\" (semoga Allah merahmatinya) kepada Umar. Kemudian ia berkata; \"Tidak ada seorangpun yang aku tinggalkan, yang lebih aku sukai jika bertemu dengan Allah amalku seperti amalannya selain kamu. Demi Allah, aku yakin Allah akan menjadikanmu bersama dengan kedua sahabatmu. Hal itu karena aku sering mendengar Rasulullah shallallahu 'alaihi wasallam selalu menyebut-nyebut: \" Aku pergi bersama Abu Bakar dan Umar. Aku masuk bersama Abu Bakar dan Umar. Dan aku keluar bersama Abu Bakar dan Umar\" Maka aku yakin Allah pasti akan menjadikanmu bersama dengan kedua sahabatmu.\""},"80":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا سَعِيدُ بْنُ مَسْلَمَةَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَبِي بَكْرٍ وَعُمَرَ فَقَالَ هَكَذَا نُبْعَثُ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] berkata, telah menceritakan kepada kami [Sa'id bin Maslamah] dari [Isma'il bin Umaiyah] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Nabi shallallahu 'alaihi wasallam keluar di antara Abu Bakar dan Umar seraya bersabda: \" Seperti ini kami akan dibangkitkan.\""},"81":{"ar":"حَدَّثَنَا أَبُو شُعَيْبٍ صَالِحُ بْنُ الْهَيْثَمِ الْوَاسِطِيُّ حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ بَكْرِ بْنِ خُنَيْسٍ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ وَعُمَرُ سَيِّدَا كُهُولِ أَهْلِ الْجَنَّةِ مِنْ الْأَوَّلِينَ وَالْآخِرِينَ إِلَّا النَّبِيِّينَ وَالْمُرْسَلِينَ","id":"Telah menceritakan kepada kami [Abu Syu'aib Shalih bin Al Haitsam Al Wasithi] berkata, telah menceritakan kepada kami [Abdul Qudus bin Bakr bin Khunais] berkata, telah menceritakan kepada kami [Malik bin Mighwal] dari ['Aun bin Abu Juhaifah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Abu Bakar dan Umar merupakan pemimpin surga bagi yang sebaya baik dari golongan terdahulu maupun yang terakhir, kecuali para Nabi dan Rasul.\""},"82":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَالْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ قَالَا حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقِيلَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ أَحَبُّ إِلَيْكَ قَالَ عَائِشَةُ قِيلَ مِنْ الرِّجَالِ قَالَ أَبُوهَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] dan [Al Husain bin Al Hasan Al Marwazi] keduanya berkata; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Humaid] dari [Anas bin Malik] ia berkata; Rasulullah ditanya; \"Siapakah orang yang paling engkau cintai?\" beliau menjawab: \"Aisyah.\" Kemudian beliau ditanya lagi; \"Dari kaum lelaki?\" beliau menjawab: \"Ayahnya.\""},"83":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ أَخْبَرَنِي الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ قُلْتُ لِعَائِشَةَأَيُّ أَصْحَابِهِ كَانَ أَحَبَّ إِلَيْهِ قَالَتْ أَبُو بَكْرٍ قُلْتُ ثُمَّ أَيُّهُمْ قَالَتْ عُمَرُ قُلْتُ ثُمَّ أَيُّهُمْ قَالَتْ أَبُو عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah mengabarkan kepadaku [Al Juairi] dari [Abdullah bin Syaqiq] ia berkata; Aku bertanya kepada [Aisyah]; \" Siapakah di antara sahabatnya yang paling beliau cintai?\" ia menjawab; \"Abu Bakar.\" Aku bertanya lagi; \"Kemudian siapa?\" ia menjawab; \"Umar.\" Aku bertanya lagi; \"Kemudian siapa?\" ia menjawab; \"Abu Ubaidah.\""},"84":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُحَمَّدٍ الطَّلْحِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ خِرَاشٍ الْحَوْشَبِيُّ عَنْ الْعَوَّامِ بْنِ حَوْشَبٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أَسْلَمَ عُمَرُ نَزَلَ جِبْرِيلُ فَقَالَ يَا مُحَمَّدُ لَقَدْ اسْتَبْشَرَ أَهْلُ السَّمَاءِ بِإِسْلَامِ عُمَرَ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad Ath Thalhi] berkata, telah menceritakan kepada kami [Abdullah bin Khirasy Al Hausyabi] dari [Al 'Awwam bin Hausyab] dari [Mujahid] dari [Ibnu Abbas] ia berkata; \" Tatkala Umar masuk Islam, Jibril turun seraya berkata: \"Wahai Muhammad, penduduk langit telah berbahagia dengan keIslaman Umar.\""},"85":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُحَمَّدٍ الطَّلْحِيُّ أَنْبَأَنَا دَاوُدُ بْنُ عَطَاءٍ الْمَدِينِيُّ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَنْ يُصَافِحُهُ الْحَقُّ عُمَرُ وَأَوَّلُ مَنْ يُسَلِّمُ عَلَيْهِ وَأَوَّلُ مَنْ يَأْخُذُ بِيَدِهِ فَيُدْخِلُهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad Ath Thalhi] berkata, telah memberitakan kepada kami [Daud bin 'Atho` Al Madani] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Ubai bin Ka'ab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang pertama kali yang dijabat oleh Al Haq adalah Umar, dia orang pertama yang diberi salam dan orang pertama yang digandeng tangannya kemudian dimasukkan ke surga.\""},"86":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ أَبُو عُبَيْدٍ الْمَدِينِيُّ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الْمَاجِشُونِ قَالَ حَدَّثَنِي الزَّنْجِيُّ بْنُ خَالِدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَعِزَّ الْإِسْلَامَ بِعُمَرَ بْنِ الْخَطَّابِ خَاصَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid Abu Ubaid Al Madini] ia berkata; telah menceritakan kepada kami [Abdul Malik Al Majisyun] ia berkata; telah menceritakan kepadaku [Al Zanji bin Khalid] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah muliakanlah Islam dengan perantaraan Umar bin Khaththab secara khusus.\""},"87":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ قَالَ سَمِعْتُ عَلِيًّا يَقُولُخَيْرُ النَّاسِ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ وَخَيْرُ النَّاسِ بَعْدَ أَبِي بَكْرٍ عُمَرُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abdullah bin Salamah] ia berkata; Aku mendengar [Ali] berkata; \"Sebaik-baik manusia setelah Rasulullah shallallahu 'alaihi wasallam adalah Abu Bakar, dan sebaik-baik manusia setelah Abu Bakar adalah Umar.\""},"88":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي فِي الْجَنَّةِ فَإِذَا أَنَا بِامْرَأَةٍ تَتَوَضَّأُ إِلَى جَانِبِ قَصْرٍ فَقُلْتُ لِمَنْ هَذَا الْقَصْرُ فَقَالَتْ لِعُمَرَ فَذَكَرْتُ غَيْرَتَهُ فَوَلَّيْتُ مُدْبِرًا قَالَ أَبُو هُرَيْرَةَ فَبَكَى عُمَرُ بْنُ الْخَطَّابِ فَقَالَ أَعَلَيْكَ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ أَغَارُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Harits Al Mishri] berkata, telah memberitakan kepada kami [Laits bin Sa'd] berkata, telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Sa'id bin Musayyab] bahwa [Abu Hurairah] berkata; Tatkala kami sedang duduk bersama Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Ketika aku tidur, aku melihat diriku di dalam surga, rupanya di sana ada seorang perempuan yang sedang berwudlu di samping sebuah istana, maka aku bertanya: 'Kepunyaan siapa istana ini? ' Perempuan itu menjawab: 'Milik Umar.' Maka aku teringat kecemburuannya, kemudian aku berbalik memutar.\" Abu Hurairah berkata; Maka menangislah Umar bin Khaththab sambil berkata: \"ayah dan ibuku sebagai tebusanmu, apakah kepadamu aku cemburu?\" "},"89":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ غُضَيْفِ بْنِ الْحَارِثِ عَنْ أَبِي ذَرٍّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ وَضَعَ الْحَقَّ عَلَى لِسَانِ عُمَرَ يَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] dari [Makhul] dari [Ghudlaif bin Al Harits] dari [Abu Dzar] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah meletakkan kebenaran pada lisan Umar yang senantiasa dia ucapkan.\""},"90":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا أَبِي عُثْمَانُ بْنُ خَالِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ نَبِيٍّ رَفِيقٌ فِي الْجَنَّةِ وَرَفِيقِي فِيهَا عُثْمَانُ بْنُ عَفَّانَ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami bapakku [Utsman bin Khalid] dari [Abdurrahman bin Abu Zinad] dari [Bapaknya] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap Nabi memiliki teman karib di surga, dan teman karibku di surga adalah Utsman bin 'Affan.\""},"91":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا أَبِي عُثْمَانُ بْنُ خَالِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَ عُثْمَانَ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَ يَا عُثْمَانُ هَذَا جِبْرِيلُ أَخْبَرَنِي أَنَّ اللَّهَ قَدْ زَوَّجَكَ أُمَّ كُلْثُومٍ بِمِثْلِ صَدَاقِ رُقَيَّةَ عَلَى مِثْلِ صُحْبَتِهَا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Utsman bin Khalid] dari [Abdurrahman bin Abu Zinad] dari [Bapaknya] dari [Al A'raj] dari [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam bertemu Utsman di depan pintu masjid, kemudian beliau bersabda: \"Wahai Utsman, ini adalah Jibril, dia mengabarkan kepadaku bahwa Allah telah menikahkanmu dengan Ummu Kultsum dengan mahar seperti yang diberikan kepada Ruqayyah dan sebagaimana kamu hidup bersamanya.\" "},"92":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِتْنَةً فَقَرَّبَهَا فَمَرَّ رَجُلٌ مُقَنَّعٌ رَأْسُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا يَوْمَئِذٍ عَلَى الْهُدَى فَوَثَبْتُ فَأَخَذْتُ بِضَبْعَيْ عُثْمَانَ ثُمَّ اسْتَقْبَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ هَذَا قَالَ هَذَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Ka'ab bin Ujrah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyebutkan fitnah dan mengisyaratkan semakin dekat kedatangannya. Lalu lewatlah seorang lelaki yang memakai caping, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Orang ini suatu hari nanti akan berada di atas petunjuk.\" Maka aku melompat dan menarik kedua lengan Utsman dan kembali menghadap Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Orang ini! \" beliau bersabda: \"Orang ini.\" "},"93":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْفَرَجُ بْنُ فَضَالَةَ عَنْ رَبِيعَةَ بْنِ يَزِيدَ الدِّمَشْقِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُثْمَانُ إِنْ وَلَّاكَ اللَّهُ هَذَا الْأَمْرَ يَوْمًا فَأَرَادَكَ الْمُنَافِقُونَ أَنْ تَخْلَعَ قَمِيصَكَ الَّذِي قَمَّصَكَ اللَّهُ فَلَا تَخْلَعْهُ يَقُولُ ذَلِكَ ثَلَاثَ مَرَّاتٍقَالَ النُّعْمَانُ فَقُلْتُ لِعَائِشَةَ مَا مَنَعَكِ أَنْ تُعْلِمِي النَّاسَ بِهَذَا قَالَتْ أُنْسِيتُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al Faraj bin Fadlalah] dari [Rabi'ah bin Yazid Ad Dimasyqi] dari [An Nu'man bin Basyir] dari [Aisyah] ia menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Utsman, jika pada suatu hari nanti Allah menguasakanmu atas perkara ini, lalu orang-orang munafik ingin agar engkau melepaskan jubah yang Allah telah memakaikannya untukmu, maka janganlah engkau lakukan.\" Beliau ulangi hal itu hingga tiga kali.\" An Nu'man berkata; Aku bertanya kepada Aisyah; \"Apa yang menyebabkanmu tidak memberitahukan kepada orang-orang seputar masalah ini?\" Aisyah berkata; \"Aku dijadikan lupa kepadanya.\" "},"94":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ وَدِدْتُ أَنَّ عِنْدِي بَعْضَ أَصْحَابِي قُلْنَا يَا رَسُولَ اللَّهِ أَلَا نَدْعُو لَكَ أَبَا بَكْرٍ فَسَكَتَ قُلْنَا أَلَا نَدْعُو لَكَ عُمَرَ فَسَكَتَ قُلْنَا أَلَا نَدْعُو لَكَ عُثْمَانَ قَالَ نَعَمْ فَجَاءَ فَخَلَا بِهِ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمُهُ وَوَجْهُ عُثْمَانَ يَتَغَيَّرُقَالَ قَيْسٌ فَحَدَّثَنِي أَبُو سَهْلَةَ مَوْلَى عُثْمَانَ أَنَّ عُثْمَانَ بْنَ عَفَّانَ قَالَ يَوْمَ الدَّارِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا فَأَنَا صَائِرٌ إِلَيْهِ وَقَالَ عَلِيٌّ فِي حَدِيثِهِ وَأَنَا صَابِرٌ عَلَيْهِ قَالَ قَيْسٌ فَكَانُوا يُرَوْنَهُ ذَلِكَ الْيَوْمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Aisyah] ia menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda diwaktu sakitnya: \"Ingin rasanya jika sebagian sahabatku ada di sisiku.\" Kami lalu bertanya; \"Ya Rasulullah, apakah perlu kami memanggil Abu Bakar untukmu?\" Beliau terdiam. Kami bertanya lagi; \"Apakah perlu kami memanggil Umar untukmu?\" Beliau masih terdiam. Kami lalu bertanya lagi; \"Apakah perlu kami memanggil Utsman untukmu?\" Beliau menjawab: \"Ya.\" Lalu Utsman pun datang dan menyendiri dengannya. Kemudian Nabi shallallahu 'alaihi wasallam berbicara kepadanya, hingga wajah Utsman berubah.\" Qais berkata; \"Telah menceritakan kepadaku [Abu Sahlah] mantan budak Utsman, [Utsman bin 'Affan] berkata di hari pengepungan rumahnya; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menjanjikan kepadaku sebuah janji dan aku akan tetap memegang janji itu.\" Dan Ali menyebutkan dalam haditsnya; \"Aku akan bersabar di atasnya\". Qais berkata; \"Maka mereka membunuhnya pada hari itu.\""},"95":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ وعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَعَهِدَ إِلَيَّ النَّبِيُّ الْأُمِّيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَا يُحِبُّنِي إِلَّا مُؤْمِنٌ وَلَا يُبْغِضُنِي إِلَّا مُنَافِقٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dan [Abdullah bin Numair] dari [Al A'masy] dari [Adi bin Tsabit] dari [Zirri bin Hubaisy] dari [Ali radliallahu 'anhu] ia berkata; \"Nabi shallallahu 'alaihi wasallam, al ummi (seorang yang buta aksara) memberikan janji kepadaku, bahwasanya tidak akan mencintaiku kecuali orang beriman dan tidak akan membenciku kecuali orang munafik.\""},"96":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَمِعْتُ إِبْرَاهِيمَ بْنَ سَعْدِ بْنِ أَبِي وَقَّاصٍ يُحَدِّثُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لِعَلِيٍّ أَلَا تَرْضَى أَنْ تَكُونَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] ia berkata; aku mendengar [Ibrahim bin Sa'id bin Abu Waqqash] menceritakan dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda kepada Ali: \"Apakah kamu tidak ridla, jika kedudukanmu di sisiku sebagaimana kedudukan Harun di sisi Musa.\" "},"97":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ أَخْبَرَنِي حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّتِهِ الَّتِي حَجَّ فَنَزَلَ فِي بَعْضِ الطَّرِيقِ فَأَمَرَ الصَّلَاةَ جَامِعَةً فَأَخَذَ بِيَدِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَلَسْتُ أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ قَالُوا بَلَى قَالَ أَلَسْتُ أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ قَالُوا بَلَى قَالَ فَهَذَا وَلِيُّ مَنْ أَنَا مَوْلَاهُ اللَّهُمَّ وَالِ مَنْ وَالَاهُ اللَّهُمَّ عَادِ مَنْ عَادَاهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abul Husain] berkata, telah mengabarkan kepadaku [Hammad bin Salamah] dari [Ali bin Zaid bin Jud'an] dari [Adi bin Tsabit] dari [Barra` bin 'Azib] ia menuturkan, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam berangkat haji diwaktu beliau melakukan haji. Lalu beliau singgah di tengah perjalanan, beliau lalu memerintahkan shalat berjama'ah. Kemudian beliau memegang tangan Ali radliallahu 'anhu dan bersabda: \"Bukankah aku lebih utama bagi kaum mukmin dari pada jiwa-jiwa mereka?\" Para sahabat menjawab; \"Benar.\" Beliau melanjutkan kembali: \"Bukankah aku lebih utama bagi seorang mukmin dari pada dirinya? Mereka menjawab; \"Benar\". Beliau bersabda: \"Maka ini (Ali) merupakan wali bagi orang yang menjadikan aku sebagai walinya. Ya Allah, tolonglah orang yang mencintainya. Ya Allah, musuhilah orang yang memusuhinya.\""},"98":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى حَدَّثَنَا الْحَكَمُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَكَانَ أَبُو لَيْلَى يَسْمُرُ مَعَ عَلِيٍّ فَكَانَ يَلْبَسُ ثِيَابَ الصَّيْفِ فِي الشِّتَاءِ وَثِيَابَ الشِّتَاءِ فِي الصَّيْفِ فَقُلْنَا لَوْ سَأَلْتَهُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَيَّ وَأَنَا أَرْمَدُ الْعَيْنِ يَوْمَ خَيْبَرَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَرْمَدُ الْعَيْنِ فَتَفَلَ فِي عَيْنِي ثُمَّ قَالَ اللَّهُمَّ أَذْهِبْ عَنْهُ الْحَرَّ وَالْبَرْدَ قَالَ فَمَا وَجَدْتُ حَرًّا وَلَا بَرْدًا بَعْدَ يَوْمِئِذٍ وَقَالَ لَأَبْعَثَنَّ رَجُلًا يُحِبُّ اللَّهَ وَرَسُولَهُ وَيُحِبُّهُ اللَّهُ وَرَسُولُهُ لَيْسَ بِفَرَّارٍ فَتَشَرَّفَ لَهُ النَّاسُ فَبَعَثَ إِلَى عَلِيٍّ فَأَعْطَاهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ibnu Abu Laila] berkata, telah menceritakan kepada kami [Al Hakam] dari [Abdurrahman bin Abu Laila] ia berkata; \"Abu Laila berbincang-bincang dengan [Ali]. Dan Ali biasa memakai baju musim panas di saat musim dingin dan memakai baju musim dingin di saat musim panas. Maka kami bergumam; \"Mari kita bertanya kepadanya.\" Dia menjawab; \"Pada saat perang Khaibar, Rasulullah shallallahu 'alaihi wasallam mengutusku, sementara aku sedang sakit mata. Aku berkata kepada Rasulullah; \"Ya Rasulullah, sesungguhnya aku sedang sakit mata. Maka Rasulullah shallallahu 'alaihi wasallam pun meniup mataku seraya berdoa: \"Ya Allah, jauhkan darinya panas dan dingin.\" Ali berkata; \"Maka aku tidak mengalami panas dan juga dingin semenjak hari itu.\" Dan beliau bersabda: \"Sungguh, aku akan mengutus seorang yang mencintai Allah dan Rasul-Nya, serta bukan seorang yang penakut.\" Maka orang-orang berdesakan untuk mendapatkannya namun Rasul mengutus serta memberikan bendera kepadanya.\""},"99":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْوَاسِطِيُّ حَدَّثَنَا الْمُعَلَّى بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَسَنُ وَالْحُسَيْنُ سَيِّدَا شَبَابِ أَهْلِ الْجَنَّةِ وَأَبُوهُمَا خَيْرٌ مِنْهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Wasithi] berkata, telah menceritakan kepada kami [Al Mu'alla bin Abdurrahman] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hasan dan Husain adalah dua pemimpin para pemuda penghuni surga. Dan ayah keduanya lebih baik dari keduanya.\""},"100":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسُوَيْدُ بْنُ سَعِيدٍ وَإِسْمَعِيلُ بْنُ مُوسَى قَالُوا حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ حُبْشِيِّ بْنِ جُنَادَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلِيٌّ مِنِّي وَأَنَا مِنْهُ وَلَا يُؤَدِّي عَنِّي إِلَّا عَلِيٌّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Suwaid bin Sa'id] dan [Isma'il bin Musa] mereka berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Hubsyi bin Junadah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ali adalah bagian dariku dan aku adalah bagian dari Ali. Dan tidak ada yang menunaikan kewajibanku kecuali Ali.\""},"101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ الرَّازِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا الْعَلَاءُ بْنُ صَالِحٍ عَنْ الْمِنْهَالِ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ عَلِيٌّ أَنَا عَبْدُ اللَّهِ وَأَخُو رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا الصِّدِّيقُ الْأَكْبَرُ لَا يَقُولُهَا بَعْدِي إِلَّا كَذَّابٌ صَلَّيْتُ قَبْلَ النَّاسِ بِسَبْعِ سِنِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il Ar Razi] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah memberitakan kepada kami ['Ala` bin Shalih] dari [Minhal] dari ['Abbad bin Abdullah] ia berkata; [Ali] berkata; \"Aku adalah hamba Allah dan saudara Rasulullah shallallahu 'alaihi wasallam, dan aku adalah Ash Shiddiq Al Akbar, tidak ada yang mengucapkannya setelahku kecuali seorang pendusta. Aku telah menegakkan shalat sebelum orang-orang, selama tujuh tahun.\""},"102":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا مُوسَى بْنُ مُسْلِمٍ عَنْ ابْنِ سَابِطٍ وَهُوَ عَبْدُ الرَّحْمَنِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقَدِمَ مُعَاوِيَةُ فِي بَعْضِ حَجَّاتِهِ فَدَخَلَ عَلَيْهِ سَعْدٌ فَذَكَرُوا عَلِيًّا فَنَالَ مِنْهُ فَغَضِبَ سَعْدٌ وَقَالَ تَقُولُ هَذَا لِرَجُلٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كُنْتُ مَوْلَاهُ فَعَلِيٌّ مَوْلَاهُ وَسَمِعْتُهُ يَقُولُ أَنْتَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى إِلَّا أَنَّهُ لَا نَبِيَّ بَعْدِي وَسَمِعْتُهُ يَقُولُ لَأُعْطِيَنَّ الرَّايَةَ الْيَوْمَ رَجُلًا يُحِبُّ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Musa bin Muslim] dari [Ibnu Sabith] -yaitu Abdurrahman- dari [Sa'd bin Abu Waqqash] ia menuturkan; Mu'awiyah tiba dari sebagian pelaksanaan ibadah hajinya, lalu masuklah Sa'd menemuinya, mereka memperbincangkan Ali dan menggunjingnya. Maka marahlah Sa'd seraya berkata: \"Kamu katakan ini kepada seorang lelaki yang aku sendiri mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjadikan aku sebagai walinya, maka Ali (juga) walinya.\" Dan aku mendengarnya bersabda: \"Kedudukanmu di sisiku sebagaimana kedudukan Harun di sisi Musa. Hanya saja tidak ada Nabi setelahku.\" Dan aku mendengarnya bersabda: \"Sungguh aku akan memberikan bendera pada hari ini kepada seorang lelaki yang mencintai Allah dan Rasul-Nya.\""},"103":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ مَنْ يَأْتِينَا بِخَبَرِ الْقَوْمِ فَقَالَ الزُّبَيْرُ أَنَا فَقَالَ مَنْ يَأْتِينَا بِخَبَرِ الْقَوْمِ فَقَالَ الزُّبَيْرُ أَنَا ثَلَاثًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ نَبِيٍّ حَوَارِيٌّ وَإِنَّ حَوَارِيَّ الزُّبَيْرُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; \"Pada hari perang Quraizhah Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bisa membawakan berita kepada kami tentang kaum itu?\" Zubair berkata; \"Saya.\" Beliau berseru kembali: \"Siapa yang bisa membawakan berita kepada kami tentang kaum itu?\" Zubair berkata; \"Aku, \" ia ulangi hingga tiga kali. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap Nabi memiliki Hawari (penolong setia), dan Zubair adalah hawariku.\""},"104":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ الزُّبَيْرِ قَالَلَقَدْ جَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Abdullah bin Zubair] dari [Zubair] ia berkata; \"Dalam perang Uhud Rasulullah shallallahu 'alaihi wasallam mengumpulkan kedua orang tuanya untukku.\""},"105":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَهَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ قَالَتْ عَائِشُةُيَا عُرْوَةُ كَانَ أَبَوَاكَ مِنْ الَّذِينَ اسْتَجَابُوا لِلَّهِ وَالرَّسُولِ مِنْ بَعْدِ مَا أَصَابَهُمْ الْقَرْحُ أَبُو بَكْرٍ وَالزُّبَيْرُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Hadiyah bin Abdul Wahhab] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin Urwah] dari [Bapaknya] ia berkata; [Aisyah] berkata; \"Wahai Urwah, kedua orang tuamu termasuk orang yang menjawab seruan Allah dan Rasul setelah tertimpa luka; yaitu Abu Bakar dan Zubair.\""},"106":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ الْأَوْدِيُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الصَّلْتُ الْأَزْدِيُّ حَدَّثَنَا أَبُو نَضْرَةَ عَنْ جَابِرٍأَنَّ طَلْحَةَ مَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَهِيدٌ يَمْشِي عَلَى وَجْهِ الْأَرْضِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Aِِِmru bin Abdullah Al Audi] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ash Shalt Al 'Azdi] berkata, telah menceritakan kepada kami [Abu Nadlrah] dari [Jabir] berkata; \"Thalhah berpapasan dengan Nabi shallallahu 'alaihi wasallam, lalu beliau pun bersabda: \"Seorang syahid sedang berjalan di atas permukaan bumi.\""},"107":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنِي إِسْحَقُ بْنُ يَحْيَى بْنِ طَلْحَةَ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ قَالَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى طَلْحَةَ فَقَالَ هَذَا مِمَّنْ قَضَى نَحْبَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar] berkata, telah menceritakan kepada kami ['Amru bin Utsman] berkata, telah menceritakan kepada kami [Zuhair bin Mu'awiyah] berkata, telah menceritakan kepadaku [Ishaq bin Yahya bin Thalhah] dari [Musa bin Thalhah] dari [Mu'awiyah bin Abu Sufyan] ia berkata; Nabi shallallahu 'alaihi wasallam melihat Thalhah dan bersabda: \"Ia termasuk orang-orang yang akan gugur.\""},"108":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا إِسْحَقُ عَنْ مُوسَى بْنِ طَلْحَةَ قَالَكُنَّا عِنْدَ مُعَاوِيَةَ فَقَالَ أَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ طَلْحَةُ مِمَّنْ قَضَى نَحْبَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Ishaq] dari [Musa bin Thalhah] ia berkata; Ketika kami sedang bersama [Mu'awiyah], ia lalu berkata; Aku bersaksi bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Thalhah termasuk dari orang yang akan gugur.\""},"109":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ عَن�� قَيْسٍ قَالَرَأَيْتُ يَدَ طَلْحَةَ شَلَّاءَ وَقَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Isma'il] dari [Qais] ia berkata; \"Aku melihat tangan [Thalhah] lumpuh karena ia gunakan untuk melindungi Rasulullah shallallahu 'alaihi wasallam pada perang Uhud.\""},"110":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ أَبَوَيْهِ لِأَحَدٍ غَيْرَ سَعْدِ بْنِ مَالِكٍ فَإِنَّهُ قَالَ لَهُ يَوْمَ أُحُدٍ ارْمِ سَعْدُ فِدَاكَ أَبِي وَأُمِّي","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Abdullah bin Syaddad] dari [Ali Radiallahu 'anhu] ia berkata; \"Aku tidak melihat Rasulullah shallallahu 'alaihi wasallam mengumpulkan kedua orang tuanya (bersumpah) untuk seseorang selain Sa'd bin Malik. Pada perang Uhud beliau bersabda kepadanya: \"Lemparlah wahai Sa'd! ayah dan ibuku sebagai tebusanmu.\" "},"111":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ وَإِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُلَقَدْ جَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ أَبَوَيْهِ فَقَالَ ارْمِ سَعْدُ فِدَاكَ أَبِي وَأُمِّي","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Laits bin Sa'd]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dan [Isma'il bin 'Ayyasy] dari [Yahya bin Sa'id] dari [Sa'id Ibnul Musayyab] ia berkata; Aku mendengar [Sa'd bin Abu Waqqash] berkata; \"Pada perang Uhud Rasulullah shallallahu 'alaihi wasallam mengumpulkan kedua orang tuanya (bersumpah) untukku, beliau bersabda: \"Lemparlah wahai Sa'd, ayah dan ibuku sebagai tebusanmu.\" "},"112":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَخَالِي يَعْلَى وَوَكِيعٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ قَالَ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُإِنِّي لَأَوَّلُ الْعَرَبِ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dan pamanku [Ya'la] dan [Waki'] dari [Isma'il] dari [Qais] ia berkata; Aku mendengar [Sa'd bin Abu Waqqash] berkata; \"Sungguh, aku adalah orang arab pertama kali yang membidikkan panah di jalan Allah.\" "},"113":{"ar":"حَدَّثَنَا مَسْرُوقُ بْنُ الْمَرْزُبَانِ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ هَاشِمِ بْنِ هَاشِمٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولَ قَالَ سَعْدُ بْنُ أَبِي ��َقَّاصٍمَا أَسْلَمَ أَحَدٌ فِي الْيَوْمِ الَّذِي أَسْلَمْتُ فِيهِ وَلَقَدْ مَكَثْتُ سَبْعَةَ أَيَّامٍ وَإِنِّي لَثُلُثُ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Masruq bin Al Marzuban] berkata, telah menceritakan kepada kami [Yahya bin Abu Za`idah] dari [Hasyim bin Hasyim] ia berkata; Aku mendengar [Sa'id Ibnul Musayyab] berkata; [Sa'd bin Abu Waqqash] berkata: \"Tidak ada seorang pun yang masuk Islam di hari keIslamanku, dan aku telah tinggal selama tujuh hari, dan aku adalah orang sepertiga Islam.\""},"114":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا صَدَقَةُ بْنُ الْمُثَنَّى أَبُو الْمُثَنَّى النَّخَعِيُّ عَنْ جَدِّهِ رِيَاحِ بْنِ الْحَارِثِ سَمِعَ سَعِيدَ بْنَ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَاشِرَ عَشَرَةٍ فَقَالَ أَبُو بَكْرٍ فِي الْجَنَّةِ وَعُمَرُ فِي الْجَنَّةِ وَعُثْمَانُ فِي الْجَنَّةِ وَعَلِيٌّ فِي الْجَنَّةِ وَطَلْحَةُ فِي الْجَنَّةِ وَالزُّبَيْرُ فِي الْجَنَّةِ وَسَعْدٌ فِي الْجَنَّةِ وَعَبْدُ الرَّحْمَنِ فِي الْجَنَّةِ فَقِيلَ لَهُ مَنْ التَّاسِعُ قَالَ أَنَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Shadaqah bin Mutsanna Abul Mutsanna An Nakha'i] dari kakeknya [Riyah bin Ibnul Harits] ia mendengar [Sa'id bin Zaid bin 'Amru bin Nufail] berkata; Rasulullah shallallahu 'alaihi wasallam adalah kesepuluh dari sepuluh orang.\" Sa'id berkata; \"Abu Bakar di surga, Umar di surga, Utsman di surga, Ali di surga, Thalhah di surga, Zubair di surga, Sa'd di surga dan Abdurrahman di surga.\" Lalu dikatakan kepadanya, \"Siapa yang kesembilan?\" ia menjawab: \"Saya.\""},"115":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عَبْدِ اللَّهِ بْنِ ظَالِمٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي سَمِعْتُهُ يَقُولُ اثْبُتْ حِرَاءُ فَمَا عَلَيْكَ إِلَّا نَبِيٌّ أَوْ صِدِّيقٌ أَوْ شَهِيدٌ وَعَدَّهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَطَلْحَةُ وَالزُّبَيْرُ وَسَعْدٌ وَابْنُ عَوْفٍ وَسَعِيدُ بْنُ زَيْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Hushain] dari [Hilal bin Yasaf] dari [Abdullah bin Zhalim] dari [Sa'id bin Zaid] ia berkata; Aku bersaksi atas Rasulullah shallallahu 'alaihi wasallam bahwa aku mendengarnya bersabda: \"Hai Hira`, diamlah kamu!, Karena di atasmu ada seorang Nabi atau shiddiq (orang yang jujur) atau syahid (orang yang syahid).\" Kemudian Rasulullah shallallahu 'alaihi wasallam menyebutkan mereka: \"Abu Bakar, Umar, Utsman, Ali, Thalhah, Zubair, Sa'd, Ibnu 'Auf dan Sa'id bin Zaid.\""},"116":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ جَمِيعًا عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَهْلِ نَجْرَانَ سَأَبْعَثُ مَعَكُمْ رَجُلًا أَمِينًا حَقَّ أَمِينٍ قَالَ فَتَشَرَّفَ لَهُ النَّاسُ فَبَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] semuanya dari [Abu Ishaq] dari [Shilah bin Zufar] dari [Hudzaifah]; Rasulullah shallallahu 'alaihi wasallam bersabda kepada penduduk Najran: \"Aku akan mengutus bersama kalian seorang laki-laki yang benar-benar bisa dipercaya.\" Hudzaifah berkata: \"maka orang-orang mengharap dirinya yang dipilih, tetapi beliau mengutus Abu Ubaidah bin Al Jarrah.\""},"117":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ هَذَا أَمِينُ هَذِهِ الْأُمَّةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Shilah bin Zufar] dari [Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda yang diperuntukkan kepada Abu Ubaidah bin Al Jarrah: \"orang ini adalah orang kepercayaan umat ini.\""},"118":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ مُسْتَخْلِفًا أَحَدًا عَنْ غَيْرِ مَشُورَةٍ لَاسْتَخْلَفْتُ ابْنَ أُمِّ عَبْدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya aku (berkenan) memilih seorang pengganti tanpa musyawarah, niscaya aku akan memilih Ibnu Ummi 'Abd.\""},"119":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ أَبَا بَكْرٍ وَعُمَرَ بَشَّرَاهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ أَنْ يَقْرَأَ الْقُرْآنَ غَضًّا كَمَا أُنْزِلَ فَلْيَقْرَأْهُ عَلَى قِرَاءَةِ ابْنِ أُمِّ عَبْدٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari ['Ashim] dari [Zirr] dari [Abdullah bin Mas'ud]; bahwa [Abu Bakar] dan [Umar] memberikan kabar gembira kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa senang membaca Al Qu`ran dengan benar sebagaimana ketika diturunkan, maka hendaklah ia membaca berdasarkan bacaan Ibnu Ummi 'Abd.\""},"120":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْنُكَ عَلَيَّ أَنْ تَرْفَعَ الْحِجَابَ وَأَنْ تَسْمَعَ سِوَادِي حَتَّى أَنْهَاكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Al Hasan bin Ubaidullah] dari [Ibrahim bin Suwaid] dari [Abdurrahman bin Yazid] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Semoga kamu mengizinkan aku hingga engkau membuka tiraimu dan mendengarkan petuahku hingga selesai.\" "},"121":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سَبْرَةَ النَّخَعِيِّ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَكُنَّا نَلْقَى النَّفَرَ مِنْ قُرَيْشٍ وَهُمْ يَتَحَدَّثُونَ فَيَقْطَعُونَ حَدِيثَهُمْ فَذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أَقْوَامٍ يَتَحَدَّثُونَ فَإِذَا رَأَوْا الرَّجُلَ مِنْ أَهْلِ بَيْتِي قَطَعُوا حَدِيثَهُمْ وَاللَّهِ لَا يَدْخُلُ قَلْبَ رَجُلٍ الْإِيمَانُ حَتَّى يُحِبَّهُمْ لِلَّهِ وَلِقَرَابَتِهِمْ مِنِّي","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sabrah An Nakha'i] dari [Muhammad bin Ka'ab Al Qurazhi] dari [Al Abbas bin Abdul Muththalib] ia berkata; \"Kami menjumpai sekelompok orang dari kaum Quraisy sedang berbincang-bincang, tiba-tiba mereka memutus perbincangan mereka (dengan kedatangan kami). Kejadian tersebut kami sampaikan kepada Nabi shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Ada apa dengan kaum itu, mereka berbincang-bincang, namun ketika mereka melihat seorang laki-laki dari ahli baitku mereka menghentikan pembicaraannya. Demi Allah, iman tidak akan masuk ke dalam hati seorang laki-laki hingga ia mencintai mereka karena Allah dan karena kedekatan mereka terhadapku.\" "},"122":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ صَفْوَانَ بْنِ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ اتَّخَذَنِي خَلِيلًا كَمَا اتَّخَذَ إِبْرَاهِيمَ خَلِيلًا فَمَنْزِلِي وَمَنْزِلُ إِبْرَاهِيمَ فِي الْجَنَّةِ يَوْمَ الْقِيَامَةِ تُجَاهَيْنِ وَالْعَبَّاسُ بَيْنَنَا مُؤْمِنٌ بَيْنَ خَلِيلَيْنِ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Adl Dlahhak] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Shafwan bin 'Amru] dari [Abdurrahman bin Jubair bin Nufair] dari [Katsir bin Murrah Al Hadlrami] dari [Abdullah bin 'Amru] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menjadikan diriku sebagai kekasih-Nya sebagaimana Ia menjadikan Ibrahim kekasih. Tempat tinggalku dan tempat tinggal Ibrahim di surga pada hari kiamat kelak saling berhadap-hadapan. Sementara Al Abbas berada di antara kami, dua kekasih Allah, adalah seorang mukmin.\""},"123":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْحَسَنِ اللَّهُمَّ إِنِّي أُحِبُّهُ فَأَحِبَّهُ وَأَحِبَّ مَنْ يُحِبُّهُ قَالَ وَضَمَّهُ إِلَى صَدْرِهِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah bin Abu Yazid] dari [Nafi' bin Jubair] dari [Abu Hurairah] Nabi shallallahu 'alaihi wasallam, beliau bersabda untuk Al Hasan: \"Ya Allah, sesungguhnya aku mencintainya maka cintailah dia dan cintai orang yang mencintainya.\" Abu Hurairah berkata; \"Beliau lalu mendekapnya ke dalam dadanya."},"124":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ دَاوُدَ بْنِ أَبِي عَوْفٍ أَبِي الْجَحَّافِ وَكَانَ مَرْضِيًّا عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ الْحَسَنَ وَالْحُسَيْنَ فَقَدْ أَحَبَّنِي وَمَنْ أَبْغَضَهُمَا فَقَدْ أَبْغَضَنِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Dawud bin Abu 'Auf Abul Jahhaf] - ia orang yang diridlai- dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mencintai Hasan dan Husain maka ia telah mencintaiku, dan barangsiapa membenci keduanya maka ia telah membenciku.\""},"125":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي رَاشِدٍ أَنَّ يَعْلَى بْنَ مُرَّةَ حَدَّثَهُمْأَنَّهُمْ خَرَجُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى طَعَامٍ دُعُوا لَهُ فَإِذَا حُسَيْنٌ يَلْعَبُ فِي السِّكَّةِ قَالَ فَتَقَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَامَ الْقَوْمِ وَبَسَطَ يَدَيْهِ فَجَعَلَ الْغُلَامُ يَفِرُّ هَا هُنَا وَهَا هُنَا وَيُضَاحِكُهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَخَذَهُ فَجَعَلَ إِحْدَى يَدَيْهِ تَحْتَ ذَقْنِهِ وَالْأُخْرَى فِي فَأْسِ رَأْسِهِ فَقَبَّلَهُ وَقَالَ حُسَيْنٌ مِنِّي وَأَنَا مِنْ حُسَيْنٍ أَحَبَّ اللَّهُ مَنْ أَحَبَّ حُسَيْنًا حُسَيْنٌ سِبْطٌ مِنْ الْأَسْبَاطِحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Yahya bin Sulaim] dari [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Abu Rasyid] bahwa [Ya'la bin Murrah] menceritakan kepada mereka, bahwasanya mereka keluar bersama Rasulullah shallallahu 'alaihi wasallam memenuhi jamuan makan. Tiba-tiba Husain sedang bermain-main di jalan. Ya'la berkata; \"Nabi shallallahu 'alaihi wasallam lalu maju mendahului para sahabat sambil membentangkan kedua tangannya. Lalu Husain berlarian kesana-kemari dan Nabi shallallahu 'alaihi wasallam mentertawakannya, hingga akhirnya beliau menggendongnya dan meletakkan salah satu tangannya di bawah janggutnya dan yang lainnya di atas kepala. Kemudian beliau menciumnya seraya bersabda: \"Husain adalah bagian dariku dan aku bagian darinya. Allah akan mencintai orang yang mencintai Husain. Husain umat dari beberapa umat.\" Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepadaku [Waki'] dari [Sufyan] seperti hadits di atas."},"126":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَعَلِيُّ بْنُ الْمُنْذِرِ قَالَا حَدَّثَنَا أَبُو غَسَّانَ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ عَنْ السُّدِّيِّ عَنْ صُبَيْحٍ مَوْلَى أُمِّ سَلَمَةَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلِيٍّ وَفَاطِمَةَ وَالْحَسَنِ وَالْحُسَيْنِ أَنَا سِلْمٌ لِمَنْ سَالَمْتُمْ وَحَرْبٌ لِمَنْ حَارَبْتُمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al-Khallal] dan [Ali Ibnul Mundzir] keduanya berkata; telah menceritakan kepada kami [Abu Ghassan] berkata, telah menceritakan kepada kami [Asbath bin Nashr] dari [As Suddi] dari [Shubaih] mantan budak Ummu Salamah dari [Zaid bin Arqam] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ali, Fathimah, Hasan dan Husain: \"Aku akan mengadakan perdamaian kepada orang yang damai dengan kalian, dan akan memerangi orang yang kalian perangi.\""},"127":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ هَانِئِ بْنِ هَانِئٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَ عَمَّارُ بْنُ يَاسِرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْذَنُوا لَهُ مَرْحَبًا بِالطَّيِّبِ الْمُطَيَّبِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Hani` bin Hani`] dari [Ali bin Abu Thalib] ia berkata; \"Ketika aku duduk di samping Nabi shallallahu 'alaihi wasallam 'Ammar bin Yasir meminta izin (untuk bergabung duduk), maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Izinkanlah dia, selamat datang kepada orang yang baik lagi berlaku baik.\" "},"128":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَثَّامُ بْنُ عَلِيٍّ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ هَانِئِ بْنِ هَانِيءٍ قَالَدَخَلَ عَمَّارٌ عَلَى عَلِيٍّ فَقَالَ مَرْحَبًا بِالطَّيِّبِ الْمُطَيَّبِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مُلِئَ عَمَّارٌ إِيمَانًا إِلَى مُشَاشِهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami ['Atstsam bin Ali] dari [Al A'masy] dari [Abu Ishaq] dari [Hani` bin Hani`] ia berkata; \"'Ammar masuk menemui Ali. Maka [Ali] pun berkata: \"Selamat datang kepada orang yang baik lagi yang berlaku baik. Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, 'Ammar telah dipenuhi keimanan hingga ke relung jiwanya.\" "},"129":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا جَمِيعًا حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ سِيَاهٍ عَنْ حَبيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّارٌ مَا عُرِضَ عَلَيْهِ أَمْرَانِ إِلَّا اخْتَارَ الْأَرْشَدَ مِنْهُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Abdul Aziz bin Siyah] dari [Habib bin Abi Tsabit] dari ['Atho` bin Yasar] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dua perkara diajukan kepada 'Ammar melainkan dia akan memilih yang paling lurus.\" "},"130":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا شَرِيكٌ عَنْ أَبِي رَبِيعَةَ الْإِيَادِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ أَمَرَنِي بِحُبِّ أَرْبَعَةٍ وَأَخْبَرَنِي أَنَّهُ يُحِبُّهُمْ قِيلَ يَا رَسُولَ اللَّهِ مَنْ هُمْ قَالَ عَلِيٌّ مِنْهُمْ يَقُولُ ذَلِكَ ثَلَاثًا وَأَبُو ذَرٍّ وَسَلْمَانُ وَالْمِقْدَادُ","id":"Telah menceritakan kepada kami [Ismail bin Musa] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Syarik] dari [Abu Rabi'ah Al Iyadi] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah memerintahkanku agar mencintai empat orang dan mengabarkan kepadaku bahwa Dia juga mencintai mereka.\" beliau ditanya; \"Wahai Rasulullah, siapakah mereka itu?\" beliau menjawab: \"Ali adalah salah satu dari mereka -beliau ucapkan hal itu hingga tiga kali- kemudian Abu Dzar, Salman dan Miqdad.\""},"131":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ أَوَّلَ مَنْ أَظْهَرَ إِسْلَامَهُ سَبْعَةٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعَمَّارٌ وَأُمُّهُ سُمَيَّةُ وَصُهَيْبٌ وَبِلَالٌ وَالْمِقْدَادُ فَأَمَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنَعَهُ اللَّهُ بِعَمِّهِ أَبِي طَالِبٍ وَأَمَّا أَبُو بَكْرٍ فَمَنَعَهُ اللَّهُ بِقَوْمِهِ وَأَمَّا سَائِرُهُمْ فَأَخَذَهُمْ الْمُشْرِكُونَ وَأَلْبَسُوهُمْ أَدْرَاعَ الْحَدِيدِ وَصَهَرُوهُمْ فِي الشَّمْسِ فَمَا مِنْهُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ وَاتَاهُمْ عَلَى مَا أَرَادُوا إِلَّا بِلَالًا فَإِنَّهُ هَانَتْ عَلَيْهِ نَفْسُهُ فِي اللَّهِ وَهَانَ عَلَى قَوْمِهِ فَأَخَذُوهُ فَأَعْطَوْهُ الْوِلْدَانَ فَجَعَلُوا يَطُوفُونَ بِهِ فِي شِعَابِ مَكَّةَ وَهُوَ يَقُولُ أَحَدٌ أَحَدٌ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Za`idah bin Qudamah] dari ['Ashim bin Abu Najud] dari [Zirr bin Hubaisy] dari [Abdullah bin Mas'ud] ia berkata; \"Yang pertama kali menampakkan keIslamannya ada tujuh orang; Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, 'Ammar dan Ibunya Sumayyah, Shuhaib, Bilal dan Al Miqdad. Adapun Rasulullah shallallahu 'alaihi wasallam, Allah melindunginya dengan perantara pamannya. Abu Bakar Allah melindunginya dengan perantara kaumnya. Sedang yang lainnya, kaum musyrik telah menyiksanya, memakaikan baju dari besi dan meletakkan mereka di bawah terik matahari. Tidaklah salah seorang dari mereka melainkan telah memenuhi apa yang mereka inginkan. Kecuali Bilal, dirinya dihinakan oleh kaumnya karena Allah, mereka membawa dan memberikannya kepada anak-anak. Sehingga mereka membawanya berkeliling di sepanjang jalan-jalan Makah, sementara dirinya tetap mengatakan; \"Ahad Ahad.\""},"132":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ أُوذِيتُ فِي اللَّهِ وَمَا يُؤْذَى أَحَدٌ وَلَقَدْ أُخِفْتُ فِي اللَّهِ وَمَا يُخَافُ أَحَدٌ وَلَقَدْ أَتَتْ عَلَيَّ ثَالِثَةٌ وَمَا لِي وَلِبِلَالٍ طَعَامٌ يَأْكُلُهُ ذُو كَبِدٍ إِلَّا مَا وَارَى إِبِطُ بِلَالٍ","id":"Telah menceritakan kepada kami [Ali bin Muhamad] berkata, telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah disakiti di jalan Allah ketika tidak ada seorang pun yang disakiti. Aku telah dicekam rasa takut di jalan Allah tatkala tidak ada seorangpun yang merasa ditakut-takuti. Dan telah datang kepadaku hari-hari sedang aku dan Bilal tidak mempunyai makanan yang dapat dimakan oleh sesuatu yang bernyawa kecuali sesuatu yang dapat menutupi ketiak Bilal.\""},"133":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمٍأَنَّ شَاعِرًا مَدَحَ بِلَالَ بْنَ عَبْدِ اللَّهِ فَقَالَ بِلَالُ بْنُ عَبْدِ اللَّهِ خَيْرُ بِلَالٍ فَقَالَ ابْنُ عُمَرَ كَذَبْتَ لَا بَلْ بِلَالُ رَسُولِ اللَّهِ خَيْرُ بِلَالٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Umar bin Hamzah] dari [Salim] Bahwasanya seorang penyair memuji Bilal bin Abdullah seraya bersenandung; \"Bilal bin Abdullah adalah sebaik-baik Bilal.\" Maka berserulah [Ibnu Umar], \"Kamu berdusta, tidak seperti itu! Akan tetapi Bilal Rasulullah adalah sebaik-baik Bilal.\""},"134":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي لَيْلَى الْكِنْدِيِّ قَالَجَاءَ خَبَّابٌ إِلَى عُمَرَ فَقَالَ ادْنُ فَمَا أَحَدٌ أَحَقَّ بِهَذَا الْمَجْلِسِ مِنْكَ إِلَّا عَمَّارٌ فَجَعَلَ خَبَّابٌ يُرِيهِ آثَارًا بِظَهْرِهِ مِمَّا عَذَّبَهُ الْمُشْرِكُونَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Laila Al Kindi] ia berkata; [Khabbab] datang menemui Umar, lalu Umar pun berkata; \"Mendekatlah, tidak ada seorangpun yang berhak dengan majlis ini darimu kecuali 'Ammar. Kemudian Khabbab menampakkan bekas-bekas penyiksaan kaum musyrik di punggungnya.\""},"135":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْحَمُ أُمَّتِي بِأُمَّتِي أَبُو بَكْرٍ وَأَشَدُّهُمْ فِي دِينِ اللَّهِ عُمَرُ وَأَصْدَقُهُمْ حَيَاءً عُثْمَانُ وَأَقْضَاهُمْ عَلِيُّ بْنُ أَبِي طَالِبٍ وَأَقْرَؤُهُمْ لِكِتَابِ اللَّهِ أُبَيُّ بْنُ كَعْبٍ وَأَعْلَمُهُمْ بِالْحَلَالِ وَالْحَرَامِ مُعَاذُ بْنُ جَبَلٍ وَأَفْرَضُهُمْ زَيْدُ بْنُ ثَابِتٍ أَلَا وَإِنَّ لِكُلِّ أُمَّةٍ أَمِينًا وَأَمِينُ هَذِهِ الْأُمَّةِ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ مِثْلَهُ عِنْدَ ابْنِ قُدَامَةَ غَيْرَ أَنَّهُ يَقُولُ فِي حَقِّ زَيْدٍ وَأَعْلَمُهُمْ بِالْفَرَائِضِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umatku yang paling penyayang terhadap umatku adalah Abu Bakar, yang paling tegas di antara mereka adalah Umar, yang paling benar rasa malunya adalah Utsman, yang paling tepat keputusannya adalah Ali bin Abu Thalib, yang paling bagus bacaannya terhadap kitabullah adalah Ubai bin Ka'ab, yang paling tahu terhadap perkara yang halal dan yang haram adalah Mu'adz bin Jabal, dan yang paling paham terhadap ilmu Fara'idl adalah Zaid binTsabit. Ketahuilah bahwa setiap umat itu mempunyai orang yang terpercaya, dan orang terpercaya umat ini adalah Abu Ubaidah bin Al Jarrah.\" Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] seperti hadits di atas. Hanya saja Ibnu Qudamah menyebutkan; \"bahwa Zaid adalah yang paling tahu terhadap ilmu fara'idl.\""},"136":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ عُثْمَانَ بْنِ عُمَيْرٍ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَقَلَّتْ الْغَبْرَاءُ وَلَا أَظَلَّتْ الْخَضْرَاءُ مِنْ رَجُلٍ أَصْدَقَ لَهْجَةً مِنْ أَبِي ذَرٍّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al A'masy] dari [Utsman bin Numair] dari [Abu Harb bin Abul Aswad Ad Dili] dari [Abdullah bin 'Amru] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bumi tidak akan diinjak dan langit tidak akan menaungi seorang laki-laki yang lebih benar dialeknya daripada Abu Dzar.\""},"137":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرَقَةٌ مِنْ حَرِيرٍ فَجَعَلَ الْقَوْمُ يَتَدَاوَلُونَهَا بَيْنَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَعْجَبُونَ مِنْ هَذَا فَقَالُوا لَهُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَمَنَادِيلُ سَعْدِ بْنِ مُعَاذٍ فِي الْجَنَّةِ خَيْرٌ مِنْ هَذَا","id":"Telah menceritakan kepada kami [Hannad bin Sarri] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Barra` bin 'Azib] ia berkata; Rasulullah Rasulullah shallallahu 'alaihi wasallam diberi hadiah sehelai kain sutra. Maka para sahabat pun saling berebutan untuk melihat. Rasul Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah kalian merasa tertarik dengannya?\" Mereka menjawab; \"Benar ya Rasulullah! beliau bersabda: \"Demi jiwaku yang berada dalam genggaman Tangan-Nya, sungguh sapu tangan Sa'd bin Mu'adz di surga lebih baik dari ini.\" "},"138":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اهْتَزَّ عَرْشُ الرَّحْمَنِ عَزَّ وَجَلَّ لِمَوْتِ سَعْدِ بْنِ مُعَاذٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Arsy Ar Rahman 'azza wajalla bergetar karena kematian Sa'd bin Mu'adz.\""},"139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَمَا حَجَبَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ أَسْلَمْتُ وَلَا رَآنِي إِلَّا تَبَسَّمَ فِي وَجْهِي وَلَقَدْ شَكَوْتُ إِلَيْهِ أَنِّي لَا أَثْبُتُ عَلَى الْخَيْلِ فَضَرَبَ بِيَدِهِ فِي صَدْرِي فَقَالَ اللَّهُمَّ ثَبِّتْهُ وَاجْعَلْهُ هَادِيًا مَهْدِيًّا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Ismail bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah Al Bajali] ia berkata; \"Rasulullah Rasulullah shallallahu 'alaihi wasallam tidak pernah menghalangiku semenjak aku memeluk Islam dan tidaklah dia melihatku kecuali tersenyum. Aku telah mengadukan kepadanya, bahwa aku tidak kokoh berada di atas kuda, maka beliau memukulkan tangannya ke dadaku seraya berdoa: \"Ya Allah, kokohkan dia dan jadikanlah dia petunjuk lagi pemberi petunjuk.\""},"140":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَجَاءَ جِبْرِيلُ أَوْ مَلَكٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا تَعُدُّونَ مَنْ شَهِدَ بَدْرًا فِيكُمْ قَالُوا خِيَارَنَا قَالَ كَذَلِكَ هُمْ عِنْدَنَا خِيَارُ الْمَلَائِكَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari ['Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] ia berkata; \"Jibril atau seorang malaikat datang kepada Nabi Rasulullah shallallahu 'alaihi wasallam seraya berkata: \"Bagaimana kalian memposisikan orang yang gugur di badar?\" mereka menjawab: \"Mereka adalah manusia pilihan dikalangan kami.\" Dia berkata: \"Seperti mereka juga, yang hadir dari kami adalah para malaikat pilihan.\" "},"141":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا أَصْحَابِي فَوَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنَّ أَحَدَكُمْ أَنْفَقَ مِثْلَ أُحُدٍ ذَهَبًا مَا أَدْرَكَ مُدَّ أَحَدِهِمْ وَلَا نَصِيفَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Jarir]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Kuraib], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], semuanya dari [Al A'masy] dari [Abu shalih] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencela sahabat-sahabatku. Demi Dzat yang jiwaku berada di tangan-Nya, sekiranya salah seorang dari kalian bersedekah dengan emas sebesar gunung uhud, maka ia tidak akan bisa menyamai satu mud salah seorang dari mereka, atau setengahnya.\""},"142":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ نُسَيْرِ بْنِ ذُعْلُوقٍ قَالَ كَانَ ابْنُ عُمَرَ يَقُولُلَا تَسُبُّوا أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمُقَامُ أَحَدِهِمْ سَاعَةً خَيْرٌ مِنْ عَمَلِ أَحَدِكُمْ عُمْرَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Nusair bin Dzu'luq] ia berkata; [Ibnu Umar] pernah berkata; \"Janganlah kalian mencela para sahabat Muhammad shallallahu 'alaihi wasallam, berdirinya salah seorang dari mereka sesaat (bersama Muhammad) lebih baik dari amalan salah seorang dari kalian seumur hidupnya.\" "},"143":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ الْأَنْصَارَ أَحَبَّهُ اللَّهُ وَمَنْ أَبْغَضَ الْأَنْصَارَ أَبْغَضَهُ اللَّهُقَالَ شُعْبَةُ لِعَدِيٍّ أَسَمِعْتَهُ مِنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ إِيَّايَ حَدَّثَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan ['Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki] ' dari [Syu'bah] dari [Adi bin Tsabit] dari [Barra` bin 'Azib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mencintai kaum Anshar maka Allah mencintainya, dan barangsiapa membeci kaum Anshar maka Allah membencinya.\" Syu'bah bertanya kepada Adi; \"Apakah anda mendengarnya dari Barra` bin 'Azib?\" ia menjawab; \"Hanya kepadakulah ia menceritakannya.\""},"144":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الْمُهَيْمِنِ بْنِ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَنْصَارُ شِعَارٌ وَالنَّاسُ دِثَارٌ وَلَوْ أَنَّ النَّاسَ اسْتَقْبَلُوا وَادِيًا أَوْ شِعْبًا وَاسْتَقْبَلَتْ الْأَنْصَارُ وَادِيًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ وَلَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdul Muhaimin bin Abbas bin Sahl bin Sa'd] dari [Bapaknya] dari [Kakeknya] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Anshar adalah syi'ar dan manusia adalah selimut. Sekiranya manusia menghadap suatu lembah atau bukit, sedangkan orang-orang Anshar menghadap lembah yang lain, niscaya aku akan meniti lembah kalangan Anshar. Dan sekiranya bukan karena hijrah niscaya aku dari kalangan Anshar.\""},"145":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنِي كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ الْأَنْصَارَ وَأَبْنَاءَ الْأَنْصَارِ وَأَبْنَاءَ أَبْنَاءِ الْأَنْصَارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepadaku [Katsir bin Abdullah bin 'Amru bin 'Auf] dari [Bapaknya] dari [Kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah menyayangi kaum Anshar, anak-anak Anshar dan cucu-cucu Anshar.\""},"146":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَأَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَضَمَّنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ وَقَالَ اللَّهُمَّ عَلِّمْهُ الْحِكْمَةَ وَتَأْوِيلَ الْكِتَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Abu Bakr bin Khallad Al Bahili] keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Khalid Al Hadda] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memelukku sambil berdoa: \"Ya Allah, ajarkanlah ia Al Hikmah dan ta`wil Al Kitab.\""},"147":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَبِيدَةَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَوَذَكَرَ الْخَوَارِجَ فَقَالَ فِيهِمْ رَجُلٌ مُخْدَجُ الْيَدِ أَوْ مَوْدُونُ الْيَدِ أَوْ مَثْدُونُ الْيَدِ وَلَوْلَا أَنْ تَبْطَرُوا لَحَدَّثْتُكُمْ بِمَا وَعَدَ اللَّهُ الَّذِينَ يَقْتُلُونَهُمْ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أَنْتَ سَمِعْتَهُ مِنْ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِي وَرَبِّ الْكَعْبَةِ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ismail bin Ulayyah] dari [Ayyub] dari [Muhammad bin Sirin] dari ['Abidah] dari [Ali bin Abu Thalib] ia berkata seraya menyebutkan Khawarij; \"Di antara mereka ada seorang lelaki yang tangannya cacat, atau kurus tangannya, atau pendek tangannya, sekiranya kalian tidak menyalah gunakan, niscaya aku akan menceritakan kepada kalian sesuatu yang telah Allah janjikan kepada orang-orang yang membunuh mereka melalui lisan Muhammad shallallahu 'alaihi wasallam.\" Aku bertanya; \"Apakah engkau mendengarnya dari Muhammad shallallahu 'alaihi wasallam?\" Ali menjawab; \"Ya demi Rabb pemilik Ka'bah, \" Ia ulangi hingga tiga kali."},"148":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ فِي آخِرِ الزَّمَانِ قَوْمٌ أَحْدَاثُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقُولُونَ مِنْ خَيْرِ قَوْلِ النَّاسِ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ فَمَنْ لَقِيَهُمْ فَلْيَقْتُلْهُمْ فَإِنَّ قَتْلَهُمْ أَجْرٌ عِنْدَ اللَّهِ لِمَنْ قَتَلَهُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abdullah bin Amir bin Zurarah] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada akhir zaman akan muncul sekelompok kaum yang masih muda-muda. Mereka adalah orang-orang bodoh, berkata dengan menggunakan sebaik-baik perkataan manusia, membaca Al Qur'an namun tidak melewati tenggorokannya, dan mereka keluar dari Islam sebagaimana anak panah melesat dari busurnya. Barangsaiapa menjumpai mereka hendaklah ia membunuhnya. Karena membunuh mereka akan mendapat pahala di sisi Allah.\" "},"149":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ قَالَقُلْتُ لِأَبِي سَعِيدٍ الْخُدْرِيِّ هَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ فِي الْحَرُورِيَّةِ شَيْئًا فَقَالَ سَمِعْتُهُ يَذْكُرُ قَوْمًا يَتَعَبَّدُونَ يَحْقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِمْ وَصَوْمَهُ مَعَ صَوْمِهِمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ أَخَذَ سَهْمَهُ فَنَظَرَ فِي نَصْلِهِ فَلَمْ يَرَ شَيْئًا فَنَظَرَ فِي رِصَافِهِ فَلَمْ يَرَ شَيْئًا فَنَظَرَ فِي قِدْحِهِ فَلَمْ يَرَ شَيْئًا فَنَظَرَ فِي الْقُذَذِ فَتَمَارَى هَلْ يَرَى شَيْئًا أَمْ لَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] ia berkata; \"Aku bertanya kepada [Abu Sa'id Al Khudri]; \"Apakah kamu mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang Haruriyyah?\" ia menjawab; \"Aku mendengar beliau menyebutkan sekelompok ahli ibadah. Kalian akan meremehkan shalat dan puasa kalian dibanding dengan shalat mereka. Mereka melesat dari agama ini sebagaimana anak panah melesat dari busurnya. Dia mengambil anak panahnya dan memperhatikan mata panahnya tetapi tidak melihat sesuatupun, kemudian memperhatikan tepinya tetapi tidak melihat sesuatupun, kemudian memperhatikan lubangnya namun tidak melihat sesutaupun, kemudian memperhatikan bulu panahnya namun ia merasa ragu apakah melihat sesuatu ataukah tidak.\""},"150":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَعْدِي مِنْ أُمَّتِي أَوْ سَيَكُونُ بَعْدِي مِنْ أُمَّتِي قَوْمٌ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حُلُوقَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ ثُمَّ لَا يَعُودُونَ فِيهِ هُمْ شِرَارُ الْخَلْقِ وَالْخَلِيقَةِقَالَ عَبْدُ اللَّهِ بْنُ الصَّامِتِ فَذَكَرْتُ ذَلِكَ لِرَافِعِ بْنِ عَمْرٍو أَخِي الْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّ فَقَالَ وَأَنَا أَيْضًا قَدْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Sulaiman bin Mughirah] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, umatku setelahku nanti, atau beliau mengatakan, \"setelahku nanti akan ada sekelompok kaum dari kalangan umatku membaca Al Qur'an namun tiada melewati kerongkongannya, mereka melesat dari agama ini sebagaimana anak panah melesat dari busurnya dan tidak kembali. Mereka adalah seburuk-buruk makhluk.\" [Abdullah bin Ash Shamit] berkata; Aku menyebutkan hadits ini kepada [Rafi' bin 'Amru], saudara Al Hakam bin 'Amru Al Ghifari, lalu ia pun berkata; \"Aku juga mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"151":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَقْرَأَنَّ الْقُرْآنَ نَاسٌ مِنْ أُمَّتِي يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan muncul sekelompok orang dari umatku yang membaca Al Qur'an, mereka melesat dari Islam sebagaimana anak panah melesat dari busurnya.\""},"152":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْجِعْرَانَةِ وَهُوَ يَقْسِمُ التِّبْرَ وَالْغَنَائِمَ وَهُوَ فِي حِجْرِ بِلَالٍ فَقَالَ رَجُلٌ اعْدِلْ يَا مُحَمَّدُ فَإِنَّكَ لَمْ تَعْدِلْ فَقَالَ وَيْلَكَ وَمَنْ يَعْدِلُ بَعْدِي إِذَا لَمْ أَعْدِلْ فَقَالَ عُمَرُ دَعْنِي يَا رَسُولَ اللَّهِ حَتَّى أَضْرِبَ عُنُقَ هَذَا الْمُنَافِقِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا فِي أَصْحَابٍ أَوْ أُصَيْحَابٍ لَهُ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah mengabarkan kepada kami [Sufyan bin Uyainah] dari [Abi Zubair] dari [Jabir bin Abdullah] dia berkata: Pada saat Rasulullah shallallahu 'alaihi wasallam berada di Ji'ranah membagi emas dan harta rampasan perang, belaiu sedang berada di samping Bilal. Tiba-tiba berkatalah seorang lelaki; \"Wahai Muhammad, berlakulah adil, sungguh engkau tidak adil.\" Maka Rasulullah menjawab: \"Celaka kamu, siapa yang bisa berlaku adil jika aku tidak berlaku adil?\" Umar berkata; \"Ya Rasulullah, biarkanlah aku memenggal leher munafik ini.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia mempunyai teman-teman, atau beliau mengatakan; \"sebagian dari teman-temannya membaca Al Qur'an namun tidak melewati kerongkongannya, mereka keluar dari agama ini sebagaimana anak panah melesat dari busurnya.\""},"153":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ الْأَعْمَشِ عَنْ ابْنِ أَبِي أَوْفَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَوَارِجُ كِلَابُ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Azraq] dari [Al A'masy] dari [Ibnu Abu Aufa] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Khawarij adalah anjing-anjing neraka.\""},"154":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْشَأُ نَشْءٌ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ كُلَّمَا خَرَجَ قَرْنٌ قُطِعَ قَالَ ابْنُ ع��مَرَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلَّمَا خَرَجَ قَرْنٌ قُطِعَ أَكْثَرَ مِنْ عِشْرِينَ مَرَّةً حَتَّى يَخْرُجَ فِي عِرَاضِهِمْ الدَّجَّالُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepada kami [Al Auza'I] dari [Nafi'] dari [Ibnu Umar] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan muncul generasi yang membaca Al Qur'an namun tidak melewati kerongkongan mereka, setiap keluar satu generasi maka akan terputus.\" Ibnu Umar berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap keluar generasi akan terputus sebanyak dua puluh kali, hingga keluar di antara keturunan mereka Dajjal.\""},"155":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ قَوْمٌ فِي آخِرِ الزَّمَانِ أَوْ فِي هَذِهِ الْأُمَّةِ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ أَوْ حُلُوقَهُمْ سِيمَاهُمْ التَّحْلِيقُ إِذَا رَأَيْتُمُوهُمْ أَوْ إِذَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Qatadah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan muncul sekelompok di akhir zaman, atau beliau mengatakan; \"dalam umat ini, mereka membaca Al Qur`an namun tidak melampaui kerongkongan atau tenggorokan mereka, ciri-ciri mereka berkepala gundul, jika kalian melihat mereka atau bertemu dengan mereka maka bunuhlah.\""},"156":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي غَالِبٍ عَنْ أَبِي أُمَامَةَ يَقُولُشَرُّ قَتْلَى قُتِلُوا تَحْتَ أَدِيمِ السَّمَاءِ وَخَيْرُ قَتِيلٍ مَنْ قَتَلُوا كِلَابُ أَهْلِ النَّارِ قَدْ كَانَ هَؤُلَاءِ مُسْلِمِينَ فَصَارُوا كُفَّارًا قُلْتُ يَا أَبَا أُمَامَةَ هَذَا شَيْءٌ تَقُولُهُ قَالَ بَلْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Ghalib] dari [Abu Umamah] ia berkata: \"(Khawarij adalah) seburuk-buruk manusia yang terbunuh di bawah permukaan langit, dan sebaik-baik manusia yang terbunuh adalah orang yang di bunuh oleh anjing-anjing neraka. Pada awalnya mereka muslim namun kemudian mereka menjadi kafir.\" Aku bertanya; \"Wahai Abu 'Umamah, apakah ini ucapanmu?\" ia menjawab; \"Bahkan aku mendengarnya langsung dari Rasulullah shallallahu 'alaihi wasallam.\""},"157":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَوَكِيعٌ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى وَوَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالُوا حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا جُلُوسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ قَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تَضَامُّونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ{ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] dan [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] dari pamanku [Ya'la] dan [Waki'] dan [Abu Mu'awiyah] mereka berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] ia berkata; \"Ketika kami duduk-duduk di sisi Rasulullah shallallahu 'alaihi wasallam, beliau melihat bulan malam purnama, kemudian bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan ini. Kalian tidak akan berdesak-desakan ketika melihatnya. Jika kalian mampu untuk tidak ketinggalan shalat sebelum terbitnya fajar dan sebelum terbenamnya matahari maka lakukanlah.\" Kemudian beliau membaca: \"Dan bertasbihlah dengan memuji Rabbmu, sebelum terbit matahari dan terbenamnya.\""},"158":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ عِيسَى الرَّمْلِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَضَامُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ قَالُوا لَا قَالَ فَكَذَلِكَ لَا تَضَامُّونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Yahya bin Isa Ar Ramli] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian berdesak-desakan ketika melihat bulan di malam purnama?\" Mereka menjawab; \"Tidak.\" Kemudian beliau bersabda: \"Seperti itulah, kalian tidak akan berdesak-desakan ketika melihat Rabb kalian pada hari kiamat.\""},"159":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ حُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَنَرَى اللَّهَ يَوْمَ الْقِيَامَةِ وَمَا آيَةُ ذَلِكَ فِي خَلْقِهِ قَالَ يَا أَبَا رَزِينٍ أَلَيْسَ كُلُّكُمْ يَرَى الْقَمَرَ مُخْلِيًا بِهِ قَالَ قُلْتُ بَلَى قَالَ فَاللَّهُ أَعْظَمُ وَذَلِكَ آيَةٌ فِي خَلْقِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atho`] dari [Waki' bin Hudus] dari pamannya [Abu Razin] ia berkata; Aku bertanya; \"Wahai Rasulullah, apakah kami akan melihat Allah pada hari kiamat? Lalu apa tanda-tandanya yang terdapat pada makhluk-Nya?\" beliau menjawab: \"Wahai Abu Razin, bukankah kalian semua bisa melihat bulan dengan jelas?\" aku menjawab; \"Benar, \" beliau bersabda: \"Maka Allah lebih agung dan itu merupakan tanda-tanda bagi makhluk-Nya.\""},"160":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ حُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ رَبُّنَا مِنْ قُنُوطِ عِبَادِهِ وَقُرْبِ غِيَرِهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَوَ يَضْحَكُ الرَّبُّ قَالَ نَعَمْ قُلْتُ لَنْ نَعْدَمَ مِنْ رَبٍّ يَضْحَكُ خَيْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atho`] dari [Waki' bin Hudus] dari pamannya [Abu Razin] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kita tertawa dengan ibadah para hamba-Nya dan besarnya kecemburuannya.\" Abu Razin berkata; Aku bertanya; \"Wahai Rasulullah, apakah Rabb tertawa?\" beliau menjawab: \"Ya benar, \" aku berkata: \"Selamanya kita akan mendapat kebaikan apabila Rabb kita tertawa.\""},"161":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ الْمَازِنِيِّ قَالَبَيْنَمَا نَحْنُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ وَهُوَ يَطُوفُ بِالْبَيْتِ إِذْ عَرَضَ لَهُ رَجُلٌ فَقَالَ يَا ابْنَ عُمَرَ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ فِي النَّجْوَى قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُدْنَى الْمُؤْمِنُ مِنْ رَبِّهِ يَوْمَ الْقِيَامَةِ حَتَّى يَضَعَ عَلَيْهِ كَنَفَهُ ثُمَّ يُقَرِّرُهُ بِذُنُوبِهِ فَيَقُولُ هَلْ تَعْرِفُ فَيَقُولُ يَا رَبِّ أَعْرِفُ حَتَّى إِذَا بَلَغَ مِنْهُ مَا شَاءَ اللَّهُ أَنْ يَبْلُغَ قَالَ إِنِّي سَتَرْتُهَا عَلَيْكَ فِي الدُّنْيَا وَأَنَا أَغْفِرُهَا لَكَ الْيَوْمَ قَالَ ثُمَّ يُعْطَى صَحِيفَةَ حَسَنَاتِهِ أَوْ كِتَابَهُ بِيَمِينِهِ قَالَ وَأَمَّا الْكَافِرُ أَوْ الْمُنَافِقُ فَيُنَادَى عَلَى رُءُوسِ الْأَشْهَادِقَالَ خَالِدٌ فِي الْأَشْهَادِ شَيْءٌ مِنْ انْقِطَاعٍ{ هَؤُلَاءِ الَّذِينَ كَذَبُوا عَلَى رَبِّهِمْ أَلَا لَعْنَةُ اللَّهِ عَلَى الظَّالِمِينَ }","id":"Telah menceritakan kepada kami [Hummaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Shafwan bin Muhriz Al Mazini] ia berkata; \"Tatkala kami sedang bersama [Abdullah bin Umar] melaksanakan thawaf di ka'bah, tiba-tiba seorang lelaki menghampirinya dan bertanya; \"Wahai Ibnu Umar, bagaimana yang anda dengar ketika Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang bermunajat?\" ia menjawab: \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat orang mukmin akan didekatkan kepada Rabbnya hingga diletakkan padanya naungan-Nya, kemudian ia mengakui dosa-dosanya. Allah lalu berfirman: 'Apakah kamu mengetahui? ' ia menjawab; 'Wahai Rabb, ya aku mengetahuinya.' Maka ketika dosanya telah menggunung sesuai kehendak Allah, Allah pun berfirman: 'Aku telah menutupi dosa itu di dunia untukmu, maka Aku akan mengampuninya pada hari ini.' Beliau bersabda: \"Kemudian ia diberi catatan kebaikannya, atau kitabnya dengan tangan kanan-Nya.\" Beliau bersabda: \"Adapun orang kafir atau munafiq, ia diseru di hadapan khalayak.\" Khalid berkata; \"Di hadapan khalayak ada sesuatu yang terputus; \"Orang-orang inilah yang telah berdusta terhadap Tuhan mereka. Ingatlah, kutukan Allah (ditimpakan) atas orang-orang yang zhalim.\" "},"162":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَاصِمٍ الْعَبَّادَانِيُّ حَدَّثَنَا الْفَضْلُ الرَّقَاشِيُّ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَهْلُ الْجَنَّةِ فِي نَعِيمِهِمْ إِذْ سَطَعَ لَهُمْ نُورٌ فَرَفَعُوا رُءُوسَهُمْ فَإِذَا الرَّبُّ قَدْ أَشْرَفَ عَلَيْهِمْ مِنْ فَوْقِهِمْ فَقَالَ السَّلَامُ عَلَيْكُمْ يَا أَهْلَ الْجَنَّةِ قَالَ وَذَلِكَ قَوْلُ اللَّهِ{ سَلَامٌ قَوْلًا مِنْ رَبٍّ رَحِيمٍ }قَالَ فَيَنْظُرُ إِلَيْهِمْ وَيَنْظُرُونَ إِلَيْهِ فَلَا يَلْتَفِتُونَ إِلَى شَيْءٍ مِنْ النَّعِيمِ مَا دَامُوا يَنْظُرُونَ إِلَيْهِ حَتَّى يَحْتَجِبَ عَنْهُمْ وَيَبْقَى نُورُهُ وَبَرَكَتُهُ عَلَيْهِمْ فِي دِيَارِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib] berkata, telah menceritakan kepada kami [Abu 'Ashim Al Abbadani] berkata, telah menceritakan kepada kami [Al Fadll Ar Raqqasyi] dari [Muhammad Al Munkadir] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tatkala penduduk surga berada dalam kesenangan mereka, tiba-tiba bersinar seberkas cahaya, mereka menengadahkan kepala mereka, ternyata Rabb mereka telah menampakkan diri di atas mereka, lalu berfirman: 'Kesejahteraan tercurah kepada kalian wahai penduduk surga.' Beliau bersabda: \"Itulah firman Allah; Salam, sebagai ucapan selamat dari Rabb Yang Maha Penyayang.\" Beliau bersabda lagi: \"Allah melihat mereka dan mereka melihat-Nya, mereka tidak berpaling karena merasa nikmat selama melihat kepada-Nya, hal itu terus berlangsung hingga Allah menghilang dari mereka. Sementara cahaya dan barakah-Nya masih membekas kepada mereka dan di tempat tinggal mereka.\""},"163":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا سَيُكَلِّمُهُ رَبُّهُ لَيْسَ بَيْنَهُ وَبَيْنَهُ تَرْجُمَانٌ فَيَنْظُرُ مِنْ عَنْ أَيْمَنَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ مِنْ عَنْ أَيْسَرَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ أَمَامَهُ فَتَسْتَقْبِلُهُ النَّارُ فَمَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَتَّقِيَ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Khaitsamah] dari [Adi bin Hatim] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorangpun di antara kalian kecuali akan diajak bicara oleh Rabbnya dan tidak ada penerjemah antara keduanya. Ia lalu menoleh ke samping kanannya, maka tidaklah ia melihat sesuatu di sana kecuali telah disodorkan kepadanya. Kemudian ia menoleh ke samping kirinya, maka tidaklah ia melihat sesuatu di sana kecuali telah disodorkan kepadanya. Kemudian ia melihat ke depannya, dan ternyata api neraka telah menghadangnya. Maka barangsiapa di antara kalian mampu menghindari api neraka meski dengan sebiji kurma, maka hendaklah ia lakukan.\" "},"164":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }وَقَالَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ نَادَى مُنَادٍ يَا أَهْلَ الْجَنَّةِ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا يُرِيدُ أَنْ يُنْجِزَكُمُوهُ فَيَقُولُونَ وَمَا هُوَ أَلَمْ يُثَقِّلْ اللَّهُ مَوَازِينَنَا وَيُبَيِّضْ وُجُوهَنَا وَيُدْخِلْنَا الْجَنَّةَ وَيُنْجِنَا مِنْ النَّارِ قَالَ فَيَكْشِفُ الْحِجَابَ فَيَنْظُرُونَ إِلَيْهِ فَوَاللَّهِ مَا أَعَطَاهُمْ اللَّهُ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْ النَّظَرِ يَعْنِي إِلَيْهِ وَلَا أَقَرَّ لِأَعْيُنِهِمْ","id":"Telah menceritakan kepada kami [Abdul Qudus bin Muhammad] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam membaca ayat ini: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya, \" beliau bersabda: \"Apabila penghuni surga telah mesuk ke dalam surga dan penghuni neraka telah masuk ke dalam neraka, berserulah seorang penyeru: 'Hai penduduk surga, sesungguhnya bagi kalian terdapat janji yang akan Allah tepati untuk kalian, ' mereka bertanya; 'Apakah itu? Bukankah Allah telah memberatkan timbangan kami, memutihkan wajah-wajah kami, memasukakan kami ke dalam surga dan menyelamatkan kami dari api neraka? '\" beliau bersabda: \"Maka tersingkaplah hijab, sehingga mereka dapat melihat kepada-Nya. Demi Allah, tidak ada sesuatu yang diberikan Allah yang lebih mereka sukai dan lebih menyejukkan pandangan mata selain melihat-Nya.\" "},"165":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْالْحَمْدُ لِلَّهِ الَّذِي وَسِعَ سَمْعُهُ الْأَصْوَاتَ لَقَدْ جَاءَتْ الْمُجَادِلَةُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا فِي نَاحِيَةِ الْبَيْتِ تَشْكُو زَوْجَهَا وَمَا أَسْمَعُ مَا تَقُولُ فَأَنْزَلَ اللَّهُ{ قَدْ سَمِعَ اللَّهُ قَوْلَ الَّتِي تُجَادِلُكَ فِي زَوْجِهَا }","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Tamim bin Salamah] dari [Urwah bin Zubair] dari [Aisyah] ia berkata; \"Segala puji bagi Allah yang pendengaran-Nya meliputi semua suara. Telah datang seorang perempuan mengajukan gugatan kepada Nabi shallallahu 'alaihi wasallam sedang aku berada di samping rumah, ia mengadukan suaminya. Aku tidak mendengar apa yang ia ucapkan, namun Allah menurunkan; \"Sesungguhnya Allah telah mendengar perkataan yang memajukan gugatan kepada kamu tentang suaminya.\""},"166":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ وَيَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَا حَدَّثَنَا مُوسَى بْنُ إِبْرَاهِيمَ بْنِ كَثِيرٍ الْأَنْصَارِيُّ الْحَرَامِيُّ قَالَ سَمِعْتُ طَلْحَةَ بْنَ خِرَاشٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمَّا قُتِلَ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ حَرَامٍ يَوْمَ أُحُدٍ لَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا جَابِرُ أَلَا أُخْبِرُكَ مَا قَالَ اللَّهُ لِأَبِيكَ وَقَالَ يَحْيَى فِي حَدِيثِهِ فَقَالَ يَا جَابِرُ مَا لِي أَرَاكَ مُنْكَسِرًا قُلْتُ يَا رَسُولَ اللَّهِ اسْتُشْهِدَ أَبِي وَتَرَكَ عِيَالًا وَدَيْنًا قَالَ أَفَلَا أُبَشِّرُكَ بِمَا لَقِيَ اللَّهُ بِهِ أَبَاكَ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ مَا كَلَّمَ اللَّهُ أَحَدًا قَطُّ إِلَّا مِنْ وَرَاءِ حِجَابٍ وَكَلَّمَ أَبَاكَ كِفَاحًا فَقَالَ يَا عَبْدِي تَمَنَّ عَلَيَّ أُعْطِكَ قَالَ يَا رَبِّ تُحْيِينِي فَأُقْتَلُ فِيكَ ثَانِيَةً فَقَالَ الرَّبُّ سُبْحَانَهُ إِنَّهُ سَبَقَ مِنِّي أَنَّهُمْ إِلَيْهَا لَا يَرْجِعُونَ قَالَ يَا رَبِّ فَأَبْلِغْ مَنْ وَرَائِي قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا بَلْ أَحْيَاءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ }","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] dan [Yahya bin Habib bin Arabi] keduanya berkata dari [Musa bin Ibrahim bin Katsir Al Anshari Al Haramia] ia berkata; Aku mendengar [Thalhah bin Khirasy] berkata; Aku mendengar [Jabir bin Abdullah] berkata; Tatkala Abdullah bin 'Amru bin Haram gugur di perang Uhud, Rasulullah shallallahu 'alaihi wasallam menjumpaiku seraya mengatakan: \"Wahai Jabir, maukah engkau aku kabarkan apa yang diucapkan Allah kepada ayahmu?\" Yahya dalam haditsnya menyebutkan; Beliau bersabda: \"Hai Jabir, kenapa aku melihatmu murung?\" aku (Jabir) menjawab; \"Wahai Rasulullah, ayahku telah menemumi syahidnya, sementara dia meninggallkan anak-anak dan hutang.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kamu aku beri kabar gembira dengan apa yang Allah berikan kepada ayahmu?\" ia menjawab; \"Mau ya Rasulullah.\" Beliau bersabda: \"Tidak pernah Allah mengajak bicara seseorang melainkan dari balik hijab, sementara Dia mengajak bicara ayahmu dengan berhadapan muka, Ia lalu berfirman: 'Wahai Hambaku, memohonlah kepada-Ku, niscaya Aku akan memberimu, ' ia menjawab; 'Wahai Rabb, hidupkan aku kembali agar aku terbunuh di jalan-Mu untuk kedua kalinya.' Allah berfirman: 'Sesungguhnya telah berlalu dari-Ku bahwasanya mereka tidak akan kembali lagi ke sana, ' ia berkata; 'Wahai Rabb, kalau begitu sampaikanlah kepada orang yang berada di belakangku.'\" Beliau bersabda: \"Maka Allah Ta'ala menurunkan: \"Janganlah kamu mengira bahwa orang-orang yang gugur di jalan Allah itu mati; bahkan mereka itu hidup di sisi Rabbnya dengan mendapat rizki.\""},"167":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ الْمُنْذِرِ بْنِ جَرِيرٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ سُنَّةً حَسَنَةً فَعُمِلَ بِهَا كَانَ لَهُ أَجْرُهَا وَمِثْلُ أَجْرِ مَنْ عَمِلَ بِهَا لَا يَنْقُصُ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ سَنَّ سُنَّةً سَيِّئَةً فَعُمِلَ بِهَا كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ لَا يَنْقُصُ مِنْ أَوْزَارِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib] berkata, telah menceritakan kepada kami [Abu 'Awanah] berkata, telah menceritakan kepada kami [Abdul Malik bin Umair] dari [Al Mundzir bin Jarir] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat satu sunnah yang baik, kemudian sunnah tersebut dikerjakan, maka ia akan mendapatkan pahalanya dan pahala orang yang mengikutinya tanpa mengurangi pahala mereka sedikitpun. Dan barangsiapa membuat satu sunnah yang buruk kemudian sunnah tersebut dikerjakan, maka ia akan mendapatkan dosanya dan dosa orang yang mengikutinya tanpa mengurangi dari dosa mereka sedikitpun.\" "},"168":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي أَبِي عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَثَّ عَلَيْهِ فَقَالَ رَجُلٌ عِنْدِي كَذَا وَكَذَا قَالَ فَمَا بَقِيَ فِي الْمَجْلِسِ رَجُلٌ إِلَّا تَصَدَّقَ عَلَيْهِ بِمَا قَلَّ أَوْ كَثُرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَنَّ خَيْرًا فَاسْتُنَّ بِهِ كَانَ لَهُ أَجْرُهُ كَامِلًا وَمِنْ أُجُورِ مَنْ اسْتَنَّ بِهِ وَلَا يَنْقُصُ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ اسْتَنَّ سُنَّةً سَيِّئَةً فَاسْتُنَّ بِهِ فَعَلَيْهِ وِزْرُهُ كَامِلًا وَمِنْ أَوْزَارِ الَّذِي اسْتَنَّ بِهِ وَلَا يَنْقُصُ مِنْ أَوْزَارِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Abdul Warits bin Abdush Shamad bin Abdul Warits] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepadaku [Bapakku] dari [Ayyub] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Seorang lelaki datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau memberi motifasi kepadanya (untuk beramal dengan sesuatu). Seorang laki-laki di antara kami berkata; \"Aku mempunyai seperti ini dan seperti ini.\" Abu Hurairah berkata: Maka tidak seorangpun yang ada di majlis tersebut kecuali ia bersedekah kepada Nabi baik sedikit maupun banyak. Kemudian Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Barangsiapa membuat sunnah yang baik, kemudian sunnah itu menjadi teladan, maka ia akan mendapatkan pahala amalnya secara sempurna berserta pahala orang yang mengikutinya tanpa mengurangi pahala mereka sedikitpun. Dan barangsiapa membuat sunnah yang buruk, kemudian sunnah itu menjadi teladan, maka ia akan mendapatkan dosa dari perbuatannya secara sempurna beserta dosa orang yang mengikutinya tanpa mengurangi dosa mereka sedikitpun.\""},"169":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَيُّمَا دَاعٍ دَعَا إِلَى ضَلَالَةٍ فَاتُّبِعَ فَإِنَّ لَهُ مِثْلَ أَوْزَارِ مَنْ اتَّبَعَهُ وَلَا يَنْقُصُ مِنْ أَوْزَارِهِمْ شَيْئًا وَأَيُّمَا دَاعٍ دَعَا إِلَى هُدًى فَاتُّبِعَ فَإِنَّ لَهُ مِثْلَ أُجُورِ مَنْ اتَّبَعَهُ وَلَا يَنْقُصُ مِنْ أُجُورِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'd bin Sinan] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, bersabda: \"Siapasaja menyeru pada kesesatan, kemudian seruannya diikuti oleh orang lain, maka ia akan mendapatkan dosa orang yang mengikutinya tanpa mengurangi dari dosa mereka. Dan siapasaja menyeru pada petunjuk, kemudian seruannya diikuti oleh orang lain, maka ia akan mendapatkan pahala orang yang mengikutinya tanpa mengurangi dari pahala mereka sedikitpun.\""},"170":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ دَعَا إِلَى هُدًى كَانَ لَهُ مِنْ الْأَجْرِ مِثْلُ أُجُورِ مَنْ اتَّبَعَهُ لَا يَنْقُصُ ذَلِكَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ دَعَا إِلَى ضَلَالَةٍ فَعَلَيْهِ مِنْ الْإِثْمِ مِثْلُ آثَامِ مَنْ اتَّبَعَهُ لَا يَنْقُصُ ذَلِكَ مِنْ آثَامِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [Bapaknya] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengajak kepada petunjuk, maka baginya pahala seperti pahala orang yang mengikutinya tanpa mengurangi pahala mereka sedikitpun. Barangsiapa mengajak kepada kesesatan maka baginya dosa seperti dosa yang mengikutinya tanpa mengurangi dosa mereka sedikitpun.\""},"171":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ الْحَكَمِ عَنْ أَبِي جُحَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ سُنَّةً حَسَنَةً فَعُمِلَ بِهَا بَعْدَهُ كَانَ لَهُ أَجْرُهُ وَمِثْلُ أُجُورِهِمْ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ سَنَّ سُنَّةً سَيِّئَةً فَعُمِلَ بِهَا بَعْدَهُ كَانَ عَلَيْهِ وِزْرُهُ وَمِثْلُ أَوْزَارِهِمْ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أَوْزَارِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Isma'il] dari [Al Hakam] dari [Abu Juhaifah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat sunnah kebaikan kemudian dikerjakan oleh orang setelahnya, maka ia akan mendapatkan seperti pahala mereka tanpa mengurangi pahala mereka sedikitpun. Dan barangsiapa membuat satu sunnah jelek, kemudian dikerjakan oleh orang setelahnya, maka dia akan menanggung seperti dosa orang yang mengikutinya tanpa mengurangi dosa mereka sedikitpun.\""},"172":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ لَيْثٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ دَاعٍ يَدْعُو إِلَى شَيْءٍ إِلَّا وُقِفَ يَوْمَ الْقِيَامَةِ لَازِمًا لِدَعْوَتِهِ مَا دَعَا إِلَيْهِ وَإِنْ دَعَا رَجُلٌ رَجُلًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al Laits] dari [Basyir bin Nahik] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat tidak ada seorang penyeru yang menyeru kepada sesuatu melainkan akan dihadapkan untuk mempertanggung jawabkan seruannya, meskipun seorang lelaki yang mengajak seorang lelaki.\""},"173":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ حَدَّثَنِي أَبِي عَنْ جَدِّيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْيَا سُنَّةً مِنْ سُنَّتِي فَعَمِلَ بِهَا النَّاسُ كَانَ لَهُ مِثْلُ أَجْرِ مَنْ عَمِلَ بِهَا لَا يَنْقُصُ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ ابْتَدَعَ بِدْعَةً فَعُمِلَ بِهَا كَانَ عَلَيْهِ أَوْزَارُ مَنْ عَمِلَ بِهَا لَا يَنْقُصُ مِنْ أَوْزَارِ مَنْ عَمِلَ بِهَا شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepada kami [Katsir bin 'Amru bin Auf Al Muzani] berkata, telah menceritakan kepadaku [Bapakku] dari [Kakekku] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghidupkan satu sunnah dari sunnah-sunnahku, kemudian orang-orang mengerjakannya, maka ia akan mendapatkan sebagaimana pahala orang yang mengamalkannya tanpa mengurangi sedikitpun dari pahala mereka. Dan barangsiapa membuat kebid'ahan, kemudian kebid'ahan itu dikerjakan oleh orang lain, maka ia akan mendapatkan dosa sebagaimana dosa orang yang mengerjakannya.\" "},"174":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي كَثِيرُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَحْيَا سُنَّةً مِنْ سُنَّتِي قَدْ أُمِيتَتْ بَعْدِي فَإِنَّ لَهُ مِنْ الْأَجْرِ مِثْلَ أَجْرِ مَنْ عَمِلَ بِهَا مِنْ النَّاسِ لَا يَنْقُصُ مِنْ أُجُورِ النَّاسِ شَيْئًا وَمَنْ ابْتَدَعَ بِدْعَةً لَا يَرْضَاهَا اللَّهُ وَرَسُولُهُ فَإِنَّ عَلَيْهِ مِثْلَ إِثْمِ مَنْ عَمِلَ بِهَا مِنْ النَّاسِ لَا يَنْقُصُ مِنْ آثَامِ النَّاسِ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, telah menceritakan kepadaku [Katisr bin Abdullah] dari [Bapaknya] dari [Kakeknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghidupkan sunnahku yang telah ditinggalkan sepeninggalku, maka ia akan mendapatkan pahala sebagaimana pahala orang yang mengamalkannya, tanpa mengurangi pahala mereka sedikitpun. Dan barangsiapa membuat kebid'ahan yang Allah dan Rasul-Nya tidak meridlainya, maka ia akan mendapatkan dosa orang yang melakukannya tanpa mengurangi dosa mereka sedikitpun.\" "},"175":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا شُعْبَةُ وَسُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ خَيْرُكُمْ وَقَالَ سُفْيَانُ أَفْضَلُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata, telah menceritakan kepada kami [Syu'bah] dan [Sufyan] dari [Alqamah bin Martsad] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Utsman] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: -Syu'bah menyebutkan; \"Sebaik-baik kalian- Sufyan menyebutkan; \"orang yang paling utama dari kalian adalah orang yang mempelajari Al Qur`an lalu mengajarkannya.\""},"176":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Alqamah bin Martsad] dari [Abu Abdurrahman As Sulami] dari [Utsman bin 'Affan] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah orang yang mempelajari Al Qur`an dan mengajarkannya.\""},"177":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِيَارُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ قَالَ وَأَخَذَ بِيَدِي فَأَقْعَدَنِي مَقْعَدِي هَذَا أُقْرِئُ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Al Harits bin Nabhan] berkata, telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Mush'ab bin Sa'd] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah yang mempelajari Al Qur`an dan mengajarkannya.\" Ia berkata; \"Kemudian beliau meraih tanganku dan mendudukkanku di tempat dudukku. Ini merupakan penghormatan bagiku.\""},"178":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ التَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ طَعْمُهَا مُرٌّ وَلَا رِيحَ لَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan orang mukmin yang membaca Al Qur`an seperti buah utrujah, rasanya enak dan baunya harum. Perumpamaan orang mukmin yang tidak membaca Al Qur`an seperti buah kurma, rasanya enak namun tidak berbau. Dan perumpamaan orang munafik yang membaca Al Qur`an seperti buah Raihanah, baunya harum sedang rasanya pahit. Sementara perumpamaan orang munafik yang tidak membaca Al Qur`an adalah seperti buah Hanzhalah, rasanya pahit dan tidak berbau.\""},"179":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بُدَيْلٍ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ أَهْلِينَ مِنْ النَّاسِ قَالُوا يَا رَسُولَ اللَّهِ مَنْ هُمْ قَالَ هُمْ أَهْلُ الْقُرْآنِ أَهْلُ اللَّهِ وَخَاصَّتُهُ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisr] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Abdurrahman bin Budail] dari [Bapaknya] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mempunyai banyak ahli (wali) dari kalangan manusia.\" Para sahabat bertanya; \"Ya Rasulullah, siapakah mereka itu?\" beliau menjawab: \"Mereka adalah ahlul Qur`an, mereka adalah para ahli dan orang khusus Allah.\" "},"180":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ أَبِي عُمَرَ عَنْ كَثِيرِ بْنِ زَاذَانَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْقُرْآنَ وَحَفِظَهُ أَدْخَلَهُ اللَّهُ الْجَنَّةَ وَشَفَّعَهُ فِي عَشَرَةٍ مِنْ أَهْلِ بَيْتِهِ كُلُّهُمْ قَدْ اسْتَوْجَبُوا النَّارَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Muhammad bin Harb] dari [Abu Umar] dari [Katsir bin Zadzan] dari ['Ashim bin Dlamrah] dari [Ali bin Abi Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca Al Qur`an dan menghafalkannya, maka Allah akan memasukkannya ke dalam surga serta akan memberi syafa'at kepada sepuluh dari keluarganya yang seharusnya masuk neraka.\""},"181":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ الْأَوْدِيُّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْمَقْبُرِيِّ عَنْ عَطَاءٍ مَوْلَى أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَلَّمُوا الْقُرْآنَ وَاقْرَءُوهُ وَارْقُدُوا فَإِنَّ مَثَلَ الْقُرْآنِ وَمَنْ تَعَلَّمَهُ فَقَامَ بِهِ كَمَثَلِ جِرَابٍ مَحْشُوٍّ مِسْكًا يَفُوحُ رِيحُهُ كُلَّ مَكَانٍ وَمَثَلُ مَنْ تَعَلَّمَهُ فَرَقَدَ وَهُوَ فِي جَوْفِهِ كَمَثَلِ جِرَابٍ أُوكِيَ عَلَى مِسْكٍ","id":"Telah menceritakan kepada kami ['Amru bin Abdullah Al Audi] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Al Maqburi] dari ['Atho`] mantan budak Abu Ahmad, dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelajari dan bacalah Al Qur`an, dan janganlah engkau berpisah dengannya. Sungguh, perumpamaan Al Qur`an dan orang yang mempelajari kemudian mengamalkannya, seperti kantong yang terisi penuh dengan minyak kesturi, dan keharumannya dapat tercium dari setiap tempat. Sedangkan perumpamaan orang yang mempelajarinya kemudian memendamnya, maka ia seperti kantong yang terisi kesturi.\""},"182":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَامِرِ بْنِ وَاثِلَةَ أَبِي الطُّفَيْلِأَنَّ نَافِعَ بْنَ عَبْدِ الْحَارِثِ لَقِيَ عُمَرَ بْنَ الْخَطَّابِ بِعُسْفَانَ وَكَانَ عُمَرُ اسْتَعْمَلَهُ عَلَى مَكَّةَ فَقَالَ عُمَرُ مَنْ اسْتَخْلَفْتَ عَلَى أَهْلِ الْوَادِي قَ��لَ اسْتَخْلَفْتُ عَلَيْهِمْ ابْنَ أَبْزَى قَالَ وَمَنْ ابْنُ أَبْزَى قَالَ رَجُلٌ مِنْ مَوَالِينَا قَالَ عُمَرُ فَاسْتَخْلَفْتَ عَلَيْهِمْ مَوْلًى قَالَ إِنَّهُ قَارِئٌ لِكِتَابِ اللَّهِ تَعَالَى عَالِمٌ بِالْفَرَائِضِ قَاضٍ قَالَ عُمَرُ أَمَا إِنَّ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَرْفَعُ بِهَذَا الْكِتَابِ أَقْوَامًا وَيَضَعُ بِهِ آخَرِينَ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Amir bin Watsilah Abu Thufail] bahwa Nafi' bin Abdul Harits bertemu dengan Umar bin Khatthab di daerah Usfan. Dan umar mengangkatnya sebagai gubernur Makkah. Umar berkata; \"Siapa yang kamu angkat untuk memimpin penduduk yang ada di pinggiran?\" Nafi' menjawab; \"Aku telah mengangkat Ibnu Abza untuk mereka\". Umar bertanya; \"Siapakah Ibnu Abza itu?\" Nafi' menjawab; \"Dia seorang dari bekas budak budak kita.\" Umar berkata; \"Kamu mengangkat seorang budak untuk mereka?\" Nafi' menjawab; \"Dia seorang yang hafal kitab Allah, paham ilmu fara'id dan seorang qadli.\" [Umar] berkata; \"Sesungguhnya Nabi kalian shallallahu 'alaihi wasallam telah bersabda: \"Sungguh, dengan kitab ini Allah akan mengangkat suatu kaum dan merendahkan kaum yang lain.\" "},"183":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ اللَّهِ الْوَاسِطِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ غَالِبٍ الْعَبَّادَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ زِيَادٍ الْبَحْرَانِيِّ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ لَأَنْ تَغْدُوَ فَتَعَلَّمَ آيَةً مِنْ كِتَابِ اللَّهِ خَيْرٌ لَكَ مِنْ أَنْ تُصَلِّيَ مِائَةَ رَكْعَةٍ وَلَأَنْ تَغْدُوَ فَتَعَلَّمَ بَابًا مِنْ الْعِلْمِ عُمِلَ بِهِ أَوْ لَمْ يُعْمَلْ خَيْرٌ لَكَ مِنْ أَنْ تُصَلِّيَ أَلْفَ رَكْعَةٍ","id":"Telah menceritakan kepada kami [Abbas bin Abdullah Al Wasithi] berkata, telah menceritakan kepada kami [Abdullah bin Ghalib Al 'Abbadani] dari [Abdullah bin Ziyad Al Bahrani] dari [Ali bin Zaid] dari [Sa'id Ibnul Musayyab] dari [Abu Dzar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Hai Abu Dzar, engkau berpagi-pagi untuk mempelajari satu ayat dari kitab Allah lebih baik bagimu dari pada engkau shalat sebanyak seratus raka'at. Dan engkau berpagi-pagi untuk mempelajari satu bab ilmu kemudian diamalkan ataupun tidak diamalkan, adalah lebih baik bagimu dari pada engkau shalat sebanyak seribu raka'at.\""},"184":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dikehendaki Allah untuk mendapat kebaikan, maka Allah akan memberikan pemahaman kepadanya tentang agama.\""},"185":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَرْوَانُ بْنُ جَنَاحٍ عَنْ يُونُسَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ أَنَّهُ حَدَّثَهُ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْخَيْرُ عَادَةٌ وَالشَّرُّ لَجَاجَةٌ وَمَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Marwan bin Janah] dari [Yunus bin Maisarah bin Halbas] bahwasanya ia menceritakan kepadanya, ia berkata; Aku mendengar [Mu'awiyah bin Abu Sufyan] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Kebaikan adalah kebiasaan (bagi seorang mukmin) dan keburukan adalah permusuhan. Dan barangsiapa Allah menghendaki kebaikan pada seseorang maka Allah akan memahamkan agama kepadanya.\""},"186":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا رَوْحُ بْنُ جَنَاحٍ أَبُو سَعْدٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيهٌ وَاحِدٌ أَشَدُّ عَلَى الشَّيْطَانِ مِنْ أَلْفِ عَابِدٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Rauh bin Janah Abu Sa'd] dari [Mujahid] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu orang faqih itu lebih keras bagi setan dari pada seribu ahli ibadah.\""},"187":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاو��دَ عَنْ عَاصِمِ بْنِ رَجَاءِ بْنِ حَيْوَةَ عَنْ دَاوُدَ بْنِ جَمِيلٍ عَنْ كَثِيرِ بْنِ قَيْسٍ قَالَكُنْتُ جَالِسًا عِنْدَ أَبِي الدَّرْدَاءِ فِي مَسْجِدِ دِمَشْقَ فَأَتَاهُ رَجُلٌ فَقَالَ يَا أَبَا الدَّرْدَاءِ أَتَيْتُكَ مِنْ الْمَدِينَةِ مَدِينَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَدِيثٍ بَلَغَنِي أَنَّكَ تُحَدِّثُ بِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا جَاءَ بِكَ تِجَارَةٌ قَالَ لَا قَالَ وَلَا جَاءَ بِكَ غَيْرُهُ قَالَ لَا قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِ وَإِنَّ الْمَلَائِكَةَ لَتَضَعُ أَجْنِحَتَهَا رِضًا لِطَالِبِ الْعِلْمِ وَإِنَّ طَالِبَ الْعِلْمِ يَسْتَغْفِرُ لَهُ مَنْ فِي السَّمَاءِ وَالْأَرْضِ حَتَّى الْحِيتَانِ فِي الْمَاءِ وَإِنَّ فَضْلَ الْعَالِمِ عَلَى الْعَابِدِ كَفَضْلِ الْقَمَرِ عَلَى سَائِرِ الْكَوَاكِبِ إِنَّ الْعُلَمَاءَ هُمْ وَرَثَةُ الْأَنْبِيَاءِ إِنَّ الْأَنْبِيَاءَ لَمْ يُوَرِّثُوا دِينَارًا وَلَا دِرْهَمًا إِنَّمَا وَرَّثُوا الْعِلْمَ فَمَنْ أَخَذَهُ أَخَذَ بِحَظٍّ وَافِرٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdullah bin Daud] dari ['Ashim bin Raja` bin Haiwah] dari [Dawud bin Jamil] dari [Katsir bin Qais] ia berkata; \"Ketika aku sedang duduk di samping [Abu Darda] di masjid Damaskus, tiba-tiba datang seseorang seraya berkata; \"Hai Abu Darda, aku mendatangi anda dari kota Madinah, kota Rasulullah shallallahu 'alaihi wasallam karena satu hadits yang telah sampai kepadaku, bahwa engkau telah menceritakannya dari Nabi shallallahu 'alaihi wasallam! \" Lalu Abu Darda bertanya; \"Apakah engkau datang karena berniaga?\" Katsir bin Qais menjawab; \"Bukan, \" Abu Darda` bertanya lagi, \"Apakah karena ada urusan yang lainnya?\" Katsir bin Qais menjawab; \"Bukan, \" Katsir bin Qais berkata; \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meniti jalan untuk mencari ilmu, Allah akan permudahkan baginya jalan menuju surga. Para Malaikat akan membentangkan sayapnya karena ridla kepada penuntut ilmu. Dan seorang penuntut ilmu akan dimintakan ampunan oleh penghuni langit dan bumi hingga ikan yang ada di air. Sungguh, keutamaan seorang alim dibanding seorang ahli ibadah adalah ibarat bulan purnama atas semua bintang. Sesungguhnya para ulama adalah pewaris para Nabi, dan para Nabi tidak mewariskan dinar maupun dirham, akan tetapi mereka mewariskan ilmu. Barangsiapa mengambilnya, maka ia telah mengambil bagian yang sangat besar.\" "},"188":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَفْصُ بْنُ سُلَيْمَانَ حَدَّثَنَا كَثِيرُ بْنُ شِنْظِيرٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَبُ الْعِلْمِ فَرِيضَةٌ عَلَى كُلِّ مُسْلِمٍ وَوَاضِعُ الْعِلْمِ عِنْدَ غَيْرِ أَهْلِهِ كَمُقَلِّدِ الْخَنَازِيرِ الْجَوْهَرَ وَاللُّؤْلُؤَ وَالذَّهَبَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hafsh bin Sulaiman] berkata, telah menceritakan kepada kami [Katsir bin Syinzhir] dari [Muhammad bin Sirin] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menuntut ilmu adalah kewajiban bagi setiap muslim. Dan orang yang meletakkan ilmu bukan pada pada ahlinya, seperti seorang yang mengalungkan mutiara, intan dan emas ke leher babi.\""},"189":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَفَّسَ عَنْ مُسْلِمٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيَا نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ وَمَنْ يَسَّرَ عَلَى مُعْسِرٍ يَسَّرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَاللَّهُ فِي عَوْنِ الْعَبْدِ مَا كَانَ الْعَبْدُ فِي عَوْنِ أَخِيهِ وَمَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ وَمَا اجْتَمَعَ قَوْمٌ فِي بَيْتٍ مِنْ بُيُوتِ اللَّهِ يَتْلُونَ كِتَابَ اللَّهِ وَيَتَدَارَسُونَهُ بَيْنَهُمْ إِلَّا حَفَّتْهُمْ الْمَلَائِكَةُ وَنَزَلَتْ عَلَيْهِمْ السَّكِينَةُ وَغَشِيَتْهُمْ الرَّحْمَةُ وَذَكَرَهُمْ اللَّهُ فِيمَنْ عِنْدَهُ وَمَنْ أَبْطَأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengilangkan kesusahan seorang muslim di dunia maka Allah akan menghilangkan kesusahannya pada hari kiamat. Barangsiapa menutupi aib seorang muslim di dunia maka Allah akan menutupi aibnya di dunia dan akhirat. Barangsiapa memudahkan seorang muslim maka Allah akan memudahkannya di dunia dan akhirat. Allah akan menolong seorang hamba selama hamba tersebut menolong saudaranya. Dan barangsiapa meniti jalan untuk menuntut ilmu maka Allah akan memudahkan jalan baginya ke surga. Dan tidaklah suatu kaum berkumpul di rumah dari rumah-rumah Allah, mereka membaca kitab Allah dan mempelajarinya kecuali para malaikat akan menaungi, ketenangan akan turun, rahmat akan menyertainya dan Allah akan menyebut-nyebut mereka di hadapan mahluk yang ada di sisi-Nya, dan barangsiapa diperlambat oleh amalnya maka tidak akan bisa dipercepat oleh nasabnya.\""},"190":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَأَتَيْتُ صَفْوَانَ بْنَ عَسَّالٍ الْمُرَادِيَّ فَقَالَ مَا جَاءَ بِكَ قُلْتُ أُنْبِطُ الْعِلْمَ قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ خَارِجٍ خَرَجَ مِنْ بَيْتِهِ فِي طَلَبِ الْعِلْمِ إِلَّا وَضَعَتْ لَهُ الْمَلَائِكَةُ أَجْنِحَتَهَا رِضًا بِمَا يَصْنَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Ma'mar] dari ['Ashim bin Abu An Nujud] dari [Zirr bin Hubaisy] ia berkata; Aku mendatangi [Shafwan bin Assal Al Muradi], lalu ia berkata; \"Ada apa engkau datang?\" aku lalu menjawab; \"Aku ingin mengambil ilmu dari sumbernya.\" Ia berkata; Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang keluar dari rumahnya untuk menuntut ilmu kecuali para malaikat akan mengepakkan sayap-sayapnya untuk orang tersebut karena ridla dengan apa yang ia kerjakan.\""},"191":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ حُمَيْدِ بْنِ صَخْرٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَاءَ مَسْجِدِي هَذَا لَمْ يَأْتِهِ إِلَّا لِخَيْرٍ يَتَعَلَّمُهُ أَوْ يُعَلِّمُهُ فَهُوَ بِمَنْزِلَةِ الْمُجَاهِدِ فِي سَبِيلِ اللَّهِ وَمَنْ جَاءَ لِغَيْرِ ذَلِكَ فَهُوَ بِمَنْزِلَةِ الرَّجُلِ يَنْظُرُ إِلَى مَتَاعِ غَيْرِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Humaid bin Shakhr] dari [Al Maqburi] dari [Abu Hurairah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendatangi masjidku ini, ia tidak datang kecuali karena sesuatu yang ia pelajari atau ia ajarkan, maka ia seperti seorang mujahid fi sabillilah. Dan barangsiapa mendatanginya untuk selain itu, maka ia seperti seseorang yang melihat barang milik orang lain.\""},"192":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي عَاتِكَةَ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِهَذَا الْعِلْمِ قَبْلَ أَنْ يُقْبَضَ وَقَبْضُهُ أَنْ يُرْفَعَ وَجَمَعَ بَيْنَ إِصْبَعَيْهِ الْوُسْطَى وَالَّتِي تَلِي الْإِبْهَامَ هَكَذَا ثُمَّ قَالَ الْعَالِمُ وَالْمُتَعَلِّمُ شَرِيكَانِ فِي الْأَجْرِ وَلَا خَيْرَ فِي سَائِرِ النَّاسِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Shadaqah bin Khalid] berkata, telah menceritakan kepada kami [Utsman bin Abu 'Atikah] dari [Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian berpegang teguh dengan ilmu ini sebelum dicabut, dan dicabutnya adalah dengan diangkat -beliau menggabungkan antara dua jarinya; jari tengah dan telunjuk seperti ini- kemudian bersabda: \"Seorang alim dan penuntut ilmu bersekutu dalam pahala, dan tidak ada kebaikan pada mayoritas manusia.\""},"193":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا دَاوُدُ بْنُ الزِّبْرِقَانِ عَنْ بَكْرِ بْنِ خُنَيْسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ مِنْ بَعْضِ حُجَرِهِ فَدَخَلَ الْمَسْجِدَ فَإِذَا هُوَ بِحَلْقَتَيْنِ إِحْدَاهُمَا يَقْرَءُونَ الْقُرْآنَ وَيَدْعُونَ اللَّهَ وَالْأُخْرَى يَتَعَلَّمُونَ وَيُعَلِّمُونَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلٌّ عَلَى خَيْرٍ هَؤُلَاءِ يَقْرَءُونَ الْقُرْآنَ وَيَدْعُونَ اللَّهَ فَإِنْ شَاءَ أَعْطَاهُمْ وَإِنْ شَاءَ مَنَعَهُمْ وَهَؤُلَاءِ يَتَعَلَّمُونَ وَإِنَّمَا بُعِثْتُ مُعَلِّمًا فَجَلَسَ مَعَهُمْ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwafi] berkata, telah menceritakan kepada kami [Dawud bin Az Zibirqan] dari [Bakr bin Khunais] dari [Abdurrahman bin Ziyad] dari [Abdullah bin Yazid] dari [Abdullah bin 'Amru] ia berkata; Pada suatu hari Rasulullah shallallahu 'alaihi wasallam keluar dari salah satu kamarnya dan masuk ke dalam masjid. Lalu beliau menjumpai dua halaqah, salah satunya sedang membaca Al Qur`an dan berdo'a kepada Allah, sedang yang lainnya melakukan proses belajar mengajar. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Masing-masing berada di atas kebaikan, mereka membaca Al Qur`an dan berdo`a kepada Allah, jika Allah menghendaki maka akan memberinya dan jika tidak menghendakinya maka tidak akan memberinya. Dan mereka sedang belajar, sementara diriku di utus sebagai pengajar, \" lalu beliau duduk bersama mereka."},"194":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا لَيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ يَحْيَى بْنِ عَبَّادٍ أَبِي هُبَيْرَةَ الْأَنْصَارِيِّ عَنْ أَبِيهِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مَقَالَتِي فَبَلَّغَهَا فَرُبَّ حَامِلِ فِقْهٍ غَيْرِ فَقِيهٍ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ زَادَ فِيهِ عَلِيُّ بْنُ مُحَمَّدٍ ثَلَاثٌ لَا يُغِلُّ عَلَيْهِنَّ قَلْبُ امْرِئٍ مُسْلِمٍ إِخْلَاصُ الْعَمَلِ لِلَّهِ وَالنُّصْحُ لِأَئِمَّةِ الْمُسْلِمِينَ وَلُزُومُ جَمَاعَتِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Laits bin Abu Sulaim] dari [Yahya bin Abbad Abu Hubairah Al Anshari] dari [Bapaknya] dari [Zaid bin Tsabit] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memperindah seseorang yang mendengar perkataanku kemudian menyampaikannya. Berapa banyak orang yang menyampaikan fikih namun tidak paham dengan fikih (tersebut). Dan berapa banyak orang yang menyampaikan fikih kepada orang lain yang lebih faham dengan fikih (tersebut). Ali menambahkan dalam hadits tersebut, \"Tiga hal yang hati seorang muslim tidak akan merasa jengkel; ikhlas karena Allah, nasihat untuk para pemimpin kaum muslimin dan komitmen kepada jama'ah mereka.\""},"195":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ السَّلَامِ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْخَيْفِ مِنْ مِنًى فَقَالَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مَقَالَتِي فَبَلَّغَهَا فَرُبَّ حَامِلِ فِقْهٍ غَيْرِ فَقِيهٍ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] dari [Muhammad bin Ishaq] dari [Abdullah Salam] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri (khutbah) di Khaif Mina, beliau bersabda: \"Allah akan memperindah seseorang yang mendengar perkataanku kemudian menyampaikannya. Berapa banyak orang yang menyampaikan fikih namun tidak paham dengan fikih (tersebut). Dan berapa banyak orang yang menyampaikan fikih kepada orang lain yang lebih faham dengan fikih (tersebut).\" Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami pamanku [Ya'la]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sa'id bin Yahya] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits diatas.\""},"196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا فَبَلَّغَهُ فَرُبَّ مُبَلَّغٍ أَحْفَظُ مِنْ سَامِعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Al Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Simak] dari [Abdurrahman bin Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah akan memperindah seseorang yang mendengar satu hadits dari kami kemudian menyampaikannya. Berapa banyak orang yang di sampaikan hadits kepadanya lebih hafal dari orang yang mendengarnya.\""},"197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ أَمْلَاهُ عَلَيْنَا حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ وَعَنْ رَجُلٍ آخَرَ هُوَ أَفْضَلُ فِي نَفْسِي مِنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي بَكْرَةَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ فَقَالَ لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّهُ رُبَّ مُبَلَّغٍ يَبْلُغُهُ أَوْعَى لَهُ مِنْ سَامِعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] ia mendektekannya kepada kami; telah menceritakan kepada kami [Qurrah bin Khalid] berkata, telah menceritakan kepada kami [Muhammad bin Sirin] dari [Abdurrahman bin Abu Bakrah] dari [Bapaknya] dan dari seorang laki-laki lain -dan ia lebih baik dari Abdurrahman- dari Abu Bakrah ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah pada hari Nahar (iedul adlha), beliau bersabda: \"Hendaklah yang hadir memberitahukan kepada yang tidak hadir. Sesungguhnya berapa banyak orang yang disampaikan kepadanya (hadits) lebih faham daripada yang mendengar (langsung).\""},"198":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ مُعَاوِيَةَ الْقُشَيْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [An Nadlr bin Syumail] dari [Bahz bin Hakim] dari [Bapaknya] dari kakeknya [Mu'awiyah Al Qusyairi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, hendaklah yang hadir memberitahukan kepada yang tidak hadir.\""},"199":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنِي قُدَامَةُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ الْحُصَيْنِ التَّمِيمِيِّ عَنْ أَبِي عَلْقَمَةَ مَوْلَى ابْنِ عَبَّاسٍ عَنْ يَسَارٍ مَوْلَى ابْنِ عُمَرَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيُبَلِّغْ شَاهِدُكُمْ غَائِبَكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] berkata, telah menceritakan kepadaku [Qudamah bin Musa] dari [Muhammad Ibnul Hushain At Tamimah] dari [Abu Alqamah] mantan budak Ibnu Abbas, dari [Yasar] mantan budak Ibnu Umar, dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah yang hadir dari kalian menyampaikan kepada yang tidak hadir dari kalian.\""},"200":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا مُبَشِّرُ بْنُ إِسْمَعِيلَ الْحَلَبِيُّ عَنْ مُعَانِ بْنِ رِفَاعَةَ عَنْ عَبْدِ الْوَهَّابِ بْنِ بُخْتٍ الْمَكِّيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَضَّرَ اللَّهُ عَبْدًا سَمِعَ مَقَالَتِي فَوَعَاهَا ثُمَّ بَلَّغَهَا عَنِّي فَرُبَّ حَامِلِ فِقْهٍ غَيْرِ فَقِيهٍ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Mubasysyir Al Halabi] dari [Mu'an bin Rifa'ah] dari [Abdul Wahhab bin Bukht Al Makki] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memperindah wajah seorang hamba, ia mendengar perkataanku lalu merekamnya dengan hati, kemudian meyampaikannya atas namaku. Berapa banyak pembawa (menyampaikan) fikih namun tidak faham fikih, dan berapa banyak orang yang membawa (menyampaikan) fikih kepada orang lain yang lebih faham fikih darinya.\""},"201":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ أَنْبَأَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حُمَيْدٍ حَدَّثَنَا حَفْصُ بْنُ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ النَّاسِ مَفَاتِيحَ لِلْخَيْرِ مَغَالِيقَ لِلشَّرِّ وَإِنَّ مِنْ النَّاسِ مَفَاتِيحَ لِلشَّرِّ مَغَالِيقَ لِلْخَيْرِ فَطُوبَى لِمَنْ جَعَلَ اللَّهُ مَفَاتِيحَ الْخَيْرِ عَلَى يَدَيْهِ وَوَيْلٌ لِمَنْ جَعَلَ اللَّهُ مَفَاتِيحَ الشَّرِّ عَلَى يَدَيْهِ","id":"Telah menceritakan kepada kami [Al Husain bin Al Hasan Al Marwazi] berkata, telah mengabarkan kepada kami [Muhammad bin Abu 'Adi] berkata, telah menceritakan kepada kami [Muhammad bin Abu Humaid] berkata, telah menceritakan kepada kami [Hafsh bin Ubaidullah bin Anas] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesunggunya di antara manusia ada yang menjadi kunci-kunci pembuka kebaikan dan penutup kejahatan. Dan di antara manusia itu juga ada yang menjadi kunci-kunci pembuka kejahatan dan penutup kebaikan. Maka beruntunglah bagi orang yang Allah jadikan sebagai kunci-kunci pembuka kebaikan melalui tangan-Nya, dan celakalah bagi orang yang Allah jadikan sebagai kunci-kunci pembuka kejahatan melalui tangannya.\""},"202":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ أَبُو جَعْفَرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ هَذَا الْخَيْرَ خَزَائِنُ وَلِتِلْكَ الْخَزَائِنِ مَفَاتِيحُ فَطُوبَى لِعَبْدٍ جَعَلَهُ اللَّهُ مِفْتَاحًا لِلْخَيْرِ مِغْلَاقًا لِلشَّرِّ وَوَيْلٌ لِعَبْدٍ جَعَلَهُ اللَّهُ مِفْتَاحًا لَلشَّرِّ مِغْلَاقًا لِلْخَيْرِ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili Abu Ja'far] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepada saya [Abdurrahman bin Zaid bin Aslam] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam berabda: \"Sesungguhnya kebaikan ini merupakan lumbung, sementara lumbung itu memiliki kunci-kunci. Maka beruntunglah bagi seorang hamba yang telah Allah jadikan sebagai kunci pembuka kebaikan dan penutup bagi kejahatan. Dan celakah seorang hamba yang Allah jadikan sebagai kunci pembuka kejahatan dan penutup bagi kebaikan.\""},"203":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ عَنْ عُثْمَانَ بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ أَبِي الدَّرْدَاءِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَيَسْتَغْفِرُ لِلْعَالِمِ مَنْ فِي السَّمَاوَاتِ وَمَنْ فِي الْأَرْضِ حَتَّى الْحِيتَانِ فِي الْبَحْرِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hafsh bin Umar] dari [Utsman bin 'Atho`] dari [Bapaknya] dari [Abu Ad Darda`] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan memintakan ampun untuk seorang alim makhluk yang di langit dan di bumi hingga ikan hiu di dasar laut.\""},"204":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ عَلَّمَ عِلْمًا فَلَهُ أَجْرُ مَنْ عَمِلَ بِهِ لَا يَنْقُصُ مِنْ أَجْرِ الْعَامِلِ","id":"Telah menceritakan kepada kami [Ahmad bin Isa Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Yahya bin Ayyub] dari [Sahl bin Mu'adz bin Anas] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengajarkan suatu ilmu, maka ia akan mendapatkan pahala orang yang mengamalkannya, tanpa mengurangi pahala orang yang mengamalkannya sedikitpun.\" "},"205":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي كَرِيمَةَ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنيْسَةَ عَنْ زيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ مَا يُخَلِّفُ الرَّجُلُ مِنْ بَعْدِهِ ثَلَاثٌ وَلَدٌ صَالِحٌ يَدْعُو لَهُ وَصَدَقَةٌ تَجْرِي يَبْلُغُهُ أَجْرُهَا وَعِلْمٌ يُعْمَلُ بِهِ مِنْ بَعْدِهِقَالَ أَبُو الْحَسَنِ وَحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ بْنِ سِنَانٍ الرَّهَاوِيُّ حَدَّثَنَا يَزِيدُ بْنُ سِنَانٍ يَعْنِي أَبَاهُ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ismail bin Abu Karimah Al Harrani] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Abu Abdurrahim] berkata, telah menceritakan kepadaku [Zaid bin Abu Unaisah] dari [Zaid bin Aslam] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik perkara yang ditinggalkan oleh seorang laki-laki sepeninggalnya ada tiga; anak shalih yang mendoakannya, sedekah jariyah yang pahalanya sampai kepadanya serta ilmu yang diamalkan oleh orang sepeninggalnya.\" Abul Hasan berkata; telah menceritakan kepadaku Abu Hatim berkata, telah menceritakan kepada saya Muhammad bin Yazid bin Sinan Ar Rahawi berkata, telah menceritakan kepada kami Yazid bin Sinan -yaitu bapaknya- berkata, telah menceritakan kepadaku Zaid bin Abu Unaisah dari Fulaih bin Sulaiman dari Zaid bin Aslam dari Abdullah bin Abu Qatadah dari Bapaknya berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam, lalu ia menyebutkan sebagaimana hadits diatas tersebut."},"206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ وَهْبِ بْنِ عَطِيَّةَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَرْزُوقُ بْنُ أَبِي الْهُذَيْلِ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي أَبُو عَبْدِ اللَّهِ الْأَغَرُّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِمَّا يَلْحَقُ الْمُؤْمِنَ مِنْ عَمَلِهِ وَحَسَنَاتِهِ بَعْدَ مَوْتِهِ عِلْمًا عَلَّمَهُ وَنَشَرَهُ وَوَلَدًا صَالِحًا تَرَكَهُ وَمُصْحَفًا وَرَّثَهُ أَوْ مَسْجِدًا بَنَاهُ أَوْ بَيْتًا لِابْنِ السَّبِيلِ بَنَاهُ أَوْ نَهْرًا أَجْرَاهُ أَوْ صَدَقَةً أَخْرَجَهَا مِنْ مَالِهِ فِي صِحَّتِهِ وَحَيَاتِهِ يَلْحَقُهُ مِنْ بَعْدِ مَوْتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Wahb bin 'Athiyyah] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Marzuq bin Abu Hudzail] berkata, telah menceritakan kepadaku [Az Zuhri] berkata, telah menceritakan kepadaku [Abu Abdullah Al Aghar] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kebaikan yang akan mengiringi seorang mukmin setelah ia meninggal adalah ilmu yang ia ajarkan dan sebarkan, anak shalih yang ia tinggalkan dan Al Qur`an yang ia wariskan, atau masjid yang ia bangun, atau rumah yang ia bangun untuk ibnu sabil, atau sungai yang ia alirkan (untuk orang lain), atau sedekah yang ia keluarkan dari harta miliknya dimasa sehat dan masa hidupnya, semuanya akan mengiringinya setelah meninggal.\""},"207":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ الْمَدَنِيُّ حَدَّثَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عُبَيْدِ اللَّهِ بْنِ طَلْحَةَ عَنْ الْحَسَنِ الْبَصْرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الصَّدَقَةِ أَنْ يَتَعَلَّمَ الْمَرْءُ الْمُسْلِمُ عِلْمًا ثُمَّ يُعَلِّمَهُ أَخَاهُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib Al Madani] berkata, telah menceritakan kepadaku [Ishaq bin Ibrahim] dari [Shafwan Sulaim] dari [Thalhah] dari [Al Hasan Al Bashri] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sedekah yang paling utama adalah seorang muslim yang mempelajari satu disiplin ilmu kemudian mengajarkannya kepada saudaranya sesama muslim.\""},"208":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُوَيْدُ بْنُ عَمْرٍو عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ شُعَيْبِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِيهِ قَالَمَا رُئِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مُتَّكِئًا قَطُّ وَلَا يَطَأُ عَقِبَيْهِ رَجُلَانِقَالَ أَبُو الْحَسَنِ وَحَدَّثَنَا حَازِمُ بْنُ يَحْيَى حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَجَّاجِ السَّامِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَبُو الْحَسَنِ وَحَدَّثَنَا إِبْرَاهِيمُ بْنُ نَصْرٍ الْهَمْدَانِيُّ صَاحِبُ الْقَفِيزِ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Suwaid bin 'Amru] dari [Hammad bin Salamah] dari [Tsabit] dari [Syu'aib bin Abdullah bin 'Amru] dari [Bapaknya] ia berkata; \"Tidak pernah sama sekali Rasulullah shallallahu 'alaihi wasallam terlihat makan sambil bersandar dan tidak pernah dua orang menginjak kedua tumitnya (Nabi tidak pernah berjalan di depan hingga tumitnya terinjak orang lain dari belakang, pent).\" Abu Al Hasan berkata; Telah menceritakan kepada kami Hazim bin Yahya berkata, telah menceritakan kepada kami Ibrahim Ibnul Hajjaj As Sami. Abu Al Hasan berkata; Telah menceritakan kepada kami Ibrahim bin Nashr Al Hamdani -pemilik takaran- berkata, telah menceritakan kepada kami Musa bin Isma'il berkata, telah menceritakan kepada kami Hammad bin Salamah."},"209":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا مُعَانُ بْنُ رِفَاعَةَ حَدَّثَنِي عَلِيُّ بْنُ يَزِيدَ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ أَبِي أُمَامَةَ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمٍ شَدِيدِ الْحَرِّ نَحْوَ بَقِيعِ الْغَرْقَدِ وَكَانَ النَّاسُ يَمْشُونَ خَلْفَهُ فَلَمَّا سَمِعَ صَوْتَ النِّعَالِ وَقَرَ ذَلِكَ فِي نَفْسِهِ فَجَلَسَ حَتَّى قَدَّمَهُمْ أَمَامَهُ لِئَلَّا يَقَعَ فِي نَفْسِهِ شَيْءٌ مِنْ الْكِبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abul Mughirah] berkata, telah menceritakan kepada kami [Mu'an bin Rifa'ah] berkata, telah menceritakan kepadaku [Ali bin Yazid] ia berkata; aku mendengar [Al Qasim bin Abdurrahman] menceritakan dari [Abu Umamah] ia berkata; \"Pada satu hari yang sangat panas Rasulullah shallallahu 'alaihi wasallam melewati pekuburan Baqi' Al Gharqad, sementara para sahabat berjalan di belakangnya. Tatkala beliau mendengar suara sandal, jiwanya tersentuh, kemudian beliau duduk seraya menyuruh agar mereka berjalan di depannya agar tidak timbul di dalam jiwanya sesuatu perasaan sombong.\""},"210":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَشَى مَشَى أَصْحَابُهُ أَمَامَهُ وَتَرَكُوا ظَهْرَهُ لِلْمَلَائِكَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Al Aswad bin Qais] dari [Nubaih al 'Anazi] dari [Jabir bin Abdullah] ia berkata; \"adalah Nabi shallallahu 'alaihi wasallam jika berjalan, maka para sahabat beliau berjalan di depan beliau, dan mereka membiarkan punggung beliau untuk para malaikat.\""},"211":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ بْنِ رَاشِدٍ الْمِصْرِيُّ حَدَّثَنَا الْحَكَمُ بْنُ عَبْدَةَ عَنْ أَبِي هَارُونَ الْعَبْدِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَأْتِيكُمْ أَقْوَامٌ يَطْلُبُونَ الْعِلْمَ فَإِذَا رَأَيْتُمُوهُمْ فَقُولُوا لَهُمْ مَرْحَبًا مَرْحَبًا بِوَصِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقْنُوهُمْقُلْتُ لِلْحَكَمِ مَا اقْنُوهُمْ قَالَ عَلِّمُوهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Harits bin Rasyid Al Mishri] berkata, telah menceritakan kepada kami [Al Hakam bin 'Abdah] dari [Abu Harun Al 'Abdi] dari [Abu Sa'id Al Khudlri] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Akan datang kepada kalian orang-orang yang menuntut ilmu. Jika kalian melihat mereka maka ucapkanlah; 'selamat datang, selamat datang dengan wasiat Rasulullah shallallahu 'alaihi wasallam' dan cukupilah mereka.\" Aku bertanya kepada Al Hakam; \"Apa yang dimaksud dengan cukupilah?\" ia menjawab; \"Ajarilah.\""},"212":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا الْمُعَلَّى بْنُ هِلَالٍ عَنْ إِسْمَعِيلَ قَالَدَخَلْنَا عَلَى الْحَسَنِ نَعُودُهُ حَتَّى مَلَأْنَا الْبَيْتَ فَقَبَضَ رِجْلَيْهِ ثُمَّ قَالَ دَخَلْنَا عَلَى أَبِي هُرَيْرَةَ نَعُودُهُ حَتَّى مَلَأْنَا الْبَيْتَ فَقَبَضَ رِجْلَيْهِ ثُمَّ قَالَ دَخَلْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى مَلَأْنَا الْبَيْتَ وَهُوَ مُضْطَجِعٌ لِجَنْبِهِ فَلَمَّا رَآنَا قَبَضَ رِجْلَيْهِ ثُمَّ قَالَ إِنَّهُ سَيَأْتِيكُمْ أَقْوَامٌ مِنْ بَعْدِي يَطْلُبُونَ الْعِلْمَ فَرَحِّبُوا بِهِمْ وَحَيُّوهُمْ وَعَلِّمُوهُمْ قَالَ فَأَدْرَكْنَا وَاللَّهِ أَقْوَامًا مَا رَحَّبُوا بِنَا وَلَا حَيَّوْنَا وَلَا عَلَّمُونَا إِلَّا بَعْدَ أَنْ كُنَّا نَذْهَبُ إِلَيْهِمْ فَيَجْفُونَا","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Al Mu'alla bin Hilal] dari [Isma'il] ia berkata; Kami mengunjungi [Al Hasan] untuk menjenguknya, sehingga kami memadati rumahnya, maka dia melipat kedua kakinya dan berkata; Kami mengunjungi [Abu Hurairah] untuk menjenguknya hingga kami memenuhi rumahnya, maka ia pun melipat kedua kakinya seraya berkata; Kami mengunjungi Rasulullah shallallahu 'alaihi wasallam hingga kami memenuhi rumahnya, sementara beliau berbaring di atas rusuknya. Maka ketika melihat kami, beliau melipat kedua kakinya kemudian bersabda: \"Sesungguhnya sepeninggalku nanti akan datang kepada kalian orang-orang yang menuntut ilmu, maka sambutlah mereka, ucapkan salam kepada mereka dan ajarilah mereka.\" Al Hasan berkata; \"Demi Allah, kami menjumpai sekelompok orang, mereka tidak menyambut kami, tidak mengucapkan salam kepada kami dan tidak mengajarkan kepada kami, kecuali setelah kami pergi kapada mereka dan merekapun berpaling dari kami.\" "},"213":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ الْعَنْقَزِيُّ أَنْبَأَنَا سُفْيَانُ عَنْ أَبِي هَارُونَ الْعَبْدِيِّ قَالَكُنَّا إِذَا أَتَيْنَا أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَ مَرْحَبًا بِوَصِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا إِنَّ النَّاسَ لَكُمْ تَبَعٌ وَإِنَّهُمْ سَيَأْتُونَكُمْ مِنْ أَقْطَارِ الْأَرْضِ يَتَفَقَّهُونَ فِي الدِّينِ فَإِذَا جَاءُوكُمْ فَاسْتَوْصُوا بِهِمْ خَيْرًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami ['Amru bin Muhammad Al 'Anqazi] berkata, telah memberitakan kepada kami [Sufyan] dari [Abu Harun Al 'Abdi] ia berkata; Jika kami mendatangi [Abu Sa'id Al Khudri], ia berkata; Selamat datang dengan wasiat Rasulullah shallallahu 'alaihi wasallam, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Sesungguhnya manusia mengikuti kalian, mereka akan mendatangi kalian dari penjuru dunia untuk memperdalam agama. Maka jika mereka datang kepada kalian berilah nasihat kebaikan kepada mereka.\""},"214":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ مِنْ دُعَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ دُعَاءٍ لَا يُسْمَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] ia berkata; Salah satu do'a Nabi shallallahu 'alaihi wasallam adalah: \"Ya Allah, aku berlindung kepada-Mu dari ilmu yang tidak bermanfaat, dari do'a yang tidak didengar dan dari hati yang tidak khusyuk serta dari jiwa yang tak pernah merasa puas.\" "},"215":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ ثَابِتٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ انْفَعْنِي بِمَا عَلَّمْتَنِي وَعَلِّمْنِي مَا يَنْفَعُنِي وَزِدْنِي عِلْمًا وَالْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Musa bin Ubaidah] dari [Muhammad bin Tsabit] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, berilah aku manfa'at dengan ilmu yang Engkau ajarkan kepadaku, ajarilah aku sesuatu yang bermanfaat bagiku, dan tambahkanlah ilmu kepadaku, segala puji bagi Allah atas setiap kondisi.\""},"216":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ وَسُرَيْجُ بْنُ النُّعْمَانِ قَالَا حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَعْمَرٍ أَبِي طُوَالَةَ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَلَّمَ عِلْمًا مِمَّا يُبْتَغَى بِهِ وَجْهُ اللَّهِ لَا يَتَعَلَّمُهُ إِلَّا لِيُصِيبَ بِهِ عَرَضًا مِنْ الدُّنْيَا لَمْ يَجِدْ عَرْفَ الْجَنَّةِ يَوْمَ الْقِيَامَةِ يَعْنِي رِيحَهَاقَالَ أَبُو الْحَسَنِ أَنْبَأَنَا أَبُو حَاتِمٍ حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] dan [Suraij bin An Nu'man] keduanya berkata; telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Abdullah bin Abdurrahman bin Ma'mar Abu Thuwalah] dari [Sa'id bin Yasar] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menuntut ilmu yang seharusnya untuk Allah, namun ia tidak menuntutnya kecuali untuk mencari dunia, maka pada hari kiamat ia tidak akan mendapatkan bau surga.\" Abu Al Hasan berkata; telah memberitakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Sa'id bin Manshur berkata, telah menceritakan kepada kami Fulaih bin Sulaim lalu ia menyebutkan sebagaimana hadits diatas.\""},"217":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَمَّادُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا أَبُو كَرِبٍ الْأَزْدِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ طَلَبَ الْعِلْمَ لِيُمَارِيَ بِهِ السُّفَهَاءَ أَوْ لِيُبَاهِيَ بِهِ الْعُلَمَاءَ أَوْ لِيَصْرِفَ وُجُوهَ النَّاسِ إِلَيْهِ فَهُوَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Hammad bin Abdurrahman] berkata, telah menceritakan kepada kami [Abu Kuraib Al 'Azdi] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menuntut ilmu untuk meremehkan orang-orang bodoh, atau untuk mendebat para ulama, atau untuk menarik perhatian manusia, maka ia akan masuk ke dalam neraka.\""},"218":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَنْبَأَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَعَلَّمُوا الْعِلْمَ لِتُبَاهُوا بِهِ الْعُلَمَاءَ وَلَا لِتُمَارُوا بِهِ السُّفَهَاءَ وَلَا تَخَيَّرُوا بِهِ الْمَجَالِسَ فَمَنْ فَعَلَ ذَلِكَ فَالنَّارُ النَّارُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah memberitakan kepada kami [Yahya bin Ayyub] dari [Ibnu Juraij] dari [Abu Zubair] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mempelajari ilmu untuk mendebat para ulama, meremehkan orang-orang bodoh dan menghiasi majelis. Barangsiapa melakukan hal itu, maka baginya neraka, baginya neraka.\""},"219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ الْكِنْدِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أُنَاسًا مِنْ أُمَّتِي سَيَتَفَقَّهُونَ فِي الدِّينِ وَيَقْرَءُونَ الْقُرْآنَ وَيَقُولُونَ نَأْتِي الْأُمَرَاءَ فَنُصِيبُ مِنْ دُنْيَاهُمْ وَنَعْتَزِلُهُمْ بِدِينِنَا وَلَا يَكُونُ ذَلِكَ كَمَا لَا يُجْتَنَى مِنْ الْقَتَادِ إِلَّا الشَّوْكُ كَذَلِكَ لَا يُجْتَنَى مِنْ قُرْبِهِمْ إِلَّاقَالَ مُحَمَّدُ بْنُ الصَّبَّاحِ كَأَنَّهُ يَعْنِي الْخَطَايَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Al Walid bin Muslim] dari [Yahya bin Abdurrahman Al Kindi] dari [Ubaidullah bin Abu Burdah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara umatku akan ada sekelompok manusia yang mempelajari agama dan membaca Al Qur`an, berkata; 'Marilah kita datangi para penguasa agar mendapatkan harta-harta mereka lalu kita menjauhi mereka dengan membawa agama kita.' Dan itu tidak berguna sebagaimana pohon duri tidaklah akan menghasilkan kecuali duri. Begitu juga dekatnya dengan mereka tidaklah menghasilkan selain, Muhammad bin Ash Shabbah berkata; \"dosa-dosa.\" "},"220":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ حَدَّثَنَا عَمَّارُ بْنُ سَيْفٍ عَنْ أَبِي مُعَاذٍ الْبَصْرِيِّ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ عَنْ عَمَّارِ بْنِ سَيْفٍ عَنْ أَبِي مُعَاذٍ الْبَصْرِيِّ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ جُبِّ الْحُزْنِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا جُبُّ الْحُزْنِ قَالَ وَادٍ فِي جَهَنَّمَ تَعَوَّذُ مِنْهُ جَهَنَّمُ كُلَّ يَوْمٍ أَرْبَعَ مِائَةِ مَرَّةٍ قِيلَ يَا رَسُولَ اللَّهِ مَنْ يَدْخُلُهُ قَالَ أُعِدَّ لِلْقُرَّاءِ الْمُرَائِينَ بِأَعْمَالِهِمْ وَإِنَّ مِنْ أَبْغَضِ الْقُرَّاءِ إِلَى اللَّهِ الَّذِينَ يَزُورُونَ الْأُمَرَاءَقَالَ الْمُحَارِبِيُّ الْجَوَرَةَ قَالَ أَبُو الْحَسَنِ حَدَّثَنَا حَازِمُ بْنُ يَحْيَى حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ نُمَيْرٍ قَالَا حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ مُعَاوِيَةَ النَّصْرِيِّ وَكَانَ ثِقَةً ثُمَّ ذَكَرَ الْحَدِيثَ نَحْوَهُ بِإِسْنَادِهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو غَسَّانَ مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَمَّارُ بْنُ سَيْفٍ عَنْ أَبِي مُعَاذٍ قَالَ مَالِكُ بْنُ إِسْمَاعِيلَ قَالَ عَمَّارٌ لَا أَدْرِي مُحَمَّدٌ أَوْ أَنَسُ بْنُ سِيرِينَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Ismail] keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Muhammad Al Muharibi] berkata, telah menceritakan kepada kami [Ammar bin Saif] dari [Abu Mu'adz Al Bashri]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ishaq bin Manshur] dari [Ammar bin Saif] dari [Abu Mu'adz Al Bashri] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlindunglah kalian kepada Allah dari Jubbul Huzn.\" Para sahabat bertanya: \"Ya Rasulullah, apa yang dimaksud dengan Jubbul Huzn?\" beliau menjawab: \"Sebuah lembah di neraka jahanam. Dan jahanam berlindung darinya empat ratus kali setiap hari.\" Beliau ditanya; \"Ya Rasulullah, siapakah yang akan memasukinya?\" beliau menjawab: \"Ia dipersiapkan bagi para Qori' yang berlaku riya` dengan amalan-amalannya. Dan Qori' yang paling dimurkai Allah adalah orang-orang yang mengunjungi para penguasa.\" Al Muharibi Al Jaurah berkata; Abul Hasan berkata; telah menceritakan kepada kami Hazim bin Yahya berkata, telah menceritakan kepada kami Abu Bakr bin Abu Syaibah dan Muhammad bin Numair keduanya berkata; telah menceritakan kepada kami Ibnu Numair dari Mu'awiyah An Nashri dan ia merupakan seorang yang terpercaya, kemudian dia menyebutkan hadits serupa dengan sanadnya; telah menceritakan kepada kami Ibrahim bin Nashr berkata, telah menceritakan kepada kami Abu Ghassan Malik bin Ismail berkata, telah menceritakan kepada kami 'Ammar bin Saif dari Abu Mu'adz ia berkata; Malik bin Isma'il berkata; 'Ammar berkata; \"Aku tidak tahu apakah ia Muhammad atau Anas bin Sirin.\""},"221":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَالْحُسَيْنُ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُعَاوِيَةَ النَّصْرِيِّ عَنْ نَهْشَلٍ عَنْ الضَّحَّاكِ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَلَوْ أَنَّ أَهْلَ الْعِلْمِ صَانُوا الْعِلْمَ وَوَضَعُوهُ عِنْدَ أَهْلِهِ لَسَادُوا بِهِ أَهْلَ زَمَانِهِمْ وَلَكِنَّهُمْ بَذَلُوهُ لِأَهْلِ الدُّنْيَا لِيَنَالُوا بِهِ مِنْ دُنْيَاهُمْ فَهَانُوا عَلَيْهِمْ سَمِعْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَعَلَ الْهُمُومَ هَمًّا وَاحِدًا هَمَّ آخِرَتِهِ كَفَاهُ اللَّهُ هَمَّ دُنْيَاهُ وَمَنْ تَشَعَّبَتْ بِهِ الْهُمُومُ فِي أَحْوَالِ الدُّنْيَا لَمْ يُبَالِ اللَّهُ فِي أَيِّ أَوْدِيَتِهَا هَلَكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Al Hussain bin Abdurrahman] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Mu'awiyah An Nashri] dari [Nahsyal] dari [Adl Dlahak] dari [Al Aswad bin Yazid] dari [Abdullah bin Mas'ud] ia berkata; \"Seandainya ahlul ilmu menjaga ilmu dan meletakkannya pada ahlinya, niscaya akan memelihara penduduk zamannya. Akan tetapi mereka mencurahkannya kepada ahli dunia untuk memperoleh harta-harta mereka, sehingga mereka merendahkan diri di hadapan ahli dunia. Aku mendengar Nabi kalian shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjadikan cita-citanya untuk menggapai akhirat, maka Allah akan mencukupkan baginya dunianya. Dan barangsiapa cita-citanya hanya untuk mencari dunia, maka Allah tidak peduli di lembah mana dia binasa.\""},"222":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ وَأَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ الْهُنَائِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ الْهُنَائِيُّ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ خَالِدِ بْنِ دُرَيْكٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ طَلَبَ الْعِلْمَ لِغَيْرِ اللَّهِ أَوْ أَرَادَ بِهِ غَيْرَ اللَّهِ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Zaid bin Ahzam] dan [Abu Badr Abbad Ibnul Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin 'Abbad Al Huna`i] berkata, telah menceritakan kepada kami [Ali Ibnul Mubarak Al Huna`i] dari [Ayub As Sikhtiyani] dari [Khalid bin Duraik] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mencari ilmu untuk selain Allah, atau dengannya ia ingin mencari selain (ridla) Allah, maka hendaklah ia menyiapkan tempat duduknya di neraka.\" "},"223":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَاصِمٍ الْعَبَّادَانِيُّ حَدَّثَنَا بَشِيرُ بْنُ مَيْمُونٍ قَالَ سَمِعْتُ أَشْعَثَ بْنَ سَوَّارٍ عَنْ ابْنِ سِيرِينَ عَنْ حُذَيْفَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَعَلَّمُوا الْعِلْمَ لِتُبَاهُوا بِهِ الْعُلَمَاءَ أَوْ لِتُمَارُوا بِهِ السُّفَهَاءَ أَوْ لِتَصْرِفُوا وُجُوهَ النَّاسِ إِلَيْكُمْ فَمَنْ فَعَلَ ذَلِكَ فَهُوَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Ashim Al 'Abbadani] berkata, telah menceritakan kepada kami [Basyir bin Maimun] ia berkata; aku mendengar [Asy'ats bin Sawwar] dari [Ibnu Sirin] dari [Hudzaifah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mempelajari ilmu untuk mendebat ulama, merendahkan orang-orang bodoh dan menarik perhatian manusia. Maka barangsiapa melakukannya ia akan berada di neraka.\""},"224":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَنْبَأَنَا وَهْبُ بْنُ إِسْمَعِيلَ الْأَسَدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْمَقْبُرِيُّ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَلَّمَ الْعِلْمَ لِيُبَاهِيَ بِهِ الْعُلَمَاءَ وَيُجَارِيَ بِهِ السُّفَهَاءَ وَيَصْرِفَ بِهِ وُجُوهَ النَّاسِ إِلَيْهِ أَدْخَلَهُ اللَّهُ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah memberitakan kepada kami [Wahb bin Isma'il Al Asadi] berkata, telah menceritakan kepada kami [Abdullah bin Sa'id Al Maqburi] dari [Kakeknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempelajari ilmu untuk mendebat ulama, merendahkan orang-orang bodoh serta memalingkan perhatian manusia kepadanya, maka Allah akan memasukkannya ke dalam jahannam.\""},"225":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا عِمَارَةُ بْنُ زَاذَانَ حَدَّثَنَا عَلِيُّ بْنُ الْحَكَمِ حَدَّثَنَا عَطاَءٌ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ رَجُلٍ يَحْفَظُ عِلْمًا فَيَكْتُمُهُ إِلَّا أُتِيَ بِهِ يَوْمَ الْقِيَامَةِ مُلْجَمًا بِلِجَامٍ مِنْ النَّارِقَالَ أَبُو الْحَسَنِ أَيِ الْقَطَّانُ وَحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عِمَارَةُ بْنُ زَاذَانَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami ['Imarah bin Zadzan] berkata, telah menceritakan kepada kami [Ali bin Al Hakam] berkata, telah menceritakan kepada kami ['Atho`] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang lelaki menghapal suatu ilmu kemudian menyembunyikannya, kecuali pada hari kiamat ia akan didatangkan dalam kondisi dicambuk dengan cambuk api neraka.\" Abul Hasan -yaitu Al Qaththan- berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abul Walid berkata, telah menceritakan kepada kami 'Imarah bin Zadzan lalu ia menyebutkan hadits yang serupa."},"226":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ مُحَمَّدُ بْنُ عُثْمَانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِأَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ وَاللَّهِ لَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ تَعَالَى مَا حَدَّثْتُ عَنْهُ يَعْنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا أَبَدًا لَوْلَا قَوْلُ اللَّهِ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلَ اللَّهُ مِنْ الْكِتَابِ }إِلَى آخِرِ الْآيَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani Muhammad bin Utsman] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Al Maqburi] dari [Abdurrahman bin Hurmuz Al A'raj] bahwasanya ia mendengar [Abu Hurairah] berkata; \"Demi Allah, kalau bukan karena dua ayat dalam kitabullah aku tidak akan meriwayatkan sesuatu pun darinya, yakni dari Nabi shallallahu 'alaihi wasallam selamanya. Kalau bukan karena firman Allah: \"Sesungguhnya orang-orang yang menyembunyikan apa yang telah diturunkan Allah, yaitu Al Kitab..\" hingga akhir dua ayat."},"227":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ أَبِي السَّرِيِّ الْعَسْقَلَانِيُّ حَدَّثَنَا خَلَفُ بْنُ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّرِيِّ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَعَنَ آخِرُ هَذِهِ الْأُمَّةِ أَوَّلَهَا فَمَنْ كَتَمَ حَدِيثًا فَقَدْ كَتَمَ مَا أَنْزَلَ اللَّهُ","id":"Telah menceritakan kepada kami [Al Husain bin Abu Sarri Al Asqalani] berkata, telah menceritakan kepada kami [Khalaf bin Tamim] dari [Abdullah bin Sarri] dari [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila penghujung umat ini telah melaknat pendahulunya, maka barangsiapa menyembunyikan satu hadits, berarti dia telah menyembunyikan apa yang telah diturunkan Allah.\" "},"228":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنِي عُمَرَ بْنُ سُلَيْمٍ حَدَّثَنَا يُوسُفُ بْنُ إِبْرَاهِيمَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سُئِلَ عَنْ عِلْمٍ فَكَتَمَهُ أُلْجِمَ يَوْمَ الْقِيَامَةِ بِلِجَامٍ مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar] berkata, telah menceritakan kepada kami [Al Haitsam bin Jamil] berkata, telah menceritakan kepadaku [Umar bin Sulaim] berkata, telah menceritakan kepada kami [Yusuf bin Ibrahim] ia berkata; Aku mendengar [Anas bin Malik] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ditanya tetang sutau ilmu lalu menyembunyikannya, maka pada hari kiamat ia akan dicambuk dengan cambuk dari neraka.\""},"229":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ حِبَّانَ بْنِ وَاقِدٍ الثَّقَفِيُّ أَبُو إِسْحَقَ الْوَاسِطِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَاصِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ دَابٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَتَمَ عِلْمًا مِمَّا يَنْفَعُ اللَّهُ بِهِ فِي أَمْرِ النَّاسِ أَمْرِ الدِّينِ أَلْجَمَهُ اللَّهُ يَوْمَ الْقِيَامَةِ بِلِجَامٍ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Isma'il bin Hibban bin Waqid Tsaqafi Abu Ishaq Al Wasithi] berkata, telah menceritakan kepada kami [Abdullah bin 'Ashim] berkata, telah menceritakan kepada kami [Muhammad bin Dab] dari [Shafwan bin Sulaim] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyembunyikan suatu ilmu yang Allah berikan kemanfaatan dengannya bagi urusan manusia dan dien, maka pada hari kiamat Allah akan mencambuknya dengan cambuk dari neraka.\""},"230":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَفْصِ بْنِ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ حَدَّثَنَا أَبُو إِبْرَاهِيمَ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْكَرَابِيسِيُّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سُئِلَ عَنْ عِلْمٍ فَكَتَمَهُ أُلْجِمَ يَوْمَ الْقِيَامَةِ بِلِجَامٍ مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Hafsh bin Hisyam bin Zaid bin Anas bin Malik] berkata, telah menceritakan kepada kami [Abu Ibrahim Isma'il bin Ibrahim Al Karasibi] dari [Ibnu 'Aun] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ditanya tentang suatu ilmu kemudian ia menyembunyikannya, maka pada hari kiamat ia akan dicambuk dengan cambuk dari neraka.\""},"231":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي رَيْحَانَةَ عَنْ سَفِينَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [isma'il bin Ibrahim] dari [Abu Raihanah] dari [Safinah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dengan satu mud air dan mandi dengan satu sha' air.\""},"232":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّ��َ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Hammam] dari [Qatadah] dari [Shafiah binti Syaibah] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dengan satu mud air dan mandi dengan satu sha' air.\""},"233":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Ar Rabi' bin Badr] berkata, telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dengan satu mud air dan mandi dengan satu sha' air.\""},"234":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُؤَمَّلِ بْنِ الصَّبَّاحِ وَعَبَّادُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا بَكْرُ بْنُ يَحْيَى بْنِ زَبَّانَ حَدَّثَنَا حِبَّانُ بْنُ عَلِيٍّ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْزِئُ مِنْ الْوُضُوءِ مُدٌّ وَمِنْ الْغُسْلِ صَاعٌ فَقَالَ رَجُلٌ لَا يُجْزِئُنَا فَقَالَ قَدْ كَانَ يُجْزِئُ مَنْ هُوَ خَيْرٌ مِنْكَ وَأَكْثَرُ شَعَرًا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Muammal bin Ash Shabbah] dan [Abbad bin Al Walid] keduanya berkata, telah menceritakan kepada kami [Bakr bin Yahya bin Zabban] berkata, telah menceritakan kepada kami [Hibban bin Ali] dari [Yazid bin Abu Ziyad] dari [Abdullah bin Muhammad bin 'Aqil bin Abu Thalib] dari [Bapaknya] dari [Kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu mud air cukup untuk berwudlu, dan satu sha' air cukup untuk mandi.\" Seorang laki-laki berkata: \"Itu tidak mencukupi kami! \" maka dia menjawab: \"Itu telah mencukupi bagi orang yang lebih baik dari dirimu dan lebih banyak rambutnya.\" Yakni Nabi shallallahu 'alaihi wasallam. "},"235":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ خَتَنُ الْمُقْرِئِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِيهِ أُسَامَةَ بْنِ عُمَيْرٍ الْهُذَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ صَلَاةً إِلَّا بِطُهُورٍ وَلَا يَقْبَلُ صَدَقَةً مِنْ غُلُولٍحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ بْنُ سَعِيدٍ وَشَبَابَةُ بْنُ سَوَّارٍ عَنْ شُعْبَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Bakr bin Khalaf Abu Busyr Khatan Al Muqri] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abul Malih bin Usamah] dari bapaknya [Usamah bin Umair Al Hudzaili] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menerima shalat kecuali dengan bersuci, dan tidak menerima sedekah dari harta curian.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaid bin Sa'id] berkata, telah menceritakan kepada kami [Syababah bin Sawwar] dari [Syu'bah] seperti hadits tersebut. "},"236":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ صَلَاةً إِلَّا بِطُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isma'il] dari [Simak]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Mush'ab bin Sa'd] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menerima shalat tanpa bersuci dan tidak menerima sedekah dari harta curian.\""},"237":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا أَبُو زُهَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سِنَانِ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقْبَلُ اللَّهُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Abu Zuhair] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Sinan bin Sa'd] dari [Anas bin Malik] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menerima shalat tanpa bersuci dan tidak menerima sedekah dari harta curian.\""},"238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَقِيلٍ حَدَّثَنَا الْخَلِيلُ بْنُ زَكَرِيَّا حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah menceritakan kepada kami [Muhammad bin Aqil] berkata, telah menceritakan kepada kami [Khalil bin Zakaria] berkata, telah menceritakan kepada kami [Hisyam bin Hassan] dari [Al Hassan] dari [Abu Bakrah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak akan menerima shalat tanpa bersuci dan tidak menerima sedekah dari harta curian.\""},"239":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Muhammad bin 'Aqil] dari [Muhammad Ibnul Hanafiah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembuka shalat adalah bersuci, dimulai dengan takbir dan diakhiri dengan salam.\""},"240":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ أَبِي سُفْيَانَ طَرِيفٍ السَّعْدِيِّ ح و حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي سُفْيَانَ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Abu Sufyan Tharif As Sa'di]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala`] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Abu Sufyan As Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudlri] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Pembuka shalat adalah bersuci, dimulai dengan takbir dan diakhiri dengan salam.\""},"241":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقِيمُوا وَلَنْ تُحْصُوا وَاعْلَمُوا أَنَّ خَيْرَ أَعْمَالِكُمْ الصَّلَاةَ وَلَا يُحَافِظُ عَلَى الْوُضُوءِ إِلَّا مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Tsauban] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beristiqamahlah kalian, dan sekali-kali kalian tidak akan dapat menghitungnya. Dan beramallah, sesungguhnya amalan kalian yang paling utama adalah shalat, dan tidak ada yang menjaga wudlu kecuali orang mukmin.\""},"242":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبِ بْنِ الشَّهِيدِ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقِيمُوا وَلَنْ تُحْصُوا وَاعْلَمُوا أَنَّ مِنْ أَفْضَلِ أَعْمَالِكُمْ الصَّلَاةَ وَلَا يُحَافِظُ عَلَى الْوُضُوءِ إِلَّا مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib bin Syahid] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Laits] dari [Mujahid] dari [Abdullah bin 'Amru] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beristiqamahlah kalian, dan sekali-kali kalian tidak akan dapat untuk menghitung. Ketahuilah, sesungguhnya amalan kalian yang paling utama adalah shalat, dan tidak ada yang menjaga wudlu kecuali orang mukmin.\""},"243":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي إِسْحَقُ بْنُ أَسِيدٍ عَنْ أَبِي حَفْصٍ الدِّمَشْقِيِّ عَنْ أَبِي أُمَامَةَ يَرْفَعُ الْحَدِيثَ قَالَاسْتَقِيمُوا وَنِعِمَّا إِنْ اسْتَقَمْتُمْ وَخَيْرُ أَعْمَالِكُمْ الصَّلَاةُ وَلَا يُحَافِظُ عَلَى الْوُضُوءِ إِلَّا مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah menceritakan kepada kami [Yahya bin Ayyub] berkata, telah menceritakan kepadaku [Ishaq bin Usaid] dari [Abu Hafsh Ad Dimasqi] dari [Abu Umamah] -dan ia memarfu'kan hadits ini-, ia berkata: \"Istiqamahlah kalian, sebaik-baik perkara adalah jika kalian beristiqamah. Sebaik-baik amalan kalian adalah shalat, dan tidak ada yang menjaga wudlu kecuali orang mukmin.\""},"244":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ أَخْبَرَنِي مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ أَخِيهِ أَنَّهُ أَخْبَرَهُ عَنْ جَدِّهِ أَبِي سَلَّامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِسْبَاغُ الْوُضُوءِ شَطْرُ الْإِيمَانِ وَالْحَمْدُ لِلَّهِ مِلْءُ الْمِيزَانِ وَالتَّسْبِيحُ وَالتَّكْبِيرُ مِلْءُ السَّمَاوَاتِ وَالْأَرْضِ وَالصَّلَاةُ نُورٌ وَالزَّكَاةُ بُرْهَانٌ وَالصَّبْرُ ضِيَاءٌ وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ كُلُّ النَّاسِ يَغْدُو فَبَائِعٌ نَفْسَهُ فَمُعْتِقُهَا أَوْ مُوبِقُهَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasqi] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] berkata, telah mengabarkan kepadaku [Mu'awiyah bin Salam] dari [Saudaranya] bahwasanya ia telah mengabarkan kepadanya, dari kakeknya [Abu Salam] dari [Abdurrahman bin Ghanm] dari [Abu Malik Al Asy'ari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menyempurnakan wudlu adalah setengah keimanan, al hamdulillah memenuhi timbangan, tasbih dan takbir memenuhi antara langit dan bumi, shalat adalah cahaya, zakat adalah bukti, sabar adalah sinar dan Al Qur`an adalah dalil untukmu atau atasmu. Setiap manusia beramal; ada yang membebaskan jiwanya (dari dosa) dan ada yang mencelakakan jiwanya (dengan dosa).\""},"245":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَدَكُمْ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْمَسْجِدَ لَا يَنْهَزُهُ إِلَّا الصَّلَاةُ لَمْ يَخْطُ خَطْوَةً إِلَّا رَفَعَهُ اللَّهُ عَزَّ وَجَلَّ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً حَتَّى يَدْخُلَ الْمَسْجِدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jika salah seorang dari kalian berwudlu kemudian membaguskan wudlunya, setelah itu datang ke masjid, dan tidak ada yang menggerakkannya untuk pergi kecuali shalat, maka tidaklah ia melangkah satu langkah kecuali dengannya Allah 'azza wajalla akan mengangkat derajat, dan menghapus kesalahannya hingga masuk ke dalam masjid.\""},"246":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنِي حَفْصُ بْنُ مَيْسَرَةَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ الصُّنَابِحِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ فَمَضْمَضَ وَاسْتَنْشَقَ خَرَجَتْ خَطَايَاهُ مِنْ فِيهِ وَأَنْفِهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَجَتْ خَطَايَاهُ مِنْ وَجْهِهِ حَتَّى يَخْرُجَ مِنْ تَحْتِ أَشْفَارِ عَيْنَيْهِ فَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ يَدَيْهِ فَإِذَا مَسَحَ بِرَأْسِهِ خَرَجَتْ خَطَايَاهُ مِنْ رَأْسِهِ حَتَّى تَخْرُجَ مِنْ أُذُنَيْهِ فَإِذَا غَسَلَ رِجْلَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ رِجْلَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ رِجْلَيْهِ وَكَانَتْ صَلَاتُهُ وَمَشْيُهُ إِلَى الْمَسْجِدِ نَافِلَةً","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepadaku [Hafsh bin Maisarah] berkata, telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abdullah Ash Shunabihi] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berwudlu lalu berkumur dan memasukkan air ke dalam hidung, maka dosa-dosanya akan keluar dari mulut dan hidungnya. Jika membasuh wajahnya maka dosa-dosanya akan keluar dari wajahnya hingga akan keluar dari ujung bulu matanya. Jika membasuh kedua tangannya maka dosa-dosanya akan keluar dari kedua tangannya. Jika mengusap kepalanya maka dosa-dosanya akan keluar dari kepalanya hingga keluar dari kedua telinganya. Jika membasuh kedua kakinya maka dosa-dosanya akan keluar dari kedua kakinya hingga keluar dari bawah kukunya. Sedangkan shalat dan jalannya menuju masjid adalah nafilah baginya.\""},"247":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا غُنْدَرٌ مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ يَزِيدَ بْنِ طَلْقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَبْدَ إِذَا تَوَضَّأَ فَغَسَلَ يَدَيْهِ خَرَّتْ خَطَايَاهُ مِنْ يَدَيْهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَّتْ خَطَايَاهُ مِنْ وَجْهِهِ فَإِذَا غَسَلَ ذِرَاعَيْهِ وَمَسَحَ بِرَأْسِهِ خَرَّتْ خَطَايَاهُ مِنْ ذِرَاعَيْهِ وَرَأْسِهِ فَإِذَا غَسَلَ رِجْلَيْهِ خَرَّتْ خَطَايَاهُ مِنْ رِجْلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Ghundar Muhammad bin ja'far] dari [Syu'bah] dari [Ya'la bin 'Atho`] dari [Yazid bin Thalq] dari [Abdurrahman Ibnul Bailamani] dari ['Amru bin 'Abasah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang hamba jika berwudlu dan membasuh kedua tangannya, maka dosa-dosanya akan keluar dari kedua tangannya. Jika ia membasuh wajahnya, maka dosa-dosanya akan keluar dari wajahnya. Jika ia membasuh kedua siku dan kepalanya, maka dosa-dosanya akan keluar dari kedua siku dan kepalanya. Dan jika ia membasuh kedua kakinya, maka dosa-dosanya akan keluar dari kedua kakinya.\""},"248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ زِرِّ بْنِ حُبَيْشٍ أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ قَالَقِيلَ يَا رَسُولَ اللَّهِ كَيْفَ تَعْرِفُ مَنْ لَمْ تَرَ مِنْ أُمَّتِكَ قَالَ غُرٌّ مُحَجَّلُونَ بُلْقٌ مِنْ آثَارِ الْوُضُوءِقَالَ أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا أَبُو الْوَلِيدِ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Abul Walid Hisyam bin Abdul Malik] berkata, telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Zirr bin Hubaisy] bahwa [Abdullah bin Mas'ud] berkata; Rasulullah ditanya, \"Bagaimana engkau tahu seseorang bukan termasuk dari umatmu?\" beliau menjawab: \"Wajahnya putih bercahaya karena bekas air wudlu.\" Abu Al Hasan Al Qaththan berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abul Walid lalu ia menyebutkan sebagaimana hadits diatas."},"249":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي شَقِيقُ بْنُ سَلَمَةَ حَدَّثَنِي حُمْرَانُ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ قَالَرَأَيْتُ عُثْمَانَ بْنَ عَفَّانَ قَاعِدًا فِي الْمَقَاعِدِ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَقْعَدِي هَذَا تَوَضَّأَ مِثْلَ وُضُوئِي هَذَا ثُمَّ قَالَ مَنْ تَوَضَّأَ مِثْلَ وُضُوئِي هَذَا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَغْتَرُّواحَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ حَدَّثَنِي حُمْرَانُ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim] berkata, telah menceritakan kepadaku [Syaqiq bin Salamah] berkata, telah menceritakan kepadaku [Humran] mantan budak Utsman bin Affan, ia berkata; Aku melihat [Utsman bin Affan] duduk di tempat duduk, lalu ia minta diambilkan air berwudlu dan berwudlu, kemudian berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam di tempat dudukku ini minta diambilkan air wudlu, lalu beliau berwudlu sebagaimana wudluku ini. Kemudian beliau bersabda: \"Barangsiapa berwudlu sebagaimana wudluku ini maka dosanya yang telah lalu akan diampuni.\" Dan beliau bersabda lagi: \"Janganlah kalian terpedaya.\" Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Habib] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Yahya] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim] berkata, telah menceritakan kepadaku [Isa bin Thalhah] berkata, telah menceritakan kepadaku [Humran] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits diatas tersebut."},"250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَأَبِي عَنْ الْأَعْمَشِ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ وَحُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَتَهَجَّدُ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Bapakku] dari [Al A'masy]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Hushain] dari [Abu Wa`il] dari [Hudzaifah] berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam bangun di waktu malam dan akan shalat beliau menggosok giginya dengan siwak.\""},"251":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dan [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak akan memberatkan umatku maka akan aku perintahkan mereka bersiwak setiap kali akan shalat.\""},"252":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَثَّامُ بْنُ عَلِيٍّ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِاللَّيْلِ رَكْعَتَيْنِ رَكْعَتَيْنِ ثُمَّ يَنْصَرِفُ فَيَسْتَاكُ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Atstsam bin Ali] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat malam dua raka'at-dua rakaaat, kemudian beliau keluar dan bersiwak.\""},"253":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي الْعَاتِكَةِ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَسَوَّكُوا فَإِنَّ السِّوَاكَ مَطْهَرَةٌ لِلْفَمِ مَرْضَاةٌ لِلرَّبِّ مَا جَاءَنِي جِبْرِيلُ إِلَّا أَوْصَانِي بِالسِّوَاكِ حَتَّى لَقَدْ خَشِيتُ أَنْ يُفْرَضَ عَلَيَّ وَعَلَى أُمَّتِي وَلَوْلَا أَنِّي أَخَافُ أَنْ أَشُقَّ عَلَى أُمَّتِي لَفَرَضْتُهُ لَهُمْ وَإِنِّي لَأَسْتَاكُ حَتَّى لَقَدْ خَشِيتُ أَنْ أُحْفِيَ مَقَادِمَ فَمِي","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib] berkata, telah menceritakan kepada kami [Utsman bin Abu 'Atikah] dari [Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian bersiwak, sesungguhnya siwak dapat membersihkan mulut dan menjadikan Rabb ridla. Tidaklah Jibril datang kepadaku kecuali menasihatiku untuk bersiwak hingga aku takut jika hal itu diwajibkan atasku dan umatku. Sekiranya aku tidak khawatir memberatkan umatku sungguh akan aku wajibkan mereka untuk bersiwak. Dan aku selalu bersiwak hingga aku khawatir gigi depanku terkikis.\""},"254":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَقُلْتُ أَخْبِرِينِي بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْدَأُ إِذَا دَخَلَ عَلَيْكِ قَالَتْ كَانَ إِذَا دَخَلَ يَبْدَأُ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Al Miqdam bin Syuraih bin Hani`] dari [Bapaknya] dari [Aisyah] ia berkata; Aku berkata; \"Kabarkanlah kepadaku apa yang pertama kali dilakukan oleh Nabi shallallahu 'alaihi wasallam ketika masuk menemuimu?\" Aisyah menjawab; \"Beliau selalu bersiwak jika akan masuk menemui aku.\""},"255":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا بَحْرُ بْنُ كَنِيزٍ عَنْ عُثْمَانَ بْنِ سَاجٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَإِنَّ أَفْوَاهَكُمْ طُرُقٌ لِلْقُرْآنِ فَطَيِّبُوهَا بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz] berkata, telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Bahr bin Kaniz] dari [Utsman bin Saj] dari [Sa'id bin Jubair] dari [Ali bin Abu Thalib] ia berkata: \"Sesungguhnya mulut-mulut kalian adalah jalan bagi Al Qur`an, maka harumkanlah dengan bersiwak.\""},"256":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفِطْرَةُ خَمْسٌ أَوْ خَمْسٌ مِنْ الْفِطْرَةِ الْخِتَانُ وَالِاسْتِحْدَادُ وَتَقْلِيمُ الْأَظْفَارِ وَنَتْفُ الْإِبِطِ وَقَصُّ الشَّارِبِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Al Musaiyib] dari [Abu Hurairah] berkata; Rasululah shallallahu 'alaihi wasallam bersabda; \"Fithrah itu ada lima -atau beliau mengatakan; lima dari fithrah- berkhitan, mencukur bulu kemaluan, memotong kuku, mencabut bulu ketiak dan mencukur kumis.\""},"257":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ طَلْقِ بْنِ حَبِيبٍ عَنْ أَبِي الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرٌ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ وَإِعْفَاءُ اللِّحْيَةِ وَالسِّوَاكُ وَالِاسْتِنْشَاقُ بِالْمَاءِ وَقَصُّ الْأَظْفَارِ وَغَسْلُ الْبَرَاجِمِ وَنَتْفُ الْإِبِطِ وَحَلْقُ الْعَانَةِ وَانْتِقَاصُ الْمَاءِ يَعْنِي الِاسْتِنْجَاءَقَالَ زَكَرِيَّا قَالَ مُصْعَبٌ وَنَسِيتُ الْعَاشِرَةَ إِلَّا أَنْ تَكُونَ الْمَضْمَضَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Zakaria bin Abu Za`idah] dari [Mush'ab bin Syaibah] dari [Thalq bin Habib] dari [Abu Az Zubair] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sepuluh dari sunah fitrah; mencukur kumis, memelihara janggut, bersiwak, memasukkan air ke dalam hidung, memotong kuku, membasuh ruas jari, mencabut bulu ketiak, mencukur bulu kemaluan dan beristinja` dengan air.\" Zakaria berkata; Mush'ab berkata; \"Aku lupa yang kesepuluh, namun yang pasti adalah berkumur-kumur.\""},"258":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَلَمَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ الْفِطْرَةِ الْمَضْمَضَةُ وَالِاسْتِنْشَاقُ وَالسِّوَاكُ وَقَصُّ الشَّارِبِ وَتَقْلِيمُ الْأَظْفَارِ وَنَتْفُ الْإِبْطِ وَالِاسْتِحْدَادُ وَغَسْلُ الْبَرَاجِمِ وَالِانْتِضَاحُ وَالِاخْتِتَانُحَدَّثَنَا جَعْفَرُ بْنُ أَحْمَدَ بْنِ عُمَرَ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Salamah bin Muhammad bin 'Ammar bin Yasir] dari ['Ammar bin Yasir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk dari fitrah adalah; berkumur-kumur, memasukkan air ke dalam hidung, bersiwak, memotong kumis, memotong kuku, mencabut bulu ketiak, mencukur bulu kemaluan, membasuh ruas jari, memercikkan air (pada kemaluan) dan khitan.\" Telah menceritakan kepada kami [Ja'far bin Ahmad bin Umar] berkata, telah menceritakan kepada kami [Affan bin Muslim] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] sebagaimana hadits diatas."},"259":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَوُقِّتَ لَنَا فِي قَصِّ الشَّارِبِ وَحَلْقِ الْعَانَةِ وَنَتْفِ الْإِبِطِ وَتَقْلِيمِ الْأَظْفَارِ أَنْ لَا نَتْرُكَ أَكْثَرَ مِنْ أَرْبَعِينَ لَيْلَةً","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Abu 'Imran Al Jauni] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memberikan kami waktu untuk memotong kumis, mencukur bulu kemaluan, mencabut bulu ketiak dan memotong kuku agar tidak lebih dari empat puluh malam.\""},"260":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ زَيْدِ بْنِ أَرْقَمَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ الْحُشُوشَ مُحْتَضَرَةٌ فَإِذَا دَخَلَ أَحَدُكُمْ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبُثِ وَالْخَبَائِثِحَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ الْعَتَكِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ ح و حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنَا عَبْدَةُ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْقَاسِمِ بْنِ عَوْفٍ الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [An Nadlr bin Anas] dari [Zaid bin Arqam] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kamar mandi banyak dihadiri oleh setan, maka jika salah seorang dari kalian ingin masuk hendaklah membaca: \"ALLAAHUMMA INNI A'UUDZU BIKA MINAL HUBUTSI WAL KHABA`ITS (Ya Allah, aku berlindung kepada-Mu dari ganguan setan laki-laki dan setan perempuan).\" Telah menceritakan kepada kami [Jamil Ibnul Hasan Al 'Ataki] berkata, telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Harun bin Ishaq] berkata, telah menceritakan kepada kami ['Abdah] berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Qasim bin Auf Asy Syaibani] dari [Zaid bin Arqam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, lalu dia menyebutkan sebagaimana hadits diatas.\""},"261":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْحَكَمُ بْنُ بَشِيرِ بْنِ سَلْمَانَ حَدَّثَنَا خَلَّادٌ الصَّفَّارُ عَنْ الْحَكَمِ النَّصَرِيِّ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي جُحَيْفَةَ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتْرُ مَا بَيْنَ الْجِنِّ وَعَوْرَاتِ بَنِي آدَمَ إِذَا دَخَلَ الْكَنِيفَ أَنْ يَقُولَ بِسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] berkata, telah menceritakan kepada kami [Al Hakam bin Basyir bin Salman] berkata, telah menceritakan kepada kami [Khallad Ash Shaffar] dari [Al Hakam An Nashari] dari [Abu Ishaq] dari [Abu Juhaifah] dari [Ali], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghalang antara jin dan aurat anak Adam adalah mengucapkan 'bismillah' ketika ingin masuk ke kamar mandi.\" "},"262":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ أَعُوذُ بِاللَّهِ مِنْ الْخُبُثِ وَالْخَبَائِثِ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata; Jika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam WC, beliau mengucapkan: \"A'UUDZU BIllAHI MINAL HUBUTSI WAL KHABA`ITS (Aku berlindung kepada Allah dari kejahatan setan laki-laki dan setan perempuan).\""},"263":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَعْجِزْ أَحَدُكُمْ إِذَا دَخَلَ مِرْفَقَهُ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الرِّجْسِ النَّجِسِ الْخَبِيثِ الْمُخْبِثِ الشَّيْطَانِ الرَّجِيمِقَالَ أَبُو الْحَسَنِ الْقَطَّانُ وَحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ فَذَكَرَ نَحْوَهُ وَلَمْ يَقُلْ فِي حَدِيثِهِ مِنْ الرِّجْسِ النَّجِسِ إِنَّمَا قَالَ مِنْ الْخَبِيثِ الْمُخْبِثِ الشَّيْطَانِ الرَّجِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah menceritakan kepada kami [Yahya bin Ayyub] dari [Ubaidullah bin Zahr] dari [Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian hendak masuk ke kamar mandi, maka jangan merasa lemah untuk mengucapkan; ALLAHUMMA INNI A'UUDZU BIKA MINAR RIJSIN NAJISIL KHABITSIL MUKHBITSISY SYAITHANIRRAJIIM (Ya Allah, aku berlindung kepada-Mu dari kotoran yang najis, buruk lagi membahayakan, yaitu setan yang terkutuk).\" Abul Hasan Al Qaththan berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Ibnu Abu Maryam lalu ia menyebutkan sebagaimana hadits tersebut. Hanya saja ia tidak menyebutkan di dalam haditsnya; \"Dari kotoran yang najis, \" ia hanya menyebutkan; \"yang buruk lagi membahayakan yaitu setan yang terkutuk.\""},"264":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا يُوسُفُ بْنُ أَبِي بُرْدَةَ قَالَ سَمِعْتُ أَبِي يَقُولُدَخَلْتُ عَلَى عَائِشَةَ فَسَمِعْتُهَا تَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مِنْ الْغَائِطِ قَالَ غُفْرَانَكَقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ أَخْبَرَنَا أَبُو حَاتِمٍ حَدَّثَنَا أَبُو غَسَّانَ النَّهْدِيُّ حَدَّثَنَا إِسْرَائِيلُ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Isra`il] berkata, telah menceritakan kepada kami [Yusuf bin Abu Burdah] ia berkata; Aku mendengar [ayahku] berkata; Aku mengunjungi [Aisyah], lalu aku mendengarnya berkata; \"Rasulullah shallallahu 'alaihi wasallam jika keluar dari dalam kamar kecil selalu mengucapkan: \"GHUFRAANAKA (Ya Allah aku memohon ampunan-Mu).\" Abu Al Hasan bin Salamah berkata; telah mengabarkan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abu Ghassan An Nahdi berkata, telah menceritakan kepada kami Isra`il sebagaimana hadits diatas.\""},"265":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ الْحَسَنِ وَقَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مِنْ الْخَلَاءِ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَذْهَبَ عَنِّي الْأَذَى وَعَافَانِي","id":"Telah menceritakan kepada kami [Harun bin Ishaq] berkata, telah menceritakan kepada kami [Abdurrahman Al Muharibi] dari [Isma'il bin Muslim] dari [Al Hasan] dan [Qatadah] dari [Anas bin Malik] ia berkata; \"Nabi shallallahu 'alaihi wasallam jika keluar dari tempat buang air besar selalu mengucapkan: \"ALHAMDULILLAAHILLADZII ADZHABA 'ANNIL ADZAA WA 'AAFAANII (Segala puji bagi Allah yang telah menghilangkan dariku rasa sakit dan menjaga kesehatanku).\""},"266":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِيهِ عَنْ خَالِدِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ الْبَهِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَذْكُرُ اللَّهَ عَزَّ وَجَلَّ عَلَى كُلِّ أَحْيَانِهِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Bapaknya] dari [Khalid bin Salamah] dari [Abdullah Al Bahi] dari [Urwah] dari [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu berdzikir (mengingat) kepada Allah 'azza wajalla disetiap saat.\""},"267":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ ابْنِ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ الْخَلَاءَ وَضَعَ خَاتَمَهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Hammam bin Yahya] dari [Ibnu Juraij] dari [Az Zuhri] dari [Anas bin Malik] ia berkata; \"Jika ingin masuk ke WC Nabi shallallahu 'alaihi wasallam selalu melepas cincinnya.\""},"268":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ أَشْعَثَ بْنِ عَبْدِ اللَّهِ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبُولَنَّ أَحَدُكُمْ فِي مُسْتَحَمِّهِ فَإِنَّ عَامَّةَ الْوَسْوَاسِ مِنْهُقَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ سَمِعْتُ مُحَمَّدَ بْنَ يَزِيدَ يَقُولُ سَمِعْتُ عَلِيَّ بْنَ مُحَمَّدٍ الطَّنَافِسِيَّ يَقُولُ إِنَّمَا هَذَا فِي الْحَفِيرَةِ فَأَمَّا الْيَوْمَ فَلَا فَمُغْتَسَلَاتُهُمْ الْجِصُّ وَالصَّارُوجُ وَالْقِيرُ فَإِذَا بَالَ فَأَرْسَلَ عَلَيْهِ الْمَاءَ لَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Asy'ats bin Abdullah] dari [Al Hasan] dari [Abdullah bin Mughaffal] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali salah seorang dari kalian kencing di tempat pemandiannya, sebab kebanyakan was-was muncul darinya.\" Abu Abdullah Ibnu Majah berkata; Aku mendengar Muhammad bin Yazid berkata; aku mendengar Ali bin Muhammad Ath Thanafusi berkata; \"Hanyasanya ini di dalam lubang. Adapun hari ini tidak seperti itu, karena tempat mandi mereka terbuat dari semen, kapur dan aspal. Jika ia kencing lalu menyiramnya dengan air maka itu tidak apa-apa.\""},"269":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ وَهُشَيْمٌ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ عَلَيْهَا قَائِمًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dan [Husyaim] dan [Waki'] dari [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mendatangi tempat pembuangan sampah suatu kaum lalu kencing dengan berdiri.\""},"270":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًاقَالَ شُعْبَةُ قَالَ عَاصِمٌ يَوْمَئِذٍ وَهَذَا الْأَعْمَشُ يَرْوِيهِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ وَمَا حَفِظَهُ فَسَأَلْتُ عَنْهُ مَنْصُورًا فَحَدَّثَنِيهِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari [Abu Wa`il] dari [Mughirah bin Syu'bah] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mendatangi tempat pembuangan sampah suatu kaum lalu kencing dengan berdiri.\" [Syu'bah] berkata; Ketika itu ['Ashim] berkata; \" [Al A'masy] meriwayatkannya dari [Abu Wa`il], dari [Hudzaifah] namun ia tidak menghafalnya. Lalu aku bertanya kepada [Manshur] tentang hadits tersebut, maka ia menceritakan hadits tersebut kepadaku dari [Abu Wa`il], dari [Hudzaifah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mendatangi tempat pembuangan sampah suatu kaum lalu kencing dengan berdiri."},"271":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسُوَيْدُ بْنُ سَعِيدٍ وَإِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ قَالُوا حَدَّثَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ قَائِمًا فَلَا تُصَدِّقْهُ أَنَا رَأَيْتُهُ يَبُولُ قَاعِدًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Suwaid bin Sa'id] dan [Isma'il bin Musa As Suddi] mereka berkata; telah menceritakan kepada kami [Syarik] dari [Miqdam bin Syuraih bin Hani`] dari [Bapaknya] dari [Aisyah] ia berkata; \"Barangsiapa menceritakan kepadamu bahwa Rasulullah shallallahu 'alaihi wasallam kencing dengan berdiri maka janganlah engkau membenarkannya, karena aku melihat beliau kencing dengan duduk.\""},"272":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي أُمَيَّةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبُولُ قَائِمًا فَقَالَ يَا عُمَرُ لَا تَبُلْ قَائِمًا فَمَا بُلْتُ قَائِمًا بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Abdul Karim bin Abu Umayyah] dari [Nafi'] dari [Ibnu Umar] dari [Umar] ia berkata; \"Ketika aku kencing dengan berdiri Rasulullah shallallahu 'alaihi wasallam melihatku, maka beliau pun menegurku: \"Wahai Umar, janganlah engkau kencing dengan berdiri.\" Maka semenjak itu aku tidak pernah kencing dengan berdiri lagi.\""},"273":{"ar":"حَدَّثَنَا يَحْيَى بْنُ الْفَضْلِ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَدِيُّ بْنُ الْفَضْلِ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبُولَ قَائِمًاسَمِعْتُ مُحَمَّدَ بْنَ يَزِيدَ أَبَا عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيَّ يَقُولُ قَالَ سُفْيَانُ الثَّوْرِيُّ فِي حَدِيثِ عَائِشَةَ أَنَا رَأَيْتُهُ يَبُولُ قَاعِدًا قَالَ الرَّجُلُ أَعْلَمُ بِهَذَا مِنْهَا قَالَ أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ وَكَانَ مِنْ شَأْنِ الْعَرَبِ الْبَوْلُ قَائِمًا أَلَا تَرَاهُ فِي حَدِيثِ عَبْدِ الرَّحْمَنِ ابْنِ حَسَنَةَ يَقُولُ قَعَدَ يَبُولُ كَمَا تَبُولُ الْمَرْأَةُ","id":"Telah menceritakan kepada kami [Yahya Ibnul Fadll] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami ['Adi Ibnul Fadll] dari [Ali bin Al Hakam] dari [Abu Nadlrah] dari [Jabir bin Abdullah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kencing sambil berdiri.\" Aku mendengar Muhammad bin Yazid Abu Abdullah berkata; aku mendengar Ahmad bin Abdurrahman Al Mahzumi berkata; Sufyan Ats Tsauri berkata tentang hadits Aisyah, \"Aku melihat beliau kencing dengan duduk\", laki-laki itu lebih tahu darinya tentang hal ini. Ahmad bin Abdurrahman berkata; \"Kebiasaan orang-orang Arab adalah kencing dengan berdiri. Apakah kamu tidak memperhatikan di dalam hadits Abdurrahman bin Hasanah, dia berkata; \"Beliau kencing sebagaimana seorang perempuan kencing.\""},"274":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ أَخْبَرَنِي أَبِيأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا بَالَ أَحَدُكُمْ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَلَا يَسْتَنْجِ بِيَمِينِهِحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Habib bin Abu Al 'Isyrin] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] berkata, telah menceritakan kepadaku [Abdullah bin Abu Qatadah] berkata, telah mengabarkan kepadaku [Bapakku] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \"Jika salah seorang dari kalian kencing maka janganlah memegang kemaluannya dengan tangan kanan dan jangan beristinja` dengan tangan kanan.\" Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Al-Walid bin Muslim] berkata, telah menceritakan kepada kami [Al-Auza'i] dengan jalan seperti hadits di atas."},"275":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الصَّلْتُ بْنُ دِينَارٍ عَنْ عُقْبَةَ بْنِ صُهْبَانَ قَالَ سَمِعْتُ عُثْمَانَ بْنَ عَفَّانَ يَقُولُمَا تَغَنَّيْتُ وَلَا تَمَنَّيْتُ وَلَا مَسِسْتُ ذَكَرِي بِيَمِينِي مُنْذُ بَايَعْتُ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ash Shalt bin Dinar] dari ['Uqbah bin Shubhan] berkata; Aku mendengar [Utsman bin Affan] berkata: \"Semenjak aku membai'at Rasulullah shallallahu 'alaihi wasallam dengan tanganku, aku tidak pernah menyanyi, tidak pernah berangan-angan dan tidak pernah memegang kemaluanku dengan tangan kananku.\" "},"276":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ وَعَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَطَابَ أَحَدُكُمْ فَلَا يَسْتَطِبْ بِيَمِينِهِ لِيَسْتَنْجِ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dan [Abdullah bin Raja` Al Makki] dari [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian beristinja` maka janganlah menggunakan tangan kanan, hendaklah ia beristinja` dengan menggunakan tangan kirinya.\""},"277":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَنَا لَكُمْ مِثْلُ الْوَالِدِ لِوَلَدِهِ أُعَلِّمُكُمْ إِذَا أَتَيْتُمْ الْغَائِطَ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا وَأَمَرَ بِثَلَاثَةِ أَحْجَارٍ وَنَهَى عَنْ الرَّوْثِ وَالرِّمَّةِ وَنَهَى أَنْ يَسْتَطِيبَ الرَّجُلُ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedudukanku bagi kalian adalah seperti seorang bapak kepada anaknya, aku akan mengajari kalian; jika kalian ingin buang hajat maka janganlah menghadap kiblat atau membelakanginya.\" Beliau memerintahkan untuk beristinja` dengan tiga butir batu dan melarang menggunakan kotoran hewan dan tulang. Dan beliau juga melarang seorang laki-laki cebok dengan menggunakan tangan kanannya."},"278":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ زُهَيْرٍ عَنْ أَبِي إِسْحَقَ قَالَ لَيْسَ أَبُو عُبَيْدَةَ ذَكَرَهُ وَلَكِنْ عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى الْخَلَاءَ فَقَالَ ائْتِنِي بِثَلَاثَةِ أَحْجَارٍ فَأَتَيْتُهُ بِحَجَرَيْنِ وَرَوْثَةٍ فَأَخَذَ الْحَجَرَيْنِ وَأَلْقَى الرَّوْثَةَ وَقَالَ هِيَ رِجْسٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Zuhair] dari [Abu Ishaq] ia berkata; bukan Abu Ubaidah yang dia sebutkan, tetapi [Abdurrahman bin Al Aswad] dari [Al Aswad] dari [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam buang air besar, lalu beliau berkata: \"Ambilkan aku tiga batu.\" Maka aku pun mengambilkannya dua batu dan kotoran hewan. Kemudian beliau mengambil dua batu dan melemparkan kotoran hewan seraya bersabda: \"Itu kotor.\" "},"279":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِي خُزَيْمَةَ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الِاسْتِنْجَاءِ ثَلَاثَةُ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] semuanya dari [Hisyam bin Urwah] dari [Abu Khuzaimah] dari [Umarah bin Khuzaimah] dari [Khuzaimah bin Tsabit] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda berkenaan dengan istinja`: \"Hendaklah menggunakan tiga batu dan tanpa dengan menggunakan kotoran.\" "},"280":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَلْمَانَ قَالَقَالَ لَهُ بَعْضُ الْمُشْرِكِينَ وَهُمْ يَسْتَهْزِئُونَ بِهِ إِنِّي أَرَى صَاحِبَكُمْ يُعَلِّمُكُمْ كُلَّ شَيْءٍ حَتَّى الْخِرَاءَةِ قَالَ أَجَلْ أَمَرَنَا أَنْ لَا نَسْتَقْبِلَ الْقِبْلَةَ وَلَا نَسْتَنْجِيَ بِأَيْمَانِنَا وَلَا نَكْتَفِيَ بِدُونِ ثَلَاثَةِ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ وَلَا عَظْمٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Al Manshur] dan [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Salman] ia berkata; Orang-orang musyrik berkata kepadanya dengan maksud untuk melecehkan, mereka berkata; \"Sesungguhnya aku melihat sahabat kalian (Muhammad) mengajarkan kalian segala sesuatu hingga urusan buang air! \" Salman menjawab; \"Benar, ia memerintahkan kepada kami agar tidak menghadap kiblat dan tidak beristinja` dengan tangan kanan kami. Dan kami tidak boleh mencukupkan hanya dengan tiga batu, yang tidak termasuk di dalamnya kotoran dan tulang.\""},"281":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ الْحَارِثِ بْنِ جَزْءٍ الزُّبَيْدِيَّ يَقُولُأَنَا أَوَّلُ مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَبُولَنَّ أَحَدُكُمْ مُسْتَقْبِلَ الْقِبْلَةِ وَأَنَا أَوَّلُ مَنْ حَدَّثَ النَّاسَ بِذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abi Habib] bahwasanya dia mendengar [Abdullah bin Al Harits bin Jaz`i Az Zubaidi] berkata; aku adalah orang yang pertama mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"janganlah salah seorang dari kalian kencing dengan menghadap ke arah Kiblat.\" Dan akulah orang yang pertama kali menyampaikan hadits ini kepada orang-orang."},"282":{"ar":"حَدَّثَنَا أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ أَنَّهُ سَمِعَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْتَقْبِلَ الَّذِي يَذْهَبُ إِلَى الْغَائِطِ الْقِبْلَةَ وَقَالَ شَرِّقُوا أَوْ غَرِّبُوا","id":"Telah menceritakan kepada kami [Abu Ath Thahir Ahmad bin Amru bin As Sarh] berkata, telah memberitakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Atho`] Bahwasanya ia mendengar [Abu Ayyub Al Anshari] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang orang yang ingin buang hajat menghadap kiblat. Beliau bersabda: \"Menghadaplah ke timur atau ke barat.\""},"283":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى الْمَازِنِيُّ عَنْ أَبِي زَيْدٍ مَوْلَى الثَّعْلَبِيِّينَ عَنْ مَعْقِلِ بْنِ أَبِي مَعْقِلٍ الْأَسَدِيِّ وَقَدْ صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَقْبِلَ الْقِبْلَتَيْنِ بِغَائِطٍ أَوْ بِبَوْلٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] dari [Sulaiman bin Bilal] berkata, telah menceritakan kepadaku ['Amru bin Yahya Al Mazi] dari [Abu Zaid] mantan budak Ats Tsa'labiyyin, dari [Ma'qil bin Abu Ma'qil Al Asadi] -sahabat Nabi shallallahu 'alaihi wasallam- ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kita menghadap dua kiblat ketika buang air besar atau air kecil.\""},"284":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّأَنَّهُ شَهِدَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِغَائِطٍ أَوْ بِبَوْلٍقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ وَحَدَّثَنَاهُ عُمَيْرُ بْنُ مِرْدَاسٍ الدَّوْنَقِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ أَبُو يَحْيَى الْبَصْرِيُّ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانِي أَنْ أَشْرَبَ قَائِمًا وَأَنْ أَبُولَ مُسْتَقْبِلَ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Abbas bin Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Zubair] dari [Jabir bin Abdullah] berkata, telah mengabarkan kepadaku [Abu Sa'id Al Khudri] ia bersaksi kepada Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau melarang kami menghadap kiblat ketika buang air besar atau air kecil. Abul Hasan bin Salamah berkata; telah menceritakan kepada kami Umair bin Mirdas Ad Daunaqi berkata, telah menceritakan kepada kami Abdurrahman bin Ibrahim Abu Yahya Al Bashri berkata, telah menceritakan kepada kami Ibnu Lahi'ah dari Abu Az Zubair dari Jabir bahwasanya ia mendengar Abu Sa'id Al Khudri berkata; \"Rasulullah shallallahu 'alaihi wasallam melarangku minum dengan berdiri dan kencing dengan menghadap kiblat.\""},"285":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ أَخْبَرَهُ أَنَّ عَمَّهُ وَاسِعَ بْنَ حَبَّانَ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَيَقُولُ أُنَاسٌ إِذَا قَعَدْتَ لِلْغَائِطِ فَلَا تَسْتَقْبِلْ الْقِبْلَةَ وَلَقَدْ ظَهَرْتُ ذَاتَ يَوْمٍ مِنْ الْأَيَّامِ عَلَى ظَهْرِ بَيْتِنَا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدًا عَلَى لَبِنَتَيْنِ مُسْتَقْبِلَ بَيْتِ الْمَقْدِسِ هَذَا حَدِيثُ يَزِيدَ بْنِ هَارُونَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Habib] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Yahya bin Sa'id Al Anshari]. Dan menurut jalur Telah menceritakan kepada kami [Abu Bakr bin Khallad] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Yahya bin Sa'id] bahwa [Muhammad bin Yahya bin Habban] mengabarkan kepadanya, bahwa pamannya [Wasi' bin Habban] mengabarkannya, bahwa [Abdullah bin Umar] berkata; Orang-orang berkata; \"Jika engkau duduk buang hajat maka janganlah menghadap kiblat, \" sungguh suatu hari aku pernah naik di atas rumah kami, lalu aku melihat Rasulullah shallallahu 'alaihi wasallam duduk di atas dua batu bata menghadap baitul maqdis.\" Ini adalah hadits Yazid bin Harun."},"286":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عِيسَى الْحَنَّاطِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَنِيفِهِ مُسْتَقْبِلَ الْقِبْلَةِقَالَ عِيسَى فَقُلْتُ ذَلِكَ لِلشَّعْبِيِّ فَقَالَ صَدَقَ ابْنُ عُمَرَ وَصَدَقَ أَبُو هُرَيْرَةَ أَمَّا قَوْلُ أَبِي هُرَيْرَةَ فَقَالَ فِي الصَّحْرَاءِ لَا يَسْتَقْبِلْ الْقِبْلَةَ وَلَا يَسْتَدْبِرْهَا وَأَمَّا قَوْلُ ابْنِ عُمَرَ فَإِنَّ الْكَنِيفَ لَيْسَ فِيهِ قِبْلَةٌ اسْتَقْبِلْ فِيهِ حَيْثُ شِئْتَ قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ وَحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isa Al Hannath] dari [Nafi'] dari [Ibnu Umar] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menghadap kiblat di dalam WC nya.\" Isa berkata; Aku sampaikan hal itu kepada Asy Sya'bi, maka ia pun berkata; \"Benar apa yang dikatakan oleh Ibnu Umar dan Abu Hurairah.\" Adapun Abu Hurairah, ia berkata; \"Di padang pasir janganlah engkau menghadap kiblat atau membelakanginya.\" Sedangkan perkataan Ibnu Umar; \"Sesungguhnya WC tidak ada kiblatnya, maka menghadaplah sesukamu.\" "},"287":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ خَالِدِ بْنِ أَبِي الصَّلْتِ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عَائِشَةَ قَالَتْذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمٌ يَكْرَهُونَ أَنْ يَسْتَقْبِلُوا بِفُرُوجِهِمْ الْقِبْلَةَ فَقَالَ أُرَاهُمْ قَدْ فَعَلُوهَا اسْتَقْبِلُوا بِمَقْعَدَتِي الْقِبْلَةَقَالَ أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَا يَحْيَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُغِيرَةِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ خَالِدِ بْنِ أَبِي الصَّلْتِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Khalid Al Hadzdza`] dari [Khalid bin Abu Ash Shalt] dari [Irak bin Malik] dari [Aisyah] berkata; \"Suatu kaum yang tidak menyukai menghadap kiblat dengan kemaluannya (buang hajat) disebut-sebut di sisi Rasulullah shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Menurutku mereka telah melakukannya, hendaklah kalian menghadap kiblat (ketika buang hajat di dalam ruangan, pent).\" Abu Al Hasan Al Qaththan berkata; Telah menceritakan kepada kami Yahya bin Ubaid berkata, telah menceritakan kepada kami Abdul Aziz Ibnul Mughirah dari Khalid Al Hadzdza` dari Khalid bin Abu Ash Shalt sebagaimana hadits diatas.\""},"288":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِبَوْلٍ فَرَأَيْتُهُ قَبْلَ أَنْ يُقْبَضَ بِعَامٍ يَسْتَقْبِلُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] berkata; aku mendengar [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kami kencing menghadap kiblat. Namun setahun menjelang wafatnya, beliau kencing menghadap kiblat.\""},"289":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ عِيسَى بْنِ يَزْدَادَ الْيَمَانِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَالَ أَحَدُكُمْ فَلْيَنْتُرْ ذَكَرَهُ ثَلَاثَ مَرَّاتٍقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَمْعَةُ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Isa bin Yazdad Al Yamani] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian kencing hendaklah mengurut kemaluannya tiga kali.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Ali bin Abdul Aziz berkata, telah menceritakan kepada kami Abu Nu'aim berkata, telah menceritakan kepada kami Zam'ah, lalu ia menyebutkan sebagaimana dalam hadits tersebut."},"290":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَحْيَى التَّوْأَمِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبُولُ فَاتَّبَعَهُ عُمَرُ بِمَاءٍ فَقَالَ مَا هَذَا يَا عُمَرُ قَالَ مَاءٌ قَالَ مَا أُمِرْتُ كُلَّمَا بُلْتُ أَنْ أَتَوَضَّأَ وَلَوْ فَعَلْتُ لَكَانَتْ سُنَّةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdullah bin Yahya At Tau`amah] dari [Ibnu Abu Mulaikah] dari [Ibunya] dari [Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam pergi untuk buang air kecil, lalu Umar mengikutinya dengan membawa air. Beliau lalu bertanya: \"apa ini, hai Umar?\" Umar menjawab; \"Air, \" beliau bersabda: \"Setiap selesai kencing aku tidak diperintahkan berwudlu, sekiranya aku melakukannya maka itu akan menjadi sunnah.\""},"291":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي نَافِعُ بْنُ يَزِيدَ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ أَنَّ أَبَا سَعِيدٍ الْحِمْيَرِيَّ حَدَّثَهُ قَالَكَانَ مُعَاذُ بْنُ جَبَلٍ يَتَحَدَّثُ بِمَا لَمْ يَسْمَعْ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَسْكُتُ عَمَّا سَمِعُوا فَبَلَغَ عَبْدَ اللَّهِ بْنَ عَمْرٍو مَا يَتَحَدَّثُ بِهِ فَقَالَ وَاللَّهِ مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هَذَا وَأَوْشَكَ مُعَاذٌ أَنْ يَفْتِنَكُمْ فِي الْخَلَاءِ فَبَلَغَ ذَلِكَ مُعَاذًا فَلَقِيَهُ فَقَالَ مُعَاذٌ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو إِنَّ التَّكْذِيبَ بِحَدِيثٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِفَاقٌ وَإِنَّمَا إِثْمُهُ عَلَى مَنْ قَالَهُ لَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اتَّقُوا الْمَلَاعِنَ الثَّلَاثَ الْبَرَازَ فِي الْمَوَارِدِ وَالظِّلِّ وَقَارِعَةِ الطَّرِيقِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahab] berkata, telah mengabarkan kepadaku [Nafi' bin Yazid] dari [Haiwah bin Syuraih] bahwa [Abu Sa'id Al Himyari] menceritakan kepadanya, ia berkata; [Mu'adz bin Jabal] menceritakan hadits yang tidak didengar oleh para sahabat yang lainnya, dan diam terhadap apa yang mereka dengar. Maka sampailah kepada Abdullah bin 'Amru apa yang ia ceritakan, sehingga Abdullah bin 'Amru berkata; \"Demi Allah, aku tidak pernah mendengar Rasulullah shallallahu 'alaihi wasallam mengatakan seperti ini. Dan (aku kawatir) Mu'adz akan menciptakan fitnah untuk kalian dalam masalah buang air besar.\" Sampailah perkataan itu ke telinga Mu'adz sehingga dia menemuinya dan berkata; \"Hai Abdullah bin 'Amru, sesungguhnya mendustakan hadits Rasulullah merupakan tindakan nifak, dan dosanya ditanggung oleh orang yang mengucapkannya. Sungguh, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Takutlah kalian kepada tiga tempat yang dilaknat; buang air besar di tempat umum, di tempat berteduh, dan di tengah jalan.\" "},"292":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ زُهَيْرٍ قَالَ قَالَ سَالِمٌ سَمِعْتُ الْحَسَنَ يَقُولُ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالتَّعْرِيسَ عَلَى جَوَادِّ الطَّرِيقِ وَالصَّلَاةَ عَلَيْهَا فَإِنَّهَا مَأْوَى الْحَيَّاتِ وَالسِّبَاعِ وَقَضَاءَ الْحَاجَةِ عَلَيْهَا فَإِنَّهَا مِنْ الْمَلَاعِنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Amru bin Abu Salamah] dari [Zuhair] ia berkata; [Salim] berkata; Aku mendengar [Al Hasan] berkata; Telah menceritakan kepada kami [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian istirahat, shalat dan buang hajat di tengah jalan. Sebab ia adalah tempat ular dan binatang buas, dan ia juga tempat yang dilaknat.\""},"293":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ قُرَّةَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلَّى عَلَى قَارِعَةِ الطَّرِيقِ أَوْ يُضْرَبَ الْخَلَاءُ عَلَيْهَا أَوْ يُبَالَ فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Amru bin Khalid] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Qurrah] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] berkata; \"Nabi shallallahu 'alaihi wasallam melarang shalat di tengah jalan, atau menjadikannya sebagai tempat buang air besar, atau kencing di sana.\""},"294":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ الْمَذْهَبَ أَبْعَدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulaiyah] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Mughirah bin Syu'bah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam apabila hendak pergi buang air besar, beliau selalu menjauh.\""},"295":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ الْمُثَنَّى عَنْ عَطَاءٍ الْخُرَاسَانِيِّ عَنْ أَنَسٍ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَتَنَحَّى لِحَاجَتِهِ ثُمَّ جَاءَ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] dari [Muhammad bin Al Mutsanna] dari ['Atho` Al Khurasani] dari [Anas] ia berkata; \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, beliau lalu menjauh untuk buang hajat. Setelah itu beliau minta diambilkan air wudlu, lalu beliau pun berwudlu.\" "},"296":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ ابْنِ خُثَيْمٍ عَنْ يُونُسَ بْنِ خَبَّابٍ عَنْ يَعْلَى بْنِ مُرَّةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا ذَهَبَ إِلَى الْغَائِطِ أَبْعَدَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ibnu Khutsaim] dari [Yunus bin Khabbab] dari [Ya'la bin Murrah] berkata; \"Jika Nabi shallallahu 'alaihi wasallam ingin buang hajat beliau selalu pergi menjauh.\" "},"297":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ قَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاسْمُهُ عُمَيْرُ بْنُ يَزِيدَ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ وَالْحَارِثُ بْنُ فُضَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍ قَالَحَجَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ لِحَاجَتِهِ فَأَبْعَدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Abu Ja'far Al Khathmi] -Abu Bakr bin Abu Syaibah mengatakan; namanya adalah Umair bin Yazid- berkata; dari [Umarah bin Khuzaimah] dan [Harits bin Fudlail] dari [Abdurrahman bin Abu Furad] ia berkata; \"Aku melaksanakan haji bersama Nabi shallallahu 'alaihi wasallam, kemudian beliau pergi menjauh untuk buang hajat.\" "},"298":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا إِسْمَعِيلُ بْنُ عَبْدِ الْمَلِكِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْتِي الْبَرَازَ حَتَّى يَتَغَيَّبَ فَلَا يُرَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah memberitakan kepada kami [Isma'il bin Abdul Malik] dari [Abu Zubair] dari [Jabir] ia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, dan Rasulullah shallallahu 'alaihi wasallam tidak buang air besar hingga beliau menjauh dan tidak terlihat.\""},"299":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ كَثِيرِ بْنِ جَعْفَرٍ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ بِلَالِ بْنِ الْحَارِثِ الْمُزَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ الْحَاجَةَ أَبْعَدَ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Abdullah bin Katsir bin Ja'far] berkata, telah menceritakan kepada kami [Katsir bin Abdullah Al Muzani] dari [Bapaknya] dari [Kakeknya] dari [Bilal bin Al Harits Al Muzani] berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam ingin buang hajat beliau selalu menjauh.\""},"300":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ حُصَيْنٍ الْحِمْيَرِيِّ عَنْ أَبِي سَعْدِ الْخَيْرِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَجْمَرَ فَلْيُوتِرْ مَنْ فَعَلَ ذَلِكَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ وَمَنْ تَخَلَّلَ فَلْيَلْفِظْ وَمَنْ لَاكَ فَلْيَبْتَلِعْ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ وَمَنْ أَتَى الْخَلَاءَ فَلْيَسْتَتِرْ فَإِنْ لَمْ يَجِدْ إِلَّا كَثِيبًا مِنْ رَمْلٍ فَلْيَمْدُدْهُ عَلَيْهِ فَإِنَّ الشَّيْطَانَ يَلْعَبُ بِمَقَاعِدِ ابْنِ آدَمَ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ بِإِسْنَادِهِ نَحْوَهُ وَزَادَ فِيهِ وَمَنْ اكْتَحَلَ فَلْيُوتِرْ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ وَمَنْ لَاكَ فَلْيَبْتَلِعْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdul Malik bin Ash Shabbah] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Hushain Al Himyari] dari [Abu Sa'id Al Khair] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beristijmar hendaklan dengan bilangan ganjil, barangsiapa melakukannya maka ia telah berbuat baik, dan barangsiapa tidak melakukannya maka ia tidak berdosa. Barangsiapa mengeluarkan sisa-sisa makan dari sela gigi hendaklah ia buang, dan barangsiapa mengunyah hendaklah ia telan. Siapa melakukannya maka ia telah berbuat baik, dan siapa yang tidak melakukannya maka ia tidak berdosa. Barangsiapa masuk WC hendaklah membuat satir. Jika ia tidak mendapatkannya kecuali gundukan pasir hendaklah ia jadikan sebagai penghalang, sebab setan mempermainkan tempat duduk anak Adam. Siapa yang melakukan sedemikian ini, berarti ia telah melakukan kebaikan. Jika tidak, iapun tak berdosa. Telah menceritakan kepada kami [Abdurrahman bin Umar] telah menceritakan kepada kami [Abdul Malik bin Ash Shabbah] dengan sanadnya seperti itu, dan dia memberikan tambahan di dalamnya; \"dan barangsiapa memakai celak hendaklah dengan ganjil. Siapa yang melakukan sedemikian ini, berarti ia telah melakukan kebaikan. dan barangsiapa mengunyah hendaklah ia telan."},"301":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ يَعْلَى بْنِ مُرَّةَ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَرَادَ أَنْ يَقْضِيَ حَاجَتَهُ فَقَالَ لِي ائْتِ تِلْكَ الْأَشَاءَتَيْنِ قَالَ وَكِيعٌ يَعْنِي النَّخْلَ الصِّغَارَ فَقُلْ لَهُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكُمَا أَنْ تَجْتَمِعَا فَاجْتَمَعَتَا فَاسْتَتَرَ بِهِمَا فَقَضَى حَاجَتَهُ ثُمَّ قَالَ لِي ائْتِهِمَا فَقُلْ لَهُمَا لِتَرْجِعْ كُلُّ وَاحِدَةٍ مِنْكُمَا إِلَى مَكَانِهَا فَقُلْتُ لَهُمَا فَرَجَعَتَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Al Minhal bin 'Amru] dari [Ya'la bin Murrah] dari [Bapaknya] berkata; \"Aku bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, beliau ingin buang hajat, lalu beliau berkata kepadaku: \"Datangilah dua Asa`ah itu, Waki' berkata; \"Yakni pohon kurma yang masih kecil, \" dan katakan kepada keduanya; 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan kalian berdua untuk berkumpul.\" Maka keduanya pun menyatu hingga beliau menggunakannya sebagai sater untuk buang hajat. Setelah itu beliau bersabda kepadaku: \"Datanglah kepada keduanya dan katakan kepada mereka; 'Hendaklah setiap kalian kembali ke tempatnya semula, ' lalu aku pun mengatakan hal itu kepada keduanya hingga mereka kembali (ke tempatnya semula).\""},"302":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَكَانَ أَحَبَّ مَا اسْتَتَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ هَدَفٌ أَوْ حَائِشُ نَخْلٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Mahdi bin Maimun] berkata, telah menceritakan kepada kami [Muhammad bin Abu Ya'qub] dari [Al Hasan bin Sa'd] dari [Abdullah bin Ja'far] berkata; \"Satir yang paling disukai oleh Nabi shallallahu 'alaihi wasallam untuk buang hajat adalah tembok atau pohon kurma yang masih kecil.\""},"303":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَقِيلِ بْنِ خُوَيْلِدٍ حَدَّثَنِي حَفْصُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُحَمَّدِ بْنِ ذَكْوَانَ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَعَدَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الشِّعْبِ فَبَالَ حَتَّى أَنِّي آوِي لَهُ مِنْ فَكِّ وَرِكَيْهِ حِينَ بَالَ","id":"Telah menceritakan kepada kami [Muhammad bin Aqil bin Khuwailid] berkata, telah menceritakan kepadaku [Hafsh bin Abdul Malik] berkata, telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Muhammad bin Dzakwan] dari [Ya'la bin Hakim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menjauh ke suatu lembah kemudian kencing, hingga akupun berpaling ketika beliau kencing.\" "},"304":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ أَنْبَأَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ عِيَاضٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَنَاجَى اثْنَانِ عَلَى غَائِطِهِمَا يَنْظُرُ كُلُّ وَاحِدٍ مِنْهُمَا إِلَى عَوْرَةِ صَاحِبِهِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ يَمْقُتُ عَلَى ذَلِكَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَلْمُ بْنُ إِبْرَاهِيمَ الْوَرَّاقُ حَدَّثَنَا عِكْرِمَةُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِيَاضِ بْنِ هِلَالٍ قَالَ مُحَمَّدُ بْنُ يَحْيَى وَهُوَ الصَّوَابُ و حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَلِيُّ بْنُ أَبِي بَكْرٍ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Raja`] berkata, telah memberitakan kepada kami [Ikrimah bin 'Ammar] dari [Yahya bin Abu Katsir] dari [Hilal bin Iyadl] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah dua orang yang sedang buang hajat bercakap-cakap, hingga setiap dari keduanya melihat aurat yang lain. Sesungguhnya Allah murka dengan yang demikian itu.\" Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Salm bin Ibrahim Al Warraq] berkata, telah menceritakan kepada kami [Ikrimah] dari [Yahya bin Abu Katsir] dari [Iyadl bin Hilal]. Muhammad bin Yahya berkata; \"sanad yang Ini yang benar.\" Telah menceritakan kepada kami [Muhammad bin Humaid] berkata, telah menceritakan kepada kami [Ali bin Abu Bakar bin Sulaiman] dari [Sufyan Ats Tsauri] dari [Ikrimah bin Ammar] dari [Yahya bin Abu Katsir] dari [Iyadl bin Abdullah] sebagaimana hadits diatas.\""},"305":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ أَنْ يُبَالَ فِي الْمَاءِ الرَّاكِدِ","id":"Telah menceritakan kepada kami [Muhammad bin Ruhm] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, ia menuturkan: \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang kencing di air yang diam.\""},"306":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الرَّاكِدِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian kencing di air yang diam.\""},"307":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ أَبِي فَرْوَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ النَّاقِعِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Al Mubarak] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Ibnu Abi Farwah] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali salah seorang di antara kalian kencing di air yang jernih (untuk minum).\" "},"308":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ ابْنِ حَسَنَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهِ الدَّرَقَةُ فَوَضَعَهَا ثُمَّ جَلَسَ فَبَالَ إِلَيْهَا فَقَالَ بَعْضُهُمْ انْظُرُوا إِلَيْهِ يَبُولُ كَمَا تَبُولُ الْمَرْأَةُ فَسَمِعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَيْحَكَ أَمَا عَلِمْتَ مَا أَصَابَ صَاحِبَ بَنِي إِسْرَائِيلَ كَانُوا إِذَا أَصَابَهُمْ الْبَوْلُ قَرَضُوهُ بِالْمَقَارِيضِ فَنَهَاهُمْ عَنْ ذَلِكَ فَعُذِّبَ فِي قَبْرِهِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا الْأَعْمَشُ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdurrahman bin Hasanah] berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami sedang di tangannya memegang perisai dari kulit. Beliau meletakkan perisai tersebut kemudian jongkok seraya kencing menghadap ke arahnya. Sebagian sahabat lalu berkata; \"Lihatlah, beliau kencing sebagaimana seorang wanita kencing! \" Nabi shallallahu 'alaihi wasallam mendengar perkataan tersebut hingga beliau bersabda: \"Celaka kamu! Tidakkah engkau tahu bagaimana orang-orang bani Isra`il, jika pakaian mereka terkena kencing mereka memotongnya dengan gunting. Mereka dilarang dan disiksa dalam kubur.\" Abu Al Hasan bin Abu Salamah berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abdullah bin Musa berkata, telah memberitakan kepada kami Al A'masy lalu ia menyebutkan sebagaimana hadits diatas.\""},"309":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْرَيْنِ جَدِيدَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَنْزِهُ مِنْ بَوْلِهِ وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melewati dua kuburan yang masih baru, lalu beliau bersabda: \"Keduanya sedang disiksa, dan mereka disiksa bukan karena dosa besar. Yang satu disiksa karena tidak bersuci ketika kencing dan yang lain disiksa karena suka mengadu-domba.\""},"310":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرُ عَذَابِ الْقَبْرِ مِنْ الْبَوْلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mayoritas siksa yang terjadi di alam kubur adalah karena sebab kencing.\""},"311":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ حَدَّثَنِي بَحْرُ بْنُ مَرَّارٍ عَنْ جَدِّهِ أَبِي بَكْرَةَ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَيُعَذَّبُ فِي الْبَوْلِ وَأَمَّا الْآخَرُ فَيُعَذَّبُ فِي الْغَيْبَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al Aswad bin Syaiban] berkata, telah menceritakan kepadaku [Bahr bin Mirar] dari kakeknya [Abu Bakrah] berkata; Nabi shallallahu 'alaihi wasallam melewati dua kuburan, lalu beliau bersabda: \"Keduanya sedang disiksa, dan mereka disiksa bukan karena dosa besar. Yang satu disiksa karena tidak menjaga kebersihan ketika kencing dan yang lain disiksa karena berbuat ghibah.\""},"312":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُحَمَّدٍ الطَّلْحِيُّ وَأَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ قَالَا حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ حُضَيْنِ بْنِ الْمُنْذِرِ بْنِ الْحَارِثِ بْنِ وَعْلَةَ أَبِي سَاسَانَ الرَّقَاشِيِّ عَنْ الْمُهَاجِرِ بْنِ قُنْفُذِ بْنِ عَمْرِو بْنِ جُدْعَانَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ السَّلَامَ فَلَمَّا فَرَغَ مِنْ وُضُوئِهِ قَ��لَ إِنَّهُ لَمْ يَمْنَعْنِي مِنْ أَنْ أَرُدَّ إِلَيْكَ إِلَّا أَنِّي كُنْتُ عَلَى غَيْرِ وُضُوءٍقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا الْأَنْصَارِيُّ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad Ath Thalhi] dan [Ahmad bin Sa'id Ad Darimi] keduanya berkata; telah menceritakan kepada kami [Rauh bin Ubadah] dari [Sa'id] dari [Qotadah] dari [Al Hasan] dari [Hudlain Ibnul Mundzir Ibnul Harits bin Wa'lah Abu Sasan Ar Raqisyi] dari [Al Muhajir bin Qunfudz bin 'Amru bin Jud'an] berkata; Aku mendatangi Nabi shallallahu 'alaihi wasallam ketika beliau sedang berwudlu, lalu aku mengucapkan salam namun beliau tidak menjawab. Maka ketika selesai beliau bersabda: \"Sebenarnya tidak ada yang menghalangiku untuk menjawabnya kecuali karena aku sedang berwudlu.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Al Anshar dari Sa'id bin Abu Arubah lalu ia menyebutkan sebagaimana hadits diatas."},"313":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَسْلَمَةُ بْنُ عَلِيٍّ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمَرَّ رَجُلٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ فَلَمَّا فَرَغَ ضَرَبَ بِكَفَّيْهِ الْأَرْضَ فَتَيَمَّمَ ثُمَّ رَدَّ عَلَيْهِ السَّلَامَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Maslamah bin Ali] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Seorang lelaki melewati Nabi shallallahu 'alaihi wasallam ketika beliau sedang kencing, laki-laki itu mengucapkan salam kepadanya namun beliau tidak menjawabnya. Tatkala selesai, beliau menepukkan kedua telapak tangannya ke tanah dan bertayamum, setelah itu menjawab salamnya.\" "},"314":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هَاشِمِ بْنِ الْبَرِيدِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا مَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَنِي عَلَى مِثْلِ هَذِهِ الْحَالَةِ فَلَا تُسَلِّمْ عَلَيَّ فَإِنَّكَ إِنْ فَعَلْتَ ذَلِكَ لَمْ أَرُدَّ عَلَيْكَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Hasyim bin Al Barid] dari [Abdullah bin Muhammad bin 'Aqil] dari [Jabir bin Abdullah] berkata; Seorang laki-laki melewati Nabi shallallahu 'alaihi wasallam, kemudian ia mengucapkan salam ketika beliau sedang kencing. maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apabila kamu melihatku dalam kondisi seperti ini maka jangan memberi salam kepadaku. Karena sesungguhnya jika kamu melakukannya, maka aku tidak akan membalasnya.\""},"315":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ وَالْحُسَيْنُ بْنُ أَبِي السَّرِيِّ الْعَسْقَلَانِيُّ قَالَا حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَمَرَّ رَجُلٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] dan [Husain bin Abu Sarri Al 'Asqalani] keduanya berkata; telah menceritakan kepada kami [Abu Dawud] dari [Sufyan] dari [Adl Dlahak bin Utsman] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Seorang lelaki melewati Rasulullah shallallahu 'alaihi wasallam ketika beliau kencing, kemudian ia mengucapkan salam kepadanya, namun beliau tidak menjawabnya.\""},"316":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ غَائِطٍ قَطُّ إِلَّا مَسَّ مَاءً","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata; \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam selesai dari buang hajat kecuali menyentuh air (bersuci).\""},"317":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا عُتْبَةُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي طَلْحَةُ بْنُ نَافِعٍ أَبُو سُفْيَانَ قَالَ حَدَّثَنِي أَبُو أَيُّوبَ الْأَنْصَارِيُّ وَجَابِرُ بْنُ عَبْدِ اللَّهِ وَأَنَسُ بْنُ مَالِكٍأَنَّ هَذِهِ الْآيَةَ نَزَلَتْ{ فِيهِ رِجَالٌ يُحِبُّونَ أَنْ يَتَطَهَّرُوا وَاللَّهُ يُحِبُّ الْمُطَّهِّرِينَ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الْأَنْصَارِ إِنَّ اللَّهَ قَدْ أَثْنَى عَلَيْكُمْ فِي الطُّهُورِ فَمَا طُهُورُكُمْ قَالُوا نَتَوَضَّأُ لِلصَّلَاةِ وَنَغْتَسِلُ مِنْ الْجَنَابَةِ وَنَسْتَنْجِي بِالْمَاءِ قَالَ فَهُوَ ذَاكَ فَعَلَيْكُمُوهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Shadaqah bin Khalid] berkata, telah menceritakan kepada kami ['Utbah bin Abu Hakim] berkata, telah menceritakan kepadaku [Thalhah bin Nafi' Abu Sufyan] ia berkata; telah menceritakan kepadaku [Abu Ayyub Al Anshari] dan [Jabir bin Abdullah] dan [Anas bin Malik] berkata; Ayat ini turun; \"Di dalamnya ada orang-orang yang ingin membersihkan diri. Dan Allah menyukai orang-orang yang bersih, \" lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai kaum Anshar, sesungguhnya Allah telah memuji kalian di dalam perkara bersuci, maka bagaimana kalian bersuci?\" mereka menjawab; \"Kami berwudlu untuk shalat, mandi besar, dan beristinja` dengan air.\" Beliau bersabda: \"Apa yang sekarang kalian lakukan maka tekunilah.\""},"318":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ جَابِرٍ عَنْ زَيْدٍ الْعَمِّيِّ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْسِلُ مَقْعَدَتَهُ ثَلَاثًاقَالَ ابْنُ عُمَرَ فَعَلْنَاهُ فَوَجَدْنَاهُ دَوَاءً وَطُهُورًا قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ وَإِبْرَاهِيمُ بْنُ سُلَيْمَانَ الْوَاسِطِيُّ قَالَا حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Jabir] dari [Zaid Al 'Ammi] dari [Abu Ash Shiddiq An Naaji] dari [Aisyah] berkata; \"Nabi shallallahu 'alaihi wasallam mencuci pantatnya tiga kali.\" [Ibnu Umar] berkata; \"Lalu kami melakukan hal itu, hingga yang kami dapatkan adalah obat dan kebersihan.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Abu Hatim dan Ibrahim bin Sulaiman Al Wasithi keduanya berkata; telah menceritakan kepada kami Abu Nu'aim berkata, Syarik sebagaimana hadits diatas.\""},"319":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ يُونُسَ بْنِ الْحَارِثِ عَنْ إِبْرَاهِيمَ بْنِ أَبِي مَيْمُونَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَتْ فِي أَهْلِ قُبَاءَ{ فِيهِ رِجَالٌ يُحِبُّونَ أَنْ يَتَطَهَّرُوا وَاللَّهُ يُحِبُّ الْمُطَّهِّرِينَ }قَالَ كَانُوا يَسْتَنْجُونَ بِالْمَاءِ فَنَزَلَتْ فِيهِمْ هَذِهِ الْآيَةُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Yunus bin Al Harits] dari [Ibrahim bin Abu Maimunah] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah turun ayat kepada penduduk Quba`: \"Di dalamnya ada orang-orang yang ingin membersihkan diri. Dan Allah menyukai orang-orang yang bersih.\" Beliau bersabda: \"Mereka beristinja` dengan air, sehingga ayat ini turun kepada mereka.\" "},"320":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ إِبْرَاهِيمَ بْنِ جَرِيرٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى حَاجَتَهُ ثُمَّ اسْتَنْجَى مِنْ تَوْرٍ ثُمَّ دَلَكَ يَدَهُ بِالْأَرْضِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ الْوَاسِطِيُّ عَنْ شَرِيكٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Ibrahim bin Jarir] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam buang hajat kemudian beristinja` dengan air, setelah itu beliau mengusapkan tangannya ke tanah.\" "},"321":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ جَرِيرٍ عَنْ أَبِيهِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْغَيْضَةَ فَقَضَى حَاجَتَهُ فَأَتَاهُ جَرِيرٌ بِإِدَاوَةٍ مِنْ مَاءٍ فَاسْتَنْجَى مِنْهَا وَمَسَحَ يَدَهُ بِالتُّرَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Aban bin Abdullah] berkata, telah menceritakan kepada kami [Ibrahim bin Jarir] dari [Bapakku] berkata; \"Nabi shallallahu 'alaihi wasallam masuk ke semak-semak dan membuang hajatnya. Kemudian Jarir membawakan setimba air, beliau lalu beristinja` dan mengusap tangannya dengan debu.\""},"322":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُوكِيَ أَسْقِيَتَنَا وَنُغَطِّيَ آنِيَتَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ya'la bin Ubaid] berkata, telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] dari [Abu Zubair] dari [Jabir] ia berkata: \"Nabi shallallahu 'alaihi wasallam memerintahkan kami mengikat geriba dan menutup bejana-bejana.\""},"323":{"ar":"حَدَّثَنَا عِصْمَةُ بْنُ الْفَضْلِ وَيَحْيَى بْنُ حَكِيمٍ قَالَا حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ بْنِ أَبِي حَفْصَةَ حَدَّثَنَا حَرِيشُ بْنُ الْخِرِّيتِ أَنْبَأَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَضَعُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ آنِيَةٍ مِنْ اللَّيْلِ مُخَمَّرَةً إِنَاءً لِطَهُورِهِ وَإِنَاءً لِسِوَاكِهِ وَإِنَاءً لِشَرَابِهِ","id":"Telah menceritakan kepada kami [Ishmah bin Al Fadhl] dan [Yahya bin Hakim] keduanya berkata; telah menceritakan kepada kami [Harami bin Umarah bin Abu Hafshah] berkata, telah menceritakan kepada kami [Huraisy bin Al Khirrit] berkata, telah memberitakan kepada kami [Ibnu Abu Mulaikah] dari [Aisyah] ia berkata: \"Pada malam hari aku menyediakan tiga bejana untuk Rasulullah shallallahu 'alaihi wasallam; satu bejana untuk bersuci, satu bejana untuk bersiwak dan satu bejana lainya untuk minum.\""},"324":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا مُطَهَّرُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَلْقَمَةُ بْنُ أَبِي جَمْرَةَ الضُّبَعِيُّ عَنْ أَبِيهِ أَبِي جَمْرَةَ الضُّبَعِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَكِلُ طُهُورَهُ إِلَى أَحَدٍ وَلَا صَدَقَتَهُ الَّتِي يَتَصَدَّقُ بِهَا يَكُونُ هُوَ الَّذِي يَتَوَلَّاهَا بِنَفْسِهِ","id":"Telah menceritakan kepada kami [Abu Badr Abbad bin Al Walid] berkata, telah menceritakan kepada kami [Muthahhar bin Al Haitsam] berkata, telah menceritakan kepada kami [Alqamah bin Abu Jamrah Adl Dluba'i] dari Bapaknya [Abu Jamrah Adl Dluba'i] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak mewakilkan bersucinya kepada seseorang dan juga tidak dengan sedekahnya, namun beliau sendiri yang mengurusinya.\""},"325":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي رَزِينٍ قَالَرَأَيْتُ أَبَا هُرَيْرَةَ يَضْرِبُ جَبْهَتَهُ بِيَدِهِ وَيَقُولُ يَا أَهْلَ الْعِرَاقِ أَنْتُمْ تَزْعُمُونَ أَنِّي أَكْذِبُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَكُونَ لَكُمْ الْمَهْنَأُ وَعَلَيَّ الْإِثْمُ أَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Razin] berkata; Aku melihat [Abu Hurairah] memukul keningnya dengan tangan dan berkata; \"Wahai penduduk Irak, kalian mengklaim bahwa aku telah berdusta atas nama Rasulullah shallallahu 'alaihi wasallam, biarlah kalian mendapatkan pahala dan aku yang mendapatkan dosa (jika aku berdusta, pent). Aku bersaksi bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seekor anjing menjilat di bejana salah seorang dari kalian maka hendaklah ia mencucinya tujuh kali.\""},"326":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seekor anjing minum di bejana salah seorang dari kalian maka hendaklah ia mencucinya tujuh kali.\""},"327":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ الْمُغَفَّلِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَلَغَ الْكَلْبُ فِي الْإِنَاءِ فَاغْسِلُوهُ سَبْعَ مَرَّاتٍ وَعَفِّرُوهُ الثَّامِنَةَ بِالتُّرَابِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] berkata; aku mendengar [Mutharrif] menceritakan dari [Abdullah Ibnul Mughaffal] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seekor anjing menjilat bejana maka cucilah sebanyak tujuh kali dan lumurilah dengan tanah yang kedelapan kalinya.\""},"328":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah memberitakan kepada kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seekor anjing menjilat bejana salah seorang di antara kalian maka cucilah sebanyak tujuh kali.\""},"329":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ أَخْبَرَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ الْأَنْصَارِيُّ عَنْ حُمَيْدَةَ بِنْتِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ كَبْشَةَ بِنْتِ كَعْبٍ وَكَانَتْ تَحْتَ بَعْضِ وَلَدِ أَبِي قَتَادَةَأَنَّهَا صَبَّتْ لِأَبِي قَتَادَةَ مَاءً يَتَوَضَّأُ بِهِ فَجَاءَتْ هِرَّةٌ تَشْرَبُ فَأَصْغَى لَهَا الْإِنَاءَ فَجَعَلْتُ أَنْظُرُ إِلَيْهِ فَقَالَ يَا ابْنَةَ أَخِي أَتَعْجَبِينَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَيْسَتْ بِنَجَسٍ هِيَ مِنْ الطَّوَّافِينَ أَوْ الطَّوَّافَاتِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah memberitakan kepada kami [Malik bin Anas] berkata, telah mengabarkan kepadaku [Ishaq bin Abdullah bin Abu Thalhah Al Anshari] dari [Humaidah binti Rifa'ah] dari [Kabsyah binti Ka'ab] -isteri salah seorang anak Abu Qotadah-, ia pernah menuangkan air wudlu untuk [Abu Qotadah], lalu datanglah seekor Kucing yang ingin minum, maka ia pun memiringkan bejana itu untuk Kucing tersebut, aku terus memandanginya. Lalu ia berkata; \"Wahai puteri saudaraku, apakah engkau merasa heran? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Kucing tidak najis, ia adalah binatang yang biasa kelilingi (di rumah).\""},"330":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ أَبُو حَجَرٍ وَإِسْمَعِيلُ بْنُ تَوْبَةَ قَالَا حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ حَارِثَةَ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَتَوَضَّأُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ قَدْ أَصَابَتْ مِنْهُ الْهِرَّةُ قَبْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Amru bin Rafi' Abu Hajar] dan [Isma'il bin Taubah] keduanya berkata; telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Haritsah] dari [Amrah] dari [Aisyah] ia berkata; \"Aku dan Rasulullah shallallahu 'alaihi wasallam berwudlu dari satu bejana yang sebelumnya telah dijilat kucing.\" "},"331":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِ��دِ يَعْنِي أَبَا بَكْرٍ الْحَنَفِيَّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْهِرَّةُ لَا تَقْطَعُ الصَّلَاةَ لِأَنَّهَا مِنْ مَتَاعِ الْبَيْتِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ubaidullah bin Abdul Majid] -yaitu Abu Bakr Al Hanafi- berkata, telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Bapaknya] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kucing tidak memutus (membatalkan) shalat, karena ia termasuk perhiasan rumah.\""},"332":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاغْتَسَلَ بَعْضُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَفْنَةٍ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَغْتَسِلَ أَوْ يَتَوَضَّأَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ جُنُبًا قَالَ الْمَاءُ لَا يُجْنِبُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Sebagian isteri Nabi shallallahu 'alaihi wasallam mandi besar dalam satu bejana, lalu Nabi shallallahu 'alaihi wasallam datang untuk mandi atau wudlu. Isterinya berkata; \"Wahai Rasulullah sesungguhnya aku junub! \" beliau bersabda: \"(Namun) air tidak junub.\""},"333":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَتْ مِنْ جَنَابَةٍ فَتَوَضَّأَ أَوْ اغْتَسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فَضْلِ وَضُوئِهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] berkata; \"Seorang isteri Nabi shallallahu 'alaihi wasallam mandi junub lalu Nabi shallallahu 'alaihi wasallam wudlu, atau mandi junub dari sisa air wudlunya (isteri).\""},"334":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ يَحْيَى وَإِسْحَقُ بْنُ مَنْصُورٍ قَالُوا حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ بِفَضْلِ غُسْلِهَا مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Yahya] dan [Ishaq bin Manshur] mereka berkata; telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] dari [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu dengan air sisa mandi janabah isterinya.\""},"335":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي حَاجِبٍ عَنْ الْحَكَمِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ بِفَضْلِ وَضُوءِ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal] dari [Abu Hajib] dari [Al Hakam bin 'Amru] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seorang lelaki berwudlu dari sisa wudlu perempuan.\""},"336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَغْتَسِلَ الرَّجُلُ بِفَضْلِ وَضُوءِ الْمَرْأَةِ وَالْمَرْأَةُ بِفَضْلِ الرَّجُلِ وَلَكِنْ يَشْرَعَانِ جَمِيعًاقَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ الصَّحِيحُ هُوَ الْأَوَّلُ وَالثَّانِي وَهْمٌ قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ وَأَبُو عُثْمَانَ الْمُحَارِبِيُّ قَالَا حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Mu'alla bin Asad] berkata, telah menceritakan kepada kami [Abdul Aziz bin Mukhtar] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abdullah bin Sarjis] ia berkata berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seorang lelaki mandi dari sisa air wudlu seorang perempuan, dan perempuan mandi dari sisa seorang laki-laki. Dan yang dibolehkan adalah dilakukan secara bersama-sama\". Abu Abdullah Ibnu Majah berkata; \"Pendapat yang benar adalah yang pertama, sedang yang kedua masih meragukan.\" Abul Hasan bin Salamah berkata; telah menceritakan kepada kami Abu Hatim dan Abu Utsman Al Muharibi keduanya berkata; telah menceritakan kepada kami Al Mu'alla bin Asad dengan hadits yang serupa.\""},"337":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ يَغْتَسِلُونَ مِنْ إِنَاءٍ وَاحِدٍ وَلَا يَغْتَسِلُ أَحَدُهُمَا بِفَضْلِ صَاحِبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; \"Nabi shallallahu 'alaihi wasallam dan isteri-isterinya mandi dalam satu bejana, dan salah satu dari keduanya tidak mandi dengan sisa pasangannya.\""},"338":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata; \"Aku dan Rasulullah shallallahu 'alaihi wasallam mandi dari satu bejana.\""},"339":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ خَالَتِهِ مَيْمُونَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas] dari bibinya [Maimunah] ia berkata; \"Aku dan Rasulullah shallallahu 'alaihi wasallam mandi dari satu bejana.\""},"340":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ الْأَشْعَرِيُّ عَبْدُ اللَّهِ بْنُ عَامِرٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَ وَمَيْمُونَةَ مِنْ إِنَاءٍ وَاحِدٍ فِي قَصْعَةٍ فِيهَا أَثَرُ الْعَجِينِ","id":"Telah menceritakan kepada kami [Abu Amir Al Asy'ari Abdullah bin 'Amir] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Hani`] berkata; \"Nabi shallallahu 'alaihi wasallam dan Maimunah pernah mandi dari satu bejana dalam satu ember besar bekas adonan.\""},"341":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ الْأَسَدِيُّ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَزْوَاجُهُ يَغْتَسِلُونَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Al Hasan Al Asadi] berkata, telah menceritakan kepada kami [Syarik] dari [Abdullah bin Muhammad bin 'Aqil] dari [Jabir bin Abdullah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam dan isteri-isterinya mandi dari satu bejana.\""},"342":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّهَا كَانَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلَانِ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulaiyah] dari [Hisyam Ad Dustuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] berkata; \"Dirinya dan Rasulullah shallallahu 'alaihi wasallam mandi dari satu bejana.\""},"343":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانَ الرِّجَالُ وَالنِّسَاءُ يَتَوَضَّئُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam kaum lelaki dan wanita berwudlu dari satu bejana.\""},"344":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ سَالِمِ بْنِ النُّعْمَانِ وَهُوَ ابْنُ سَرْحٍ عَنْ أُمِّ صُبَيَّةَ الْجُهَنِيَّةِ قَالَتْرُبَّمَا اخْتَلَفَتْ يَدِي وَيَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْوُضُوءِ مِنْ إِنَاءٍ وَاحِدٍقَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ سَمِعْتُ مُحَمَّدًا يَقُولُ أُمُّ صُبَيَّةَ هِيَ خَوْلَةُ بِنْتُ قَيْسٍ فَذَكَرْتُ لِأَبِي زُرْعَةَ فَقَالَ صَدَقَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari [Salim bin Nu'man] -yaitu Ibnu Sarh- dari [Ummu Shubaiyyah Al Juhaniyyah] ia berkata; \"Kadang-kadang tanganku dan tangan Rasulullah shallallahu 'alaihi wasallam saling beradu saat wudlu dalam satu bejana.\" Abu Abdullah Ibnu Majah berkata; Aku mendengar Muhammad berkata; \"Ummu Shubaiyyah adalah Khaulah binti Qais.\" Lalu hal itu aku tanyakan kepada Abu Zur'ah, maka ia menjawab; \"Benar.\""},"345":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا دَاوُدُ بْنُ شَبِيبٍ حَدَّثَنَا حَبِيبُ بْنُ أَبِي حَبِيبٍ عَنْ عَمْرِو بْنِ هَرَمٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمَا كَانَا يَتَوَضَّآَنِ جَمِيعًا لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Dawud bin Syabib] berkata, telah menceritakan kepada kami [Habib bin Abu Habib] dari [Amru bin Harm] dari [Ikrimah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, bahwa keduanya pernah wudlu bersama untuk shalat."},"346":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ أَبِيهِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ أَبِي فَزَارَةَ الْعَبْسِيِّ عَنْ أَبِي زَيْدٍ مَوْلَى عَمْرِو بْنِ حُرَيْثٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ لَيْلَةَ الْجِنِّ عِنْدَكَ طَهُورٌ قَالَ لَا إِلَّا شَيْءٌ مِنْ نَبِيذٍ فِي إِدَاوَةٍ قَالَ تَمْرَةٌ طَيِّبَةٌ وَمَاءٌ طَهُورٌ فَتَوَضَّأَ هَذَا حَدِيثُ وَكِيعٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Bapaknya]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] dari [Sufyan] dari [Abu Fazarah Al 'Absi] dari [Abu Zaid] mantan budak Amru bin Huraist, dari [Abdullah bin Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu malam yang gelap gulita bertanya kepadanya: \"Apakah kamu mempunyai air untuk bersuci?\" ia menjawab; \"Tidak, kecuali sedikit nabidz (air arak) yang ada di kantong kulit.\" Beliau bersabda: \"Kurma itu baik dan air itu suci.\" Lalu beliau pun berwudlu. Ini merupakan hadits Waki'."},"347":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا قَيْسُ بْنُ الْحَجَّاجِ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِابْنِ مَسْعُودٍ لَيْلَةَ الْجِنِّ مَعَكَ مَاءٌ قَالَ لَا إِلَّا نَبِيذًا فِي سَطِيحَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمْرَةٌ طَيِّبَةٌ وَمَاءٌ طَهُورٌ صُبَّ عَلَيَّ قَالَ فَصَبَبْتُ عَلَيْهِ فَتَوَضَّأَ بِهِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Qais bin Al Hajjaj] dari [Hanasy Ash Shan'ani] dari [Abdullah bin 'Abbas] berkata, Rasulullah shallallahu 'alaihi wasallam bertanya kepada Ibnu Mas'ud di malam yang gelap gulita: \"Apakah kamu punya air?\" ia menjawab; \"Tidak, kecuali nabidz dalam kantong air.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \" Kurma itu baik dan air itu suci. Tuangkanlah untukku.\" Ia berkata; \"Maka aku pun menuangkan untuk wudlu beliau.\""},"348":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي صَفْوَانُ بْنُ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ هُوَ مِنْ آلِ ابْنِ الْأَزْرَقِ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ وَهُوَ مِنْ بَنِي عَبْدِ الدَّارِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا نَرْكَبُ الْبَحْرَ وَنَحْمِلُ مَعَنَا الْقَلِيلَ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah menceritakan kepadaku [Shafwan bin Sulaim] dari [Sa'id bin Salamah] -dari keluarga Ibnu Al Azraq- bahwa [Al Mughirah bin Abu Burdah] -dari bani Abdu Ad Dar- mendengar [Abu Hurairah] berkata; \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam seraya bertanya; \"Wahai Rasulullah, kami berlayar di lautan dan kami hanya membawa sedikit air, jika kami berwudlu dengannya maka kami akan kehausan. Bolehkah kami berwudlu dengan air laut?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Laut itu suci airnya dan halal bangkainya.\""},"349":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ بْنُ سَعْدٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُسْلِمِ بْنِ مَخْشِيٍّ عَنْ ابْنِ الْفِرَاسِيِّ قَالَكُنْتُ أَصِيدُ وَكَانَتْ لِي قِرْبَةٌ أَجْعَلُ فِيهَا مَاءً وَإِنِّي تَوَضَّأْتُ بِمَاءِ الْبَحْرِ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah menceritakan kepada kami [Sahal bin Abu Sahal] berkata, telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepadaku [Al Laits bin Sa'd] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muslim bin Makhsyi] dari [Ibnul Firasi] ia berkata; \"Aku pergi mencari ikan, dan aku mempunyai satu geriba yang aku jadikan sebagai tempat menyimpan air, dan aku berwudlu dengan air laut. Lantas hal itu aku tanyakan kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Laut itu suci airnya dan halal bangkainya.\" "},"350":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو الْقَاسِمِ بْنُ أَبِي الزِّنَادِ قَالَ حَدَّثَنِي إِسْحَقُ بْنُ حَازِمٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ مِقْسَمٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ مَاءِ الْبَحْرِ فَقَالَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ الْهَسْتَجَانِيُّ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو الْقَاسِمِ بْنُ أَبِي الزِّنَادِ حَدَّثَنِي إِسْحَقُ بْنُ حَازِمٍ عَنْ عُبَيْدِ اللَّهِ هُوَ ابْنُ مِقْسَمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ahmad bin Hambal] berkata, telah menceritakan kepada kami [Abul Qasim bin Abu Zanad] ia berkata; telah menceritakan kepadaku [Ishaq bin Hazim] dari [Ubaidullah bin Miqsam] dari [Jabir] berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang air laut, maka beliau menjawab: \"Laut itu suci airnya dan halal bangkainya.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Ali Ibnul Hasan Al Hastajani berkata, telah menceritakan kepada kami Ahmad bin Hambal berkata, telah menceritakan kepada kami Abu Al Qasim bin Abu Az Zinad berkata, telah menceritakan kepadaku Ishaq bin Hazim dari Ubaidullah -yaitu Ibnu Miqsam- dari Jabir bin Abdullah bahwa Nabi shallallahu 'alaihi wasallam… lalu ia menyebutkan sebagaimana hadits diatas."},"351":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمِ بْنِ صُبَيْحٍ عَنْ مَسْرُوقٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَعْضِ حَاجَتِهِ فَلَمَّا رَجَعَ تَلَقَّيْتُهُ بِالْإِدَاوَةِ فَصَبَبْتُ عَلَيْهِ فَغَسَلَ يَدَيْهِ ثُمَّ غَسَلَ وَجْهَهُ ثُمَّ ذَهَبَ يَغْسِلُ ذِرَاعَيْهِ فَضَاقَتْ الْجُبَّةُ فَأَخْرَجَهُمَا مِنْ تَحْتِ الْجُبَّةِ فَغَسَلَهُمَا وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ صَلَّى بِنَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al A'masy] dari [Muslim bin Shubaih] dari [Masruq] dari [Mughirah bin Syu'bah] ia berkata; \"Suatu kali Nabi shallallahu 'alaihi wasallam keluar untuk buang hajat. Tatkala beliau kembali, aku menjumpainya dengan membawa sebuah kantong kulit berisi air, aku lalu menuangkan air untuknya, kemudian beliau mencuci tangannya dan membasuh muka, setelah itu mencuci kedua lengannya hingga ke siku. Karena jubah beliau sempit, maka beliau mengeluarkan keduanya dari bawah jubah seraya membasuh keduanya. Lalu mengusap kedua khufnya kemudian shalat bersama kami.\" "},"352":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذٍ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِيضَأَةٍ فَقَالَ اسْكُبِي فَسَكَبْتُ فَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ وَأَخَذَ مَاءً جَدِيدًا فَمَسَحَ بِهِ رَأْسَهُ مُقَدَّمَهُ وَمُؤَخَّرَهُ وَغَسَلَ قَدَمَيْهِ ثَلَاثًا ثَلَاثًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Haitsam bin Jamil] berkata, telah menceritakan kepada kami [Syarik] dari [Abdullah bin Muhammad bin 'Aqil] dari [Ar Rubayyi' binti Mu'awwidz] ia berkata; Aku mendatangi Nabi shallallahu 'alaihi wasallam membawa tempat wudlu, lalu beliau bersabda: \"Tuangkanlah untukku, \" maka akupun menuangkan untuknya. Kemudian beliau mencuci mukanya dan kedua lengannya hingga ke siku, beliau lalu mengambil air yang baru seraya mengusap kepalanya dari bagian depannya hingga ke bagian belakangnya, setelah itu membasuh kedua kakinya tiga kali-tiga kali.\""},"353":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي الْوَلِيدُ بْنُ عُقْبَةَ حَدَّثَنِي حُذَيْفَةُ بْنُ أَبِي حُذَيْفَةَ الْأَزْدِيُّ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَصَبَبْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَاءَ فِي السَّفَرِ وَالْحَضَرِ فِي الْوُضُوءِ","id":"Telah menceritakan kepada kami [Bisyr bin Adam] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepadaku [Al Walid bin Uqbah] berkata, telah menceritakan kepadaku [Hudzaifah bin Abu Hudzaifah Al 'Azdi] dari [Shafwan bin 'Assal] ia berkata; \"Aku menuangkan air untuk wudlu Nabi shallallahu 'alaihi wasallam baik dalam safar maupun muqim.\" "},"354":{"ar":"حَدَّثَنَا كُرْدُوسُ بْنُ أَبِي عَبْدِ اللَّهِ الْوَاسِطِيُّ حَدَّثَنَا عَبْدُ الْكَرِيمِ بْنُ رَوْحٍ حَدَّثَنَا أَبِي رَوْحُ بْنُ عَنْبَسَةَ بْنِ سَعِيدِ بْنِ أَبِي عَيَّاشٍ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ عَنْ أَبِيهِ عَنْبَسَةَ بْنِ سَعِيدٍ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ أُمِّ عَيَّاشٍ وَكَانَتْ أَمَةً لِرُقَيَّةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكُنْتُ أُوَضِّئُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا قَائِمَةٌ وَهُوَ قَاعِدٌ","id":"Telah menceritakan kepada kami [Kurdus bin Abu Abdullah Al Wasithi] berkata, telah menceritakan kepada kami [Abdul Karim bin Rauh] berkata, telah menceritakan kepada kami [Rauh bin 'Anbasah bin Sa'id bin Abu 'Ayyasy] mantan budak Utsman bin 'Affan, dari bapaknya ['Anbasah bin Sa'id] dari neneknya yaitu ibu ayahnya [Ummu 'Ayyasy] -dan ia adalah pembantu Ruqayyah puteri Rasulullah shallallahu 'alaihi wasallam- ia berkata; \"Aku memberi air wudlu Rasulullah shallallahu 'alaihi wasallam dengan berdiri sementara beliau duduk.\""},"355":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُمَا حَدَّثَاهُ أَنَّ أَبَا هُرَيْرَةَ كَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ اللَّيْلِ فَلَا يُدْخِلْ يَدَهُ فِي الْإِنَاءِ حَتَّى يُفْرِغَ عَلَيْهَا مَرَّتَيْنِ أَوْ ثَلَاثًا فَإِنَّ أَحَدَكُمْ لَا يَدْرِي فِيمَ بَاتَتْ يَدُهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Az Zuhri] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah bin Abdurrahman] bahwa keduanya menceritakan kepadanya bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian bangun malam maka janganlah memasukkan tangannya ke dalam bejana hingga ia menuangkan ke tangannya dua atau tiga kali. Sebab salah seorang dari kalian tidak tahu ke mana tangannya bermalam.\""},"356":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ وَجَابِرُ بْنُ إِسْمَعِيلَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلَا يُدْخِلْ يَدَهُ فِي الْإِنَاءِ حَتَّى يَغْسِلَهَا","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dan [Jabir bin Isma'il] dari [Uqail] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian bangun dari tidurnya, maka janganlah memasukkan tangannya kedalam bejana hingga ia mencucinya terlebih dahulu.\""},"357":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ الْبَكَّائِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ النَّوْمِ فَأَرَادَ أَنْ يَتَوَضَّأَ فَلَا يُدْخِلْ يَدَهُ فِي وَضُوئِهِ حَتَّى يَغْسِلَهَا فَإِنَّهُ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُ وَلَا عَلَى مَا وَضَعَهَا","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami [Ziyad bin Abdullah Al Bakka`i] dari [Abdul Malik bin Abu Sulaiman] dari [Abu Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian bangun dari tidur dan hendak berwudlu, maka jangan memasukkan tangannya ke tempat wudlu hingga ia mencucinya, karena ia tidak tahu di mana tangannya bermalam dan di atas apa ia meletakkannya.\""},"358":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ قَالَدَعَا عَلِيٌّ بِمَاءٍ فَغَسَلَ يَدَيْهِ قَبْلَ أَنْ يُدْخِلَهُمَا الْإِنَاءَ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Ishaq] dari [Al Harits] ia berkata; [Ali] minta untuk diambilkan air, kemudian ia pun mencuci kedua tangannya sebelum memasukkan keduanya ke dalam bejana, setelah itu ia berkata; \"Seperti inilah aku melihat Rasulullah shallallahu 'alaihi wasallam melakukannya.\""},"359":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ ح و حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ قَالُوا حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ عَنْ رُبَيْحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir Al 'Aqdi]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Abu Ahmad Az Zubairi] mereka berkata; telah menceritakan kepada kami [Katsir bin Zaid] dari [Rubaih bin Abdurrahman bin Abu Sa'id] dari [Bapaknya] dari [Kakeknya], berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada wudlu bagi orang yang tidak menyebut nama Allah ketika berwudlu.\""},"360":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا يَزِيدُ بْنُ عِيَاضٍ حَدَّثَنَا أَبُو ثِفَالٍ عَنْ رَبَاحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سُفْيَانَ أَنَّهُ سَمِعَ جَدَّتَهُ بِنْتَ سَعِيدِ بْنِ زَيْدٍ تَذْكُرُ أَنَّهَا سَمِعَتْ أَبَاهَا سَعِيدَ بْنَ زَيْدٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Yazid bin 'Iyadl] berkata, telah menceritakan kepada kami [Abu Tsifal] dari [Rabah bin Abdurrahman bin Abu Sufyan], bahwasanya ia mendengar neneknya [Binti Sa'id bin Zaid] menuturkan, bahwa ia pernah mendengar bapaknya [Sa'id bin Zaid] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat bagi orang yang tidak berwudlu, dan tidak ada wudlu orang yang tidak menyebut nama Allah ketika berwudlu.\""},"361":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَبِي عَبْدِ اللَّهِ عَنْ يَعْقُوبَ بْنِ سَلَمَةَ اللَّيْثِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Abdurrahman bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] berkata, telah menceritakan kepada kami [Muhammad bin Musa bin Abu Abdullah] dari [Ya'qub bin Salamah Al Laitsi] dari [bapaknya] dari [Abu Hurairah], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat bagi orang yang tidak memiliki wudlu, dan tidak ada wudlu bagi orang yang tidak menyebut nama Allah ketika berwudlu.\""},"362":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الْمُهَيْمِنِ بْنِ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَلَا صَلَاةَ لِمَنْ لَا يُصَلِّي عَلَى النَّبِيِّ وَلَا صَلَاةَ لِمَنْ لَا يُحِبُّ الْأَنْصَارَقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا عِيسَى بْنُ مَرْحُومٍ الْعَطَّارُ حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ عَبَّاسٍ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdul Muhaimin bin 'Abbas bin Sahal bin Sa'd As Sa'idi] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada shalat bagi orang yang tidak memiliki wudlu, dan tidak ada wudlu bagi orang yang tidak menyebut nama Allah ketika berwudlu. Dan tidak ada shalat bagi orang yang tidak bershalawat kepada Nabi, serta tidak ada shalat bagi orang yang tidak menyukai kaum Anshar.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Isa bin Marhum Al 'Aththar berkata, telah menceritakan kepada kami Abdul Muhaimin bin Abbas lalu ia menyebutkan sebagaimana hadits diatas."},"363":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ ح و حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُحِبُّ التَّيَمُّنَ فِي الطُّهُورِ إِذَا تَطَهَّرَ وَفِي تَرَجُّلِهِ إِذَا تَرَجَّلَ وَفِي انْتِعَالِهِ إِذَا انْتَعَلَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Asy'ats bin Abu Asy Sya'tsa`]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Umar bin Ubaid Ath Thanafusi] dari [Asy'ats bin Abu Asy Sya'tsa`] dari [Bapaknya] dari [Masruq] dari [Aisyah], ia menuturkan; \"Rasulullah shallallahu 'alaihi wasallam suka mendahulukan yang kanan jika berwudlu, mendahulukan yang kanan jika berjalan, dan mendahulukan yang kanan jika mengenakan sandal.\""},"364":{"ar":"حَدَّثَن��ا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو جَعْفَرٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتُمْ فَابْدَءُوا بِمَيَامِنِكُمْقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا ابْنُ صَالِحٍ وَابْنُ نُفَيْلٍ وَغَيْرُهُمَا قَالُوا حَدَّثَنَا زُهَيْرٌ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Ja'far An Nufaili] berkata, telah menceritakan kepada kami [Zuhair bin Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia menuturkan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian berwudlu maka mulailah dengan yang sebelah kanan.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Ibnu Shalih dan Ibnu Nufail dan selain keduanya, mereka berkata; telah menceritakan kepada kami Zuhair lalu ia menyebutkan sebagaimana hadits diatas."},"365":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ وَأَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَضْمَضَ وَاسْتَنْشَقَ مِنْ غُرْفَةٍ وَاحِدَةٍ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] dan [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Ibnu Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam berkumur dan memasukkan air ke hidung dari satu gayung.\""},"366":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ خَالِدِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَضْمَضَ ثَلَاثًا وَاسْتَنْشَقَ ثَلَاثًا مِنْ كَفٍّ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Khalid bin Alqamah] dari [Abdu Khair] dari [Ali], ia menuturkan; \"Rasulullah shallallahu 'alaihi wasallam berwudlu, lalu beliau berkumur-kumur tiga kali dan istinsyaq tiga kali dari satu telapak tangan.\" "},"367":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ الْعُكْلِيُّ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَنْصَارِيِّ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَنَا وَضُوءًا فَأَتَيْتُهُ بِمَاءٍ فَمَضْمَضَ وَاسْتَنْشَقَ مِنْ كَفٍّ وَاحِدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Al Husain Al 'Ukli] dari [Khalid bin Abdullah] dari [Amru bin Yahya] dari [bapaknya] dari [Abdullah bin Zaid Al Anshari] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam datang kepada kami dan meminta air wudlu hingga kami pun memberinya air, kemudian beliau berkumur dan memasukkan air ke hidung dengan satu telapak tangan.\" "},"368":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مَنْصُورٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْثُرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Manshur]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Jika engkau berwudlu maka keluarkanlah (air) dari dalam hidung, dan jika engkau beristijmar (bersuci dengan batu) maka hendaklah dengan bilangan ganjil.\""},"369":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ إِسْمَعِيلَ بْنِ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبْرَةَ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي عَنْ الْوُضُوءِ قَالَ أَسْبِغْ الْوُضُوءَ وَبَالِغْ فِي الِاسْتِنْشَاقِ إِلَّا أَنْ تَكُونَ صَائِمًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`ifi] dari [Isma'il bin Katsir] dari ['Ashim bin Laqith bin Shabrah] dari [Bapaknya] ia berkata; Aku berkata; \"Wahai Rasulullah, kabarkanlah kepadaku tentang wudlu, \" beliau bersabda: \"Sempurnakan wudlu dan perdalamlah dalam memasukkan air ke dalam hidung, kecuali jika engkau berpuasa.\""},"370":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ قَارِظِ بْنِ شَيْبَةَ عَنْ أَبِي غَطَفَانَ الْمُرِّيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَنْثِرُوا مَرَّتَيْنِ بَالِغَتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ishaq bin Sulaiman]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Qarizh bin Syaibah] dari [Abu Ghathafan Al Murri] dari [Ibnu 'Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah Istinstar (keluarkan air dari hidung) dengan sempurna dua atau tiga kali.\""},"371":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ وَدَاوُدُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَلْيَسْتَنْثِرْ وَمَنْ اسْتَجْمَرَ فَلْيُوتِرْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] dan [Dawud bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Abu Idris Al Khaulani] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu hendaklah memasukkan air ke hidung, dan barangsiapa beristijmar hendaklah dengan bilangan ganjil.\" "},"372":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ النَّخَعِيُّ عَنْ ثَابِتِ بْنِ أَبِي صَفِيَّةَ الثُّمَالِيِّ قَالَ سَأَلْتُ أَبَا جَعْفَرٍ قُلْتُ لَهُ حُدِّثْتَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً قَالَ نَعَمْ قُلْتُ وَمَرَّتَيْنِ مَرَّتَيْنِ وَثَلَاثًا ثَلَاثًا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Syarik bin Abdullah An Nakha'I] dari [Tsabit bin Abu Shafiyyah Ats Tsumali] ia berkata; aku bertanya [Abu Ja'far]; \"Apakah engkau pernah diceritakan dari [Jabir] bin Abdullah bahwa Nabi shallallahu 'alaihi wasallam berwudlu satu kali satu kali?\" ia menjawab; \"Benar.\" Aku bertanya lagi; \"Dan dua kali-dua kali, dan tiga kali-tiga kali?\" ia menjawab; \"Benar.\""},"373":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ غُرْفَةً غُرْفَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Sufyan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Ibnu 'Abbas] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu satu gayung-satu gayung.\""},"374":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ أَنْبَأَنَا الضَّحَّاكُ بْنُ شُرَحْبِيلَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ تَوَضَّأَ وَاحِدَةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Risydin bin Sa'd] berkata, telah memberitakan kepada kami [Adl Dlahhak bin Syurahbil] dari [Zaid bin Aslam] dari [Bapaknya] dari [Umar] ia berkata; \"Pada perang Tabuk aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu satu kali-satu kali.\""},"375":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ الدِّمَشْقِيُّ عَنْ ابْنِ ثَوْبَانَ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ شَقِيقِ بْنِ سَلَمَةَ قَالَرَأَيْتُ عُثْمَانَ وَعَلِيًّا يَتَوَضَّآَنِ ثَلَاثًا ثَلَاثًا وَيَقُولَانِ هَكَذَا كَانَ وُضُوءُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَاهُ أَبُو حَاتِمٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim Ad Dimasyqi] dari [Ibnu Tsauban] dari ['Abdah bin Abu Lubabah] dari [Syaqiq bin Salamah] ia berkata, \"Aku melihat [Utsman] dan [Ali] berwudlu tiga kali-tiga kali, lalu keduanya berkata: \"Seperti inilah wudlu Rasulullah shallallahu 'alaihi wasallam.\" Abul Hasan bin Salamah berkata; telah menceritakannya kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abu Nu'aim berkata, telah menceritakan kepada kami Abdurrahman bin Tsabit bin Tsauban kemudian dia menyebutkan hadits yang serupa."},"376":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ عَنْ ابْنِ عُمَرَأَنَّهُ تَوَضَّأَ ثَلَاثًا ثَلَاثًا وَرَفَعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Al Muththalib bin Abdullah bin Hanthab] dari [Ibnu Umar], bahwasanya ia berwudlu tiga kali-tiga kali, dan memarfu'kan hadits itu kepada Nabi shallallahu 'alaihi wasallam.\" "},"377":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا خَالِدُ بْنُ حَيَّانَ عَنْ سَالِمٍ أَبِي الْمُهَاجِرِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثَلَاثًا ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Khalid bin Hayyan] dari [Salim Abul Muhajir] dari [Maimun bin Mihran] dari ['Aisyah] dan [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu tiga kali-tiga kali.\""},"378":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ فَائِدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثَلَاثًا ثَلَاثًا وَمَسَحَ رَأْسَهُ مَرَّةً","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Faid bin Abdurrahman] dari [Abdullah bin Abu Aufa] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu tiga kali-tiga kali dan mengusap kepalanya sekali.\""},"379":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ لَيْثٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ ثَلَاثًا ثَلَاثًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Laits] dari [Syahr bin Hausyab] dari [Abu Malik Al Asy'ari] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu tiga kali-tiga kali.\""},"380":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثَلَاثًا ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Muhammad bin 'Aqil] dari [Ar Rubayyi' binti Mu'awwidz bin Afra'] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu tiga kali-tiga kali.\""},"381":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنِي مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ الْعَطَّارُ حَدَّثَنِي عَبْدُ الرَّحِيمِ بْنُ زَيْدٍ الْعَمِّيُّ عَنْ أَبِيهِ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ ابْنِ عُمَرَ قَالَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدَةً وَاحِدَةً فَقَالَ هَذَا وُضُوءُ مَنْ لَا يَقْبَلُ اللَّهُ مِنْهُ صَلَاةً إِلَّا بِهِ ثُمَّ تَوَضَّأَ ثِنْتَيْنِ ثِنْتَيْنِ فَقَالَ هَذَا وُضُوءُ الْقَدْرِ مِنْ الْوُضُوءِ وَتَوَضَّأَ ثَلَاثًا ثَلَاثًا وَقَالَ هَذَا أَسْبَغُ الْوُضُوءِ وَهُوَ وُضُوئِي وَوُضُوءُ خَلِيلِ اللَّهِ إِبْرَاهِيمَ وَمَنْ تَوَضَّأَ هَكَذَا ثُمَّ قَالَ عِنْدَ فَرَاغِهِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فُتِحَ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهَا شَاءَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepadaku [Marhum bin Abdul Aziz Al 'Aththar] berkata, telah menceritakan kepadaku [Abdurrahim bin Zaid Al 'Ammi] dari [Bapaknya] dari [Mu'wiyah bin Qurrah] dari [Ibnu Umar] ia berkata, Rasulullah shallallahu 'alaihi wasallam berwudlu satu kali-satu kali. Dan beliau bersabda: \"Ini adalah wudlu orang yang shalatnya tidak diterima oleh Allah kecuali dengannya.\" Kemudian beliau berwudlu dua kali-dua kali dan bersabda: \"Ini wudlu yang bagus.\" Dan beliau berwudlu tiga kali-tiga kali seraya bersabda: \"Ini wudlu yang sempurna, inilah wudluku dan wudlu kekasih Allah, Ibrahim. Barangsiapa berwudlu seperti ini setelah itu mengucapkan: ASYHADU ANLAA ILAAHA ILLALLAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU (Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya), akan dibuka baginya delapan pintu surga, ia diperbolehka masuk lewat pintu mana saja.\" "},"382":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ قَعْنَبٍ أَبُو بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَرَادَةَ الشَّيْبَانِيُّ عَنْ زَيْدِ بْنِ الْحَوَارِيِّ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا بِمَاءٍ فَتَوَضَّأَ مَرَّةً مَرَّةً فَقَالَ هَذَا وَظِيفَةُ الْوُضُوءِ أَوْ قَالَ وُضُوءٌ مَنْ لَمْ يَتَوَضَّأْهُ لَمْ يَقْبَلْ اللَّهُ لَهُ صَلَاةً ثُمَّ تَوَضَّأَ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ قَالَ هَذَا وُضُوءٌ مَنْ تَوَضَّأَهُ أَعْطَاهُ اللَّهُ كِفْلَيْنِ مِنْ الْأَجْرِ ثُمَّ تَوَضَّأَ ثَلَاثًا ثَلَاثًا فَقَالَ هَذَا وُضُوئِي وَوُضُوءُ الْمُرْسَلِينَ مِنْ قَبْلِي","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] berkata, telah menceritakan kepada kami [Isma'il bin Qa'nab Abu Bisyr] berkata, telah menceritakan kepada kami [Abdullah bin 'Aradah As Syaibani] dari [Zaid bin Al Hawari] dari [Mu'awiyah bin Qurrah] dari [Ubaid bin Umair] dari [Ubai bin Ka'ab] berkata; \"Rasulullah shallallahu 'alaihi wasallam minta diambilkan air, lalu beliau berwudlu satu kali-satu kali dan bersabda: \"Ini adalah kewajiban wudlu, atau beliau bersabda: \"Wudlu yang Allah tidak akan menerima shalat seseorang kecuali dengannya.\" Kemudian beliau berwudlu dua kali-dua kali dan bersabda: \"orang yang berwudlu seperti ini akan Allah berikan kepadanya dua pahala.\" Kemudian beliau berwudlu tiga kali-tiga kali dan bersabda: \"Inilah wudluku dan wudlu para rasul sebelumku.\" "},"383":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا خَارِجَةُ بْنُ مُصْعَبٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عُتَيِّ بْنِ ضَمْرَةَ السَّعْدِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلْوُضُوءِ شَيْطَانًا يُقَالُ لَهُ وَلَهَانُ فَاتَّقُوا وَسْوَاسَ الْمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Kharijah bin Mus'ab] dari [Yunus bin Ubaid] dari [Al Hasan] dari ['Utai bin Dlamrah As Sa'di] dari [Ubai bin Ka'ab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya wudlu itu mempunyai setan yang disebut Walhan, maka berhati-hatilah terhadap bisikan air.\""},"384":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ الْوُضُوءِ فَأَرَاهُ ثَلَاثًا ثَلَاثًا ثُمَّ قَالَ هَذَا الْوُضُوءُ فَمَنْ زَادَ عَلَى هَذَا فَقَدْ أَسَاءَ أَوْ تَعَدَّى أَوْ ظَلَمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami pamanku [Ya'la] dari [Sufyan] dari [Musa bin Abu Aisyah] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata; \"Seorang arab badui datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya tentang wudlu, menurutku beliau berwudlu tiga kali-tiga kali, kemudian beliau bersabda: \"seperti Inilah tatacara wudlu, barangsiapa menambahi maka ia telah berbuat keburukan, atau melampaui batas, atau zhalim.\""},"385":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ كُرَيْبًا يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَضَّأَ مِنْ شَنَّةٍ وُضُوءًا يُقَلِّلُهُ فَقُمْتُ فَصَنَعْتُ كَمَا صَنَعَ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'i Ibrahim bin Muhammad bin Al 'Abbas] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru] ia mendengar [Kuraib] berkata; aku mendengar [Ibnu 'Abbas] berkata: aku menginap di tempat bibiku Maimunah, lalu Rasulullah shallallahu 'alaihi wasallam bangun berwudlu dengan hemat dari air yang ada di geriba. Maka akupun bangun dan melakukan sebagaimana yang beliau lakukan.\""},"386":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ مُحَمَّدِ بْنِ الْفَضْلِ عَنْ أَبِيهِ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَتَوَضَّأُ فَقَالَ لَا تُسْرِفْ لَا تُسْرِفْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Muhammad bin Al Fadhl] dari [Bapaknya] dari [Salim] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat seorang lelaki yang sedang berwudlu, kemudian bersabda: \"Jangan berlebih-lebihan, jangan berlebih-lebihan.\""},"387":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ حُيَيِّ بْنِ عَبْدِ اللَّهِ الْمَعَافِرِيِّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِسَعْدٍ وَهُوَ يَتَوَضَّأُ فَقَالَ مَا هَذَا السَّرَفُ فَقَالَ أَفِي الْوُضُوءِ إِسْرَافٌ قَالَ نَعَمْ وَإِنْ كُنْتَ عَلَى نَهَرٍ جَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Huyai bin Abdullah Al Ma'arifi] dari [Abi Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru] berkata; \"Rasulullah shallallahu 'alaihi wasallam melewati Sa'd yang sedang berwudlu, lalu beliau bersabda: \"Kenapa berlebih-lebihan! \" Sa'd berkata; \"Apakah dalam wudlu juga ada berlebih-lebihan?\" beliau menjawab: \"Ya, meskipun engkau berada di sungai yang mengalir.\""},"388":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا مُوسَى بْنُ سَالِمٍ أَبُو جَهْضَمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِسْبَاغِ الْوُضُوءِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Musa bin Salim Abu Jahdlam] berkata, telah menceritakan kepada kami [Abdullah bin Ubaidullah bin 'Abbas] dari [Ibnu 'Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menyempurnakan wudlu.\""},"389":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكُمْ عَلَى مَا يُكَفِّرُ اللَّهُ بِهِ الْخَطَايَا وَيَزِيدُ بِهِ فِي الْحَسَنَاتِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَى إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin Aqil] dari [Sa'id Ibnul Musayyab] dari [Abu Sa'id Al Khudri] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"maukah aku tunjukkan kepada kalian sesuatu yang dengannya Allah menghapus dosa dan mengangkat derajat?\" mereka menjawab: \"Mau wahai Rasulullah, \" beliau bersabda: \"Menyempurnakan wudlu di saat yang tidak disukai, memperbanyak langkah menuju masjid dan menunggu shalat setelah shalat.\""},"390":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا سُفْيَانُ بْنُ حَمْزَةَ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ الْوَلِيدِ بْنِ رَبَاحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَفَّارَاتُ الْخَطَايَا إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَإِعْمَالُ الْأَقْدَامِ إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Sufyan bin Hamzah] dari [Katsir bin Zaid] dari [Al Walid bin Rabah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Menyempurnakan wudlu di saat yang tidak di sukai, melangkahkan kaki menuju masjid dan menunggu shalat setelah shalat dapat menghapus kesalahan.\""},"391":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ أَبِي أُمَيَّةَ عَنْ حَسَّانَ بْنِ بِلَالٍ عَنْ عَمَّارِ بْنِ يَاسِرٍ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ حَسَّانَ بْنِ بِلَالٍ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَلِّلُ لِحْيَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] berkata, telah menceritakan kepada kami [Sufyan] dari [Abdul Karim Abu Umayyah] dari [Hassan bin Bilal] dari ['Ammar bin Yasir]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ibnu Abu Umar] berkata; telah menceritakan kepada kami [Sufyan] dari [Sa'id bin Abu 'Arubah] dari [Qotadah] dari [Hassan bin Bilal] dari ['Ammar bin Yasir] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menyelah-nyelah jenggotnya.\" "},"392":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي خَالِدٍ الْقَزْوِينِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ إِسْرَائِيلَ عَنْ عَامِرِ بْنِ شَقِيقٍ الْأَسَدِيِّ عَنْ أَبِي وَائِلٍ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Khalid Al Qazwini] berkata, telah menceritakan kepada kami [Abdurrazzaq] dari [Isra`il] dari [Amir bin Syaqiq Al Asadi] dari [Abu Wa`il] dari [Utsman bin 'Affan] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu menyelah-nyelah jenggotnya.\""},"393":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَفْصِ بْنِ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ أَبُو النَّضْرِ صَاحِبُ الْبَصْرِيِّ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ خَلَّلَ لِحْيَتَهُ وَفَرَّجَ أَصَابِعَهُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Hafsh bin Hisyam bin Zaid bin Anas bin Malik] berkata, telah menceritakan kepada kami [Yahya bin Katsir Abu An Nadlr] dari [Yazid Ar Raqasyi] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika berwudlu selalu menyelah-nyelah jenggotnya, dan merenggangkan jari-jemarinya dua kali.\""},"394":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ قَيْسٍ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ عَرَكَ عَارِضَيْهِ بَعْضَ الْعَرْكِ ثُمَّ شَبَكَ لِحْيَتَهُ بِأَصَابِعِهِ مِنْ تَحْتِهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Abdul Humaid bin Habib] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Abdul Wahid bin Qais] berkata, telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam apabila berwudlu selalu menggosok kedua pipi lalu menyelah-nyelah jenggotnya dengan jemarinya dari bawah.\" "},"395":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ الْكِلَابِيُّ حَدَّثَنَا وَاصِلُ بْنُ السَّائِبِ الرَّقَاشِيُّ عَنْ أَبِي سَوْرَةَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqqi] berkata, telah menceritakan kepada kami [Muhammad bin Rabi'ah Al Kilabi] berkata, telah menceritakan kepada kami [Washil bin Sa`ib Ar Raqasyi] dari [Abu Saurah] dari [Abu Ayyub Al Anshari] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu seraya menyelah-nyelah jenggotnya.\""},"396":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا أَخْبَرَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ قَالَ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِأَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدٍ وَهُوَ جَدُّ عَمْرِو بْنِ يَحْيَى هَلْ تَسْتَطِيعُ أَنْ تُرِيَنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ فَقَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ فَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَ يَدَيْهِ مَرَّتَيْنِ ثُمَّ تَمَضْمَضَ وَاسْتَنْثَرَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Sulaiman] dan [Harmalah bin Yahya] keduanya berkata; telah mengabarkan kepada kami [Muhammad bin Idris Asy SYafi'i] berkata; telah memberitakan kepada kami [Malik bin Anas] dari ['Amru bin Yahya] dari [Bapaknya] bahwasanya ia berkata kepada [Abdullah bin Zaid] -dia adalah kakek 'Amru bin Yahya- berkata; \"Bisakah engkau memperlihatkan kepadaku bagaimana Rasulullah shallallahu 'alaihi wasallam berwudlu?\" Abdullah bin Zaid menjawab; \"Ya, \" lalu ia minta diambilkan air wudlu, kemudian ia menuangkan air ke tangannya seraya membasuh kedua tangannya dua kali, berkumur dan istintsar (mengeluarkan air dari hidung) tiga kali, membasuh wajah tiga kali, membasuh kedua tangan hingga siku dua kali-dua kali, kemudian mengusap kepalanya dengan kedua tangan dimulai dari bagian depan kepala ke belakang lalu kembali lagi ke tempat semula. Setelah itu membasuh kedua kakinya.\""},"397":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ رَأْسَهُ مَرَّةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abbad bin Al 'Awwam] dari [Hajjaj] dari ['Atho`] dari [Utsman bin 'Affan] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu lalu mengusap kepalanya satu kali.\""},"398":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ رَأْسَهُ مَرَّةً","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Abu Hayyah] dari [Ali] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengusap kepalanya satu kali.\""},"399":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيُّ حَدَّثَنَا يَحْيَى بْنُ رَاشِدٍ الْبَصْرِيُّ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ رَأْسَهُ مَرَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Al Harist Al Mishri] berkata, telah menceritakan kepada kami [Yahya bin Rasyid Al Bashri] dari [Yazid] -mantan budak Salamah- dari [Salamah bin Al Akwa'] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu lalu mengusap kepalanya satu kali.\""},"400":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ رَأْسَهُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayyi' binti Mu'awwidz bin Afra'] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu mengusap kepalanya dua kali.\""},"401":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ أُذُنَيْهِ دَاخِلَهُمَا بِالسَّبَّابَتَيْنِ وَخَالَفَ إِبْهَامَيْهِ إِلَى ظَاهِرِ أُذُنَيْهِ فَمَسَحَ ظَاهِرَهُمَا وَبَاطِنَهُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu 'Ajlan] dari [Zaid] dari [Atho` bin Yasar] dari [Ibnu 'Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengusap kedua telinganya bagian dalam dengan kedua jari telunjuk, dan bagian belakang dengan dua ibu jarinya, hingga beliau mengusapnya luar dan dalamnya.\""},"402":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ ظَاهِرَ أُذُنَيْهِ وَبَاطِنَهُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] berkata, telah menceritakan kepada kami [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayyi'] berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu lalu mengusap kedua telinganya pada bagian dalam dan luarnya.\""},"403":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدْخَلَ إِصْبَعَيْهِ فِي جُحْرَيْ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al Hasan bin Shalih] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayyi' binti Mu'awwidz bin Afra'] ia berkata, \"Nabi shallallahu 'alaihi wasallam berwudlu lalu beliau memasukkan kedua jarinya ke dalam lubang telinga.\""},"404":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَيْسَرَةَ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ ظَاهِرَهُمَا وَبَاطِنَهُمَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Hariz bin Utsman] dari [Abdurrahman bin Maisarah] dari [Al Miqdam bin Ma'dikarib] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu, lalu mengusap kepalanya dan kedua telinga baik luar maupun dalamnya.\""},"405":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ شُعْبَةَ عَنْ حَبِيبِ بْنِ زَيْدٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأُذُنَانِ مِنْ الرَّأْسِ","id":"Telah menceritakan kepada kami [Suwaid bin sa'id] berkata, telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Syu'bah] dari [Habib bin Zaid] dari [Abbad bin Tamim] dari [Abdullah bin Zaid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedua telinga termasuk bagian dari kepala.\""},"406":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سِنَانِ بْنِ رَبِيعَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأُذُنَانِ مِنْ الرَّأْسِ وَكَانَ يَمْسَحُ رَأْسَهُ مَرَّةً وَكَانَ يَمْسَحُ الْمَأْقَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Sinan bin Rabi'ah] dari [Syahr bin Hausyab] dari [Abu Umamah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedua telinga adalah bagian dari kepala.\" Dan beliau mengusap kepalanya satu kali serta mengusap dua daun telinganya.\""},"407":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ الْحُصَيْنِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُلَاثَةَ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأُذُنَانِ مِنْ الرَّأْسِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Amru bin Al Hushain] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah bin 'Ulatsah] dari [Abdul Karim Al Jazari] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedua telinga adalah bagian dari kepala.\""},"408":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرٍ عَنْ ابْنِ لَهِيعَةَ حَدَّثَنِي يَزِيدُ بْنُ عَمْرٍو الْمَعَافِرِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَخَلَّلَ أَصَابِعَ رِجْلَيْهِ بِخِنْصِرِهِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا خَازِمٌ بْنُ يَحْيَي الْحُلْوَانِيُّ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Muhammad bin Himyar] dari [Ibnu Lahi'ah] berkata, telah menceritakan kepadaku [Yazid bin 'Amru Al Ma'afiri] dari [Abu Abdurrahman Al Hubuli] dari [Al Mustaurid bin Syaddad] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu lalu menyela jari-jari kakinya dengan jari kelingkingnya.\" Abu Al Hasan bin Salamah berkata; telah menceritakan kepada kami Khazim bin Yahya Al Hulwani berkata, telah menceritakan kepada kami Qutaibah berkata, telah menceritakan kepada kami Ibnu Lahi'ah lalu ia menyebutkan sebagaimana hadits di atas.\""},"409":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا سَعْدُ بْنُ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ ابْنِ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَأَسْبِغْ الْوُضُوءَ وَاجْعَلْ الْمَاءَ بَيْنَ أَصَابِعِ يَدَيْكَ وَرِجْلَيْكَ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] berkata, telah menceritakan kepada kami [Sa'd bin Abdul Hamid bin Ja'far] dari [Ibnu Abu Az Zinad] dari [Musa bin Uqbah] dari [Shalih] mantan budak At Tau`amah, dari [Ibnu 'Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu ingin mendirikan shalat maka sempurnakanlah wudlu, dan jadikanlah air di antara jari-jari tangan dan kedua kakimu.\""},"410":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ إِسْمَعِيلَ بْنِ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْبِغْ الْوُضُوءَ وَخَلِّلْ بَيْنَ الْأَصَابِعِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`ifi] dari [Isma'il bin Katsir] dari ['Ashim bin Laqith bin Shabrah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sempurnakanlah wudlu dan sela-sela-lah antara jemari.\""},"411":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الرَّقَاشِيُّ حَدَّثَنَا مَعْمَرُ بْنُ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ حَدَّثَنِي أَبِي عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا تَوَضَّأَ حَرَّكَ خَاتَمَهُ","id":"Telah menceritakan kepada kami [Abdul Malik bin Muhammad Ar Raqasyi] berkata, telah menceritakan kepada kami [Ma'mar bin Muhammad bin Ubaidullah bin Abu Rafi'] berkata, telah menceritakan kepadaku [Bapakku] dari [Ubaidullah bin Abu Rafi'] dari [Bapaknya] berkata, \"Jika berwudlu Rasulullah shallallahu 'alaihi wasallam selalu menggerak-gerakkan cincinnya.\""},"412":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمًا يَتَوَضَّئُونَ وَأَعْقَابُهُمْ تَلُوحُ فَقَالَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ أَسْبِغُوا الْوُضُوءَقَالَ الْقَطَّانُ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا عَبْدُ الْمُؤْمِنِ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Yahya] dari [Abdullah bin 'Amru] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melihat suatu kaum yang sedang berwudlu, namun tumit-tumit mereka masih kering, maka beliau pun bersabda: \"Tumit-tumit yang tidak terbasuh air wudlu akan masuk neraka, sempurnakanlah wudlu kalian.\" Al Qaththan berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abdul Mukmin bin Ali berkata, telah menceritakan kepada kami Abdus Salam bin Harb dari Hisyam bin 'Urwah dari Bapaknya dari Aisyah ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tumit-tumit yang tidak terbasuh air wudlu akan masuk neraka.\""},"413":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ ابْنِ عَجْلَانَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَأَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَلَمَةَ قَالَرَأَتْ عَائِشَةُ عَبْدَ الرَّحْمَنِ وَهُوَ يَتَوَضَّأُ فَقَالَتْ أَسْبِغْ الْوُضُوءَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلْعَرَاقِيبِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdullah bin Raja` Al Makki] dari [Ibnu 'Ajlan]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abu Khalid bin Ahmar] dari [Muhammad bin 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Salamah] ia berkata; [Aisyah] melihat Abdurrahman sedang berwudlu, lalu ia berkata; \"Sempurnakanlah wudlumu, Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Araqib (urat di atas tumit) yang tidak terbasuh air wudlu akan masuk neraka.\""},"414":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Aziz Ibnul Mukhtar] berkata, telah menceritakan kepada kami [Suhail] dari [Bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tumit-tumit yang tidak terbasuh air wudlu akan masuk neraka.\""},"415":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي كَرِبٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلْعَرَاقِيبِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Sa'id bin Abu Karib] dari [Jabir bin Abdullah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Araqib (urat di atas tumit) yang tidak terbasuh air wudlu akan masuk neraka.\""},"416":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ وَعُثْمَانُ بْنُ إِسْمَعِيلَ الدِّمَشْقِيَّانِ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا شَيْبَةُ بْنُ الْأَحْنَفِ عَنْ أَبِي سَلَّامٍ الْأَسْوَدِ عَنْ أَبِي صَالِحٍ الْأَشْعَرِيِّ حَدَّثَنِي أَبُو عَبْدِ اللَّهِ الْأَشْعَرِيُّ عَنْ خَالِدِ بْنِ الْوَلِيدِ وَيَزِيدَ بْنِ أَبِي سُفْيَانَ وَشُرَحْبِيلَ ابْنِ حَسَنَةَ وَعَمْرِو بْنِ الْعَاصِ كُلُّ هَؤُلَاءِسَمِعُوا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتِمُّوا الْوُضُوءَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman] dan [Utsman bin Isma'il Ad Dimasyqi] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Syaibah bin Al Ahnaf] dari [Abu Sallam Al Aswad] dari [Abu Shalih Al Asy'ari] berkata, telah menceritakan kepadaku [Abu Abdullah Al Asy'ari] dari [Khalid bin Al Walid] dan [Yazid bin Abu Sufyan] dan [Syurahbil bin Hasanah] dan ['Amru bin Al 'Ash] semuanya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sempurnakanlah wudlu, tumit-tumit yang tidak terbasuh air wudlu akan masuk neraka.\""},"417":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ قَالَرَأَيْتُ عَلِيًّا تَوَضَّأَ فَغَسَلَ قَدَمَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ قَالَ أَرَدْتُ أَنْ أُرِيَكُمْ طُهُورَ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abu Hayyah] ia berkata; Aku melihat Ali berwudlu, lalu ia membasuh kedua telapak kakinya hingga mata kaki, kemudian ([Ali]) berkata; \"Aku ingin memperlihatkan kepada kalian tatacara Nabi kalian shallallahu 'alaihi wasallam dalam bersuci.\" "},"418":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَيْسَرَةَ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَغَسَلَ رِجْلَيْهِ ثَلَاثًا ثَلَاثًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Hariz bin Utsman] dari [Abdurrahman bin Maisarah] dari [Al Miqdam bin Ma'dikarib] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu membasuh kedua kakinya tiga kali-tiga kali.\""},"419":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ رَوْحِ بْنِ الْقَاسِمِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ قَالَتْ أَتَانِي ابْنُ عَبَّاسٍ فَسَأَلَنِي عَنْ هَذَا الْحَدِيثِ تَعْنِي حَدِيثَهَا الَّذِي ذَكَرَتْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَغَسَلَ رِجْلَيْهِفَقَالَ ابْنُ عَبَّاسٍ إِنَّ النَّاسَ أَبَوْا إِلَّا الْغَسْلَ وَلَا أَجِدُ فِي كِتَابِ اللَّهِ إِلَّا الْمَسْحَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Rauh Ibnul Qasim] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayyi'] ia berkata; \"Ibnu 'Abbas mendatangiku dan bertanya berkenaan dengan hadits ini, yaitu hadits yang menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam berwudlu dan membasuh kedua kakinya. Ibnu 'Abbas berkata; \"Manusia tidak menghendaki kecuali membasuh, sedangkan aku tidak mendapatkan dalam Kitabullah selain mengusap.\" "},"420":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ أَبِي صَخْرَةَ قَالَ سَمِعْتُ حُمْرَانَ يُحَدِّثُ أَبَا بُرْدَةَ فِي الْمَسْجِدِ أَنَّهُ سَمِعَ عُثْمَانَ بْنَ عَفَّانَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَمَّ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ فَالصَّلَاةُ الْمَكْتُوبَاتُ كَفَّارَاتٌ لِمَا بَيْنَهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad Abu Shakhrah] berkata; Di masjid aku mendengar [Humran] menceritakan kepada Abu Burdah bahwa ia pernah mendengar [Utsman bin 'Affan] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menyempurnakan wudlu sebagaimana yang diperintahkan Allah maka shalat-shalat maktubah akan menghapus dosa antara shalat-shalat tersebut.\""},"421":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَنِي عَلِيُّ بْنُ يَحْيَى بْنِ خَلَّادٍ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَةَ بْنِ رَافِعٍأَنَّهُ كَانَ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهَا لَا تَتِمُّ صَلَاةٌ لِأَحَدٍ حَتَّى يُسْبِغَ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ تَعَالَى يَغْسِلُ وَجْهَهُ وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ وَيَمْسَحُ بِرَأْسِهِ وَرِجْلَيْهِ إِلَى الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] berkata, telah menceritakan kepadaku [Ali bin Yahya bin Khallad] dari [Bapaknya] dari pamannya [Rifa'ah bin Rafi'] ketika dia duduk di samping Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat seseorang tidak akan sempurna hingga ia menyempurnakan wudlu sebagaimana yang diperintahkan oleh Allah Ta'ala, membasuh muka dan kedua tangannya hingga siku, lalu mengusap kepala dan membasuh kedua kakinya hingga ke kedua mata kakinya.\""},"422":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ قَالَ قَالَ مَنْصُورٌ حَدَّثَنَا مُجَاهِدٌ عَنْ الْحَكَمِ بْنِ سُفْيَانَ الثَّقَفِيِّأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ ثُمَّ أَخَذَ كَفًّا مِنْ مَاءٍ فَنَضَحَ بِهِ فَرْجَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Zakaria bin Abu Za`idah] ia berkata; [Manshur] berkata; telah menceritakan kepada kami [Mujahid] dari [Al Hakam bin Sufyan Ats Tsaqafi] bahwasanya ia pernah melihat Rasulullah shallallahu 'alaihi wasallam berwudlu, kemudian mengambil air setelapak tangan dan memercikannya pada kemaluannya.\""},"423":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ الْفِرْيَابِيُّ حَدَّثَنَا حَسَّانُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدِ بْنِ حَارِثَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَنِي جِبْرَائِيلُ الْوُضُوءَ وَأَمَرَنِي أَنْ أَنْضَحَ تَحْتَ ثَوْبِي لِمَا يَخْرُجُ مِنْ الْبَوْلِ بَعْدَ الْوُضُوءِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ ح وَحَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ التَّنِّيسِيُّ عَنْ ابْنِ لَهِيعَةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad Al Firwani] berkata, telah menceritakan kepada kami [Hassan bin Abdullah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Uqail] dari [Az Zuhri] dari [Urwah] berkata; telah menceritakan kepada kami [Usamah bin Zaid bin Haritsah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Jibril mengajariku wudlu dan memerintahkan agar aku memercikkan air pada bagian bawah kain karena (sisa) kencing yang keluar setelah wudhu.\" "},"424":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ سَلَمَةَ الْيَحْمِدِيُّ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْهَاشِمِيُّ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَضِحْ","id":"Telah menceritakan kepada kami [Al Husain bin Maslamah Al Yahmidi] berkata, telah menceritakan kepada kami [Salm bin Qutaibah] berkata, telah menceritakan kepada kami [Al Hasan bin Ali Al Hasyimi] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu berwudlu maka percikkanlah (air pada kemaluan).\""},"425":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا قَيْسٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Ashim bin Ali] berkata, telah menceritakan kepada kami [Qais] dari [Ibnu Abu Laila] dari [Abu Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu memercikkan air pada kemaluannya.\" "},"426":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْث�� بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ أَنَّ أَبَا مُرَّةَ مَوْلَى عَقِيلٍ حَدَّثَهُ أَنَّ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ حَدَّثَتْهُأَنَّهُ لَمَّا كَانَ عَامُ الْفَتْحِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى غُسْلِهِ فَسَتَرَتْ عَلَيْهِ فَاطِمَةُ ثُمَّ أَخَذَ ثَوْبَهُ فَالْتَحَفَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'id bin Abu Hind] bahwa [Abu Murrah] mantan budak Aqil menceritakan kepadanya, bahwa [Ummu Hani` binti Abu Thalib] menceritakan kepadanya, bahwa pada tahun penaklukan, Rasulullah shallallahu 'alaihi wasallam masuk ke pemandiannya sedang Fatimah menutupi beliau. Kemudian beliau mengambil kain miliknya dan berselimut.\""},"427":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَسْعَدَ بْنِ زُرَارَةَ عَنْ مُحَمَّدِ بْنِ شُرَحْبِيلَ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْنَا لَهُ مَاءً فَاغْتَسَلَ ثُمَّ أَتَيْنَاهُ بِمِلْحَفَةٍ وَرْسِيَّةٍ فَاشْتَمَلَ بِهَا فَكَأَنِّي أَنْظُرُ إِلَى أَثَرِ الْوَرْسِ عَلَى عُكَنِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ibnu Abu Laila] dari [Muhammad bin Abdurrahman bin As'ad bin Zurarah] dari [Muhammad bin Syurahbil] dari [Qais bin Sa'd] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendatangi kami, kemudian kami menyiapkan air untuknya hingga beliau pun mandi. Setelah itu kami memberikan kain berwarna merah, lalu beliau berselimut dengannya hingga seakan-akan kami melihat bekas warnanya pada lipatan perutnya.\" "},"428":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ حَدَّثَنَا ابْنُ عَبَّاسٍ عَنْ خَالَتِهِ مَيْمُونَةَ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَوْبٍ حِينَ اغْتَسَلَ مِنْ الْجَنَابَةِ فَرَدَّهُ وَجَعَلَ يَنْفُضُ الْمَاءَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] berkata, telah menceritakan kepada kami [Ibnu 'Abbas] dari bibinya [Maimunah] ia berkata; \"Ketika beliau mandi junub aku membawakan kain untuknya, namun beliau menolak seraya menyeka air.\""},"429":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ وَأَحْمَدُ بْنُ الْأَزْهَرِ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ السِّمْطِ حَدَّثَنَا الْوَضِينُ بْنُ عَطَاءٍ عَنْ مَحْفُوظِ بْنِ عَلْقَمَةَ عَنْ سَلْمَانَ الْفَارِسِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَقَلَبَ جُبَّةَ صُوفٍ كَانَتْ عَلَيْهِ فَمَسَحَ بِهَا وَجْهَهُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid] dan [Ahmad Al Azhar] keduanya berkata; telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Yazid bin As Simth] berkata, telah menceritakan kepada kami [Al Wadlin bin 'Atho`] dari [Mahfuzh bin Alqamah] dari [Salman Al Farisi] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu beliau membalik jubah wol yang dipakainya kemudian mengusap wajahnya dengannya.\""},"430":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ وَزَيْدُ بْنُ الْحُبَابِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ قَالُوا حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ بْنِ وَهْبٍ أَبُو سُلَيْمَانَ النَّخَعِيُّ قَالَ حَدَّثَنِي زَيْدٌ الْعَمِّيُّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَالَ ثَلَاثَ مَرَّاتٍ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فُتِحَ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ مِنْ أَيِّهَا شَاءَ دَخَلَقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ الْقَطَّانُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو نُعَيْمٍ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Musa bin Abdurrahman] berkata, telah menceritakan kepada kami [Al Husain bin Ali] dan [Zaid Ibnul Hubab]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Nu'aim] mereka berkata; telah menceritakan kepada kami ['Amru bin Abdullah bin Wahb Abu Sulaiman An Nakha'i] berkata; telah menceritakan kepadaku [Zaid Al Ammi] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berwudlu dan membaguskannya, setelah itu membaca; ASYHADU ANLAA ILAAHA ILLAALLHU WAHDAHUU LAA SYARIIKALAH WA ASYHADU ANNA MUHAMMADAN ABDUHU WA RASUULUHU (Aku bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah Yang Maha Esa dan tidak dan tidak ada sekutu bagi-Nya. Dan aku bersaksi bahwa Muhammad adalah hamba dan Rasul-Nya) sebanyak tiga kali, maka akan dibukakan untuknya delapan pintu surga, ia masuk dari pintu mana saja yang ia sukai.\" Abu Al Hasan bin Salamah Al Qaththan berkata; telah menceritakan kepada kami Ibrahim bin Nashr berkata, telah menceritakan kepada kami Abu Nu'aim sebagaimana hadits diatas.\" "},"431":{"ar":"حَدَّثَنَا عَلْقَمَةُ بْنُ عَمْرٍو الدَّارِمِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ عَطَاءٍ الْبَجَلِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يَتَوَضَّأُ فَيُحْسِنُ الْوُضُوءَ ثُمَّ يَقُولُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ إِلَّا فُتِحَتْ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهَا شَاءَ","id":"Telah menceritakan kepada kami [Alqamah bin 'Amru Ad Darimi] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Ishaq] dari [Abdullah bin 'Atho` Al Bajali] dari [Uqbah bin Amir Al Juhani] dari [Umar Ibnul Khaththab] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim berwudlu dan membaguskan wudlunya kemudian membaca; ASYHADU ANLAA ILAAHA ILLAALLHU WA ASYHADU ANNA MUHAMMADAN ABDUHU WA RASUULUHU (Aku bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah selain Allah. Dan aku bersaksi bahwa Muhammad adalah hamba dan Rasul-Nya), kecuali akan dibukakan untuknya delapan pintu surga, ia masuk dari pintu mana saja yang ia suka.\" "},"432":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ الْعَزِيزِ بْنِ الْمَاجِشُونِ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْرَجْنَا لَهُ مَاءً فِي تَوْرٍ مِنْ صُفْرٍ فَتَوَضَّأَ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ahmad bin Abdullah] dari [Abdul Aziz bin Al Majisyun] berkata, telah menceritakan kepada kami ['Amru bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] sahabat Nabi shallallahu 'alaihi wasallam, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami, lalu kami mengeluarkan air dalam bejana kecil dari tembaga hingga beliau berwudlu dengannya.\" "},"433":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ جَحْشٍأَنَّهُ كَانَ لَهَا مِخْضَبٌ مِنْ صُفْرٍ قَالَتْ فَكُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad bin Ad Darawardi] dari [Ubaidullah bin Umar] dari [Ibrahim bin Muhammad bin Abdullah bin Jahsy] dari [Bapaknya] dari [Zainab binti Jahsy] bahwasanya ia mempunyai bejana dari tembaga, ia berkata; \"Aku biasa merapikan rambut Rasulullah shallallahu 'alaihi wasallam dengan bejana tersebut.\""},"434":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ إِبْرَاهِيمَ بْنِ جَرِيرٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فِي تَوْرٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Ibrahim bin Jarir] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam berwudlu dalam mangkuk kecil dari tembaga.\""},"435":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنَامُ حَتَّى يَنْفُخَ ثُمَّ يَقُومُ فَيُصَلِّي وَلَا يَتَوَضَّأُقَالَ الطَّنَافِسِيُّ قَالَ وَكِيعٌ تَعْنِي وَهُوَ سَاجِدٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidur hingga terdengar tarikan nafasnya, kemudian beliau bangun dan shalat tanpa berwudlu terlebih dahulu.\" Ath Thanafusi berkata; Waki' berkata; \"Maksudnya bahwa beliau dalam keadaan sujud.\""},"436":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ حَجَّاجٍ عَنْ فُضَيْلِ بْنِ عَمْرٍو عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ حَتَّى نَفَخَ ثُمَّ قَامَ فَصَلَّى","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Al Hajjaj] dari [Fudlail bin 'Amru] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata; \"Rasulullah shallallahu 'alaihi wasallam tidur hingga terdengar tarikan nafasnya, setelah itu beliau shalat dan tidak berwudlu.\""},"437":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ عَنْ ابْنِ أَبِي زَائِدَةَ عَنْ حُرَيْثِ بْنِ أَبِي مَطَرٍ عَنْ يَحْيَى بْنِ عَبَّادٍ أَبِي هُبَيْرَةَ الْأَنْصَارِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ نَوْمُهُ ذَلِكَ وَهُوَ جَالِسٌ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] dari [Ibnu Abu Za`idah] dari [Huraits bin Abu Mathar] dari [Yahya bin Abbad Abu Hubairah Al Anshari] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas], ia berkata; \"Begitulah beliau tidur, yakni dalam keadaan duduk.\" Yang dimaksud adalah Nabi shallallahu 'alaihi wasallam.\" "},"438":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ الْوَضِينِ بْنِ عَطَاءٍ عَنْ مَحْفُوظِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَائِذٍ الْأَزْدِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَيْنُ وِكَاءُ السَّهِ فَمَنْ نَامَ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Al Wadlin bin 'Atho`] dari [Mahfuzh bin Alqamah] dari [Abdurrahman bin A`idz Al 'Azdi] dari [Ali bin Abu Thalib] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mata adalah tali penutup dubur, maka barangsiapa tertidur hendaklah ia wudlu.\""},"439":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ لَا نَنْزِعَ خِفَافَنَا ثَلَاثَةَ أَيَّامٍ إِلَّا مِنْ جَنَابَةٍ لَكِنْ مِنْ غَائِطٍ وَبَوْلٍ وَنَوْمٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ashim] dari [Zirr] dari [Shafwan bin 'Assal] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kami tidak melepas khuf kami selama tiga hari kecuali jika junub. dan tetap dibolehkan memakai karena sebab buang air besar, buang air kecil dan tidur.\""},"440":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ بُسْرَةَ بِنْتِ صَفْوَانَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَسَّ أَحَدُكُمْ ذَكَرَهُ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Marwan Ibnul Hakam] dari [Busrah binti Shafwan] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menyentuh kemaluannya hendaklah berwudlu.\""},"441":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ جَمِيعًا عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ عُقْبَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَسَّ أَحَدُكُمْ ذَكَرَهُ فَعَلَيْهِ الْوُضُوءُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizam] berkata, telah menceritakan kepada kami [Ma'n bin Isa]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Abdullah bin Nafi'] dari [Ibnu Abu Dzi`b] dari [Uqbah bin Abdurrahman] dari [Muhammad bin Abdurrahman bin Tsauban] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menyentuh kemaluannya, maka baginya wajib berwudlu.\" "},"442":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْمُعَلَّى بْنُ مَنْصُورٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ مَسَّ فَرْجَهُ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Mu'alla bin Manshur]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan Ad Dimasyqi] berkata, telah menceritakan kepada kami [Marwan bin Muhammad] mereka berkata; telah menceritakan kepada kami [Al Haitsam bin Humaid] berkata, telah menceritakan kepada kami [Al 'Ala` bin Al Harits] dari [Makhul] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyentuh kemaluannya, hendaklah ia berwudlu.\""},"443":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ إِسْحَقَ بْنِ أَبِي فَرْوَةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ عَنْ أَبِي أَيُّوبَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ مَسَّ فَرْجَهُ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Ishaq bin Abu Farwah] dari [Az Zuhri] dari [Abdurrahman bin Abd Al Qoriy] dari [Abu Ayyub] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyentuh kemaluannya, hendaklah ia berwudlu.\""},"444":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ قَالَ سَمِعْتُ قَيْسَ بْنَ طَلْقٍ الْحَنَفِيَّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ مَسِّ الذَّكَرِ فَقَالَ لَيْسَ فِيهِ وُضُوءٌ إِنَّمَا هُوَ مِنْكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Muhammad bin Jabir] berkata; aku mendengar [Qais bin Thalq Al Hanafi] dari [Bapaknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam ditanya tentang hukum menyentuh kemaluan, maka beliau menjawab: \"Tidak ada kewajiban wudlu karena ia adalah bagian dari tubuhmu.\""},"445":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مَسِّ الذَّكَرِ فَقَالَ إِنَّمَا هُوَ جِذْيَةٌ مِنْكَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Ja'far bin Zubair] dari [Al Qasim] dari [Abu Umamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang hukum menyentuh kemaluan, lalu beliau menjawab: \"Ia hanyalah bagian darimu.\" "},"446":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَلْقَمَةَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا غَيَّرَتْ النَّارُفَقَالَ ابْنُ عَبَّاسٍ أَتَوَضَّأُ مِنْ الْحَمِيمِ فَقَالَ لَهُ يَا ابْنَ أَخِي إِذَا سَمِعْتَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا فَلَا تَضْرِبْ لَهُ الْأَمْثَالَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin 'Amru bin Alqamah] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Berwudlulah kalian dari sesuatu yang telah diubah oleh api.\" Maka Ibnu 'Abbas pun bertanya; \"Apakah kami juga berwudlu karena air hangat?\" Abu Hurairah lalu berkata kepada Ibnu 'Abbas; \"Wahai putra saudaraku, jika engkau mendengar hadits Rasulullah shallallahu 'alaihi wasallam janganlah membuat perumpamaan-perumpamaan.\""},"447":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah memberitakan kepada kami [Yunus bin Yazid] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berwudlulah dari sesuatu yang tersentuh oleh api.\""},"448":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ الْأَزْرَقُ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ بْنِ أَبِي مَالِكٍ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ يَضَعُ يَدَيْهِ عَلَى أُذُنَيْهِ وَيَقُولُ صُمَّتَا إِنْ لَمْ أَكُنْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah menceritakan kepada kami [Hisyam bin Khalid Al Azraq] berkata, telah menceritakan kepada kami [Khalid bin Yazid bin Abu Malik] dari [Bapaknya] dari [Anas bin Malik], Yazid menuturkan; dia meletakkan kedua tangannya di kedua telinganya, dan berkata; diamlah kalian berdua, sekiranya aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berwudlulah dari sesuatu yang tersentuh oleh api.\""},"449":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتِفًا ثُمَّ مَسَحَ يَدَيْهِ بِمِسْحٍ كَانَ تَحْتَهُ ثُمَّ قَامَ إِلَى الصَّلَاةِ فَصَلَّى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu 'Abbas], ia menuturkan; \"Nabi shallallahu 'alaihi wasallam makan kaki kambing, lalu beliau mengusap kedua tangannya dengan kain yang ada di bawahnya dan bergegas menegakkan shalat.\" "},"450":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَعَمْرِو بْنِ دِينَارٍ وَعَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ خُبْزًا وَلَحْمًا وَلَمْ يَتَوَضَّئُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah mengabarkan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin Al Munkadir] dan ['Amru bin Dinar] dan [Abdullah bin Muhammad bin 'Aqil] dari [Jabir bin Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar makan roti dan daging, namun mereka tidak berwudlu.\""},"451":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ قَالَحَضَرْتُ عَشَاءَ الْوَلِيدِ أَوْ عَبْدِ الْمَلِكِ فَلَمَّا حَضَرَتْ الصَّلَاةُ قُمْتُ لِأَتَوَضَّأَ فَقَالَ جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَشْهَدُ عَلَى أَبِي أَنَّهُ شَهِدَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَكَلَ طَعَامًا مِمَّا غَيَّرَتْ النَّارُ ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْو قَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ وَأَنَا أَشْهَدُ عَلَى أَبِي بِمِثْلِ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Az Zuhri] berkata; Aku menghadiri jamuan makan malam Al Walid atau Abdul Malik, ketika waktu shalat tiba aku berdiri dan berwudlu, maka berkatalah [Ja'far bin 'Amru bin Umayyah]; \"Aku bersaksi atas [bapakku], bahwa ia bersaksi atas Rasulullah shallallahu 'alaihi wasallam; bahwasanya beliau makan makanan yang telah diubah oleh api, kemudian beliau shalat dan tidak berwudlu.\" [Ali bin Abdullah bin 'Abbas] berkata; \"Aku bersaksi atas [bapakku] seperti itu pula.\""},"452":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَتِفِ شَاةٍ فَأَكَلَ مِنْهُ وَصَلَّى وَلَمْ يَمَسَّ مَاءً","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ali Ibnul Husain] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam diberi hidangan kaki kambing, kemudian beliau makan dan shalat tanpa menyentuh air.\""},"453":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ أَنْب��أَنَا سُوَيْدُ بْنُ النُّعْمَانِ الْأَنْصَارِيُّأَنَّهُمْ خَرَجُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ حَتَّى إِذَا كَانُوا بِالصَّهْبَاءِ صَلَّى الْعَصْرَ ثُمَّ دَعَا بِأَطْعِمَةٍ فَلَمْ يُؤْتَ إِلَّا بِسَوِيقٍ فَأَكَلُوا وَشَرِبُوا ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ فَاهُ ثُمَّ قَامَ فَصَلَّى بِنَا الْمَغْرِبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] berkata, telah memberitakan kepada kami [Suwaid bin An Nu'man Al Anshari]; bahwasanya para sahabat berangkat bersama Rasulullah shallallahu 'alaihi wasallam menuju Khaibar, dan ketika mereka sampai Ash Shahba` beliau shalat ashar. Kemudian beliau minta dihidangkan makanan, namun beliau tidak mendapat hidangan kecuali sawiq hingga para sahabat ikut makan dan minum. Setelah itu beliau minta dibawakan air, kemudian beliau berkumur lalu berdiri dan shalat maghrib bersama kami.\" "},"454":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ كَتِفَ شَاةٍ فَمَضْمَضَ وَغَسَلَ يَدَيْهِ وَصَلَّى","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Aziz Ibnul Mukhtar] berkata, telah menceritakan kepada kami [Suhail] dari [Bapaknya] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam makan kaki kambing, lalu beliau berkumur, mencuci tangan dan shalat.\""},"455":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوُضُوءِ مِنْ لُحُومِ الْإِبِلِ فَقَالَ تَوَضَّئُوا مِنْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Abdullah] dari [Abdurrahman bin Abu Laila] dari [Al Bara` bin Azib] berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang wudlu karena makan daging unta, maka beliau menjawab: \"Berwudlulah kalian karena memakannya.\""},"456":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا زَائِدَةُ وَإِسْرَائِيلُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ جَعْفَرِ بْنِ أَبِي ثَوْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَتَوَضَّأَ مِنْ لُحُومِ الْإِبِلِ وَلَا نَتَوَضَّأَ مِنْ لُحُومِ الْغَنَمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Za`idah] dan [Isra`il] dari [Asy'ats bin Abu Asy Sya'tsa`] dari [Ja'far bin Abu Tsaur] dari [Jabir bin Samurah] berkata; \" Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk berwudlu karena makan daging unta, dan tidak berwudlu karena makan daging kambing.\""},"457":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ حَجَّاجٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ وَكَانَ ثِقَةً وَكَانَ الْحَكَمُ يَأْخُذُ عَنْهُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى عَنْ أُسَيْدِ بْنِ حُضَيْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَوَضَّئُوا مِنْ أَلْبَانِ الْغَنَمِ وَتَوَضَّئُوا مِنْ أَلْبَانِ الْإِبِلِ","id":"Telah menceritakan kepada kami [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] berkata, telah menceritakan kepada kami [Abbad Ibnul Awwam] dari [Hajjaj] dari [Abdullah bin Abdullah] mantan budak bani Hasyim, -ia adalah seorang yang dapat dipercaya dan Al Hakam mengambil hadits darinya, - dari [Abdurrahman bin Abu Laila] dari [Usaid bin Hudlair], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berwudlu karena susu kambing dan berwudlulah karena susu unta.\""},"458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ عَنْ خَالِدِ بْنِ يَزِيدَ بْنِ عُمَرَ بْنِ هُبَيْرَةَ الْفَزَارِيِّ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ سَمِعْتُ مُحَارِبَ بْنَ دِثَارٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِنْ لُحُومِ الْإِبِلِ وَلَا تَتَوَضَّئُوا مِنْ لُحُومِ الْغَنَمِ وَتَوَضَّئُوا مِنْ أَلْبَانِ الْإِبِلِ وَلَا تَوَضَّئُوا مِنْ أَلْبَانِ الْغَنَمِ وَصَلُّوا فِي مُرَاحِ الْغَنَمِ وَلَا تُصَلُّوا فِي مَعَاطِنِ الْإِبِلِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Abdu Rabbih] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Khalid bin Yazid bin Umar bin Hubairah Al Fajari] dari ['Atho` bin As Sa`ib] ia berkata; aku mendengar [Muharib bin Ditsar] berkata; aku mendengar [Abdullah bin Umar] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berwudlulah kalian karena daging unta, dan jangan berwudlu karena daging kambing. Berwudlulah kalian karena susu unta, dan jangan berwudlu karena susu kambing. Dan shalatlah kalian di kandang kambing, dan jangan shalat di kandang unta.\""},"459":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَضْمِضُوا مِنْ اللَّبَنِ فَإِنَّ لَهُ دَسَمًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibarhim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu 'Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Berkumur-kumurlah kalian karena susu, sebab di dalamnya terdapat lemak.\""},"460":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ مُوسَى بْنِ يَعْقُوبَ حَدَّثَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ عَنْ أَبِي��ِ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبْتُمْ اللَّبَنَ فَمَضْمِضُوا فَإِنَّ لَهُ دَسَمًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] dari [Musa bin Ya'qub] berkata, telah menceritakan kepadaku [Abu Ubaidah bin Abdullah bin Zam'ah] dari [Bapaknya] dari [Ummu Salamah] istri Nabi shallallahu 'alaihi wasallam, ia menuturkan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian meminum susu, maka berkumurlah, karena ia mengandung lemak.\""},"461":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَضْمِضُوا مِنْ اللَّبَنِ فَإِنَّ لَهُ دَسَمًا","id":"Telah menceritakan kepada kami [Abu Mush'ab] berkata, telah menceritakan kepada kami [Abdul Muhaimin bin 'Abbas bin Sahl bin Sa'd] dari [Bapaknya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berkumurlah kalian karena susu, sesungguhnya ia mengandung lemak.\""},"462":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ السَّوَّاقُ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَحَلَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً وَشَرِبَ مِنْ لَبَنِهَا ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ فَاهُ وَقَالَ إِنَّ لَهُ دَسَمًا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim As Sawwaq] berkata, telah menceritakan kepada kami [Ad Dlahhak bin Makhlad] berkata, telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerah susu kambing dan meminumnya. Kemudian beliau minta diambilkan air lalu berkumur-kumur seraya bersabda: \"Sesungguhnya ia mengandung lemak.\""},"463":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبَّلَ بَعْضَ نِسَائِهِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْ قُلْتُ مَا هِيَ إِلَّا أَنْتِ فَضَحِكَتْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Habib bin Abu Tsabit] dari [Urwah bin Az Zubair] dari [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam mencium sebagian isterinya kemudian pergi shalat tanpa berwudlu dahulu, \" Aku berkata, \"Bukankah yang beliau cium engkau sendiri?.\" Aisyah pun tertawa."},"464":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ زَيْنَبَ السَّهْمِيَّةِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ ثُمَّ يُقَبِّلُ وَيُصَلِّي وَلَا يَتَوَضَّأُ وَرُبَّمَا فَعَلَهُ بِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Al Hajjaj] dari ['Amru bin Syu'aib] dari [Zainab As Sahmiyah] dari [Aisyah] berkata; \"Beliau berwudlu kemudian mencium dan shalat tanpa berwudlu kembali. Dan barangkali hal itu beliau lakukan karena aku.\""},"465":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَذْيِ فَقَالَ فِيهِ الْوُضُوءُ وَفِي الْمَنِيِّ الْغُسْلُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] dari [Yazid bin Abu Zinad] dari [Abdurrahman bin Abu Laila] dari [Ali] ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang madzi, lalu beliau menjawab: \"dalam masalah ini (hanya) wudlu, sedangkan mani harus mandi.\" "},"466":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجْلِ يَدْنُو مِنْ امْرَأَتِهِ فَلَا يُنْزِلُ قَالَ إِذَا وَجَدَ أَحَدُكُمْ ذَلِكَ فَلْيَنْضَحْ فَرْجَهُ يَعْنِي لِيَغْسِلْهُ وَيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Utsman bin Umar] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Salim Abu An Nadlr] dari [Sulaiman bin Yasar] dari [Al Miqdad bin Al Aswad] bahwasanya ia bertanya kepada Nabi shallallahu 'alaihi wasallam tentang seorang laki-laki yang bercumbu dengan isterinya kemudian tidak mengeluarkan mani, maka beliau lalu menjawab: \"Jika salah seorang dari kalian mendapati yang demikian hendaklah memercikkan air pada kemaluannya. Yakni mencucinya dan berwudlu.\""},"467":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَعَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ حُنَيْفٍ قَالَكُنْتُ أَلْقَى مِنْ الْمَذْيِ شِدَّةً فَأُكْثِرُ مِنْهُ الِاغْتِسَالَ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا يُجْزِيكَ مِنْ ذَلِكَ الْوُضُوءُ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ بِمَا يُصِيبُ ثَوْبِي قَالَ إِنَّمَا يَكْفِيكَ كَفٌّ مِنْ مَاءٍ تَنْضَحُ بِهِ مِنْ ثَوْبِكَ حَيْثُ تَرَى أَنَّهُ أَصَابَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dan [Abdah bin Sulaiman] dari [Muhammad bin Ishaq] berkata, telah menceritakan kepada kami [Sa'id bin Ubaid As Sabbaq] dari [Bapaknya] dari [Sahal bin Hunaif] berkata; Aku banyak mengeluarkan madzi hingga aku pun sering mandi. Lalu aku bertanya kepada Nabi shallallahu 'alaihi wasallam, maka beliau menjawab: \"Kamu cukup berwudlu dari hal itu, \" aku bertanya lagi; \"Wahai Rasulullah, bagaimana dengan madzi yang mengenai kainku?\" beliau menjawab: \"Engkau cukup memercikkan air dengan telapak tangan pada kain yang menurutmu terkena.\""},"468":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مِسْعَرٌ عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ أَبِي حَبِيبِ بْنِ يَعْلَى بْنِ مُنْيَةَ عَنْ ابْنِ عَبَّاسٍأَنَّهُ أَتَى أُبَيَّ بْنَ كَعْبٍ وَمَعَهُ عُمَرُ فَخَرَجَ عَلَيْهِمَا فَقَالَ إِنِّي وَجَدْتُ مَذْيًا فَغَسَلْتُ ذَكَرِي وَتَوَضَّأْتُ فَقَالَ عُمَرُ أَوَ يُجْزِئُ ذَلِكَ قَالَ نَعَمْ قَالَ أَسَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Mis'ar] dari [Mush'ab bin Syaibah] dari [Abu Habib bin Ya'la bin Munabbih] dari [Ibnu 'Abbas] bahwasanya ia mendatangi Ubai bin Ka'ab yang waktu itu ia sedang bersama Umar, ia menemui keduanya dan berkata: \"Aku mendapati madzi, lalu aku mencuci kemaluanku dan berwudlu.\" Umar berkata; \"Apakah itu bisa mencukupi?\" ia menjawab; \"Ya.\" Umar bertanya lagi, \"Apakah kamu mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab; \"Benar.\""},"469":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ سَمِعْتُ سُفْيَانَ الثَّوْرِيَّ يَقُولُ لِزَائِدَةَ بْنِ قُدَامَةَ يَا أَبَا الصَّلْتِ هَلْ سَمِعْتَ فِي هَذَا شَيْئًا فَقَالَ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ مِنْ اللَّيْلِ فَدَخَلَ الْخَلَاءَ فَقَضَى حَاجَتَهُ ثُمَّ غَسَلَ وَجْهَهُ وَكَفَّيْهِ ثُمَّ نَامَحَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ أَنْبَأَنَا سَلَمَةُ بْنُ كُهَيْلٍ أَنْبَأَنَا بُكَيْرٌ عَنْ كُرَيْبٍ قَالَ فَلَقِيتُ كُرَيْبًا فَحَدَّثَنِي عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki] berkata; Aku mendengar Sufyan Ats Tsauri bertanya kepada [Za`idah bin Qudamah]; \"Wahai Abu Shalt, apakah engkau pernah mendengar sesuatu tentang hal ini?\" Maka ia menjawab; Telah menceritakan kepada kami [Salamah bin Kuhail] dari [Kuraib] dari [Ibnu 'Abbas]; bahwa pada suatu malam Nabi shallallahu 'alaihi wasallam bangun lalu masuk ke kamar kecil dan membuang hajatnya, kemudian beliau membasuh muka dan kedua telapak tangannya dan tidur kembali.\" Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah memberitakan kepada kami [Salamah bin Kuhail], berkata; telah memberitakan kepada kami [Bukair] dari [Kuraib], ia berkata; aku bertemu Kuraib, lalu ia menceritakan kepadaku dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, lalu dia menyebutkan sebagaimana hadits diatas."},"470":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا شَرِيكٌ عَنْ عَمْرِو بْنِ عَامِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَكُنَّا نَحْنُ نُصَلِّي الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Syarik] dari ['Amru bin Amir] dari [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu berwudlu setiap kali shalat, sedangkan kami melakukan semua shalat dengan satu wudlu.\""},"471":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ فَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ صَلَّى الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Muharib bin Ditsar] dari [Sulaiman bin Buraidah] dari [Bapaknya]; \"bahwa Nabi shallallahu 'alaihi wasallam berwudlu setiap kali shalat. Ketika terjadi penaklukan kota Makkah beliau melakukan semua shalat dengan satu kali wudlu.\""},"472":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْفَضْلُ بْنُ مُبَشِّرٍ قَالَرَأَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يُصَلِّي الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ فَقُلْتُ مَا هَذَا فَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ هَذَا فَأَنَا أَصْنَعُ كَمَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami [Ziyad bin Abdullah] berkata, telah menceritakan kepada kami [Al Fadhl bin Mubasysyir] ia berkata; Aku melihat [Jabir bin Abdullah] melaksanakan beberapa shalat dengan satu kali wudlu, maka aku bertanya; \"Apa ini?\" ia menjawab; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti ini, maka aku melakukan sebagaimana yang dilakukan oleh Rasulullah shallallahu 'alaihi wasallam.\""},"473":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ عَنْ أَبِي غُطَيْفٍ الْهُذَلِيِّ قَالَسَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ بْنِ الْخَطَّابِ فِي مَجْلِسِهِ فِي الْمَسْجِدِ فَلَمَّا حَضَرَتْ الصَّلَاةُ قَامَ فَتَوَضَّأَ وَصَلَّى ثُمَّ عَادَ إِلَى مَجْلِسِهِ فَلَمَّا حَضَرَتْ الْعَصْرُ قَامَ فَتَوَضَّأَ وَصَلَّى ثُمَّ عَادَ إِلَى مَجْلِسِهِ فَلَمَّا حَضَرَتْ الْمَغْرِبُ قَامَ فَتَوَضَّأَ وَصَلَّى ثُمَّ عَادَ إِلَى مَجْلِسِهِ فَقُلْتُ أَصْلَحَكَ اللَّهُ أَفَرِيضَةٌ أَمْ سُنَّةٌ الْوُضُوءُ عِنْدَ كُلِّ صَلَاةٍ قَالَ أَوَ فَطِنْتَ إِلَيَّ وَإِلَى هَذَا مِنِّي فَقُلْتُ نَعَمْ فَقَالَ لَا لَوْ تَوَضَّأْتُ لِصَلَاةِ الصُّبْحِ لَصَلَّيْتُ بِهِ الصَّلَوَاتِ كُلَّهَا مَا لَمْ أُحْدِثْ وَلَكِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ عَلَى كُلِّ طُهْرٍ فَلَهُ عَشْرُ حَسَنَاتٍ وَإِنَّمَا رَغِبْتُ فِي الْحَسَنَاتِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri`] berkata, telah menceritakan kepada kami [Abdurrahman bin Ziyad] dari [Abu Ghuthaif Al Hudzali] ia berkata; \"Aku mendengar [Abdullah bin Umar bin Al Khaththab] di majlisnya dalam masjid. Tatkala masuk waktu shalat ia bangun berwudlu dan shalat, kemudian kembali ke majlisnya. Tatkala tiba waktu shalat ashar, ia kembali bangun wudlu dan shalat, kemudian kembali ke majlisnya. Tatkala tiba waktu shalat maghrib, ia kembali bangun wudlu dan shalat, kemudian kembali ke majlisnya. Maka aku bertanya; \"Semoga Allah memberikan kemaslahatan kepadamu, sesuatu yang wajib atau sunnah berwudlu dalam setiap waktu shalat?\" ia menjawab; \"Apakah kamu sudah paham kepadaku dan kepada apa yang datang dariku?\" aku menjawab; \"Ya.\" Dia berkata; \"Tidak, sekiranya aku berwudlu untuk shalat subuh, sungguh aku akan melakukan semua shalat dengan satu kali wudlu selama aku belum berhadats. Tetapi aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu untuk setiap suci maka baginya sepuluh kebaikan, dan aku sangat menyukai kebaikan.\""},"474":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ قَالَ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَعَبَّادُ بْنُ تَمِيمٍ عَنْ عَمِّهِ قَالَشُكِيَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ يَجِدُ الشَّيْءَ فِي الصَّلَاةِ فَقَالَ لَا حَتَّى يَجِدَ رِيحًا أَوْ يَسْمَعَ صَوْتًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata; telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id] dan [Abbad bin Tamim] dari [Pamannya] ia berkata; Telah diadukan kepada Nabi shallallahu 'alaihi wasallam perihal seorang lelaki yang menemui kejanggalan dalam shalatnya, lalu beliau bersabda: \"Tidak, hingga ia mencium bau atau mendengar suara.\""},"475":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ مَعْمَرِ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ أَنْبَأَنَا سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّشَبُّهِ فِي الصَّلَاةِ فَقَالَ لَا يَنْصَرِفْ حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Al Muharibi] dari [Ma'mar bin Rasyid] dari [Az Zuhri] berkata, telah memberitakan kepada kami [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudri] ia berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang perasaan ragu dalam shalat. Beliau lalu menjawab: \"Jangan berhenti, sehingga ia mendengar suara atau mencium bau.\""},"476":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وُضُوءَ إِلَّا مِنْ صَوْتٍ أَوْ رِيحٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman] keduanya menuturkan; telah menceritakan kepada kami [Syu'bah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada wudlu kecuali karena suara atau Kentut.\""},"477":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُبَيْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ قَالَرَأَيْتُ السَّائِبَ بْنَ يَزِيدَ يَشُمُّ ثَوْبَهُ فَقُلْتُ مِمَّ ذَلِكَ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وُضُوءَ إِلَّا مِنْ رِيحٍ أَوْ سَمَاعٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Abdul Aziz bin Ubaidullah] dari [Muhammad bin 'Amru bin 'Atho`] ia berkata; \"Aku melihat [As Sa`ib bin Yazid] mencium kainnya, maka akupun bertanya; \"Kenapa?\" ia menjawab; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada wudlu kecuali karena bau atau suara.\""},"478":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْمَاءِ يَكُونُ بِالْفَلَاةِ مِنْ الْأَرْضِ وَمَا يَنُوبُهُ مِنْ الدَّوَابِّ وَالسِّبَاعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَلَغَ الْمَاءُ قُلَّتَيْنِ لَمْ يُنَجِّسْهُ شَيْءٌحَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Az Zubair] dari [Ubaidullah bin Abdullah bin Umar] dari [Bapaknya] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam ditanya tentang hukum air yang berada di tanah lapang dan air yang dijilat oleh binatang melata dan binatang buas?\" maka beliau pun menjawab: \"Jika air itu mencapai dua qullah (tempayan besar) maka ia tidak akan najis karena sesuatu.\" Telah menceritakan kepada kami ['Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Muhammad bin Ishaq] dari [Muhammad bin Ja'far] dari [Ubaidullah bin Abdullah bin Umar] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits diatas."},"479":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمِ بْنِ الْمُنْذِرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ أَوْ ثَلَاثًا لَمْ يُنَجِّسْهُ شَيْءٌقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا أَبُو الْوَلِيدِ وَأَبُو سَلَمَةَ وَابْنُ عَائِشَةَ الْقُرَشِيُّ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim Ibnul Mundzir] dari [Ubaidullah bin Abdullah bin Umar] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika banyak air itu mencapai dua atau tiga qullah, maka ia tidak menjadi najis karena sesuatu.\" Abu Al Hasan bin Salamah berkata; Telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Abu Al Walid dan Abu Salamah dan Ibnu Aisyah Al Qurasyi mereka berkata; telah menceritakan kepada kami Hammad bin Salamah sebagaimana hadits diatas."},"480":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدَنِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْحِيَاضِ الَّتِي بَيْنَ مَكَّةَ وَالْمَدِينَةِ تَرِدُهَا السِّبَاعُ وَالْكِلَابُ وَالْحُمُرُ وَعَنْ الطَّهَارَةِ مِنْهَا فَقَالَ لَهَا مَا حَمَلَتْ فِي بُطُونِهَا وَلَنَا مَا غَبَرَ طَهُورٌ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madani] berkata, telah menceritakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [Bapaknya] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam ditanya tentang telaga-telaga yang terdapat di antara Makkah dan Madinah yang dikunjungi hewan buas, anjing dan himar, serta hukum bersuci dengannya. Maka beliau pun menjawab: \"Baginya apa yang dikandung di dalam perutnya dan bagi kita tidak menghalangi untuk bersuci.\" "},"481":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا شَرِيكٌ عَنْ طَرِيفِ بْنِ شِهَابٍ قَالَ سَمِعْتُ أَبَا نَضْرَةَ يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَانْتَهَيْنَا إِلَى غَدِيرٍ فَإِذَا فِيهِ جِيفَةُ حِمَارٍ قَالَ فَكَفَفْنَا عَنْهُ حَتَّى انْتَهَى إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الْمَاءَ لَا يُنَجِّسُهُ شَيْءٌ فَاسْتَقَيْنَا وَأَرْوَيْنَا وَحَمَلْنَا","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Syarik] dari [Tharif bin Syihab] ia berkata; aku mendengar [Abu Nadlrah] menceritakan dari [Jabir bin Abdullah] ia berkata; Kami sampai pada sebuah mata air, ternyata di sana terdapat bangkai keledai. Jabir berkata; Kami menahan diri darinya hingga Rasulullah shallallahu 'alaihi wasallam datang. Maka beliau bersabda: \"Sesungguhnya air tidak menjadi najis karena sesuatu\". Lalu kami mengambil dan meminum serta berbekal dengannya.\" "},"482":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ وَالْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيَّانِ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا رِشْدِينُ أَنْبَأَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَاءَ لَا يُنَجِّسُهُ شَيْءٌ إِلَّا مَا غَلَبَ عَلَى رِيحِهِ وَطَعْمِهِ وَلَوْنِهِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] dan ['Abbas bin Al Walid Ad Dimasyqi] keduanya berkata; telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Risydin] berkata, telah memberitakan kepada kami [Mu'awiyah bin Shalih] dari [Rasyid bin Sa'd] dari [Abu Umamah Al Bahili] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya air tidak bisa menjadi najis karena sesuatu kecuali bila merubah bau, rasa dan warnanya.\""},"483":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَابُوسَ بْنِ أَبِي الْمُخَارِقِ عَنْ لُبَابَةَ بِنْتِ الْحَارِثِ قَالَتْبَالَ الْحُسَيْنُ بْنُ عَلِيٍّ فِي حِجْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعْطِنِي ثَوْبَكَ وَالْبَسْ ثَوْبًا غَيْرَهُ فَقَالَ إِنَّمَا يُنْضَحُ مِنْ بَوْلِ الذَّكَرِ وَيُغْسَلُ مِنْ بَوْلِ الْأُنْثَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Simak bin Harb] dari [Qabus bin Abul Mukhariq] dari [Lubabah binti Al Harits] ia berkata; Al Hasan bin Ali kencing di pangkuan Rasulullah shallallahu 'alaihi wasallam, maka aku berkata; \"Ya Rasulullah, berikan bajumu kepadaku, dan pakailah baju yang lainnya.\" Maka beliau pun bersabda: \"Kencing bayi lelaki cukup diperciki dan kencing bayi perempuan hendaknya dicuci.\""},"484":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ فَبَالَ عَلَيْهِ فَأَتْبَعَهُ الْمَاءَ وَلَمْ يَغْسِلْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; \"Seorang anak kecil diberikan kepada Nabi shallallahu 'alaihi wasallam kemudian ia mengencinginya, maka beliau pun memercikkan air dan tidak mencucinya.\""},"485":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْدَخَلْتُ بِابْنٍ لِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْكُلْ الطَّعَامَ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَرَشَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ummu Qais binti Mihshan] ia berkata; \"Aku bersama anakku yang belum makan makanan (masih bayi), masuk menemui Rasulullah shallallahu 'alaihi wasallam hingga ia mengencinginya, maka beliau pun minta diambilkan air seraya memercikinya.\""},"486":{"ar":"حَدَّثَنَا حَوْثَرَةُ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ سَعِيدِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ أَنْبَأَنَا أَبِي عَنْ قَتَادَةَ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ أَبِيهِ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي بَوْلِ الرَّضِيعِ يُنْضَحُ بَوْلُ الْغُلَامِ وَيُغْسَلُ بَوْلُ الْجَارِيَةِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَحْمَدُ بْنُ مُوسَى بْنِ مَعْقِلٍ حَدَّثَنَا أَبُو الْيَمَانِ الْمِصْرِيُّ قَالَ سَأَلْتُ الشَّافِعِيَّ عَنْ حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَشُّ مِنْ بَوْلِ الْغُلَامِ وَيُغْسَلُ مِنْ بَوْلِ الْجَارِيَةِ وَالْمَاءَانِ جَمِيعًا وَاحِدٌ قَالَ لِأَنَّ بَوْلَ الْغُلَامِ مِنْ الْمَاءِ وَالطِّينِ وَبَوْلَ الْجَارِيَةِ مِنْ اللَّحْمِ وَالدَّمِ ثُمَّ قَالَ لِي فَهِمْتَ أَوْ قَالَ لَقِنْتَ قَالَ قُلْتُ لَا قَالَ إِنَّ اللَّهَ تَعَالَى لَمَّا خَلَقَ آدَمَ خُلِقَتْ حَوَّاءُ مِنْ ضِلْعِهِ الْقَصِيرِ فَصَارَ بَوْلُ الْغُلَامِ مِنْ الْمَاءِ وَالطِّينِ وَصَارَ بَوْلُ الْجَارِيَةِ مِنْ اللَّحْمِ وَالدَّمِ قَالَ قَالَ لِي فَهِمْتَ قُلْتُ نَعَمْ قَالَ لِي نَفَعَكَ اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Hautsarah bin Muhammad] dan [Muhammad bin Sa'id bin Yazid bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah memberitakan kepada kami [Bapakku] dari [Qotadah] dari [Abu Harb bin Abul Aswad Ad Dili] dari [Bapaknya] dari [Ali] bahwa Nabi shallallahu 'alaihi wasallam bersabda berkenaan dengan kencing anak kecil yang masih menyusu: \"Anak laki-laki diperciki sedangkan anak perempuan di cuci.\" Abu Al Hasan bin Salamah berkata, telah menceritakan kepada kami Ahmad bin Musa bin Ma'qil berkata, telah menceritakan kepada kami Abu Al Yamani Al Mishri berkata; aku bertanya kepada Imam Asy Syafi'i berkenaan dengan hadits Nabi shallallahu 'alaihi wasallam: \"Pada bayi laki-laki diperciki dan pada bayi perempuan di cuci. Sedang kedua air tersebut adalah satu.\" Beliau bersabda lagi: \"Sebab kencing anak laki-laki dari air dan tanah sedangkan kencing anak perempuan dari daging dan darah.\" Setelah itu Imam Syafi'i berkata kepadaku; \"Engkau paham! \", atau ia mengatakan, \"engkau mengerti! \" Abu Al Yamani Al Mishri berkata; Aku berkata; \"Tidak.\" Imam Syafi'i berkata; \"Ketika Allah menciptakan Adam, Hawa juga dicipta dari tulang rusuknya yang pendek. Maka kencing anak laki-laki dari air dan tanah sedangkan kencing anak perempuan dari daging dan darah.\" Abu Al Yamani Al Mishri berkata; \"Imam Syafi'i berkata kepadaku; \"Engkau paham! \" Aku menjawab; \"Ya, \" Imam Syafi'i berkata kepadaku; \"Semoga dengannya Allah memberimu manfaat.\""},"487":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ وَمُجَاهِدُ بْنُ مُوسَى وَالْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالُوا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا يَحْيَى بْنُ الْوَلِيدِ حَدَّثَنَا مُحِلُّ بْنُ خَلِيفَةَ أَخْبَرَنَا أَبُو السَّمْحِ قَالَكُنْتُ خَادِمَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِيءَ بِالْحَسَنِ أَوْ الْحُسَيْنِ فَبَالَ عَلَى صَدْرِهِ فَأَرَادُوا أَنْ يَغْسِلُوهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُشَّهُ فَإِنَّهُ يُغْسَلُ بَوْلُ الْجَارِيَةِ وَيُرَشُّ مِنْ بَوْلِ الْغُلَامِ","id":"Telah menceritakan kepada kami ['Amru bin Ali] dan [Mujahid bin Musa] dan ['Abbas bin Abdul Azhim] mereka berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Yahya Ibnul Walid] berkata, telah menceritakan kepada kami [Muhil bin Khalifah] berkata, telah mengabarkan kepada kami [Abu As Samh] ia berkata; Ketika Aku menjadi pembantu Nabi shallallahu 'alaihi wasallam, Hasan atau Husain datang hingga ia kencing di dada beliau. Maka para sahabat pun hendak mencucinya. Namun Rasulullah shallallahu 'alaihi wasallam bersabda: \"Percikilah ia, sesungguhnya kencing bayi wanita dicuci dan kencing bayi lelaki cukup diperciki.\""},"488":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أُمِّ كُرْزٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَوْلُ الْغُلَامِ يُنْضَحُ وَبَوْلُ الْجَارِيَةِ يُغْسَلُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari ['Amru bin Syu'aib] dari [Ummi Kurz] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kencing bayi lelaki cukup diperciki sedangkan kencing bayi wanita dicuci.\""},"489":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ أَعْرَابِيًّا بَالَ فِي الْمَسْجِدِ فَوَثَبَ إِلَيْهِ بَعْضُ الْقَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُزْرِمُوهُ ثُمَّ دَعَا بِدَلْوٍ مِنْ مَاءٍ فَصَبَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Tsabit] dari [Anas] berkata; Seorang arab badui kencing di dalam masjid hingga sebagian para sahabat melompat kepadanya (hendak menghajar). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan ia lari! \" lalu beliau minta diambilkan satu ember air dan menyiramkannya."},"490":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَقَالَ دَخَلَ أَعْرَابِيٌّ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَقَالَ اللَّهُمَّ اغْفِرْ لِي وَلِمُحَمَّدٍ وَلَا تَغْفِرْ لِأَحَدٍ مَعَنَا فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَقَدْ احْتَظَرْتَ وَاسِعًا ثُمَّ وَلَّى حَتَّى إِذَا كَانَ فِي نَاحِيَةِ الْمَسْجِدِ فَشَجَ يَبُولُ فَقَالَ الْأَعْرَابِيُّ بَعْدَ أَنْ فَقِهَ فَقَامَ إِلَيَّ بِأَبِي وَأُمِّي فَلَمْ يُؤَنِّبْ وَلَمْ يَسُبَّ فَقَالَ إِنَّ هَذَا الْمَسْجِدَ لَا يُبَالُ فِيهِ وَإِنَّمَا بُنِيَ لِذِكْرِ اللَّهِ وَلِلصَّلَاةِ ثُمَّ أَمَرَ بِسَجْلٍ مِنْ مَاءٍ فَأُفْرِغَ عَلَى بَوْلِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam duduk, seorang arab badui masuk ke dalam masjid. Kemudian arab badui itu berdoa; \"Ya Allah, ampunilah aku dan Muhammad dan jangan engkau ampuni orang lain bersama kami.\" Maka Rasulullah shallallahu 'alaihi wasallam tertawa seraya bersabda: \"Engkau telah mempersempit sesuatu yang luas.\" Laki-laki itu kemudian berlalu dan kencing di pojok masjid. maka ketika arab badui itu telah memahami (tidak boleh kencing dalam masjid) ia berjalan ke arahku dan berkata; \"Demi bapak dan ibuku, ia (Muhammad) tidak menghardik dan tidak mencela.\" Beliau lalu bersabda: \"Sesungguhnya masjid ini tidak boleh dikencingi, ia dibangun untuk dzikir dan shalat kepada Allah.\" Beliau kemudian minta diambilkan satu ember air, lalu menyiramkan pada bekas kencing tersebut.\""},"491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ عَنْ عُبَيْدِ اللَّهِ الْهُذَلِيِّ قَالَ مُحَمَّدُ بْنُ يَحْيَى هُوَ عِنْدَنَا ابْنُ أَبِي حُمَيْدٍ أَنْبَأَنَا أَبُو الْمَلِيحِ الْهُذَلِيُّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تُشْرِكْ فِي رَحْمَتِكَ إِيَّانَا أَحَدًا فَقَالَ لَقَدْ حَظَرْتَ وَاسِعًا وَيْحَكَ أَوْ وَيْلَكَ قَالَ فَشَجَ يَبُولُ فَقَالَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ ثُمَّ دَعَا بِسَجْلٍ مِنْ مَاءٍ فَصَبَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah] dari [Ubaidullah Al Hudzali], berkata Muhammad bin Yahya -menurut kami dia itu anaknya Abu Humaid-, telah memberitakan kepada kami [Abu Malih Al Hudzali] dari [Watsilah bin Al Asyqa'] ia berkata; Seorang arab badui datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; \"Ya Allah, rahmatilah aku dan Muhammad, dan jangan Engkau sekutukan kami dengan seorang pun dalam rahmat-Mu.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau telah mempersempit sesuatu yang luas, celaka engkau, \" atau beliau mengatakan, \"malangnya dirimu.\" Watsilah berkata; \"Kemudian arab badui tersebut kencing. Para sahabat Nabi shallallahu 'alaihi wasallam menghardiknya; \"pergi! \" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Biarkan dia.\" Kemudian beliau meminta setimba air dan menyiramkan ke atasnya.\""},"492":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُمَارَةَ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أُمِّ وَلَدٍ لِإِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهَا سَأَلَتْ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْإِنِّي امْرَأَةٌ أُطِيلُ ذَيْلِي فَأَمْشِي فِي الْمَكَانِ الْقَذِرِ فَقَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطَهِّرُهُ مَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah menceritakan kepada kami [Muhammad bin Umarah bin 'Amru bin Hazm] dari [Muhammad bin Ibrahim Ibnul Harits At Taimi] dari [Budak wanita] milik Ibrahim bin Abdurrahman bin Auf, bahwasanya ia bertanya kepada Ummu Salamah, isteri Nabi shallallahu 'alaihi wasallam, Ia berkata; \"Sesungguhnya aku adalah seorang wanita yang kain bajunya memanjang ke bawah, dan aku berjalan di tempat-tempat kotor?\" [Ummu Salamah] menjawab; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia akan disucikan oleh tanah setelahnya.\""},"493":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ الْيَشْكُرِيُّ عَنْ ابْنِ أَبِي حَبِيبَةَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقِيلَ يَا رَسُولَ اللَّهِ إِنَّا نُرِيدُ الْمَسْجِدَ فَنَطَأُ الطَّرِيقَ النَّجِسَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَرْضُ يُطَهِّرُ بَعْضُهَا بَعْضًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Ibrahim bin Isma'il Al Yasykuri] dari [Ibnu Abu Habibah] dari [Dawud bin Al Hushain] dari [Abu Sufyan] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya; \"Ya Rasulullah, ketika kami ingin bergegas ke masjid, kami menginjak tanah yang bernajis! \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara tanah satu dengan yang lain saling mensucikan.\" "},"494":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ امْرَأَةٍ مِنْ بَنِي عَبْدِ الْأَشْهَلِ قَالَتْسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ بَيْنِي وَبَيْنَ الْمَسْجِدِ طَرِيقًا قَذِرَةً قَالَ فَبَعْدَهَا طَرِيقٌ أَنْظَفُ مِنْهَا قُلْتُ نَعَمْ قَالَ فَهَذِهِ بِهَذِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Abdullah bin Isa] dari [Musa bin Abdullah bin Yazid] dari [Seorang wanita] bani Abdul Asyhal, ia berkata; Aku bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Sesungguhnya antara aku dan masjid ada jalan yang kotor (najis), \" maka beliau bersabda: \"Apakah setelahnya ada jalan yang lebih bersih darinya?\" aku menjawab; \"Benar.\" Beliau bersabda: \"Yang kotor akan disucikan dengan yang bersih.\" "},"495":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ حُمَيْدٍ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّهُ لَقِيَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ وَهُوَ جُنُبٌ فَانْسَلَّ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ قَالَ أَيْنَ كُنْتَ يَا أَبَا هُرَيْرَةَ قَالَ يَا رَسُولَ اللَّهِ لَقِيتَنِي وَأَنَا جُنُبٌ فَكَرِهْتُ أَنْ أُجَالِسَكَ حَتَّى أَغْتَسِلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ لَا يَنْجُسُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulaiyah] dari [Humaid] dari [Bakr bin Abdullah] dari [Abu Rafi'] dari [Abu Hurairah] bahwasanya ia pernah bertemu dengan Nabi shallallahu 'alaihi wasallam di jalanan Madinah, sedangkan dirinya dalam kondisi junub. Ia kemudian menghilang pergi hingga Nabi shallallahu 'alaihi wasallam mencarinya. Ketika ia datang, Nabi shallallahu 'alaihi wasallam bertanya: \"Wahai Abu Hurairah, dari mana engkau?\" Abu Hurairah menjawab; \"Wahai Rasulullah, ketika engkau bertemu dengan aku, sesungguhnya aku dalam keadaan junub, dan aku tidak nyaman untuk duduk bersamamu hingga aku mandi dahulu.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin itu tidak najis.\""},"496":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ جَمِيعًا عَنْ مِسْعَرٍ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيَنِي وَأَنَا جُنُبٌ فَحِدْتُ عَنْهُ فَاغْتَسَلْتُ ثُمَّ جِئْتُ فَقَالَ مَا لَكَ قُلْتُ كُنْتُ جُنُبًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُسْلِمَ لَا يَنْجُسُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Yahya bin Sa'id], semuanya dari [Mis'ar] dari [Washil Al Ahdab] dari [Abu Wa`il] dari [Hudzaifah] ia berkata; Nabi shallallahu 'alaihi wasallam keluar dan bertemu denganku sedangkan aku dalam kodisi junub. Maka aku merasa tidak nyaman hingga aku mandi dan datang kembali menemui beliau. Beliau pun bertanya: \"Ada apa denganmu?\" aku menjawab; \"Aku dalam kondisi junub, \" maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya seorang muslim tidak najis.\""},"497":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ سَأَلْتُ سُلَيْمَانَ بْنَ يَسَارٍ عَنْ الثَّوْبِ يُصِيبُهُ الْمَنِيُّ أَنَغْسِلُهُ أَوْ نَغْسِلُ الثَّوْبَ كُلَّهُ قَالَ سُلَيْمَانُ قَالَتْ عَائِشَةُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصِيبُ ثَوْبَهُ فَيَغْسِلُهُ مِنْ ثَوْبِهِ ثُمَّ يَخْرُجُ فِي ثَوْبِهِ إِلَى الصَّلَاةِ وَأَنَا أَرَى أَثَرَ الْغَسْلِ فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari ['Amru bin Maimun] ia berkata; Aku bertanya kepada [Sulaiman bin Yasar] tentang kain yang terkena mani, apakah kami cukup mencuci bekasnya atau mencuci kain seluruhnya? Maka Sulaiman menjawab; [Aisyah] berkata; \"Kain Nabi shallallahu 'alaihi wasallam terkena mani, lalu beliau mencuci bekas mani pada kain tersebut. Setelah itu beliau keluar shalat dan aku masih melihat bekas cuciannya tersebut.\""},"498":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْرُبَّمَا فَرَكْتُهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Tharif] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] semuanya dari [Al A'masy] dari [Ibrahim] dari [Hammam Ibnul Harits] dari [Aisyah] ia berkata; \"Aku pernah mengerik bekas mani pada kain Rasulullah shallallahu 'alaihi wasallam dengan tanganku.\""},"499":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَنَزَلَ بِعَائِشَةَ ضَيْفٌ فَأَمَرَتْ لَهُ بِمِلْحَفَةٍ لَهَا صَفْرَاءَ فَاحْتَلَمَ فِيهَا فَاسْتَحْيَا أَنْ يُرْسِلَ بِهَا وَفِيهَا أَثَرُ الِاحْتِلَامِ فَغَمَسَهَا فِي الْمَاءِ ثُمَّ أَرْسَلَ بِهَا فَقَالَتْ عَائِشَةُ لِمَ أَفْسَدَ عَلَيْنَا ثَوْبَنَا إِنَّمَا كَانَ يَكْفِيهِ أَنْ يَفْرُكَهُ بِإِصْبَعِهِ رُبَّمَا فَرَكْتُهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِصْبَعِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Himam Ibnul Harits] berkata; \"Seorang tamu singgah di rumah Aisyah, lalu Aisyah memberikan selimut kuning miliknya. Tamu tersebut mimpi basah dan mengenai selimut tersebut hingga timbul rasa malu untuk mengembalikan kepada Aisyah sedangkan di dalamnya masih ada bekas air maninya. Maka tamu tersebut mencelupkan selimut tersebut ke dalam air setelah itu mengirimkannya kepada Aisyah. Maka [Aisyah] pun berkata; \"Kenapa orang itu merusak kain kami, padahal cukup baginya mengerik dengan jari tangannya. Aku pernah mengerik bekas mani pada kain Rasulullah shallallahu 'alaihi wasallam dengan jemariku.\" "},"500":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي أَجِدُهُ فِي ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَحُتُّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] dari [Mughirah] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata; \"Aku pernah mendapati pada kain Rasulullah shallallahu 'alaihi wasallam (bekas mani), lalu aku menggosoknya.\""}};
